insert into public.quiz_questions
  (id, category, subtopic, question, options, correct, explanation, code_reference, source_url, difficulty, verified, verifier_note)
values
  ('ibc-027', 'IBC', 'occupant-load', 'Under IBC Table 1004.5, what occupant load factor (gross) is used for a business area such as an office?', '{"A": "100 square feet per occupant", "B": "150 square feet per occupant", "C": "200 square feet per occupant", "D": "50 square feet per occupant"}'::jsonb, 'B', 'Table 1004.5 assigns business areas a factor of 150 gross square feet per occupant. To find occupant load you divide the gross floor area by 150. This is one of the most-tested factors on the exam because business space is so common.', 'IBC Table 1004.5', 'https://up.codes/s/areas-without-fixed-seating', 'iniciante', true, 'Confirmed 150 gross SF/occupant for Business in IBC Table 1004.5 (2018/2021/2024).'),
  ('ibc-028', 'IBC', 'occupant-load', 'For an assembly space with chairs only (concentrated, not fixed), IBC Table 1004.5 assigns which occupant load factor?', '{"A": "5 net square feet per occupant", "B": "7 net square feet per occupant", "C": "15 net square feet per occupant", "D": "11 net square feet per occupant"}'::jsonb, 'B', 'Concentrated assembly use without fixed seats (chairs only, such as a lecture hall set with chairs) uses 7 net square feet per occupant. Unconcentrated assembly (tables and chairs) is 15 net, and standing space is 5 net. Net area excludes fixed equipment and accessory spaces.', 'IBC Table 1004.5', 'https://up.codes/s/areas-without-fixed-seating', 'intermediario', true, 'Confirmed: concentrated chairs-only 7 net, unconcentrated tables/chairs 15 net, standing 5 net per Table 1004.5.'),
  ('ibc-029', 'IBC', 'occupant-load', 'Under IBC Table 1004.5, the occupant load factor for a commercial kitchen is:', '{"A": "100 gross square feet per occupant", "B": "150 gross square feet per occupant", "C": "200 gross square feet per occupant", "D": "300 gross square feet per occupant"}'::jsonb, 'C', 'Commercial kitchens use 200 gross square feet per occupant. Mercantile general sales is 60 gross, exercise rooms 50 gross, and accessory storage or mechanical equipment rooms 300 gross. Knowing the relative size of each factor helps you pick correct answers quickly.', 'IBC Table 1004.5', 'https://idighardware.com/ibc-occupant-load-estimator/', 'intermediario', true, 'Confirmed commercial kitchen 200 gross; mercantile 60; exercise 50; storage/mechanical 300 in Table 1004.5.'),
  ('ibc-030', 'IBC', 'egress', 'A single-story Group B (business) space is being designed with one exit. Under IBC Table 1006.2.1, what is the maximum occupant load permitted before a second exit access doorway is required?', '{"A": "29", "B": "49", "C": "50", "D": "100"}'::jsonb, 'B', 'Table 1006.2.1 permits a single exit or exit access doorway from a Group B space when the occupant load does not exceed 49 (and the common path of egress travel limit is met). At an occupant load of 50 or more, a second exit access doorway is required.', 'IBC Table 1006.2.1', 'https://up.codes/s/egress-based-on-occupant-load-and-common-path-of-egress-travel-distance', 'intermediario', true, 'Confirmed Group B single-exit max occupant load 49 in Table 1006.2.1.'),
  ('ibc-031', 'IBC', 'egress', 'Under IBC Section 1006.2.1.1, three exits or exit access doorways are required from any space when the occupant load is:', '{"A": "Greater than 100", "B": "Greater than 250", "C": "501 to 1,000", "D": "More than 1,000"}'::jsonb, 'C', 'Two exit access doorways serve up to 500 occupants. Three are required for an occupant load of 501 to 1,000, and four are required for an occupant load greater than 1,000. These thresholds are heavily tested.', 'IBC 1006.2.1.1', 'https://up.codes/s/number-of-exits-and-exit-access-doorways', 'intermediario', true, 'Confirmed: 3 exits for 501-1000, 4 exits for >1000 per Section 1006.2.1.1/1006.3.'),
  ('ibc-032', 'IBC', 'egress', 'Under IBC Table 1017.2, the maximum exit access travel distance for a Group B occupancy that is NOT equipped with an automatic sprinkler system is:', '{"A": "150 feet", "B": "200 feet", "C": "250 feet", "D": "300 feet"}'::jsonb, 'B', 'Table 1017.2 limits exit access travel distance in a non-sprinklered Group B occupancy to 200 feet. Where the building is equipped throughout with an automatic sprinkler system, the limit increases to 300 feet. The sprinkler bonus is a recurring exam theme.', 'IBC Table 1017.2', 'https://up.codes/s/limitations', 'intermediario', true, 'Confirmed Group B 200 ft non-sprinklered / 300 ft sprinklered in Table 1017.2.'),
  ('ibc-033', 'IBC', 'egress', 'Under IBC Table 1017.2, a Group F-1 or S-1 occupancy that is one story, has a minimum ceiling height of 24 feet, and is fully sprinklered may have a maximum exit access travel distance of:', '{"A": "250 feet", "B": "300 feet", "C": "400 feet", "D": "500 feet"}'::jsonb, 'C', 'Section 1017.2.2 permits an increased exit access travel distance of 400 feet in a one-story Group F-1 or S-1 building with at least a 24-foot ceiling and a full automatic sprinkler system. The tall, open, sprinklered industrial building gets the most generous allowance.', 'IBC 1017.2.2', 'https://up.codes/s/group-f-1-and-s-1-increase', 'avancado', true, 'Confirmed 400 ft increase for 1-story F-1/S-1 with 24 ft ceiling and sprinklers, Section 1017.2.2.'),
  ('ibc-034', 'IBC', 'corridors', 'Under IBC Section 1020.2, the minimum width of a corridor serving an occupant load of 50 or more in a typical commercial building is:', '{"A": "36 inches", "B": "44 inches", "C": "48 inches", "D": "60 inches"}'::jsonb, 'B', 'The general minimum corridor width is 44 inches. A 36-inch corridor is permitted only where the occupant load served is less than 50. Where calculated egress capacity demands more, the larger required width governs over the minimum.', 'IBC 1020.2', 'https://usmadesupply.com/resources/building-codes-standards/emergency-life-safety/ibc-corridor-width', 'iniciante', true, 'Confirmed 44 in general minimum, 36 in for occupant load <50, Section 1020.2.'),
  ('ibc-035', 'IBC', 'corridors', 'Under IBC Table 1020.1, a corridor in a non-sprinklered building serving an occupant load greater than 30 must have a fire-resistance rating of at least:', '{"A": "0 hours", "B": "1 hour", "C": "1.5 hours", "D": "2 hours"}'::jsonb, 'B', 'Corridors serving an occupant load greater than 30 require a 1-hour fire-resistance rating where the building is not sprinklered. In buildings equipped throughout with an automatic sprinkler system, the required corridor rating commonly drops to 0 hours for most occupancies.', 'IBC Table 1020.1', 'https://usmadesupply.com/resources/building-codes-standards/emergency-life-safety/ibc-corridor-width', 'intermediario', true, 'Confirmed 1-hr corridor rating for OL>30 non-sprinklered, 0-hr sprinklered, Table 1020.1.'),
  ('ibc-036', 'IBC', 'corridors', 'Under IBC Section 1020.4, the maximum length of a dead-end corridor in a building that is NOT equipped throughout with an automatic sprinkler system is:', '{"A": "10 feet", "B": "20 feet", "C": "35 feet", "D": "50 feet"}'::jsonb, 'B', 'Dead-end corridors are limited to 20 feet in non-sprinklered buildings. Several occupancies permit up to 50 feet where the building is equipped throughout with an automatic sprinkler system. Beyond these limits, the dead end must be eliminated or shortened.', 'IBC 1020.4', 'https://usmadesupply.com/resources/building-codes-standards/emergency-life-safety/ibc-corridor-width', 'intermediario', true, 'Confirmed 20 ft dead-end max, 50 ft sprinklered, Section 1020.4.'),
  ('ibc-037', 'IBC', 'interior-finish', 'Under IBC Table 803.13 / Section 803, an interior wall and ceiling finish with a flame spread index of 0 to 25 is classified as:', '{"A": "Class A", "B": "Class B", "C": "Class C", "D": "Class D"}'::jsonb, 'A', 'Class A finishes have a flame spread index of 0 to 25. Class B is 26 to 75 and Class C is 76 to 200. All three classes share a smoke-developed index limit of 0 to 450. Class A is the most fire-restrictive and is required in the highest-hazard locations such as enclosed vertical exits.', 'IBC 803.1.2', 'https://up.codes/s/interior-finish-requirements-based-on-occupancy', 'iniciante', true, 'Confirmed Class A 0-25, B 26-75, C 76-200 flame spread; smoke-developed 0-450 all classes.'),
  ('ibc-038', 'IBC', 'interior-finish', 'Under the IBC, a Class C interior wall and ceiling finish has a flame spread index in which range?', '{"A": "0 to 25", "B": "26 to 75", "C": "76 to 200", "D": "201 to 450"}'::jsonb, 'C', 'Class C finishes carry a flame spread index of 76 to 200. Class C is the least fire-restrictive of the three classes and is generally permitted only in lower-hazard locations such as rooms and enclosed spaces, not in exit enclosures or exit passageways.', 'IBC 803.1.2', 'https://up.codes/s/interior-finish-requirements-based-on-occupancy', 'iniciante', true, 'Confirmed Class C flame spread 76-200 per Section 803.1.2.'),
  ('ibc-039', 'IBC', 'fire-resistance', 'Under IBC Table 601, the required fire-resistance rating of the primary structural frame for Type I-A construction is:', '{"A": "1 hour", "B": "2 hours", "C": "3 hours", "D": "4 hours"}'::jsonb, 'C', 'Type I-A construction requires a 3-hour rated primary structural frame. Type II-A requires 1 hour, and Type V-B requires 0 hours (no rating). Table 601 is the core matrix linking construction type to required hourly ratings of structural elements.', 'IBC Table 601', 'https://bahlfireproofing.com/ib-table-601-fire-resistance-ratings/', 'intermediario', true, 'Confirmed Type I-A frame 3 hr, II-A 1 hr, V-B 0 hr in Table 601.'),
  ('ibc-040', 'IBC', 'fire-resistance', 'Under IBC Table 601, which construction type permits a primary structural frame with a 0-hour (unrated) fire-resistance rating?', '{"A": "Type I-B", "B": "Type II-A", "C": "Type III-A", "D": "Type V-B"}'::jsonb, 'D', 'Type V-B (and Type II-B and III-B for the structural frame) permit 0-hour, unrated primary structural frames under Table 601. The ''B'' sub-classification of each type is the unprotected, lower fire-resistance version. Type V-B is the most common construction type for small wood-frame commercial buildings.', 'IBC Table 601', 'https://bahlfireproofing.com/ib-table-601-fire-resistance-ratings/', 'intermediario', true, 'Confirmed Type V-B (and II-B/III-B) frame 0 hr in Table 601.'),
  ('ibc-041', 'IBC', 'occupancy-separation', 'Under IBC Table 508.4, a Group A-2 occupancy adjacent to a Group B occupancy in a fully sprinklered building requires a separation with a fire-resistance rating of:', '{"A": "0 hours", "B": "1 hour", "C": "2 hours", "D": "3 hours"}'::jsonb, 'B', 'Table 508.4 requires a 1-hour separation between A-2 and B occupancies in a sprinklered building (2 hours where not sprinklered). The separation is achieved with fire barriers (Section 707), horizontal assemblies (Section 711), or both. Sprinklers reduce the required rating.', 'IBC Table 508.4', 'https://up.codes/s/separated-occupancies', 'intermediario', true, 'Confirmed A-2/B separation 1 hr sprinklered, 2 hr non-sprinklered, Table 508.4.'),
  ('ibc-042', 'IBC', 'occupancy-separation', 'Under IBC Section 508.4, where separated occupancies are used, the required separation is constructed as fire barriers, horizontal assemblies, or both. The fire barriers must comply with which section?', '{"A": "Section 705", "B": "Section 707", "C": "Section 713", "D": "Section 1020"}'::jsonb, 'B', 'Fire barriers used to separate occupancies must comply with Section 707, and horizontal assemblies must comply with Section 711. Section 705 governs exterior walls, Section 713 governs shaft enclosures, and Section 1020 governs corridors. Matching the feature to its governing section is a common exam test.', 'IBC 508.4.4', 'https://up.codes/s/separated-occupancies', 'avancado', true, 'Confirmed fire barriers per Section 707, horizontal assemblies per 711, for separated occupancies (508.4.4).'),
  ('ibc-043', 'IBC', 'fire-partitions', 'Under IBC Section 708.3, the general minimum fire-resistance rating of a fire partition (for example, a corridor wall or tenant separation) is:', '{"A": "20 minutes", "B": "0.5 hour", "C": "1 hour", "D": "2 hours"}'::jsonb, 'C', 'Fire partitions must have a minimum 1-hour fire-resistance rating. Limited exceptions allow a 0.5-hour rating, such as corridor walls permitted at 0.5 hour by Table 1020.1 or dwelling-unit separations in certain sprinklered Type IIB, IIIB, or VB buildings. The default to remember is 1 hour.', 'IBC 708.3', 'https://codes.iccsafe.org/s/IBC2018P6/chapter-7-fire-and-smoke-protection-features/IBC2018P6-Ch07-Sec708.3', 'intermediario', true, 'Confirmed fire partition 1-hr default, 0.5-hr exceptions, Section 708.3.'),
  ('ibc-044', 'IBC', 'shaft-enclosures', 'Under IBC Section 713.4, a shaft enclosure connecting four or more stories must have a fire-resistance rating of not less than:', '{"A": "1 hour", "B": "1.5 hours", "C": "2 hours", "D": "3 hours"}'::jsonb, 'C', 'Shaft enclosures connecting four or more stories require a 2-hour fire-resistance rating; those connecting fewer than four stories require 1 hour. The rating need not exceed 2 hours, and the count of connected stories includes basements but not mezzanines.', 'IBC 713.4', 'https://up.codes/s/fire-resistance-rating', 'intermediario', true, 'Confirmed 2-hr for 4+ stories, 1-hr for <4 stories, Section 713.4.'),
  ('ibc-045', 'IBC', 'shaft-enclosures', 'Under IBC Section 713.4, a shaft enclosure connecting fewer than four stories must have a fire-resistance rating of not less than:', '{"A": "0.5 hour", "B": "1 hour", "C": "2 hours", "D": "3 hours"}'::jsonb, 'B', 'A shaft connecting fewer than four stories requires a 1-hour fire-resistance rating. The enclosure rating must also be at least equal to the rating of the floor assembly penetrated, but it need not exceed 2 hours. Basements count toward the story total; mezzanines do not.', 'IBC 713.4', 'https://up.codes/s/fire-resistance-rating', 'intermediario', true, 'Confirmed 1-hr for <4 stories per Section 713.4.'),
  ('ibc-046', 'IBC', 'guards', 'Under IBC Section 1015.3, the minimum height of a guard in a commercial occupancy, measured vertically, is generally:', '{"A": "36 inches", "B": "38 inches", "C": "42 inches", "D": "48 inches"}'::jsonb, 'C', 'Guards must be at least 42 inches high, measured vertically from the adjacent walking surface (or from the leading edge of stair treads). Do not confuse this with handrail height of 34 to 38 inches; a guard prevents falls from an open side, while a handrail provides grasping support.', 'IBC 1015.3', 'https://codes.iccsafe.org/s/IBC2021P1/chapter-10-means-of-egress/IBC2021P1-Ch10-Sec1015.3', 'iniciante', true, 'Confirmed 42-in minimum guard height, Section 1015.3.'),
  ('ibc-047', 'IBC', 'guards', 'Under IBC Section 1015.2, a guard is required along an open-sided walking surface where the vertical drop to the surface below is more than:', '{"A": "24 inches", "B": "30 inches", "C": "36 inches", "D": "42 inches"}'::jsonb, 'B', 'A guard is required where a walking surface has an open side with a vertical drop of more than 30 inches, measured to the surface below, within 36 inches horizontally of the open edge. The 30-inch trigger and the 42-inch height are two separate dimensions the exam likes to mix up.', 'IBC 1015.2', 'https://co.routt.co.us/DocumentCenter/View/15200/Guards-Fall-Protection-IBC', 'intermediario', true, 'Confirmed 30-in vertical drop trigger within 36 in, Section 1015.2.'),
  ('ibc-048', 'IBC', 'handrails', 'Under IBC Section 1014.2, the height of a handrail above stair tread nosings must be uniform and within which range?', '{"A": "30 to 34 inches", "B": "32 to 36 inches", "C": "34 to 38 inches", "D": "36 to 42 inches"}'::jsonb, 'C', 'Handrail height, measured above stair tread nosings or the finished surface of a ramp slope, must be uniform and not less than 34 inches and not more than 38 inches. This range applies to handrails on stairways and ramps in commercial construction.', 'IBC 1014.2', 'https://www.co.routt.co.us/DocumentCenter/View/15201', 'iniciante', true, 'Confirmed handrail height 34-38 in, Section 1014.2.'),
  ('ibc-049', 'IBC', 'egress-illumination', 'Under IBC Section 1008.2, the means of egress illumination level under normal power must be not less than:', '{"A": "0.1 footcandle at the walking surface", "B": "1 footcandle at the walking surface", "C": "5 footcandles at the walking surface", "D": "10 footcandles at the walking surface"}'::jsonb, 'B', 'The means of egress must be illuminated to at least 1 footcandle (11 lux) at the walking surface during normal operation. Under emergency power, the initial average is 1 footcandle with a minimum of 0.1 footcandle at any point along the egress path at floor level.', 'IBC 1008.2', 'https://up.codes/s/illumination-required', 'intermediario', true, 'Confirmed 1 fc normal at walking surface; emergency avg 1 fc, min 0.1 fc, Section 1008.'),
  ('ibc-050', 'IBC', 'exit-signs', 'Under IBC Section 1013.1, exit signs must be placed so that no point in an exit access corridor or exit passageway is more than which distance from the nearest visible exit sign?', '{"A": "50 feet", "B": "75 feet", "C": "100 feet", "D": "150 feet"}'::jsonb, 'C', 'No point in an exit access corridor or exit passageway may be more than 100 feet, or the listed viewing distance of the sign (whichever is less), from the nearest visible exit sign. Exits and exit access doors must be marked with approved exit signs visible from any direction of egress travel.', 'IBC 1013.1', 'https://codes.iccsafe.org/s/IBC2021P1/chapter-10-means-of-egress/IBC2021P1-Ch10-Sec1013.1', 'intermediario', true, 'Confirmed 100-ft (or listed viewing distance, whichever less) spacing, Section 1013.1.'),
  ('ibc-051', 'IBC', 'accessible-egress', 'Under IBC Section 1009.6.3, an area of refuge must be sized to accommodate one wheelchair space of 30 inches by 48 inches for each how many occupants (or portion thereof) it serves?', '{"A": "50", "B": "100", "C": "200", "D": "300"}'::jsonb, 'C', 'Each area of refuge must provide one 30-inch by 48-inch wheelchair space for every 200 occupants (or portion thereof) based on the occupant load served. These wheelchair spaces must not reduce the required means of egress width, and access to a required space cannot be blocked by more than one adjoining space.', 'IBC 1009.6.3', 'https://www.corada.com/documents/2019CBCPG/1009-6-areas-of-refuge', 'avancado', true, 'Confirmed 30x48 in wheelchair space per 200 occupants, Section 1009.6.3.'),
  ('ibc-052', 'IBC', 'live-loads', 'Under IBC Table 1607.1, the minimum uniformly distributed live load for an office floor area in an office building is:', '{"A": "40 psf", "B": "50 psf", "C": "80 psf", "D": "100 psf"}'::jsonb, 'B', 'Office floor areas use a minimum uniformly distributed live load of 50 psf. Lobbies and first-floor corridors use 100 psf, and corridors above the first floor use 80 psf. The higher loads for circulation reflect the heavier traffic and assembly potential of those spaces.', 'IBC Table 1607.1', 'https://codes.iccsafe.org/content/IBC2021P2/chapter-16-structural-design', 'intermediario', true, 'Confirmed office 50 psf, lobbies/first-floor corridors 100 psf, corridors above first floor 80 psf, Table 1607.1.'),
  ('ibc-053', 'IBC', 'live-loads', 'Under IBC Table 1607.1, the minimum uniformly distributed live load for first-floor lobbies and corridors is:', '{"A": "50 psf", "B": "80 psf", "C": "100 psf", "D": "125 psf"}'::jsonb, 'C', 'First-floor lobbies and corridors are designed for a minimum uniformly distributed live load of 100 psf, matching assembly and egress areas where crowds may gather. Corridors above the first floor drop to 80 psf, and office areas to 50 psf.', 'IBC Table 1607.1', 'https://codes.iccsafe.org/content/IBC2021P2/chapter-16-structural-design', 'intermediario', true, 'Confirmed first-floor lobbies/corridors 100 psf, Table 1607.1.'),
  ('ibc-054', 'IBC', 'plumbing-fixtures', 'Under IBC Table 2902.1, the minimum number of water closets in a Business (B) occupancy is based on a ratio of one fixture per how many occupants for the first 50?', '{"A": "1 per 15", "B": "1 per 25", "C": "1 per 40", "D": "1 per 50"}'::jsonb, 'B', 'For Business occupancies, water closets are provided at 1 per 25 for the first 50 occupants, then 1 per 50 for the remainder. Lavatories are 1 per 40 for the first 80, then 1 per 80. Drinking fountains are 1 per 100 occupants.', 'IBC Table 2902.1', 'https://up.codes/s/minimum-number-of-fixtures', 'avancado', true, 'Confirmed Business water closets 1 per 25 first 50 then 1 per 50, Table 2902.1 (2021).'),
  ('ibc-055', 'IBC', 'plumbing-fixtures', 'Under IBC Table 2902.1, restaurants, banquet halls, and food courts must provide water closets at a minimum ratio of:', '{"A": "1 per 40", "B": "1 per 50", "C": "1 per 75", "D": "1 per 100"}'::jsonb, 'C', 'Assembly uses for food and drink consumption (restaurants, banquet halls, food courts) require water closets at 1 per 75 and drinking fountains at 1 per 500 (or as amended). These ratios are tighter than business because of higher occupant density.', 'IBC Table 2902.1', 'https://up.codes/s/minimum-number-of-fixtures', 'avancado', true, 'Confirmed restaurant/banquet/food court water closets 1 per 75, Table 2902.1.'),
  ('ibc-056', 'IBC', 'accessible-parking', 'Under IBC Table 1106.1, a parking facility with a total of 26 to 50 parking spaces must provide a minimum of how many accessible parking spaces?', '{"A": "1", "B": "2", "C": "3", "D": "4"}'::jsonb, 'B', 'Table 1106.1 requires 1 accessible space for lots of 1 to 25 spaces, 2 for 26 to 50, 3 for 51 to 75, and 4 for 76 to 100. The required accessible count rises with total parking provided.', 'IBC Table 1106.1', 'https://up.codes/s/parking-and-passenger-loading-facilities', 'intermediario', true, 'Confirmed 26-50 spaces = 2 accessible, Table 1106.1.'),
  ('ibc-057', 'IBC', 'accessible-parking', 'Under IBC Section 1106.6, van-accessible parking spaces must be provided at a minimum ratio of:', '{"A": "1 for every 4 accessible spaces", "B": "1 for every 6 accessible spaces", "C": "1 for every 8 accessible spaces", "D": "1 for every 10 accessible spaces"}'::jsonb, 'B', 'For every six, or fraction of six, accessible parking spaces, at least one must be van-accessible. A facility with one to six accessible spaces therefore needs at least one van-accessible space.', 'IBC 1106.6', 'https://up.codes/s/parking-and-passenger-loading-facilities', 'intermediario', true, 'Confirmed 1 van-accessible per 6 (or fraction) accessible spaces, Section 1106.6.'),
  ('ibc-058', 'IBC', 'special-inspections', 'Under IBC Chapter 17, the statement of special inspections identifying the required inspections and tests for a project must be prepared by:', '{"A": "The general contractor", "B": "The building official", "C": "The registered design professional in responsible charge", "D": "The special inspector"}'::jsonb, 'C', 'The registered design professional in responsible charge prepares the statement of special inspections, which the building official approves before work begins. The special inspector then performs the inspections and reports to the building official and design professional; the contractor performs the work being inspected.', 'IBC 1704.3', 'https://codes.iccsafe.org/content/IBC2018/chapter-17-special-inspections-and-tests', 'intermediario', true, 'Confirmed statement of special inspections prepared by registered design professional, approved by building official, Section 1704.3.'),
  ('ibc-059', 'IBC', 'special-inspections', 'Under IBC Section 1705.2, complete joint penetration (CJP) groove welds in structural steel generally require which type of special inspection?', '{"A": "No special inspection", "B": "Periodic special inspection", "C": "Continuous special inspection", "D": "Owner self-certification"}'::jsonb, 'C', 'Complete joint penetration groove welds generally require continuous special inspection, meaning the special inspector is present during the welding operation. Many fillet welds and single-pass welds require only periodic inspection. The distinction between continuous and periodic is a recurring Chapter 17 exam topic.', 'IBC 1705.2', 'https://codes.iccsafe.org/content/IBC2018/chapter-17-special-inspections-and-tests', 'avancado', true, 'Confirmed CJP welds continuous inspection, fillet/single-pass periodic per Section 1705.2 / AWS D1.1 referenced tables.'),
  ('ibc-060', 'IBC', 'egress', 'Under IBC Section 1006.2.1, a Group A or E space served by a single exit access doorway is generally limited to a maximum occupant load of:', '{"A": "10", "B": "29", "C": "49", "D": "50"}'::jsonb, 'C', 'Group A and E spaces (along with most other groups) are limited to a maximum occupant load of 49 for a single exit access doorway under Table 1006.2.1. At 50 or more occupants, a second exit access doorway is required. Higher-hazard Group H spaces have far lower single-exit limits.', 'IBC Table 1006.2.1', 'https://up.codes/s/egress-based-on-occupant-load-and-common-path-of-egress-travel-distance', 'intermediario', true, 'Confirmed Group A/E single-exit max occupant load 49 in Table 1006.2.1.'),
  ('ibc-061', 'IBC', 'occupant-load', 'A 9,000-square-foot office floor is classified as Group B. Using the IBC Table 1004.5 occupant load factor for business areas, what is its calculated occupant load?', '{"A": "45", "B": "60", "C": "90", "D": "180"}'::jsonb, 'B', 'Business areas use 150 gross square feet per occupant. Dividing 9,000 by 150 gives an occupant load of 60. Because this exceeds 49, the space would require at least two exit access doorways under Table 1006.2.1.', 'IBC Table 1004.5', 'https://up.codes/s/areas-without-fixed-seating', 'intermediario', true, 'Math check: 9000 / 150 = 60. Business factor 150 gross confirmed Table 1004.5.'),
  ('ibc-062', 'IBC', 'opening-protectives', 'Under IBC Table 716.1(2), a fire door assembly in a 2-hour fire barrier wall (other than enclosures of vertical exits and shafts) is generally required to have what minimum fire protection rating?', '{"A": "20 minutes", "B": "45 minutes", "C": "60 minutes (1 hour)", "D": "90 minutes (1 1/2 hours)"}'::jsonb, 'D', 'Opening protectives are rated lower than the wall they protect. Per Table 716.1(2), a 2-hour fire barrier (such as a shaft or exit enclosure) requires a 1 1/2-hour (90-minute) fire door. A 1-hour fire barrier requires a 3/4-hour (45-minute) door, and a 3-hour wall requires a 3-hour door. The door rating is keyed to the wall rating, not equal to it.', 'IBC Table 716.1(2)', 'https://up.codes/s/opening-fire-protection-assemblies-ratings-and-markings', 'intermediario', true, 'Confirmed Table 716.1(2): 2-hr fire barrier (shaft/exit enclosure) requires 90-min door; 1-hr requires 45-min; 3-hr requires 3-hr door.'),
  ('ibc-063', 'IBC', 'opening-protectives', 'Per IBC Table 716.1(2), a fire door assembly protecting an opening in a 1-hour fire partition (corridor wall) requires what minimum fire protection rating?', '{"A": "20 minutes", "B": "45 minutes (3/4 hour)", "C": "60 minutes", "D": "90 minutes"}'::jsonb, 'A', 'Fire partitions used for corridor walls and dwelling/sleeping unit separations get a reduced door rating. A 1-hour corridor fire partition requires only a 20-minute fire door (smoke- and draft-control). This is distinct from a 1-hour fire barrier, where the door would need to be 45 minutes.', 'IBC Table 716.1(2)', 'https://up.codes/s/opening-fire-protection-assemblies-ratings-and-markings', 'avancado', true, 'Confirmed Table 716.1(2): corridor walls rated 1-hr require 20-min doors; other fire partitions 1-hr require 3/4-hr doors.'),
  ('ibc-064', 'IBC', 'opening-protectives', 'Under IBC Table 716.1(2), a fire window assembly permitted in a 1-hour fire partition is required to have a fire protection rating of:', '{"A": "20 minutes", "B": "45 minutes (3/4 hour)", "C": "60 minutes", "D": "90 minutes"}'::jsonb, 'B', 'Fire window assemblies in a 1-hour fire partition or interior 1-hour fire barrier require a 3/4-hour (45-minute) rating. Fire windows are limited in area and generally are not permitted in walls where the required wall rating exceeds 1 hour unless the opening uses fire-resistance-rated glazing tested as a wall assembly.', 'IBC Table 716.1(2)', 'https://up.codes/s/opening-fire-protection-assemblies-ratings-and-markings', 'intermediario', true, 'Confirmed Table 716.1(2): fire windows in 1-hr fire partitions/barriers require 3/4-hr rating.'),
  ('ibc-065', 'IBC', 'opening-protectives', 'A fire door assembly that has a fire protection rating of 3/4 hour or more, and is used to protect an opening in an interior wall in the means of egress, must limit the temperature rise on the unexposed surface to not more than what value at the end of 30 minutes of standard fire test exposure?', '{"A": "250 degrees F", "B": "450 degrees F", "C": "650 degrees F", "D": "There is no temperature-rise limit for fire doors"}'::jsonb, 'B', 'IBC Section 716 references the maximum transmitted temperature end point for certain doors in exit enclosures and exit passageways: not more than 450 degrees F above ambient at 30 minutes. This limits radiant heat through the door so occupants can still use the egress path. The 250 degree F limit is associated with through-penetration firestop temperature-rise (T rating) criteria, not the door temperature-rise classification.', 'IBC 716.2.6.4', 'https://up.codes/s/door-assemblies', 'avancado', true, 'Confirmed maximum transmitted temperature rise of 450 deg F at 30 min for doors in exit enclosures/passageways per Section 716 door provisions.'),
  ('ibc-066', 'IBC', 'opening-protectives', 'Under IBC, the maximum aggregate width of openings protected by fire doors in a fire wall is limited so that the total openings do not exceed what percentage of the wall length on each story (general rule)?', '{"A": "10 percent", "B": "15 percent", "C": "25 percent", "D": "Openings are not permitted in fire walls"}'::jsonb, 'C', 'IBC Section 706.8 limits openings in fire walls: each opening generally cannot exceed 156 square feet, and the aggregate width of openings at any floor level cannot exceed 25 percent of the length of the wall. Fire walls are the most restrictive vertical separation because they must allow a collapse on one side without affecting the other.', 'IBC 706.8', 'https://up.codes/s/fire-walls', 'avancado', true, 'Confirmed Section 706.8: aggregate width of openings at any floor level limited to 25 percent of wall length; each opening max 156 sq ft (unless both buildings sprinklered).'),
  ('ibc-067', 'IBC', 'firestop', 'Under IBC Section 714, a through-penetration firestop system tested to ASTM E814 or UL 1479 must achieve which two ratings to be acceptable for a floor assembly penetration?', '{"A": "F rating and T rating", "B": "L rating and W rating", "C": "F rating only", "D": "STC rating and IIC rating"}'::jsonb, 'A', 'Through-penetrations of fire-resistance-rated floors generally require both an F rating (flame, equal to the required fire-resistance rating) and a T rating (temperature rise on the unexposed side limited to 325 degrees F). Through-penetrations of walls usually need only an F rating. The T rating matters for floors because items above could ignite.', 'IBC 714.4.1.2 / 714.5.1.2', 'https://up.codes/s/penetrations', 'avancado', true, 'Confirmed Section 714: through-penetration firestop systems tested to ASTM E814/UL 1479; floor penetrations require both F and T ratings; T rating limits temp rise to 325 deg F.'),
  ('ibc-068', 'IBC', 'firestop', 'Per IBC Section 714, a noncombustible penetrating item (such as a steel pipe) that penetrates a single concrete floor and is not in direct contact with combustible material may be permitted without a tested firestop system provided the annular space is filled with what, and the penetration does not exceed a specified area?', '{"A": "Spray foam insulation", "B": "Concrete, grout, or mortar (for the full thickness or a minimum specified depth)", "C": "Fiberglass batt", "D": "Any caulk rated for outdoor use"}'::jsonb, 'B', 'Section 714 provides a prescriptive concrete-floor alternative: where a noncombustible penetrating item such as steel, ferrous, or copper pipe penetrates concrete or masonry, the annular space may be filled with concrete, grout, or mortar for the full thickness (or to a minimum specified depth) instead of using a tested firestop system, subject to maximum nominal pipe/penetration size limits.', 'IBC 714.4.1.1.1 / 714.5.1.1', 'https://up.codes/s/penetrations', 'avancado', true, 'Confirmed concrete/grout/mortar fill exception for noncombustible penetrating items in concrete/masonry floors and walls, subject to size limits, per Section 714.'),
  ('ibc-069', 'IBC', 'joint-systems', 'Under IBC Section 715, fire-resistant joint systems (such as at the head of a wall or between floor edges and exterior walls) must be tested to which standard to confirm they maintain the fire-resistance rating of the assembly?', '{"A": "ASTM E84", "B": "ASTM E119 or UL 263 (and ASTM E1966 / UL 2079 for joints)", "C": "ASTM E96", "D": "NFPA 252 only"}'::jsonb, 'B', 'Fire-resistant joint systems are tested in accordance with ASTM E1966 or UL 2079 (with the assembly rated per ASTM E119/UL 263). These systems seal the gaps that allow movement (expansion, seismic, wind) while preserving the fire rating of the floor or wall. ASTM E84 is the surface burning (flame spread) test, a different standard.', 'IBC 715.3', 'https://up.codes/s/fire-resistant-joint-systems', 'avancado', true, 'Confirmed Section 715: fire-resistant joint systems tested to ASTM E1966 or UL 2079; assemblies rated per ASTM E119/UL 263.'),
  ('ibc-070', 'IBC', 'joint-systems', 'An exterior curtain wall is installed with a gap between the floor slab edge and the back of the exterior wall. Under IBC Section 715, what must be installed in this voided space (the perimeter fire containment area)?', '{"A": "Nothing, because exterior walls are exempt", "B": "An approved perimeter (voids) fire containment system or system tested to ASTM E2307", "C": "Standard fiberglass batt insulation", "D": "A smoke detector only"}'::jsonb, 'B', 'The gap at the perimeter of each floor where it meets a curtain wall (the safing slot) is a path for vertical fire spread. Section 715 requires an approved fire-resistant joint (perimeter fire containment) system tested in accordance with ASTM E2307 to seal this void and resist the interior spread of fire and hot gases between floors.', 'IBC 715.4', 'https://up.codes/s/fire-resistant-joint-systems', 'avancado', true, 'Confirmed Section 715.4: voids at intersection of exterior curtain wall and floor require perimeter fire containment system tested to ASTM E2307.'),
  ('ibc-071', 'IBC', 'dampers', 'Under IBC Section 717, a fire damper is generally required where an air duct or transfer opening penetrates which of the following?', '{"A": "A smoke partition only", "B": "A fire wall, and at certain fire barriers, shaft enclosures, and fire partitions per the table", "C": "Any interior nonrated partition", "D": "Only exterior walls"}'::jsonb, 'B', 'Section 717 (Table 717.3.2.1 and related) requires fire dampers where ducts or transfer openings penetrate fire walls, certain fire barriers, shaft enclosures, and fire partitions. The damper closes on heat (a fusible link or actuator) to maintain the fire-resistance rating of the penetrated assembly.', 'IBC 717.5', 'https://up.codes/s/ducts-and-air-transfer-openings', 'intermediario', true, 'Confirmed Section 717: fire dampers required where ducts/transfer openings penetrate fire walls, fire barriers, shaft enclosures, and certain fire partitions.'),
  ('ibc-072', 'IBC', 'dampers', 'What is the primary difference between a fire damper and a smoke damper as regulated by IBC Section 717?', '{"A": "There is no difference; the terms are interchangeable", "B": "A fire damper closes to resist flame/heat passage and a smoke damper closes to resist the passage of smoke (often actuated by a smoke detector)", "C": "A smoke damper is only used outdoors", "D": "A fire damper is only used in residential buildings"}'::jsonb, 'B', 'A fire damper is rated and tested (UL 555) to resist the passage of flame and is typically heat-activated (fusible link). A smoke damper is tested (UL 555S) to resist the passage of smoke and is actuated by a smoke detection signal or the fire alarm system. Combination fire/smoke dampers perform both functions and are required where a barrier serves both purposes (such as a smoke barrier that is also fire-rated).', 'IBC 717.3 / 717.5.5', 'https://up.codes/s/ducts-and-air-transfer-openings', 'intermediario', true, 'Confirmed Section 717: fire dampers tested UL 555 (flame), smoke dampers tested UL 555S (smoke); combination dampers where both required (e.g., smoke barriers).'),
  ('ibc-073', 'IBC', 'dampers', 'Under IBC Section 717, smoke dampers are required where a duct or air transfer opening penetrates a:', '{"A": "Fire wall", "B": "Smoke barrier", "C": "Exterior bearing wall", "D": "Nonrated interior partition"}'::jsonb, 'B', 'Smoke dampers are required where ducts or air transfer openings penetrate a smoke barrier (and certain shaft enclosures and corridor walls where required). Their purpose is to maintain the smoke-resistance of the barrier. A fire wall penetration calls for a fire damper, which addresses flame, not necessarily smoke.', 'IBC 717.5.2 / 717.5.3', 'https://up.codes/s/ducts-and-air-transfer-openings', 'intermediario', true, 'Confirmed Section 717: smoke dampers required at smoke barrier penetrations (and certain shafts/corridors).'),
  ('ibc-074', 'IBC', 'fire-walls', 'Under IBC Section 706, a fire wall is defined primarily by which structural characteristic that distinguishes it from a fire barrier?', '{"A": "It must have a minimum 4-hour rating in all cases", "B": "It has sufficient structural stability to allow collapse of construction on either side without collapse of the wall", "C": "It can only be made of gypsum board", "D": "It is never permitted to have openings"}'::jsonb, 'B', 'Per Section 706, a fire wall has sufficient structural stability under fire conditions to allow collapse of construction on either side without collapse of the wall itself. This is what allows a fire wall to create separate buildings for code purposes (area, height, type of construction). A fire barrier does not have this independent-collapse requirement.', 'IBC 706.2', 'https://up.codes/s/fire-walls', 'intermediario', true, 'Confirmed Section 706.2: fire wall has structural stability to allow collapse on either side without collapse of the wall; creates separate buildings.'),
  ('ibc-075', 'IBC', 'fire-walls', 'Per IBC Table 706.4, the minimum fire-resistance rating of a fire wall separating two Group B occupancies is:', '{"A": "1 hour", "B": "2 hours", "C": "3 hours", "D": "4 hours"}'::jsonb, 'B', 'Table 706.4 establishes fire wall ratings by occupancy. Group B (along with A, E, I, R, U) requires a 2-hour fire wall. Group F-1, M, and S-1 require 3 hours, and Group H requires up to 4 hours (or 3 for some). When a fire wall separates two different groups, the higher required rating governs.', 'IBC Table 706.4', 'https://up.codes/s/fire-walls', 'intermediario', true, 'Confirmed Table 706.4: Group B fire wall = 2 hr; F-1/M/S-1 = 3 hr; H groups up to 4 hr.'),
  ('ibc-076', 'IBC', 'fire-walls', 'Under IBC Section 706, a fire wall is generally required to be continuous from the foundation to or through the roof. What is the typical minimum height a parapet must extend above the roof where a parapet is required?', '{"A": "12 inches", "B": "18 inches", "C": "30 inches", "D": "36 inches"}'::jsonb, 'C', 'Where a parapet is required for a fire wall, Section 706.6 requires it to extend not less than 30 inches above both roof surfaces. The code also provides exceptions allowing the parapet to be omitted under specified roof construction and combustibility conditions, but where it is required, 30 inches is the standard projection.', 'IBC 706.6', 'https://up.codes/s/fire-walls', 'intermediario', true, 'Confirmed Section 706.6: fire wall parapet extends not less than 30 inches above roof where required; exceptions allow omission under stated conditions.'),
  ('ibc-077', 'IBC', 'fire-barriers', 'Under IBC Section 707, a fire barrier used to enclose an exit stairway (interior exit stairway) connecting four or more stories is required to have a minimum fire-resistance rating of:', '{"A": "1 hour", "B": "1 1/2 hours", "C": "2 hours", "D": "3 hours"}'::jsonb, 'C', 'Interior exit stairway and ramp enclosures must be fire barriers (and/or horizontal assemblies). Where they connect four or more stories, the enclosure must be a minimum of 2-hour fire-resistance-rated. Connecting fewer than four stories allows a 1-hour enclosure. This four-story threshold is frequently tested.', 'IBC 707.3.1 / 1023.2', 'https://up.codes/s/fire-barriers', 'intermediario', true, 'Confirmed Section 1023.2 / 707: interior exit stairway enclosures connecting 4+ stories = 2 hr; fewer than 4 stories = 1 hr.'),
  ('ibc-078', 'IBC', 'fire-barriers', 'Under IBC Section 707, fire barriers must be continuous and supported by construction having at least what fire-resistance rating relative to the barrier?', '{"A": "No supporting construction rating is required", "B": "The supporting construction must have a fire-resistance rating at least equal to that of the fire barrier supported", "C": "Half the rating of the barrier", "D": "Always 4 hours"}'::jsonb, 'B', 'Section 707.5 requires fire barriers to be continuous from the top of the floor/ceiling assembly below to the underside of the floor or roof slab above, and Section 707.5.1 requires the supporting construction to be protected to afford the required fire-resistance rating of the fire barrier supported. An exception permits reduced support ratings for certain incidental and shaft conditions, but the general rule ties the support rating to the barrier rating.', 'IBC 707.5.1', 'https://up.codes/s/fire-barriers', 'avancado', true, 'Confirmed Section 707.5.1: supporting construction for fire barriers must equal the fire-resistance rating of the barrier supported (with stated exceptions).'),
  ('ibc-079', 'IBC', 'fire-partitions', 'Under IBC Section 708, fire partitions (such as corridor walls, tenant separations in covered malls, and dwelling/sleeping unit separations) are generally required to have a minimum fire-resistance rating of:', '{"A": "1 hour (with a 1/2-hour reduction allowed in some sprinklered conditions)", "B": "2 hours", "C": "3 hours", "D": "4 hours"}'::jsonb, 'A', 'Fire partitions are generally 1-hour rated. Section 708 permits a reduction to 1/2 hour for corridor walls and dwelling/sleeping unit separations in Type IIB, IIIB, and VB construction where the building is sprinklered, and for certain other conditions. Fire partitions are a lighter category than fire barriers.', 'IBC 708.3', 'https://up.codes/s/fire-partitions', 'intermediario', true, 'Confirmed Section 708.3: fire partitions generally 1 hr; 1/2-hr reduction permitted for certain sprinklered conditions.'),
  ('ibc-080', 'IBC', 'fire-partitions', 'Under IBC Section 708, where must a fire partition extend in a building with a fire-resistance-rated floor/ceiling above?', '{"A": "Only to the suspended ceiling in all cases", "B": "From the top of the floor/ceiling assembly below to the underside of the floor or roof sheathing/slab above, or to the underside of a fire-resistance-rated floor/ceiling or roof/ceiling above", "C": "It need not be continuous", "D": "Only 6 inches above the finished floor"}'::jsonb, 'B', 'Fire partitions must extend from the top of the floor/ceiling assembly below to the underside of the floor or roof sheathing, slab, or deck above, OR to the underside of a fire-resistance-rated floor/ceiling or roof/ceiling assembly above. Section 708.4 also allows termination at a ceiling membrane under specified conditions (a key exception for corridors with rated ceilings).', 'IBC 708.4', 'https://up.codes/s/fire-partitions', 'avancado', true, 'Confirmed Section 708.4: fire partition continuity to deck above or to rated floor/roof-ceiling, with ceiling-membrane termination exceptions.'),
  ('ibc-081', 'IBC', 'smoke-barriers', 'Under IBC Section 709, a smoke barrier is required to have a minimum fire-resistance rating of:', '{"A": "0 hours (smoke resistance only, no fire rating)", "B": "1 hour", "C": "2 hours", "D": "3 hours"}'::jsonb, 'B', 'A smoke barrier is a continuous membrane designed to restrict the movement of smoke, and per Section 709.3 it must have a minimum 1-hour fire-resistance rating. Smoke barriers are commonly used to create smoke compartments in Group I-2 (hospitals) and areas of refuge. They differ from smoke partitions, which resist smoke but are not required to be fire-rated.', 'IBC 709.3', 'https://up.codes/s/smoke-barriers', 'intermediario', true, 'Confirmed Section 709.3: smoke barriers require minimum 1-hr fire-resistance rating and continuous construction.'),
  ('ibc-082', 'IBC', 'smoke-partitions', 'Under IBC Section 710, a smoke partition (where not also required to be fire-resistance-rated) must be constructed to limit smoke passage and must extend:', '{"A": "Only 12 inches above the floor", "B": "From the floor to the underside of the floor or roof deck above, or to the underside of a ceiling where the ceiling membrane is constructed to limit smoke transfer", "C": "Only to the height of the door", "D": "Smoke partitions have no continuity requirement"}'::jsonb, 'B', 'Per Section 710.4, a smoke partition must extend from the top of the floor below to the underside of the floor or roof deck above, OR to the underside of a ceiling where the ceiling is constructed to limit the transfer of smoke. Smoke partitions are not required to have a fire-resistance rating (unless required elsewhere), distinguishing them from smoke barriers.', 'IBC 710.4', 'https://up.codes/s/smoke-partitions', 'intermediario', true, 'Confirmed Section 710: smoke partitions limit smoke passage, extend to deck or smoke-limiting ceiling; not required to be fire-rated unless otherwise required.'),
  ('ibc-083', 'IBC', 'construction-elements', 'Under IBC Table 601, in Type IA construction, the minimum required fire-resistance rating of the primary structural frame is:', '{"A": "1 hour", "B": "2 hours", "C": "3 hours", "D": "4 hours"}'::jsonb, 'C', 'Table 601 lists required fire-resistance ratings of building elements by type of construction. In Type IA, the primary structural frame is 3 hours, bearing walls (exterior and interior) are 3 hours, and floor construction is 2 hours. Type IB drops the frame to 2 hours. These ratings are the backbone of the type-of-construction system.', 'IBC Table 601', 'https://up.codes/s/fire-resistance-rating-requirements-for-building-elements-hours', 'intermediario', true, 'Confirmed Table 601: Type IA primary structural frame = 3 hr; bearing walls = 3 hr; floor = 2 hr; Type IB frame = 2 hr.'),
  ('ibc-084', 'IBC', 'construction-elements', 'Per IBC Table 601, the required fire-resistance rating of the primary structural frame in Type IIB construction is:', '{"A": "0 hours", "B": "1 hour", "C": "2 hours", "D": "3 hours"}'::jsonb, 'A', 'Type IIB is noncombustible but unprotected, so Table 601 assigns 0 hours to the primary structural frame, bearing walls (interior), floors, and roofs. Type IIA, by contrast, requires 1 hour for these elements. Type IIB and Type VB are the two most common types with all 0-hour interior elements, which is why they are often the baseline for sprinklered commercial buildings.', 'IBC Table 601', 'https://up.codes/s/fire-resistance-rating-requirements-for-building-elements-hours', 'intermediario', true, 'Confirmed Table 601: Type IIB primary structural frame = 0 hr; Type IIA = 1 hr.'),
  ('ibc-085', 'IBC', 'construction-types', 'Under IBC Section 602, the fundamental difference between Type I/II construction and Type III/IV/V construction is:', '{"A": "Building height only", "B": "Type I and II require building elements (including structural members) to be of noncombustible materials, while Types III, IV, and V permit combustible materials in specified locations", "C": "Type I and II are only for residential use", "D": "There is no material difference"}'::jsonb, 'B', 'Section 602 classifies construction by the combustibility and fire resistance of materials. Types I and II require building elements to be of noncombustible materials (Type I is more highly protected). Type III has noncombustible exterior walls with interior elements of any material permitted by code. Type IV is heavy timber/mass timber. Type V permits any code-allowed materials throughout, including combustible.', 'IBC 602.2 / 602.3 / 602.4 / 602.5', 'https://up.codes/s/construction-classification', 'iniciante', true, 'Confirmed Section 602: Types I/II noncombustible; Type III noncombustible exterior walls + any interior; Type IV heavy/mass timber; Type V any permitted materials.'),
  ('ibc-086', 'IBC', 'construction-types', 'Under IBC Section 602.3, Type III construction is characterized by exterior walls of noncombustible materials and interior building elements of:', '{"A": "Required noncombustible materials only", "B": "Any material permitted by the code (including combustible)", "C": "Heavy timber only", "D": "Mass timber only"}'::jsonb, 'B', 'In Type III construction, the exterior walls must be of noncombustible materials, but the interior building elements may be of any material permitted by the code, including wood framing. This is the classic brick-and-joist or ''ordinary'' construction. Fire-retardant-treated wood is allowed within exterior walls of 2-hour or less rating under Section 602.3.', 'IBC 602.3', 'https://up.codes/s/construction-classification', 'intermediario', true, 'Confirmed Section 602.3: Type III exterior walls noncombustible, interior elements any permitted material; FRTW allowed in exterior walls rated 2 hr or less.'),
  ('ibc-087', 'IBC', 'construction-types', 'Under IBC Section 602.4, Type IV-HT (Heavy Timber) construction requires solid or laminated wood structural members to meet minimum nominal dimensions. Wood columns supporting floor loads must be a minimum nominal dimension of:', '{"A": "4 inches by 4 inches", "B": "6 inches by 6 inches", "C": "8 inches by 8 inches", "D": "10 inches by 10 inches"}'::jsonb, 'C', 'In Type IV-HT, columns supporting floor loads must be not less than 8 inches nominal in any dimension. Beams and girders supporting floor loads must be not less than 6 inches nominal width and 10 inches nominal depth. The large cross-sections char on the outside and retain structural capacity, which is the principle behind heavy timber fire performance.', 'IBC 602.4 / 2304.11', 'https://up.codes/s/types-iv-construction-heavy-timber-mass-timber', 'avancado', true, 'Confirmed Type IV-HT minimum nominal sizes: columns supporting floor loads 8x8; floor beams/girders 6 wide x 10 deep.'),
  ('ibc-088', 'IBC', 'construction-types', 'Under IBC Section 602, which type of construction permits the use of any materials allowed by the code throughout the building, including combustible framing for all building elements?', '{"A": "Type I", "B": "Type II", "C": "Type III", "D": "Type V"}'::jsonb, 'D', 'Type V construction is that in which the structural elements, exterior walls, and interior walls are of any materials permitted by the code, including wood throughout. Type VA requires 1-hour protection of most elements, while Type VB is unprotected (0 hours). Type V is the most common residential and light commercial construction type.', 'IBC 602.5', 'https://up.codes/s/construction-classification', 'iniciante', true, 'Confirmed Section 602.5: Type V allows any permitted materials throughout; VA = 1 hr protected, VB = 0 hr unprotected.'),
  ('ibc-089', 'IBC', 'exterior-walls', 'Under IBC Table 602, an exterior wall with a fire separation distance of less than 5 feet generally requires what minimum fire-resistance rating for a Group B occupancy (based on fire separation distance)?', '{"A": "0 hours", "B": "1 hour", "C": "2 hours", "D": "3 hours"}'::jsonb, 'B', 'Table 602 sets exterior wall ratings by fire separation distance (FSD) and occupancy group. For most occupancies including Group B, an FSD of less than 5 feet requires a 1-hour rated exterior wall (Group H and certain F-1/M/S-1 require more). As FSD increases, the required rating decreases and eventually reaches 0 hours at 30 feet or more for most groups.', 'IBC Table 602', 'https://up.codes/s/fire-resistance-rating-requirements-for-exterior-walls-based-fire-separation-distance', 'intermediario', true, 'Confirmed Table 602: FSD < 5 ft for Group B/A/E/I/R/U = 1 hr; H groups higher; rating decreases as FSD increases.'),
  ('ibc-090', 'IBC', 'exterior-walls', 'Under IBC Table 705.8 (exterior wall openings), the allowable area of unprotected openings increases as the fire separation distance increases. At a fire separation distance of 30 feet or greater, the allowable area of unprotected openings in an exterior wall of a nonsprinklered building is generally:', '{"A": "10 percent", "B": "25 percent", "C": "45 percent", "D": "No limit (unlimited)"}'::jsonb, 'D', 'Table 705.8 ties allowable openings to fire separation distance and protection. At a fire separation distance of 30 feet or more, unprotected openings are generally unlimited (no maximum percentage) because the radiant heat exposure to adjacent property is low. At smaller distances, the allowable percentage is sharply limited and openings may need protection.', 'IBC Table 705.8', 'https://up.codes/s/exterior-walls', 'intermediario', true, 'Confirmed Table 705.8: at FSD 30 ft or greater, unprotected openings are unlimited; protection/limits increase as FSD decreases.'),
  ('ibc-091', 'IBC', 'atriums', 'Under IBC Section 404, a building containing an atrium connecting more than two stories is required to be equipped throughout with what life-safety system?', '{"A": "Standpipes only", "B": "An automatic sprinkler system and a smoke control system", "C": "Manual fire alarm only", "D": "No special systems are required"}'::jsonb, 'B', 'Section 404 requires buildings with an atrium to be equipped throughout with an automatic sprinkler system (404.3) and to provide a smoke control system for the atrium (404.5) where the atrium connects more than two stories. An automatic fire detection system and emergency voice/alarm communication are also required. The atrium provisions exist because the open vertical space defeats normal compartmentation.', 'IBC 404.3 / 404.5', 'https://up.codes/s/atriums', 'avancado', true, 'Confirmed Section 404: atriums require building-wide automatic sprinklers and smoke control (where connecting more than two stories), plus detection and EVACS.'),
  ('ibc-092', 'IBC', 'atriums', 'Under IBC Section 404, the fire-resistance rating of the enclosure (atrium walls) separating the atrium from adjacent spaces is generally required to be:', '{"A": "1-hour fire barrier (with exceptions allowing a glass wall smoke partition where sprinklered)", "B": "Always 4 hours", "C": "No separation is required", "D": "Always 3 hours"}'::jsonb, 'A', 'Section 404.6 requires atrium spaces to be separated from adjacent spaces by a 1-hour fire barrier. Exceptions allow a glass wall forming a smoke partition (with closely spaced sprinklers) and permit up to three floors to open into the atrium without the separation. This balances open architectural design with smoke control.', 'IBC 404.6', 'https://up.codes/s/atriums', 'avancado', true, 'Confirmed Section 404.6: atrium separated by 1-hr fire barrier; glass-wall smoke partition exception with sprinklers; up to 3 floors may open to atrium.'),
  ('ibc-093', 'IBC', 'vertical-openings', 'Under IBC Section 712, which of the following is NOT one of the methods permitted to address a vertical opening connecting two or more stories?', '{"A": "Shaft enclosure (Section 713)", "B": "Atrium (Section 404)", "C": "Leaving the opening completely unprotected with no further provisions", "D": "An approved opening in a two-story space, or escalator/convenience-stair opening protection methods"}'::jsonb, 'C', 'Section 712 lists the permitted methods to address vertical openings: shaft enclosures, individual dwelling unit openings, escalator openings, penetrations, two-story openings, atriums, masonry chimneys, combustion air openings, and others. Simply leaving a multi-story vertical opening unprotected with no provision is not a listed method; it must fit one of the enumerated approaches.', 'IBC 712.1', 'https://up.codes/s/vertical-openings', 'intermediario', true, 'Confirmed Section 712.1 lists permitted vertical-opening methods (shafts, atriums, two-story openings, escalators, etc.); unprotected with no provision is not permitted.'),
  ('ibc-094', 'IBC', 'shaft-enclosures', 'Under IBC Section 713, a shaft enclosure that connects four or more stories is required to have a minimum fire-resistance rating of:', '{"A": "1 hour", "B": "1 1/2 hours", "C": "2 hours", "D": "3 hours"}'::jsonb, 'C', 'Per Section 713.4, shaft enclosures connecting four or more stories must be 2-hour fire-resistance-rated (fire barriers, horizontal assemblies, or both). Shafts connecting fewer than four stories may be 1-hour rated. The four-story threshold mirrors the interior exit stairway enclosure rule.', 'IBC 713.4', 'https://up.codes/s/shaft-enclosures', 'intermediario', true, 'Confirmed Section 713.4: shaft enclosures connecting 4+ stories = 2 hr; fewer than 4 stories = 1 hr.'),
  ('ibc-095', 'IBC', 'shaft-enclosures', 'Under IBC Section 713, at the top and bottom of a shaft, what is required to maintain the integrity of the enclosure?', '{"A": "Nothing; shafts are open at the top and bottom", "B": "The shaft must be enclosed at the top and bottom with construction of the same fire-resistance rating as the shaft (with limited exceptions)", "C": "Only a smoke detector", "D": "A 6-inch curb only"}'::jsonb, 'B', 'Section 713.12 requires shafts to be enclosed at the top and bottom. Where the shaft does not extend to the underside of the roof, the top must be enclosed with construction having the same rating as the shaft enclosure. The bottom must likewise be enclosed unless it complies with stated exceptions. This prevents the shaft from becoming a fire/smoke conduit at its ends.', 'IBC 713.12', 'https://up.codes/s/shaft-enclosures', 'avancado', true, 'Confirmed Section 713.12: shafts enclosed at top and bottom with rated construction equal to shaft, subject to exceptions.'),
  ('ibc-096', 'IBC', 'combustibility', 'Under IBC, a material is generally classified as noncombustible if it passes which test, or is composed of materials meeting specific criteria?', '{"A": "ASTM E84 (Steiner Tunnel) only", "B": "ASTM E136 (or is composed of materials defined as noncombustible by the code)", "C": "ASTM E119 only", "D": "There is no test for noncombustibility"}'::jsonb, 'B', 'Section 703.5 (and the definition of noncombustible material in Chapter 2) ties noncombustibility to ASTM E136: a material that, when tested, does not contribute to fire and meets the pass criteria. Materials such as concrete, masonry, steel, and certain mineral products qualify. ASTM E84 measures surface flame spread and smoke (a different property), and ASTM E119 measures fire-resistance rating of assemblies.', 'IBC 703.5 / Chapter 2 (Noncombustible material)', 'https://up.codes/s/general-fire-and-smoke-protection-features', 'intermediario', true, 'Confirmed: noncombustible material defined via ASTM E136 testing (or composed of noncombustible materials); E84 = flame spread, E119 = fire resistance.'),
  ('ibc-097', 'IBC', 'concealed-spaces', 'Under IBC Section 718, fireblocking is required in concealed spaces of combustible construction. In concealed wall spaces (stud walls and partitions), fireblocking must occur vertically at the ceiling and floor levels and horizontally at intervals not exceeding:', '{"A": "8 feet", "B": "10 feet", "C": "12 feet", "D": "20 feet"}'::jsonb, 'B', 'Section 718.2.1 requires fireblocking in concealed spaces of stud walls and partitions, including furred spaces, at the ceiling and floor levels and at horizontal intervals not exceeding 10 feet. Fireblocking cuts off concealed draft openings so fire cannot travel unseen through wall cavities. It can be wood, gypsum, mineral wool, or other approved materials.', 'IBC 718.2.1', 'https://up.codes/s/concealed-spaces', 'intermediario', true, 'Confirmed Section 718.2.1: fireblocking in concealed wall spaces at ceiling/floor levels and horizontal intervals not exceeding 10 ft.'),
  ('ibc-098', 'IBC', 'concealed-spaces', 'Under IBC Section 718, what is the primary purpose of draftstopping in floor/ceiling and attic concealed spaces (as distinguished from fireblocking)?', '{"A": "To provide structural support", "B": "To subdivide large concealed combustible spaces (such as floor/ceiling assemblies and attics) to restrict the movement of air and limit fire spread within the concealed space", "C": "To provide thermal insulation only", "D": "To carry electrical wiring"}'::jsonb, 'B', 'Draftstopping (Section 718.3 and 718.4) subdivides large concealed spaces in combustible floor/ceiling assemblies and attics into smaller areas to restrict air movement and the spread of fire within those concealed spaces. For example, attic draftstopping is generally required to limit concealed areas (with larger areas allowed when sprinklered). Fireblocking, by contrast, cuts off smaller vertical/horizontal openings at connections.', 'IBC 718.3 / 718.4', 'https://up.codes/s/concealed-spaces', 'intermediario', true, 'Confirmed Section 718.3/718.4: draftstopping subdivides large concealed floor/ceiling and attic spaces; areas larger where sprinklered.'),
  ('ibc-099', 'IBC', 'opening-protectives', 'Under IBC Section 716, a fire door assembly is required to be self-closing or automatic-closing. Where a fire door is held open, the hold-open device must release the door upon:', '{"A": "A manual key only", "B": "Actuation of the fire alarm/smoke detection system (the door closes automatically on detection)", "C": "A timer after 24 hours", "D": "Loss of building power only"}'::jsonb, 'B', 'Section 716 requires fire doors to be self-closing or automatic-closing. Doors that are normally held open must be released by automatic-closing action initiated by the actuation of an approved smoke detector or the fire alarm system, so the opening is protected when a fire occurs. A simple manual key or arbitrary timer does not satisfy the automatic-closing requirement.', 'IBC 716.2.6.6', 'https://up.codes/s/door-assemblies', 'intermediario', true, 'Confirmed Section 716: fire doors self/automatic-closing; hold-open release on smoke detection/fire alarm actuation.'),
  ('ibc-100', 'IBC', 'fire-barriers', 'Under IBC Section 707.3, which of the following uses is required to be enclosed with fire barriers (or horizontal assemblies, or both)?', '{"A": "A nonrated tenant demising wall", "B": "Shaft enclosures, interior exit stairways, exit passageways, and fire areas separating different occupancies", "C": "An interior decorative partition", "D": "A suspended acoustic ceiling"}'::jsonb, 'B', 'Section 707.3 enumerates the uses that must be fire barriers: shaft enclosures, interior exit stairways and ramps, exit passageways, horizontal exits, atriums, incidental uses, fire areas, and the separation between occupancies. These are the high-importance separations. Nonrated demising walls and decorative or acoustic partitions are not in this list.', 'IBC 707.3', 'https://up.codes/s/fire-barriers', 'intermediario', true, 'Confirmed Section 707.3: fire barriers required for shaft enclosures, interior exit stairways/ramps, exit passageways, horizontal exits, atriums, incidental uses, fire areas, occupancy separations.'),
  ('ibc-101', 'IBC', 'construction-elements', 'Under IBC Table 601, a structural member that is part of a roof but is more than 20 feet above the floor immediately below in certain types of construction may be permitted to have what fire-resistance rating?', '{"A": "It must always equal the primary structural frame rating", "B": "It may be reduced (in some types the roof construction and associated members 20 feet or more above the floor are permitted to be unprotected / 0 hours)", "C": "It must always be 3 hours", "D": "Roof members are never rated"}'::jsonb, 'B', 'Footnotes to Table 601 permit the fire-resistance rating of roof construction (including secondary members and the primary structural frame supporting only the roof) to be reduced or eliminated in certain types of construction where every part of the roof is 20 feet or more above the floor immediately below. This recognizes that high roof members pose less life-safety risk to occupants below.', 'IBC Table 601 (footnotes)', 'https://up.codes/s/fire-resistance-rating-requirements-for-building-elements-hours', 'avancado', true, 'Confirmed Table 601 footnotes: roof members 20 ft or more above floor below may have reduced/eliminated rating in specified construction types.'),
  ('ibc-102', 'IBC', 'construction-types', 'Under the IBC (2021 and later) Section 602.4, the new mass timber Type IV subtypes are designated as:', '{"A": "Type IV-1, IV-2, IV-3", "B": "Type IV-A, IV-B, IV-C (in addition to IV-HT)", "C": "Type IV-X, IV-Y, IV-Z", "D": "There are no subtypes; Type IV is a single category"}'::jsonb, 'B', 'The 2021 IBC introduced mass timber subtypes: Type IV-A, IV-B, and IV-C, in addition to traditional Type IV-HT (Heavy Timber). IV-A is the most protected (more noncombustible protection of the mass timber and greater allowable heights), IV-C the least, allowing more exposed timber. These permit taller mass timber buildings using cross-laminated timber (CLT).', 'IBC 602.4', 'https://up.codes/s/types-iv-construction-heavy-timber-mass-timber', 'avancado', true, 'Confirmed 2021 IBC Section 602.4: Type IV-A, IV-B, IV-C mass timber subtypes plus Type IV-HT; IV-A most protected, IV-C most exposed timber.'),
  ('ibc-231', 'IBC', 'exterior-walls', 'Under IBC Chapter 14, the minimum required fire-resistance rating and the limits on openings of an exterior wall are determined primarily by what factor?', '{"A": "The roof covering class", "B": "The fire separation distance", "C": "The occupant load", "D": "The seismic design category"}'::jsonb, 'B', 'IBC Section 1402 (Performance Requirements) and Table 602 tie the exterior wall fire-resistance rating to the fire separation distance (the distance from the building face to the lot line, centerline of street, or an imaginary line between buildings). The smaller the fire separation distance, the higher the required rating and the more restrictive the allowable openings under Table 705.8.', 'IBC 1402; Table 602', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-14-exterior-walls', 'intermediario', true, 'Confirmed exterior wall ratings keyed to fire separation distance via Table 602 referenced from Chapter 14 (IBC 2018/2021).'),
  ('ibc-103', 'IBC', 'exterior-walls', 'Per IBC Section 1403/1404, combustible materials are permitted on the exterior side of exterior walls of Type I, II, III, and IV (noncombustible) construction only when which condition is met?', '{"A": "Never, under any circumstance", "B": "When permitted by Section 1405 and the applicable use, height, and area limits", "C": "Only on buildings under 30 feet tall", "D": "Only where sprinklers are omitted"}'::jsonb, 'B', 'IBC 1404 (Materials) and 1405 (Combustible Materials on the Exterior Side of Exterior Walls) allow specific combustible exterior materials, such as combustible veneer, metal composite materials, high-pressure decorative laminates, and water-resistive barriers, on noncombustible buildings when the conditions, height limits, and testing requirements of those sections are satisfied. They are not categorically prohibited.', 'IBC 1404; 1405', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-14-exterior-walls', 'avancado', true, 'Confirmed combustible exterior materials on noncombustible construction governed by Section 1405 conditions (IBC 2021).'),
  ('ibc-104', 'IBC', 'exterior-walls', 'Under IBC Section 1404 (and referenced 1405), exterior walls are required to be covered with a what to protect against the passage of water behind the exterior veneer?', '{"A": "Vapor retarder", "B": "Water-resistive barrier", "C": "Air barrier only", "D": "Fire-retardant coating"}'::jsonb, 'B', 'IBC 1404.2 requires a water-resistive barrier behind the exterior veneer, complying with the referenced standards (such as one layer of No. 15 asphalt felt or an equivalent approved barrier). It directs water that penetrates the cladding back to the exterior and is distinct from a vapor retarder, which controls vapor diffusion.', 'IBC 1404.2', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-14-exterior-walls', 'intermediario', true, 'Confirmed water-resistive barrier requirement behind exterior veneer in Section 1404.2 (IBC 2021).'),
  ('ibc-105', 'IBC', 'exterior-walls', 'Per IBC Section 1405, exterior wall veneer of more than 5 inches in thickness, or anchored masonry veneer in general, must be supported in what manner unless an engineered design is provided?', '{"A": "By the wall framing only", "B": "On noncombustible structural supports such as foundations or noncombustible corbeling", "C": "By adhesive bonding only", "D": "By mechanical fasteners spaced 48 inches on center"}'::jsonb, 'B', 'IBC 1405 requires veneer to be supported on noncombustible foundations, footings, or noncombustible corbeling, with anchored masonry veneer specifically governed by 1405.6 and the referenced TMS standards. Adhered masonry veneer (1405.10) is bonded directly, but heavier anchored masonry must bear on noncombustible supports.', 'IBC 1405.5; 1405.6', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-14-exterior-walls', 'avancado', true, 'Confirmed anchored masonry veneer support and corbeling provisions in Section 1405 (IBC 2021).'),
  ('ibc-106', 'IBC', 'exterior-walls', 'Under IBC Table 705.8, when the fire separation distance is greater than or equal to 30 feet, the maximum area of unprotected openings in an exterior wall is:', '{"A": "10 percent", "B": "25 percent", "C": "Unlimited (no limit)", "D": "45 percent"}'::jsonb, 'C', 'Table 705.8 progressively increases allowable opening area as fire separation distance increases. At a fire separation distance of 30 feet or more, there is no limit on unprotected openings. At smaller distances the allowable percentage drops sharply, and openings may be prohibited at very small separations.', 'IBC Table 705.8', 'https://up.codes/s/maximum-area-of-exterior-wall-openings', 'avancado', true, 'Confirmed no limit on openings at fire separation distance >= 30 ft in Table 705.8 (IBC 2018/2021).'),
  ('ibc-107', 'IBC', 'roof-assemblies', 'Under IBC Section 1505, which roof covering classification provides the highest level of fire resistance and is effective against severe fire test exposure?', '{"A": "Class A", "B": "Class B", "C": "Class C", "D": "Class D"}'::jsonb, 'A', 'IBC 1505 classifies roof assemblies as Class A, B, or C based on ASTM E108 or UL 790 testing. Class A is the most fire-resistant (severe exposure), Class B is moderate, and Class C is light exposure. There is no Class D. Higher construction types and certain locations require Class A roofs.', 'IBC 1505.1', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-15-roof-assemblies-and-rooftop-structures', 'iniciante', true, 'Confirmed Class A is highest fire-resistance roof classification in Section 1505 (IBC 2021).'),
  ('ibc-108', 'IBC', 'roof-assemblies', 'Per IBC Section 1502/1503, what is the primary purpose of roof drainage provisions, including secondary (emergency overflow) drains or scuppers?', '{"A": "To reduce the roof live load by half", "B": "To prevent ponding and structural overload when primary drains are blocked", "C": "To satisfy the energy code", "D": "To meet seismic bracing requirements"}'::jsonb, 'B', 'IBC 1502 and 1503, with the secondary drainage requirements (and the plumbing code reference), require overflow drains or scuppers so that if the primary roof drainage system becomes blocked, water can escape before it ponds and overloads the structure. Roofs must also be designed for the rain load that results, addressed in Chapter 16.', 'IBC 1502; 1503', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-15-roof-assemblies-and-rooftop-structures', 'intermediario', true, 'Confirmed secondary (overflow) roof drainage purpose to prevent ponding overload in Sections 1502/1503 (IBC 2021).'),
  ('ibc-109', 'IBC', 'roof-assemblies', 'Under IBC Section 1503, a parapet wall and other vertical surfaces at the roof edge generally must be provided with what to protect the top of the wall and direct water?', '{"A": "Coping", "B": "A gutter only", "C": "Fire sprinklers", "D": "A guardrail"}'::jsonb, 'A', 'IBC 1503.3 requires parapet walls to have coping of noncombustible, weatherproof materials with a width not less than the thickness of the parapet wall. Coping protects the top of the wall from water intrusion and directs water off the assembly. Parapet height and fire requirements appear in 705.11.', 'IBC 1503.3', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-15-roof-assemblies-and-rooftop-structures', 'intermediario', true, 'Confirmed parapet coping requirement in Section 1503.3 (IBC 2021).'),
  ('ibc-110', 'IBC', 'roof-assemblies', 'Per IBC Section 1505, a roof covering of Class B or C is allowed only when the requirements for the building''s construction type permit it. Which condition most commonly forces a Class A roof?', '{"A": "Any building over two stories", "B": "Type I and Type II (and certain other) construction or specific fire-hazard locations", "C": "All residential occupancies", "D": "Buildings with a basement"}'::jsonb, 'B', 'IBC 1505.1 and the construction-type provisions require Class A roof assemblies for the most fire-resistive construction types and in defined high-fire-hazard areas. Lesser classes are permitted for lower construction types where allowed. The roof class must be coordinated with the overall construction type from Chapter 6.', 'IBC 1505.1', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-15-roof-assemblies-and-rooftop-structures', 'avancado', true, 'Confirmed Class A roof requirement tied to construction type and fire-hazard areas in Section 1505 (IBC 2021).'),
  ('ibc-111', 'IBC', 'structural-loads', 'Under IBC Table 1607.1, what is the minimum uniformly distributed live load for office buildings (offices)?', '{"A": "40 psf", "B": "50 psf", "C": "100 psf", "D": "125 psf"}'::jsonb, 'B', 'IBC Table 1607.1 assigns 50 psf for office use. Corridors above the first floor in offices are 80 psf, lobbies and first-floor corridors are 100 psf, and file/computer rooms may require higher loads. The 50 psf office value is one of the most frequently tested live loads.', 'IBC Table 1607.1', 'https://up.codes/s/minimum-uniformly-distributed-live-loads-and-minimum-concentrated-live-loads', 'intermediario', true, 'Confirmed 50 psf office live load in Table 1607.1 (IBC 2018/2021).'),
  ('ibc-112', 'IBC', 'structural-loads', 'Per IBC Table 1607.1, the minimum uniformly distributed live load for the first-floor lobbies and corridors of an assembly or commercial building is:', '{"A": "50 psf", "B": "80 psf", "C": "100 psf", "D": "150 psf"}'::jsonb, 'C', 'First-floor corridors and lobbies are assigned 100 psf in Table 1607.1 to account for crowd loading at ground level. Corridors above the first floor generally take the load of the served occupancy but not less than 80 psf. Knowing the lobby/corridor distinction is commonly tested.', 'IBC Table 1607.1', 'https://up.codes/s/minimum-uniformly-distributed-live-loads-and-minimum-concentrated-live-loads', 'intermediario', true, 'Confirmed 100 psf for first-floor corridors/lobbies in Table 1607.1 (IBC 2018/2021).'),
  ('ibc-113', 'IBC', 'structural-loads', 'Under IBC Section 1602, the weight of the building''s permanent construction, including walls, floors, roofs, fixed equipment, and finishes, is defined as the:', '{"A": "Live load", "B": "Dead load", "C": "Snow load", "D": "Impact load"}'::jsonb, 'B', 'Dead load is the weight of all permanent construction and fixed service equipment, per IBC 1602 definitions and Section 1606. Live load (1607) is the transient load from occupancy and use. Distinguishing dead from live load is foundational to applying the load combinations of Section 1605.', 'IBC 1602; 1606', 'https://up.codes/s/dead-loads', 'iniciante', true, 'Confirmed dead load definition (permanent construction weight) in IBC 1602/1606 (2018/2021).'),
  ('ibc-114', 'IBC', 'structural-loads', 'Per IBC Section 1608, the design snow load for a building is determined using which referenced standard?', '{"A": "ACI 318", "B": "ASCE 7", "C": "AISC 360", "D": "TMS 402"}'::jsonb, 'B', 'IBC 1608.1 directs that snow loads be determined in accordance with ASCE 7 Chapter 7, using the ground snow load, exposure, thermal, and importance factors. ASCE 7 is the primary referenced loading standard for snow, wind, seismic, and load combinations throughout IBC Chapter 16.', 'IBC 1608.1', 'https://up.codes/s/snow-loads', 'intermediario', true, 'Confirmed snow loads determined per ASCE 7 in Section 1608.1 (IBC 2018/2021).'),
  ('ibc-115', 'IBC', 'structural-loads', 'Under IBC Section 1609, wind loads are determined using ASCE 7 and are based primarily on which input value?', '{"A": "The ground snow load", "B": "The basic (ultimate) design wind speed for the site", "C": "The seismic design category", "D": "The allowable soil bearing pressure"}'::jsonb, 'B', 'IBC 1609.3 establishes wind loads from the basic design wind speed (Vult) mapped for the site, combined with exposure category, risk category, and topographic effects per ASCE 7. Coastal and high-wind regions carry higher mapped wind speeds, increasing the design pressures.', 'IBC 1609.3', 'https://up.codes/s/wind-loads', 'intermediario', true, 'Confirmed wind loads based on basic design wind speed per Section 1609 and ASCE 7 (IBC 2018/2021).'),
  ('ibc-116', 'IBC', 'structural-loads', 'Per IBC Section 1613, earthquake (seismic) loads must be determined in accordance with which standard, with the building first assigned a Seismic Design Category (SDC)?', '{"A": "ASCE 7", "B": "ASTM E119", "C": "ANSI A117.1", "D": "NFPA 13"}'::jsonb, 'A', 'IBC 1613.1 requires seismic design per ASCE 7 (with IBC modifications). The building''s Seismic Design Category (A through F) is established from the mapped spectral accelerations, site class, and risk category, and it governs the level of seismic detailing and bracing required.', 'IBC 1613.1', 'https://up.codes/s/earthquake-loads', 'intermediario', true, 'Confirmed seismic loads per ASCE 7 and SDC assignment in Section 1613 (IBC 2018/2021).'),
  ('ibc-117', 'IBC', 'structural-loads', 'Under IBC Table 1604.3, the deflection limit for a floor member supporting plaster or other brittle finishes under live load (L) is commonly:', '{"A": "L/180", "B": "L/240", "C": "L/360", "D": "L/120"}'::jsonb, 'C', 'Table 1604.3 sets L/360 as the live-load deflection limit for floor members, which protects brittle finishes like plaster from cracking. Roof members supporting plaster also use L/360, while members with no ceiling may use L/180 or L/240. The denominator increases (stiffer limit) as the finish becomes more deflection-sensitive.', 'IBC Table 1604.3', 'https://up.codes/s/deflection', 'avancado', true, 'Confirmed L/360 live-load deflection limit for floor members in Table 1604.3 (IBC 2018/2021).'),
  ('ibc-118', 'IBC', 'structural-loads', 'Per IBC Section 1605, structures and their components must be designed to resist the most critical effects resulting from what?', '{"A": "Dead load only", "B": "The applicable load combinations of the referenced standard", "C": "Live load minus dead load", "D": "Wind load only"}'::jsonb, 'B', 'IBC 1605 requires structural members to be designed for the most critical effects from the load combinations (either strength design/LRFD or allowable stress design combinations as referenced from ASCE 7). Designers must check multiple combinations, since the governing case varies by member and loading.', 'IBC 1605.1', 'https://up.codes/s/load-combinations', 'avancado', true, 'Confirmed design for critical effects from load combinations in Section 1605 (IBC 2018/2021).'),
  ('ibc-119', 'IBC', 'structural-loads', 'Under IBC Section 1607, when a member supports a large tributary floor area, the code permits the designer to apply a what to the design live load?', '{"A": "Live load increase factor", "B": "Live load reduction", "C": "Snow load surcharge", "D": "Seismic amplification"}'::jsonb, 'B', 'IBC 1607.12 (live load reduction) recognizes that the full design live load is statistically unlikely to act simultaneously over a large area, so it permits a reduction based on the influence area (KLL times AT). Reductions are limited and prohibited for certain uses such as places of public assembly and heavy live loads.', 'IBC 1607.12', 'https://up.codes/s/reduction-in-uniform-live-loads', 'avancado', true, 'Confirmed live load reduction provisions based on tributary/influence area in Section 1607.12 (IBC 2021).'),
  ('ibc-120', 'IBC', 'soils-foundations', 'Under IBC Table 1806.2, in the absence of a soils investigation, what is the presumptive allowable foundation (bearing) pressure for sandy gravel and/or gravel (GW and GP)?', '{"A": "1,500 psf", "B": "2,000 psf", "C": "3,000 psf", "D": "12,000 psf"}'::jsonb, 'C', 'Table 1806.2 lists 3,000 psf for sandy gravel and gravel (GW, GP). Crystalline bedrock is 12,000 psf, sedimentary/foliated rock 4,000 psf, sand/silty sand/clayey sand 2,000 psf, and clay/sandy clay/silty clay 1,500 psf. These presumptive values apply only when an engineered soils report is not provided.', 'IBC Table 1806.2', 'https://up.codes/s/presumptive-load-bearing-values', 'avancado', true, 'Confirmed 3,000 psf for sandy gravel/gravel in Table 1806.2 (IBC 2018/2021).'),
  ('ibc-121', 'IBC', 'soils-foundations', 'Per IBC Table 1806.2, the presumptive allowable bearing value for clay, sandy clay, silty clay, and clayey silt is:', '{"A": "1,500 psf", "B": "2,000 psf", "C": "3,000 psf", "D": "4,000 psf"}'::jsonb, 'A', 'Clay and similar fine-grained soils (CL, ML, MH, CH) carry the lowest presumptive bearing value of 1,500 psf in Table 1806.2 because of their lower strength and higher settlement potential. Sand-based soils are 2,000 psf and gravels 3,000 psf. A soils report can justify higher values.', 'IBC Table 1806.2', 'https://up.codes/s/presumptive-load-bearing-values', 'avancado', true, 'Confirmed 1,500 psf for clay soils in Table 1806.2 (IBC 2018/2021).'),
  ('ibc-122', 'IBC', 'soils-foundations', 'Under IBC Section 1809, the bottom of exterior footings must be placed below what depth to protect against frost damage?', '{"A": "Below the frost line for the locality", "B": "Always 12 inches below grade", "C": "Below the water table", "D": "Below the basement slab only"}'::jsonb, 'A', 'IBC 1809.5 requires exterior footings and foundation systems to extend below the frost line of the locality (or be otherwise protected from frost per the section). Frost depth varies by region and is set by the local jurisdiction, which is why footing depth is a locally adopted value.', 'IBC 1809.5', 'https://up.codes/s/footings', 'intermediario', true, 'Confirmed footings below frost line requirement in Section 1809.5 (IBC 2018/2021).'),
  ('ibc-123', 'IBC', 'soils-foundations', 'Per IBC Section 1807, retaining walls must be designed to resist what, ensuring stability against overturning, sliding, and excessive soil pressure?', '{"A": "Only the weight of the wall itself", "B": "Lateral soil loads and surcharge, with required safety factors against overturning and sliding", "C": "Snow load only", "D": "Wind load only"}'::jsonb, 'B', 'IBC 1807.2 requires retaining walls to resist lateral earth pressure plus any surcharge, and 1807.2.3 generally requires a minimum factor of safety of 1.5 against lateral sliding and overturning (unless resisting forces include dead loads). Stability and pressure on the supporting soil must both be checked.', 'IBC 1807.2', 'https://up.codes/s/retaining-walls', 'avancado', true, 'Confirmed retaining wall lateral load design with 1.5 safety factor against sliding/overturning in Section 1807.2 (IBC 2018/2021).'),
  ('ibc-124', 'IBC', 'soils-foundations', 'Under IBC Section 1810, a deep foundation element (such as a driven pile or drilled shaft) is used primarily when:', '{"A": "Shallow soils cannot adequately support the loads and load must transfer to deeper, stronger strata", "B": "The building is under one story", "C": "The site has no frost", "D": "The roof load exceeds the floor load"}'::jsonb, 'A', 'IBC 1810 governs deep foundations, which transfer structural loads through weak or compressible near-surface soils to deeper bearing strata or by skin friction. They are used when presumptive or tested shallow bearing values are insufficient or settlement would be excessive. Deep foundations require specific analysis, installation, and often special inspection.', 'IBC 1810', 'https://up.codes/s/deep-foundations', 'intermediario', true, 'Confirmed deep foundation purpose and provisions in Section 1810 (IBC 2018/2021).'),
  ('ibc-125', 'IBC', 'soils-foundations', 'Per IBC Section 1808, foundations must be designed and constructed so that the allowable bearing capacity of the soil is not exceeded and that differential settlement does not do what?', '{"A": "Increase the snow load", "B": "Cause damage to the structure or its components", "C": "Reduce the frost depth", "D": "Change the occupancy classification"}'::jsonb, 'B', 'IBC 1808.2 requires foundations to be designed to limit differential settlement and prevent damage to the supported structure. Both total and differential settlement matter, since uneven movement induces cracking and distress even when total settlement is within tolerance.', 'IBC 1808.2', 'https://up.codes/s/foundations', 'intermediario', true, 'Confirmed foundation design to limit settlement damage in Section 1808 (IBC 2018/2021).'),
  ('ibc-126', 'IBC', 'concrete', 'Under IBC Chapter 19, the design, materials, and construction of structural concrete must comply primarily with which referenced standard?', '{"A": "AISC 360", "B": "ACI 318", "C": "TMS 402", "D": "NDS"}'::jsonb, 'B', 'IBC 1901.2 and 1905 adopt ACI 318 (Building Code Requirements for Structural Concrete) as the governing standard for the design and construction of structural concrete, with IBC modifications. ACI 318 covers mixture proportioning, reinforcement, durability, and strength design.', 'IBC 1901.2; 1905', 'https://up.codes/s/general', 'iniciante', true, 'Confirmed ACI 318 adopted for structural concrete in Chapter 19 (IBC 2018/2021).'),
  ('ibc-127', 'IBC', 'concrete', 'In IBC Chapter 19 and ACI 318, the symbol f''c represents which property of concrete?', '{"A": "The yield strength of the reinforcing steel", "B": "The specified compressive strength of the concrete", "C": "The modulus of elasticity", "D": "The water-cement ratio"}'::jsonb, 'B', 'The symbol f''c is the specified compressive strength of concrete, typically expressed in psi (for example, 3,000 or 4,000 psi) and measured on standard cylinders at 28 days. The reinforcing steel yield strength is denoted fy. f''c drives the concrete''s structural capacity and durability mix requirements.', 'IBC Chapter 19 (ACI 318)', 'https://up.codes/s/general', 'intermediario', true, 'Confirmed f''c is specified compressive strength of concrete per ACI 318 referenced in Chapter 19.'),
  ('ibc-128', 'IBC', 'concrete', 'Per IBC Chapter 19 and ACI 318, the minimum concrete cover over reinforcing steel is specified primarily to provide what?', '{"A": "A larger live load capacity", "B": "Protection of the reinforcement against corrosion and fire, and proper bond", "C": "A lower water table", "D": "A higher roof class"}'::jsonb, 'B', 'Minimum concrete cover protects reinforcing steel from corrosion (especially with exposure to weather or earth) and fire, and ensures adequate bond between concrete and steel. ACI 318 specifies cover by exposure condition, for example 3 inches for concrete cast against earth and 1.5 to 2 inches for surfaces exposed to weather.', 'IBC Chapter 19 (ACI 318)', 'https://up.codes/s/general', 'avancado', true, 'Confirmed purpose of minimum concrete cover (corrosion, fire, bond) per ACI 318 in Chapter 19.'),
  ('ibc-129', 'IBC', 'masonry', 'Under IBC Chapter 21, the design and construction of masonry must comply principally with which referenced standard?', '{"A": "TMS 402/602", "B": "ACI 318", "C": "AISC 360", "D": "AWC NDS"}'::jsonb, 'A', 'IBC 2101 adopts TMS 402 (Building Code Requirements for Masonry Structures) and TMS 602 (Specification for Masonry Structures) as the governing documents for masonry design and construction, with IBC modifications. These cover allowable stress and strength design, materials, and quality assurance.', 'IBC 2101', 'https://up.codes/s/general', 'iniciante', true, 'Confirmed TMS 402/602 adopted for masonry in Chapter 21 (IBC 2018/2021).'),
  ('ibc-130', 'IBC', 'masonry', 'Per IBC Chapter 21, the strength of masonry assemblies is characterized by which specified value used in design?', '{"A": "f''m, the specified compressive strength of masonry", "B": "Fy, the yield strength of mortar", "C": "The water-cement ratio of grout", "D": "The roof covering class"}'::jsonb, 'A', 'Masonry design uses f''m, the specified compressive strength of masonry, which is verified either by the unit strength method or by prism testing per TMS 602. f''m is analogous to f''c in concrete and governs the allowable or nominal capacity of walls, columns, and piers.', 'IBC Chapter 21 (TMS 402/602)', 'https://up.codes/s/general', 'intermediario', true, 'Confirmed f''m (specified compressive strength of masonry) verified by unit-strength or prism method per TMS 602.'),
  ('ibc-131', 'IBC', 'steel', 'Under IBC Chapter 22, the design, fabrication, and erection of structural steel must comply primarily with which referenced standard?', '{"A": "ACI 318", "B": "AISC 360 (Specification for Structural Steel Buildings)", "C": "TMS 402", "D": "AWC NDS"}'::jsonb, 'B', 'IBC 2205 adopts AISC 360 for the design of structural steel buildings, with AISC 341 for seismic provisions in higher Seismic Design Categories and AISC 303 for the code of standard practice. Cold-formed steel uses AISI standards. AISC 360 covers both LRFD and ASD design methods.', 'IBC 2205', 'https://up.codes/s/structural-steel', 'iniciante', true, 'Confirmed AISC 360 adopted for structural steel in Chapter 22 (IBC 2018/2021).'),
  ('ibc-132', 'IBC', 'steel', 'Per IBC Chapter 22, when a building is assigned to a higher Seismic Design Category, structural steel seismic-force-resisting systems generally must also comply with which standard?', '{"A": "AISC 341 (Seismic Provisions)", "B": "ASTM E84", "C": "NFPA 13", "D": "ANSI A117.1"}'::jsonb, 'A', 'IBC 2205.2 requires that the seismic-force-resisting systems of structural steel buildings in the higher Seismic Design Categories be designed per AISC 341, the Seismic Provisions for Structural Steel Buildings, in addition to AISC 360. This adds ductility detailing for special and intermediate systems.', 'IBC 2205.2', 'https://up.codes/s/structural-steel', 'avancado', true, 'Confirmed AISC 341 seismic provisions required in higher SDCs per Section 2205.2 (IBC 2018/2021).'),
  ('ibc-133', 'IBC', 'wood', 'Under IBC Chapter 23, the allowable stress design of wood members and their connections must comply principally with which referenced standard?', '{"A": "AWC NDS (National Design Specification for Wood Construction)", "B": "ACI 318", "C": "AISC 360", "D": "TMS 402"}'::jsonb, 'A', 'IBC 2306 references the AWC NDS for allowable stress design of wood, with the AWC SDPWS for shear walls and diaphragms. The NDS provides reference design values and adjustment factors for sawn lumber, glued-laminated timber, and connections.', 'IBC 2306', 'https://up.codes/s/allowable-stress-design', 'iniciante', true, 'Confirmed AWC NDS adopted for allowable stress design of wood in Chapter 23 (IBC 2018/2021).'),
  ('ibc-134', 'IBC', 'wood', 'Per the NDS referenced in IBC Chapter 23, the load-duration factor (CD) recognizes that wood can carry higher loads for shorter durations. Which load duration corresponds to the highest CD among these choices?', '{"A": "Permanent (dead) load", "B": "Ten-year (normal/occupancy) load", "C": "Wind or seismic (short duration) load", "D": "Snow load"}'::jsonb, 'C', 'The NDS load-duration factor increases as the duration of the load shortens. Permanent load uses CD = 0.9, normal (ten-year) load 1.0, snow 1.15, wind/seismic 1.6, and impact 2.0. Among the choices given, wind/seismic (short duration) has the highest CD, reflecting wood''s ability to resist brief loads at higher stress.', 'IBC Chapter 23 (AWC NDS)', 'https://up.codes/s/allowable-stress-design', 'avancado', true, 'Confirmed NDS load-duration factors: 0.9 permanent, 1.0 normal, 1.15 snow, 1.6 wind/seismic per referenced NDS.'),
  ('ibc-135', 'IBC', 'wood', 'Under IBC Section 2308, conventional light-frame wood construction is permitted only when the building stays within prescribed limits, including a maximum of how many stories above grade plane (for most occupancies)?', '{"A": "One story", "B": "Two stories", "C": "Three stories", "D": "Six stories"}'::jsonb, 'C', 'IBC 2308.2 limits conventional (prescriptive) light-frame wood construction to a maximum of three stories above grade plane, along with limits on bearing wall heights, spans, and loads. Buildings exceeding these limits must be engineered per the general provisions of Chapter 23 rather than the conventional rules.', 'IBC 2308.2', 'https://up.codes/s/conventional-light-frame-construction', 'avancado', true, 'Confirmed three-story limit for conventional light-frame construction in Section 2308.2 (IBC 2018/2021).'),
  ('ibc-136', 'IBC', 'wood', 'Per IBC Chapter 23, where wood is in contact with the ground or exposed to weather and decay hazard, the code requires the use of:', '{"A": "Untreated kiln-dried lumber", "B": "Naturally durable wood or preservative-treated wood", "C": "Fire-retardant-treated wood only", "D": "Engineered I-joists only"}'::jsonb, 'B', 'IBC 2304.12 requires protection against decay, mandating naturally durable or preservative-treated wood where members are in contact with the ground, exposed to weather, or otherwise subject to decay (such as sills on concrete in contact with the ground). This is distinct from fire-retardant treatment, which addresses flame spread, not decay.', 'IBC 2304.12', 'https://up.codes/s/protection-against-decay-and-termites', 'intermediario', true, 'Confirmed naturally durable or preservative-treated wood required for decay protection in Section 2304.12 (IBC 2018/2021).'),
  ('ibc-137', 'IBC', 'safeguards-construction', 'Under IBC Chapter 33 (Safeguards During Construction), how must the means of egress be handled in a building undergoing alteration while it remains occupied?', '{"A": "Egress is suspended during construction", "B": "The required means of egress must be maintained at all times during occupancy", "C": "Only the fire department maintains egress", "D": "Egress is required only after construction is complete"}'::jsonb, 'B', 'IBC 3303 and 3310 require that in buildings occupied during construction, alteration, or demolition, the required means of egress be maintained at all times. Construction cannot block or eliminate the required exits while occupants are present, protecting occupants from being trapped during work.', 'IBC 3303; 3310', 'https://up.codes/s/safeguards-during-construction', 'intermediario', true, 'Confirmed required means of egress maintained during construction in occupied buildings per Chapter 33 (IBC 2018/2021).'),
  ('ibc-138', 'IBC', 'safeguards-construction', 'Per IBC Chapter 33, before a structure is demolished, what must be addressed regarding utility service connections?', '{"A": "Nothing, utilities are left in service", "B": "Service utility connections must be discontinued and capped, or otherwise controlled, in accordance with approved rules", "C": "Only the water service is shut off", "D": "Utilities are upgraded to a higher capacity"}'::jsonb, 'B', 'IBC 3306 and the demolition provisions of Chapter 33 require that service utility connections, such as gas, electric, water, and sewer, be discontinued and capped or otherwise controlled before demolition begins, with notification to the serving utilities. This prevents gas leaks, electrocution, and flooding during demolition.', 'IBC 3306', 'https://up.codes/s/demolition', 'intermediario', true, 'Confirmed utility connections must be discontinued/capped before demolition per Chapter 33 demolition provisions (IBC 2018/2021).'),
  ('ibc-139', 'IBC', 'safeguards-construction', 'Under IBC Chapter 33, a fence or barrier is required around a construction or demolition site primarily to:', '{"A": "Reduce the wind load on the building", "B": "Protect the public from construction and demolition hazards", "C": "Satisfy the energy code", "D": "Increase the allowable floor area"}'::jsonb, 'B', 'IBC 3303 requires construction and demolition sites to be protected with fences or barriers to keep the public away from hazards such as falling debris and open excavations. The protection requirements scale with the proximity to lot lines and public ways and may include covered walkways.', 'IBC 3303', 'https://up.codes/s/safeguards-during-construction', 'iniciante', true, 'Confirmed site fencing/barrier requirement to protect the public in Chapter 33 (IBC 2018/2021).'),
  ('ibc-140', 'IBC', 'safeguards-construction', 'Per IBC Chapter 33, when a portion of a building is occupied during construction, the required fire protection systems serving the occupied area must be:', '{"A": "Removed to allow construction access", "B": "Maintained in operable condition", "C": "Replaced with portable extinguishers only", "D": "Disabled until final inspection"}'::jsonb, 'B', 'IBC 3310 and related provisions require that required fire protection systems, such as sprinklers and standpipes, be maintained operable in occupied portions during construction. Where systems are required during construction of high-rise or other buildings, standpipes and water supply must keep pace with construction height.', 'IBC 3310; 3313', 'https://up.codes/s/safeguards-during-construction', 'avancado', true, 'Confirmed fire protection systems maintained operable in occupied areas and standpipe-during-construction rules in Chapter 33 (IBC 2018/2021).'),
  ('ibc-141', 'IBC', 'safeguards-construction', 'Under IBC Chapter 31, temporary structures and uses (such as a construction trailer or a temporary tent) erected on a site are generally permitted for a limited period not to exceed how long unless extended by the building official?', '{"A": "30 days", "B": "90 days", "C": "180 days", "D": "Three years"}'::jsonb, 'C', 'IBC 3103.1 limits temporary structures and uses to a period of not more than 180 days, unless extended for a demonstrated cause by the building official. Temporary structures must still meet structural strength, fire safety, means of egress, and accessibility requirements appropriate to the use.', 'IBC 3103.1', 'https://up.codes/s/general', 'intermediario', true, 'Confirmed 180-day limit for temporary structures/uses in Section 3103.1 (IBC 2018/2021).'),
  ('ibc-142', 'IBC', 'exterior-walls', 'Per IBC Chapter 14, exterior walls and their associated weather-resistive components are required to perform what fundamental function in addition to any structural role?', '{"A": "Provide the seismic-force-resisting system", "B": "Provide weather protection (resist water and air intrusion)", "C": "Serve as the roof drainage system", "D": "Establish the occupant load"}'::jsonb, 'B', 'IBC 1402.2 (Weather Protection) requires exterior walls to provide a weather-resistant exterior wall envelope that prevents the accumulation of water within the assembly, using flashing, a water-resistive barrier, and proper integration of openings. This weather-protection role is the central performance objective of Chapter 14.', 'IBC 1402.2', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-14-exterior-walls', 'iniciante', true, 'Confirmed weather-protection performance requirement for exterior walls in Section 1402.2 (IBC 2021).'),
  ('ibc-143', 'IBC', 'structural-loads', 'Under IBC Section 1604, the risk category assigned to a building (I through IV) primarily affects which aspect of structural design?', '{"A": "The roof covering class", "B": "The importance factors used for snow, wind, and seismic loads", "C": "The minimum concrete cover", "D": "The allowable soil bearing pressure"}'::jsonb, 'B', 'IBC 1604.5 and Table 1604.5 assign each building a risk category (I lowest to IV highest, such as essential facilities) based on the hazard to human life. The risk category sets the importance factors that scale snow, wind, and seismic design loads in ASCE 7, requiring more critical facilities to be designed for higher loads.', 'IBC 1604.5; Table 1604.5', 'https://up.codes/s/risk-category-of-buildings-and-other-structures', 'avancado', true, 'Confirmed risk category drives importance factors for snow/wind/seismic per Section 1604.5 and Table 1604.5 (IBC 2018/2021).'),
  ('ibc-144', 'IBC', 'sprinkler-systems', 'Per IBC Section 903.2.1.1, an automatic sprinkler system is required throughout a Group A-1 occupancy when which threshold is exceeded?', '{"A": "The fire area exceeds 12,000 square feet, has an occupant load of 300 or more, the fire area is on a floor other than a level of exit discharge, or it is a multitheater complex", "B": "The fire area exceeds 5,000 square feet", "C": "The occupant load exceeds 50", "D": "Any A-1 occupancy regardless of size"}'::jsonb, 'A', 'IBC 903.2.1.1 requires sprinklers throughout the building''s fire area containing an A-1 occupancy where the fire area exceeds 12,000 sq ft, where it has an occupant load of 300 or more, where it is located on a floor other than a level of exit discharge serving such occupancies, or where it is a multitheater complex. The same numeric triggers apply to A-3 and A-4 under 903.2.1.3/.1.4.', 'IBC 903.2.1.1', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-9-fire-protection-and-life-safety-systems', 'avancado', true, 'Confirmed the four A-1 sprinkler triggers (12,000 sf / 300 OL / floor other than exit discharge / multitheater) in IBC 2018/2021 Section 903.2.1.1.'),
  ('ibc-145', 'IBC', 'sprinkler-systems', 'Under IBC Section 903.2.7, a Group M (mercantile) occupancy requires an automatic sprinkler system throughout the building''s fire area when which condition is met?', '{"A": "The fire area exceeds 12,000 sq ft, the fire area is located more than three stories above grade plane, or the combined area of all M fire areas on all floors exceeds 24,000 sq ft", "B": "Only when the building exceeds four stories", "C": "Only when the occupant load exceeds 1,000", "D": "M occupancies never require sprinklers"}'::jsonb, 'A', 'IBC 903.2.7 requires sprinklers in a Group M occupancy where a fire area exceeds 12,000 sq ft, where a fire area is located more than three stories above grade plane, or where the combined area of all Group M fire areas on all floors, including any mezzanines, exceeds 24,000 sq ft. The 12,000 / 24,000 sq ft thresholds parallel the Group B, F-1, and S-1 triggers in Chapter 9.', 'IBC 903.2.7', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-9-fire-protection-and-life-safety-systems', 'avancado', true, 'Confirmed Group M sprinkler thresholds 12,000 sf fire area / >3 stories / 24,000 sf aggregate in IBC 903.2.7.'),
  ('ibc-146', 'IBC', 'sprinkler-systems', 'IBC Section 903.2.8 requires an automatic sprinkler system throughout all buildings containing a Group R fire area. Which statement best describes this requirement?', '{"A": "It applies only to R-1 hotels over four stories", "B": "It applies to all Group R occupancies (R-1, R-2, R-3, R-4) regardless of fire area size", "C": "It applies only when the fire area exceeds 12,000 sq ft", "D": "It applies only to R-2 apartment buildings"}'::jsonb, 'B', 'IBC 903.2.8 mandates an automatic sprinkler system installed throughout all buildings with a Group R fire area, with no minimum area threshold. The system type can vary, NFPA 13 for general R use, NFPA 13R for R occupancies up to four stories in height (per 903.3.1.2), or NFPA 13D for one- and two-family dwellings and townhouses, but the sprinkler requirement itself applies to all Group R.', 'IBC 903.2.8', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-9-fire-protection-and-life-safety-systems', 'intermediario', true, 'Confirmed all Group R fire areas require sprinklers per IBC 903.2.8 (no area threshold).'),
  ('ibc-147', 'IBC', 'sprinkler-systems', 'An NFPA 13R sprinkler system, referenced in IBC Section 903.3.1.2, is permitted in Group R occupancies that meet which height limitation?', '{"A": "Up to and including four stories above grade plane and not exceeding 60 feet in height measured to the highest occupiable floor", "B": "Any height with no limit", "C": "Up to 12 stories", "D": "Only one- and two-family dwellings"}'::jsonb, 'A', 'IBC 903.3.1.2 permits an NFPA 13R system in Group R occupancies up to and including four stories above grade plane, with a maximum height of 60 feet measured to the highest occupiable floor. Above those limits a full NFPA 13 system is required. NFPA 13D (option D) is the standard for one- and two-family dwellings and townhouses, a different system.', 'IBC 903.3.1.2', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-9-fire-protection-and-life-safety-systems', 'avancado', true, 'Confirmed NFPA 13R limit of 4 stories above grade plane / 60 ft to highest occupiable floor in IBC 2018/2021 903.3.1.2.'),
  ('ibc-148', 'IBC', 'sprinkler-systems', 'Which sprinkler standard does IBC Section 903.3.1.3 reference for the protection of one- and two-family dwellings and townhouses?', '{"A": "NFPA 13", "B": "NFPA 13R", "C": "NFPA 13D", "D": "NFPA 25"}'::jsonb, 'C', 'IBC 903.3.1.3 references NFPA 13D for automatic sprinkler systems in one- and two-family dwellings and townhouses. NFPA 13 (option A) is the full commercial standard, NFPA 13R (B) is for low-rise residential up to four stories, and NFPA 25 (D) is the standard for the inspection, testing, and maintenance of water-based fire protection systems, not their design.', 'IBC 903.3.1.3', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-9-fire-protection-and-life-safety-systems', 'intermediario', true, 'Confirmed NFPA 13D referenced for 1- and 2-family dwellings/townhouses in IBC 903.3.1.3.'),
  ('ibc-149', 'IBC', 'sprinkler-systems', 'Per IBC Section 903.4, where a required automatic sprinkler system serves a building, the valves controlling the water supply and other monitored components must be:', '{"A": "Automatically shut off the building electrical service when water flows", "B": "Electrically supervised, and water flow must transmit an alarm signal and activate occupant notification appliances", "C": "Equipped only with a local bell with no monitoring required", "D": "Inspected only once every five years"}'::jsonb, 'B', 'IBC 903.4 requires that valves controlling the water supply and other components be electrically supervised, and 903.4.2 requires an approved audible alarm/water-flow device. Activation of a required sprinkler system must transmit an alarm signal and activate alarm-notification appliances. This supervision ensures that valve closure (tamper) or water flow is detected and reported.', 'IBC 903.4; 903.4.2', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-9-fire-protection-and-life-safety-systems', 'intermediario', true, 'Confirmed IBC 903.4 monitoring/supervision and 903.4.2 alarm requirements for sprinkler systems.'),
  ('ibc-150', 'IBC', 'standpipes', 'IBC Section 905 and NFPA 14 define standpipe classes by intended user. A Class I standpipe system is intended for use by whom and provides what hose connection size?', '{"A": "Trained building occupants, with 1-1/2 inch connections", "B": "Fire department personnel and trained users, with 2-1/2 inch hose connections", "C": "Automatic fire suppression only, with no hose connection", "D": "Sprinkler heads only"}'::jsonb, 'B', 'Under IBC 905 / NFPA 14, a Class I standpipe provides 2-1/2 inch hose connections for use by fire department personnel or trained personnel with heavy fire-fighting hose streams. Class II provides 1-1/2 inch connections (option A) for use by the building occupants until the fire department arrives. Class III provides both 1-1/2 inch and 2-1/2 inch connections, serving both groups.', 'IBC 905.3; NFPA 14', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-9-fire-protection-and-life-safety-systems', 'intermediario', true, 'Confirmed Class I = 2-1/2 in fire-department connection, Class II = 1-1/2 in occupant use, Class III = both, per IBC 905 / NFPA 14.'),
  ('ibc-151', 'IBC', 'standpipes', 'Per IBC Section 905.3.1, a standpipe system is generally required in a building where the floor level of the highest story is located more than what distance above the lowest level of fire department vehicle access?', '{"A": "More than 30 feet", "B": "More than 75 feet", "C": "More than 120 feet", "D": "More than 200 feet"}'::jsonb, 'A', 'IBC 905.3.1 requires standpipe systems in buildings where the floor level of the highest story is more than 30 feet above the lowest level of fire department vehicle access, or where the floor level of the lowest story is more than 30 feet below the highest level of fire department vehicle access. (The 75-foot threshold, option B, is the separate definition of a high-rise building under Sections 202/403, which triggers additional protection.)', 'IBC 905.3.1', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-9-fire-protection-and-life-safety-systems', 'avancado', true, 'Confirmed standpipe primary trigger 30 ft above/below fire department vehicle access per IBC 905.3.1; 75 ft is the distinct high-rise definition (202/403).'),
  ('ibc-152', 'IBC', 'fire-alarm-detection', 'IBC Section 907.2 establishes where manual and/or automatic fire alarm systems are required. A manual fire alarm system is generally NOT required (pull stations may be omitted) in a Group A occupancy when which condition is satisfied?', '{"A": "Never; A occupancies always require manual pull stations regardless", "B": "The building has an approved automatic sprinkler system per 903.3.1.1 and the occupant notification appliances activate upon sprinkler water flow", "C": "Only when the building is single-story", "D": "When the building is naturally ventilated"}'::jsonb, 'B', 'IBC 907.2.1 requires a manual fire alarm in Group A with an occupant load of 300 or more, or where the occupant load is more than 100 above or below the lowest level of exit discharge. Manual pull stations are not required where the building is equipped throughout with an automatic sprinkler system installed per 903.3.1.1 and the occupant notification appliances activate upon sprinkler water flow (907.2.1 exception).', 'IBC 907.2.1', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-9-fire-protection-and-life-safety-systems', 'avancado', true, 'Confirmed Group A manual fire alarm trigger (OL 300, or 100 above/below exit discharge) and sprinkler/notification exception in IBC 907.2.1.'),
  ('ibc-153', 'IBC', 'fire-alarm-detection', 'Under IBC Section 907.5.2.3, where occupant notification is required, visible alarm notification appliances (strobes) must be provided in which areas to comply with accessibility requirements?', '{"A": "Only in private offices", "B": "Public-use and common-use areas, in accordance with NFPA 72", "C": "Only in stairwells", "D": "Visible appliances are optional in all cases"}'::jsonb, 'B', 'IBC 907.5.2.3 requires visible alarm notification appliances (strobe lights) in public-use and common-use areas, and 907.5.2.3.1/.3.2 address public and common areas plus employee work areas, all in accordance with NFPA 72. This ensures notification reaches occupants with hearing impairments, an ADA/accessibility-driven requirement.', 'IBC 907.5.2.3; NFPA 72', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-9-fire-protection-and-life-safety-systems', 'intermediario', true, 'Confirmed visible notification in public/common areas per IBC 907.5.2.3 and NFPA 72.'),
  ('ibc-154', 'IBC', 'fire-alarm-detection', 'Per IBC Section 907.2.3, in a Group E (educational) occupancy, manual pull stations may be limited to a single location when which conditions are met?', '{"A": "The occupant load is below 50, regardless of any other condition", "B": "The building is equipped throughout with an approved automatic sprinkler system, the notification appliances activate on sprinkler water flow, and manual activation is provided at a normally occupied location such as the main office", "C": "The school has fewer than 10 classrooms", "D": "The building is single-story and naturally ventilated"}'::jsonb, 'B', 'IBC 907.2.3 requires a manual fire alarm in Group E occupancies (exception for very small E with OL under 50). The pull-station exception allows manual stations to be limited to a single, constantly attended/normally occupied location such as the main office when the building has an automatic sprinkler system and the alarm notification activates automatically on water flow. This balances life safety with reduced false alarms in schools.', 'IBC 907.2.3', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-9-fire-protection-and-life-safety-systems', 'avancado', true, 'Confirmed Group E manual fire alarm + pull-station exception (sprinklered + single constantly-attended location) in IBC 907.2.3.'),
  ('ibc-155', 'IBC', 'smoke-control', 'IBC Section 909 governs smoke control systems. When a smoke control system is provided to comply with the code, what is required to verify its proper operation before occupancy?', '{"A": "No testing; visual inspection of ducts only", "B": "Special inspections and acceptance testing in accordance with Sections 909 and 1705, of components such as fans, dampers, controls, and pressure differences", "C": "A simple smoke detector calibration", "D": "Only annual recertification after occupancy"}'::jsonb, 'B', 'IBC 909 requires smoke control systems to be designed using a rational analysis (909.4), and 909.18 plus Section 1705.18 mandate special inspections and acceptance testing of the smoke control system components (fans, dampers, controls, pressure differences) before a certificate of occupancy is issued. The system must be commissioned and demonstrated to perform as designed.', 'IBC 909.18; 1705.18', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-9-fire-protection-and-life-safety-systems', 'avancado', true, 'Confirmed smoke control special inspection/acceptance testing requirement per IBC 909.18 / 1705.18.'),
  ('ibc-156', 'IBC', 'fire-extinguishers', 'Per IBC Section 906, the selection, installation, and distribution of portable fire extinguishers must conform to which standard?', '{"A": "NFPA 13", "B": "NFPA 10", "C": "NFPA 72", "D": "NFPA 14"}'::jsonb, 'B', 'IBC 906.2 requires that the selection, installation, and distribution of portable fire extinguishers comply with the International Fire Code and NFPA 10 (Standard for Portable Fire Extinguishers). NFPA 13 (A) is sprinklers, NFPA 72 (C) is fire alarm/signaling, and NFPA 14 (D) is standpipes.', 'IBC 906.2; NFPA 10', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-9-fire-protection-and-life-safety-systems', 'iniciante', true, 'Confirmed portable fire extinguishers per IBC 906 reference NFPA 10.'),
  ('ibc-157', 'IBC', 'fire-extinguishers', 'Under NFPA 10 as referenced by IBC Section 906, what is the maximum travel distance to a portable fire extinguisher for a Class A hazard (ordinary combustibles)?', '{"A": "30 feet", "B": "50 feet", "C": "75 feet", "D": "100 feet"}'::jsonb, 'C', 'NFPA 10 (referenced by IBC 906.3) establishes a maximum travel distance of 75 feet to a Class A fire extinguisher. For Class B (flammable liquids) the maximum travel distance is typically 30 or 50 feet depending on hazard level, and Class C/D/K have their own placement rules. IBC 906.3 reproduces these distance limits in its tables.', 'IBC 906.3; NFPA 10', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-9-fire-protection-and-life-safety-systems', 'intermediario', true, 'Confirmed 75 ft max travel distance to Class A extinguisher per NFPA 10 / IBC 906.3.'),
  ('ibc-158', 'IBC', 'fire-pump', 'Where a fire pump is required to provide adequate water pressure or flow for a fire protection system, IBC Chapter 9 requires the fire pump installation to comply with which NFPA standard?', '{"A": "NFPA 20", "B": "NFPA 25", "C": "NFPA 13D", "D": "NFPA 70"}'::jsonb, 'A', 'Fire pumps are designed and installed in accordance with NFPA 20 (Standard for the Installation of Stationary Pumps for Fire Protection), referenced through IBC Chapter 9 (e.g., 913). NFPA 25 (B) covers inspection/testing/maintenance, NFPA 13D (C) is residential sprinklers, and NFPA 70 (D) is the National Electrical Code. IBC 913 also requires fire pump rooms to be protected with specific fire-resistance separation.', 'IBC 913; NFPA 20', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-9-fire-protection-and-life-safety-systems', 'intermediario', true, 'Confirmed fire pumps per IBC 913 reference NFPA 20.'),
  ('ibc-159', 'IBC', 'fire-command-center', 'Per IBC Section 911, a fire command center is required for high-rise buildings and certain other structures. Which describes the minimum required size and rating of the fire command center?', '{"A": "No minimum; it can be any closet", "B": "A minimum of 200 square feet with a minimum dimension of 10 feet, separated from the remainder of the building by not less than a 1-hour fire barrier", "C": "A minimum of 50 square feet with no separation", "D": "It must be located outdoors"}'::jsonb, 'B', 'IBC 911.1.2 requires the fire command center to be a minimum of 200 square feet in area with a minimum dimension of 10 feet, and 911.1.1 requires separation from the remainder of the building by not less than a 1-hour fire barrier. The room houses controls and indicators (annunciators, sprinkler/standpipe valves, smoke control panel, emergency power, etc.) for fire department use.', 'IBC 911.1.1; 911.1.2', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-9-fire-protection-and-life-safety-systems', 'avancado', true, 'Confirmed fire command center min 200 sf, 10 ft min dimension, 1-hour fire barrier per IBC 911.1.1/.1.2.'),
  ('ibc-160', 'IBC', 'sprinkler-systems', 'IBC Section 903.2.9 requires sprinkler protection in Group S-1 storage occupancies. Which of the following correctly states a trigger?', '{"A": "Storage of office paper records, in any quantity", "B": "A Group S-1 fire area exceeding 12,000 sq ft, a fire area more than three stories above grade plane, a combined S-1 area on all floors exceeding 24,000 sq ft, plus specific repair-garage and high-piled-storage triggers", "C": "Only frozen-food storage", "D": "S-1 occupancies never require sprinklers"}'::jsonb, 'B', 'IBC 903.2.9 requires sprinklers in a Group S-1 fire area exceeding 12,000 sq ft, where a fire area is on a floor more than three stories above grade, or where the combined S-1 fire area on all floors exceeds 24,000 sq ft. 903.2.9.1 specifically addresses repair garages (by area, stories, and basement), and high-piled combustible storage (903.2.9.2 / IFC Chapter 32) carries additional sprinkler triggers based on commodity class and pile height.', 'IBC 903.2.9; 903.2.9.1; 903.2.9.2', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-9-fire-protection-and-life-safety-systems', 'avancado', true, 'Confirmed S-1 sprinkler triggers and repair garage/high-piled storage provisions in IBC 903.2.9 and subsections.'),
  ('ibc-161', 'IBC', 'sprinkler-systems', 'When an automatic sprinkler system is installed throughout a building, IBC permits various code reductions (sprinkler trade-offs). Which of the following is a recognized trade-off?', '{"A": "Elimination of all exits", "B": "Increases in allowable building height and area (Tables 504 and 506) and increases in maximum exit access travel distance under Section 1017", "C": "Removal of all fire-resistance-rated assemblies in every case", "D": "Elimination of the requirement for a certificate of occupancy"}'::jsonb, 'B', 'A fully sprinklered building is permitted increases in allowable height (Table 504.3/504.4) and allowable area (Table 506.2 area factor for S1/SM vs NS), and longer maximum exit access travel distances under Table 1017.2. Sprinklers do not eliminate exits, all required fire-resistance assemblies, or the CO. These trade-offs reflect the proven life-safety value of sprinklers.', 'IBC 504; 506; 1017.2', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-10-means-of-egress', 'intermediario', true, 'Confirmed sprinkler trade-offs for height (504), area (506), and travel distance (Table 1017.2) in IBC 2018/2021.'),
  ('ibc-162', 'IBC', 'panic-hardware', 'Per IBC Section 1010.1.10, panic hardware or fire exit hardware is required on latched/locked egress doors serving which occupancies?', '{"A": "All occupancies without exception", "B": "Group A and Group E occupancies with an occupant load of 50 or more, and all Group H occupancies regardless of occupant load", "C": "Only Group R-3 dwellings", "D": "Only mechanical rooms"}'::jsonb, 'B', 'IBC 1010.1.10 requires panic hardware (or fire exit hardware on fire-rated doors) on doors equipped with a latch or lock that serve a Group A or E occupancy with an occupant load of 50 or more, and on all Group H occupancies regardless of occupant load. The hardware must release the latch when a force of not more than 15 pounds is applied in the direction of egress travel.', 'IBC 1010.1.10', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-10-means-of-egress', 'avancado', true, 'Confirmed panic hardware required for A and E (OL 50+) and all H per IBC 2018/2021 1010.1.10.'),
  ('ibc-163', 'IBC', 'door-operations', 'Under IBC Section 1010.1.9, egress doors must be readily openable from the egress side without which of the following?', '{"A": "Without the use of a key, special knowledge, or effort", "B": "Without a door handle", "C": "Without any latch whatsoever", "D": "Without a closer"}'::jsonb, 'A', 'IBC 1010.1.9.1 requires that egress doors be openable from the egress side without the use of a key, special knowledge, or effort. The unlatching of any door must be accomplished by not more than one releasing operation (1010.1.9.5), and operable hardware must be mounted between 34 and 48 inches above the floor. This guarantees occupants can exit quickly under emergency conditions.', 'IBC 1010.1.9.1; 1010.1.9.5', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-10-means-of-egress', 'iniciante', true, 'Confirmed egress-side operation without key/special knowledge/effort and single-operation unlatching per IBC 1010.1.9.'),
  ('ibc-164', 'IBC', 'door-operations', 'IBC Section 1010.1.9.9 permits sensor-release of electrically locked egress doors. Which condition is required for such locking arrangements?', '{"A": "The lock may stay engaged during a power failure", "B": "Loss of power to the sensor or locking device must automatically unlock the door in the direction of egress, and a manual unlocking device must be provided", "C": "Doors may be chained during occupancy", "D": "No release mechanism is required"}'::jsonb, 'B', 'IBC 1010.1.9.9 (sensor release of electrically locked egress doors) requires that the egress-side sensor unlock the door upon detection of an approaching occupant, that loss of power to the sensor or locking device automatically unlock the door, and that a manual unlocking device (push button) be provided that, when operated, directly interrupts power for at least 30 seconds. Doors must fail unlocked, never locked, on power loss.', 'IBC 1010.1.9.9', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-10-means-of-egress', 'avancado', true, 'Confirmed sensor-release electrically locked egress door must fail unlocked on power loss and provide manual release per IBC 1010.1.9.9 (2018/2021).'),
  ('ibc-165', 'IBC', 'exit-signs', 'Per IBC Section 1013.5, the word EXIT on an exit sign must use letters of what minimum height with what minimum principal stroke width?', '{"A": "Letters not less than 4 inches high with a stroke not less than 0.5 inch", "B": "Letters not less than 6 inches high with a principal stroke not less than 0.75 inch", "C": "Letters not less than 6 inches high with a stroke not less than 0.5 inch", "D": "Letters not less than 2 inches high"}'::jsonb, 'B', 'IBC 1013.5 requires exit sign graphics with the word EXIT in letters not less than 6 inches high, with the principal strokes of the letters not less than 0.75 inch wide, and minimum spacing between letters not less than 3/8 inch. Signs larger than minimum must keep stroke width proportional. The 6-inch letter / 3/4-inch stroke pairing is the standard answer.', 'IBC 1013.5', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-10-means-of-egress', 'intermediario', true, 'Confirmed exit sign letters 6 in high, principal stroke 0.75 in, 3/8 in spacing per IBC 1013.5.'),
  ('ibc-166', 'IBC', 'egress-illumination', 'IBC Section 1008.2.1 requires the means of egress to be illuminated to a minimum level at the walking surface during occupancy. What is that minimum?', '{"A": "Not less than 1 foot-candle", "B": "Not less than 5 foot-candles", "C": "Not less than 10 foot-candles", "D": "Not less than 0.1 foot-candle"}'::jsonb, 'A', 'IBC 1008.2.1 requires the means of egress to be illuminated to a level of not less than 1 foot-candle (11 lux) at the walking surface during occupancy. Under emergency power conditions (1008.3), illumination may decline to an average of not less than 1 foot-candle initially and not less than 0.1 foot-candle minimum at the end of 90 minutes along the path of egress.', 'IBC 1008.2.1; 1008.3', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-10-means-of-egress', 'intermediario', true, 'Confirmed 1 foot-candle minimum egress illumination (1008.2.1) and emergency power decline to 0.1 fc at 90 min (1008.3).'),
  ('ibc-167', 'IBC', 'stairways', 'Per IBC Section 1011.5.2, the maximum riser height and minimum tread depth for means-of-egress (commercial) stairways are which of the following?', '{"A": "Maximum 8-1/4 inch riser, minimum 9 inch tread", "B": "Maximum 7 inch riser, minimum 11 inch tread", "C": "Maximum 7-3/4 inch riser, minimum 10 inch tread", "D": "Maximum 6 inch riser, minimum 13 inch tread"}'::jsonb, 'B', 'IBC 1011.5.2 establishes a maximum riser height of 7 inches and a minimum tread depth of 11 inches for means-of-egress stairways (the standard commercial 7/11 rule). This contrasts with the dwelling-unit limits of 7-3/4 inch maximum riser and 10 inch minimum tread, which the IBC allows only for stairs within individual dwelling units under the 1011.5.2 exceptions.', 'IBC 1011.5.2', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-10-means-of-egress', 'intermediario', true, 'Confirmed commercial stair 7 in max riser / 11 in min tread per IBC 1011.5.2; dwelling-unit exception 7-3/4 / 10.'),
  ('ibc-168', 'IBC', 'stairways', 'IBC Section 1011.2 sets the minimum width of stairways in the means of egress. What is the minimum clear width generally required where the stairway serves an occupant load of 50 or more?', '{"A": "36 inches", "B": "44 inches", "C": "48 inches", "D": "60 inches"}'::jsonb, 'B', 'IBC 1011.2 requires a minimum stairway width of 44 inches where the stairway serves an occupant load of 50 or more. Stairways serving an occupant load of less than 50 are permitted a minimum width of 36 inches. The required width is also subject to the per-occupant capacity factor of Section 1005 (0.3 inch per occupant for sprinklered, 0.2 inch otherwise), whichever yields the greater width.', 'IBC 1011.2; 1005.3.1', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-10-means-of-egress', 'intermediario', true, 'Confirmed 44 in min stair width for OL 50+, 36 in for OL<50 per IBC 1011.2; capacity factor per 1005.'),
  ('ibc-169', 'IBC', 'stairways', 'Per IBC Section 1011.8, what is the maximum vertical rise permitted for a single stairway flight between floor levels or landings?', '{"A": "8 feet", "B": "10 feet", "C": "12 feet", "D": "16 feet"}'::jsonb, 'C', 'IBC 1011.8 limits the maximum vertical rise of a stairway flight to 12 feet between floor levels or landings. A landing must be provided at the top and bottom of each stairway, and intermediate landings break flights so that no single flight rises more than 12 feet, reducing fall distance and providing rest points.', 'IBC 1011.8', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-10-means-of-egress', 'intermediario', true, 'Confirmed 12 ft maximum vertical rise between landings per IBC 1011.8 (2018/2021).'),
  ('ibc-170', 'IBC', 'handrails', 'IBC Section 1014.6 requires handrail extensions at stairway flights. At the top of a stair flight, the handrail must extend horizontally beyond the top riser nosing for what minimum distance?', '{"A": "Not less than 6 inches", "B": "Not less than 12 inches horizontally beyond the top riser nosing", "C": "Not less than 24 inches", "D": "No extension is required at the top"}'::jsonb, 'B', 'IBC 1014.6 requires the handrail at the top of a stairway to extend horizontally above the landing not less than 12 inches beyond the top riser nosing, and at the bottom to continue to slope for the depth of one tread beyond the bottom riser nosing. These extensions give a continuous graspable surface where users begin and finish the stair.', 'IBC 1014.6', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-10-means-of-egress', 'avancado', true, 'Confirmed handrail extension: top 12 in horizontal, bottom one tread depth beyond bottom nosing per IBC 1014.6.'),
  ('ibc-171', 'IBC', 'handrails', 'Per IBC Section 1014.2, the top of handrail gripping surfaces must be mounted at what height above stair tread nosings and the finished surface of ramps?', '{"A": "Between 30 and 34 inches", "B": "Between 36 and 40 inches", "C": "Not less than 34 inches and not more than 38 inches", "D": "Between 42 and 48 inches"}'::jsonb, 'C', 'IBC 1014.2 requires handrail height, measured vertically from the top of the gripping surface, to be not less than 34 inches and not more than 38 inches above stair tread nosings and the finished surface of ramp slopes. A guard, by contrast, must be at least 42 inches high per 1015.3; do not confuse handrail height with guard height.', 'IBC 1014.2', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-10-means-of-egress', 'iniciante', true, 'Confirmed handrail height 34-38 in per IBC 1014.2; distinguished from 42 in guard height (1015.3).'),
  ('ibc-172', 'IBC', 'exit-access-stairways', 'IBC Section 1019 regulates exit access stairways and ramps that are NOT within an interior exit stairway enclosure. Under the general rule, unenclosed (open) exit access stairways are permitted to connect how many stories?', '{"A": "Any number of stories with no limit", "B": "Not more than two stories, unless an express exception applies (e.g., mezzanines or certain sprinklered conditions per 1019.3)", "C": "Only one story", "D": "Only in single-family homes"}'::jsonb, 'B', 'IBC 1019.3 generally permits floor openings containing exit access stairways/ramps to connect not more than two stories without enclosure (including mezzanines and certain limited conditions). Connections of more than two stories require enclosure in a shaft (Section 713) or qualification as an interior exit stairway unless specific exceptions apply (atriums under 404, or limited sprinklered occupancy conditions). The two-story limit is the core rule.', 'IBC 1019.3', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-10-means-of-egress', 'avancado', true, 'Confirmed exit access stairways generally limited to connecting 2 stories unless enclosed/exception per IBC 1019.3.'),
  ('ibc-173', 'IBC', 'exit-discharge', 'Per IBC Section 1028.1, the exit discharge is the portion of the means of egress between the termination of an exit and a public way. What fraction of the number and capacity of exits is generally permitted to discharge through an interior element (such as a lobby) on the level of exit discharge?', '{"A": "100 percent", "B": "Not more than 50 percent of the number and capacity of the exits", "C": "Not more than 25 percent", "D": "None; all exits must discharge directly to the exterior"}'::jsonb, 'B', 'IBC 1028.1 requires exits to discharge directly to the exterior/public way, but exception 1 (the lobby / level-of-exit-discharge exception) permits not more than 50 percent of the number and capacity of exits to discharge through an interior egress element such as a lobby or vestibule on the level of exit discharge, provided the level is sprinklered, the path is unobstructed and identifiable, and separation conditions are met.', 'IBC 1028.1', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-10-means-of-egress', 'avancado', true, 'Confirmed 50% exit discharge through lobby/level-of-discharge exception per IBC 1028.1, exception 1 (2018/2021).'),
  ('ibc-174', 'IBC', 'horizontal-exits', 'IBC Section 1026 permits horizontal exits. What is the maximum percentage of the total required number of exits and exit capacity that horizontal exits are generally permitted to provide?', '{"A": "100 percent in all occupancies", "B": "Not more than one-half (50 percent), except up to two-thirds in Group I-2 and up to 100 percent in Group I-3", "C": "Not more than 25 percent", "D": "Horizontal exits are not permitted in the IBC"}'::jsonb, 'B', 'IBC 1026.1 permits horizontal exits to comprise not more than one-half of the total number of exits or the total required exit minimum width/capacity from any building or floor. Exceptions allow horizontal exits to provide up to two-thirds in Group I-2 and up to 100 percent in Group I-3 (institutional/detention), where evacuation by relocation to an adjacent compartment is the design strategy.', 'IBC 1026.1', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-10-means-of-egress', 'avancado', true, 'Confirmed horizontal exits limited to 50% generally, 2/3 in I-2, 100% in I-3 per IBC 1026.1.'),
  ('ibc-175', 'IBC', 'horizontal-exits', 'Per IBC Section 1026.2, the separation forming a horizontal exit (a fire wall or fire barrier) must have what minimum fire-resistance rating?', '{"A": "1 hour", "B": "2 hours", "C": "3 hours", "D": "No rating is required"}'::jsonb, 'B', 'IBC 1026.2 requires that a horizontal exit be provided by a fire wall complying with Section 706 or, where the horizontal exit is on a single floor, a fire barrier complying with Section 707, in both cases having a fire-resistance rating of not less than 2 hours. The separation must be continuous and the area on each side must serve as a refuge area sized per 1026.4.', 'IBC 1026.2', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-10-means-of-egress', 'intermediario', true, 'Confirmed horizontal exit separation min 2-hour fire wall/fire barrier per IBC 1026.2.'),
  ('ibc-176', 'IBC', 'assembly-egress', 'IBC Section 1029 governs assembly seating and aisles. For rows of seating, what is the minimum clear width of the aisle accessway between rows (the clear horizontal space between the back of one row and the nearest projection of the row behind)?', '{"A": "Not less than 6 inches", "B": "Not less than 12 inches", "C": "Not less than 24 inches", "D": "Not less than 36 inches"}'::jsonb, 'B', 'IBC 1029.13.2.1 requires a minimum clear width of 12 inches for the aisle accessway between rows of seating (measured as the clear horizontal distance from the back of the row ahead to the nearest projection of the row behind), increasing by 0.3 inch for each additional seat beyond a base number where the row exceeds the permitted seats. This guarantees passage to reach an aisle.', 'IBC 1029.13.2.1', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-10-means-of-egress', 'avancado', true, 'Confirmed 12 in minimum clear width for aisle accessway between rows per IBC 1029.13.2.1, plus 0.3 in/seat increase.'),
  ('ibc-177', 'IBC', 'assembly-egress', 'Per IBC Section 1029.14.2, aisle stairs in assembly seating may use risers steeper than ordinary stairs to accommodate sightlines. What is the maximum riser height permitted for assembly aisle stairs?', '{"A": "7 inches", "B": "8 inches", "C": "9 inches", "D": "There is no maximum for assembly aisle stairs"}'::jsonb, 'C', 'IBC 1029.14.2 permits aisle stair risers a maximum of 9 inches and a minimum of 4 inches to accommodate sightlines in sloped seating. Within any flight the riser heights must be uniform, except that nonuniform risers required for sightlines are permitted only under controlled conditions with specific marking and lighting. The 9-inch maximum is the key figure that distinguishes assembly aisle stairs from the standard 7-inch egress stair riser.', 'IBC 1029.14.2', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-10-means-of-egress', 'avancado', true, 'Confirmed assembly aisle stair riser max 9 in / min 4 in per IBC 1029.14.2 (2018/2021), with uniformity/sightline conditions.'),
  ('ibc-178', 'IBC', 'common-path-egress', 'IBC Section 1006.2.1 limits the common path of egress travel. In a sprinklered Group B occupancy, what is the typical maximum common path of egress travel?', '{"A": "25 feet", "B": "75 feet", "C": "100 feet", "D": "250 feet"}'::jsonb, 'C', 'Per IBC Table 1006.2.1, the common path of egress travel for Group B (along with A, E, F, M, S, U) is limited to 75 feet, increased to 100 feet where the building is equipped throughout with an automatic sprinkler system and the occupant load of the space is within the table limits. The common path limit ensures occupants quickly reach a point with a choice of two exit directions.', 'IBC 1006.2.1; Table 1006.2.1', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-10-means-of-egress', 'avancado', true, 'Confirmed Group B common path 75 ft non-sprinklered / 100 ft sprinklered per IBC Table 1006.2.1 (2018/2021).'),
  ('ibc-179', 'IBC', 'common-path-egress', 'Per IBC Table 1006.2.1, a space is permitted a single exit/exit access doorway when the occupant load is within table limits. For Group B, F, M, S, and U occupancies, what is the maximum occupant load permitted with a single exit?', '{"A": "10", "B": "29", "C": "49", "D": "300"}'::jsonb, 'C', 'IBC Table 1006.2.1 sets the maximum occupant load for spaces with one exit/exit access doorway at 49 occupants for Group B, F, M, S, and U (and others), 29 for higher-hazard groups, and 10 for certain H occupancies, each subject to the listed maximum common path of travel. Above these occupant loads, at least two exits/exit access doorways are required.', 'IBC 1006.2.1; Table 1006.2.1', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-10-means-of-egress', 'avancado', true, 'Confirmed single-exit OL limit 49 for B/F/M/S/U, 29 and 10 for higher-hazard groups, per IBC Table 1006.2.1.'),
  ('ibc-180', 'IBC', 'sprinkler-systems', 'Per IBC Section 903.3.1.1, where a building is required to be equipped throughout with an automatic sprinkler system, which standard governs the design and how are small concealed spaces and closets treated?', '{"A": "NFPA 13; full coverage is required, and limited omissions (such as certain small closets or concealed spaces) are permitted only where NFPA 13 expressly allows", "B": "NFPA 13D; only living areas need coverage", "C": "NFPA 72; only detection is required", "D": "No standard; the designer chooses freely"}'::jsonb, 'A', 'IBC 903.3.1.1 specifies that where sprinklers are required throughout, the system must be designed and installed in accordance with NFPA 13. Throughout means full coverage; specific limited omissions (e.g., small closets in dwelling units, certain electrical or concealed spaces) are permitted only where NFPA 13 itself expressly allows the omission. The designer cannot freely omit heads.', 'IBC 903.3.1.1; NFPA 13', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-9-fire-protection-and-life-safety-systems', 'intermediario', true, 'Confirmed NFPA 13 governs throughout systems per IBC 903.3.1.1; omissions only per NFPA 13 allowances.'),
  ('ibc-186', 'IBC', 'high-rise', 'Under IBC Section 403, a building is classified as a high-rise building requiring the special provisions of that section when it has an occupied floor located what distance above the lowest level of fire department vehicle access?', '{"A": "More than 55 feet", "B": "More than 60 feet", "C": "More than 75 feet", "D": "More than 120 feet"}'::jsonb, 'C', 'IBC defines a high-rise building (Section 202 / scoping in 403.1) as a building with an occupied floor more than 75 feet above the lowest level of fire department vehicle access. The 75-foot threshold triggers the additional protection requirements of Section 403, including increased sprinkler reliability, smokeproof exit enclosures, emergency power, and a fire command center.', 'IBC 403.1; 202 (definition)', 'https://up.codes/s/high-rise-buildings', 'iniciante', true, '75-foot occupied-floor threshold confirmed for high-rise classification (IBC 2015/2021).'),
  ('ibc-187', 'IBC', 'high-rise', 'Per IBC Section 403.6.1, a fire service access elevator must be provided in high-rise buildings having an occupied floor more than what height above the lowest level of fire department vehicle access?', '{"A": "75 feet", "B": "100 feet", "C": "120 feet", "D": "420 feet"}'::jsonb, 'C', 'IBC 403.6.1 requires not fewer than two fire service access elevators (or all elevators, if fewer than two) where the building has an occupied floor more than 120 feet above the lowest level of fire department vehicle access. These elevators comply with Section 3007 and are intended to let firefighters reach upper floors without climbing stairs.', 'IBC 403.6.1; 3007', 'https://up.codes/viewer/massachusetts/ibc-2015/chapter/30/elevators-and-conveying-systems', 'intermediario', true, 'Fire service access elevator triggered at 120 ft occupied floor per 403.6.1 (IBC 2015).'),
  ('ibc-188', 'IBC', 'high-rise', 'In a high-rise building over 420 feet in building height, IBC Section 403 requires which of the following additional structural/fire measures beyond the baseline high-rise provisions?', '{"A": "A second, redundant fire pump and water supply (riser redundancy) and enhanced structural fire resistance", "B": "Elimination of the standpipe system", "C": "A reduction in required sprinkler coverage", "D": "Removal of the fire command center"}'::jsonb, 'A', 'For buildings exceeding 420 feet, IBC 403 adds requirements such as redundant water supply risers/fire pumps and increased fire-resistance ratings (structural frame protection). The 420-foot threshold reflects very tall buildings where additional redundancy is warranted; lower high-rises (over 75 feet) get the baseline package.', 'IBC 403.2.1.1; 403.3.1', 'https://up.codes/viewer/massachusetts/ibc-2015/chapter/4/special-detailed-requirements-based-on-use-and-occupancy', 'avancado', true, '420-foot threshold confirmed for riser redundancy and enhanced fire resistance in Section 403 (IBC 2015).'),
  ('ibc-189', 'IBC', 'covered-mall', 'Under IBC Section 402, a covered mall building is limited to how many stories above grade plane and floor levels at any point (for the special mall provisions to apply)?', '{"A": "Two stories / two floor levels", "B": "Three stories / three floor levels", "C": "Four stories / four floor levels", "D": "Unlimited stories"}'::jsonb, 'B', 'IBC 402.1 limits a covered mall building (and anchor buildings as governed) such that the mall does not exceed three floor levels at any point and is not more than three stories above grade plane. Beyond these limits the building cannot use the covered mall provisions and is regulated by the general code.', 'IBC 402.1', 'https://up.codes/viewer/massachusetts/ibc-2015/chapter/4/special-detailed-requirements-based-on-use-and-occupancy', 'intermediario', true, 'Three-story / three-floor-level limit confirmed in 402.1 (IBC 2015).'),
  ('ibc-190', 'IBC', 'covered-mall', 'In a covered mall building, IBC Section 402 establishes a maximum travel distance within a tenant space to an exit or to the mall (which then serves as a pedestrian way) of how many feet?', '{"A": "100 feet", "B": "150 feet", "C": "200 feet", "D": "250 feet"}'::jsonb, 'C', 'IBC 402.8.5 permits a travel distance of up to 200 feet within the mall and tenant spaces in a covered mall building (a longer distance than the general occupancy travel limits) because the mall is treated as a controlled pedestrian way with smoke control and sprinklers throughout.', 'IBC 402.8.5', 'https://up.codes/viewer/massachusetts/ibc-2015/chapter/4/special-detailed-requirements-based-on-use-and-occupancy', 'avancado', true, '200-foot travel distance confirmed for covered mall buildings, Section 402.8.5 (IBC 2015).'),
  ('ibc-191', 'IBC', 'atrium', 'IBC Section 404 generally requires that an atrium be separated from adjacent spaces by a fire barrier of what minimum fire-resistance rating?', '{"A": "No separation is ever required", "B": "1-hour fire barrier", "C": "2-hour fire barrier", "D": "3-hour fire wall"}'::jsonb, 'B', 'IBC 404.6 requires atrium spaces to be separated from adjacent spaces by a 1-hour fire barrier (or horizontal assembly). Exceptions allow a glass-wall smoke partition system or allow up to three floors to be open to the atrium without the barrier where the smoke control and sprinkler provisions of 404 are met.', 'IBC 404.6', 'https://up.codes/viewer/massachusetts/ibc-2015/chapter/4/special-detailed-requirements-based-on-use-and-occupancy', 'intermediario', true, '1-hour fire barrier for atrium separation confirmed, Section 404.6 (IBC 2015).'),
  ('ibc-192', 'IBC', 'atrium', 'Which fire protection feature does IBC Section 404 require throughout a building containing an atrium?', '{"A": "Only standpipes", "B": "An automatic sprinkler system throughout the building", "C": "Only manual fire alarm pull stations", "D": "No special systems beyond the base occupancy"}'::jsonb, 'B', 'IBC 404.3 requires an approved automatic sprinkler system throughout the entire building that contains an atrium (with a limited exception where the atrium ceiling is more than 55 feet above the floor). Section 404.5 also requires a smoke control system except where the atrium connects only two stories.', 'IBC 404.3; 404.5', 'https://up.codes/viewer/massachusetts/ibc-2015/chapter/4/special-detailed-requirements-based-on-use-and-occupancy', 'intermediario', true, 'Building-wide sprinkler requirement confirmed for atriums, Section 404.3 (IBC 2015).'),
  ('ibc-193', 'IBC', 'atrium', 'Per IBC Section 404, a smoke control system is required for an atrium EXCEPT when the atrium connects only how many stories?', '{"A": "Two stories", "B": "Three stories", "C": "Four stories", "D": "Smoke control is never required"}'::jsonb, 'A', 'IBC 404.5 requires an engineered smoke control system in accordance with Section 909 for atriums, with an exception where the atrium connects only two stories. Connecting three or more stories triggers the smoke control requirement.', 'IBC 404.5', 'https://up.codes/viewer/massachusetts/ibc-2015/chapter/4/special-detailed-requirements-based-on-use-and-occupancy', 'avancado', true, 'Two-story smoke control exception confirmed, Section 404.5 (IBC 2015).'),
  ('ibc-194', 'IBC', 'underground-buildings', 'IBC Section 405 special provisions for underground buildings apply where the floor surface used for human occupancy is located how far below the lowest level of exit discharge?', '{"A": "More than 15 feet", "B": "More than 20 feet", "C": "More than 30 feet", "D": "More than 50 feet"}'::jsonb, 'C', 'IBC 405.1 applies the underground building provisions to building spaces with a floor used for human occupancy more than 30 feet below the lowest level of exit discharge. These spaces require compartmentation, smoke control, automatic sprinklers, and standby/emergency power.', 'IBC 405.1', 'https://up.codes/viewer/massachusetts/ibc-2015/chapter/4/special-detailed-requirements-based-on-use-and-occupancy', 'intermediario', true, '30-foot-below-exit-discharge threshold confirmed for underground buildings, Section 405.1 (IBC 2015).'),
  ('ibc-195', 'IBC', 'underground-buildings', 'Where an underground building under IBC Section 405 has occupied floor levels more than 30 feet below the lowest level of exit discharge, the code requires those levels to be divided into a minimum of how many smoke compartments?', '{"A": "One compartment (no division)", "B": "Two compartments of approximately equal size", "C": "Three compartments", "D": "Four compartments"}'::jsonb, 'B', 'IBC 405.4.2 requires that the levels more than 30 feet below the lowest level of exit discharge be divided into a minimum of two smoke compartments of approximately equal size. The compartmentation lets occupants move horizontally to a protected area away from the fire.', 'IBC 405.4.2', 'https://up.codes/viewer/massachusetts/ibc-2015/chapter/4/special-detailed-requirements-based-on-use-and-occupancy', 'avancado', true, 'Two-smoke-compartment compartmentation confirmed for underground buildings, Section 405.4.2 (IBC 2015).'),
  ('ibc-196', 'IBC', 'motor-vehicle-occupancies', 'Under IBC Section 406, an open parking garage is distinguished from an enclosed parking garage primarily by which characteristic?', '{"A": "It is fully sprinklered", "B": "It has uniformly distributed openings in the exterior walls for natural ventilation meeting the area requirements", "C": "It has fewer than 10 parking spaces", "D": "It uses mechanical ventilation only"}'::jsonb, 'B', 'IBC 406.5 defines open parking garages by required natural ventilation: exterior openings distributed along at least two sides, with minimum aggregate opening area (generally not less than 20 percent of the total perimeter wall area, openings on not less than 40 percent of the perimeter). Enclosed garages (406.6) lack these openings and require mechanical ventilation per the mechanical code.', 'IBC 406.5; 406.6', 'https://up.codes/viewer/massachusetts/ibc-2015/chapter/4/special-detailed-requirements-based-on-use-and-occupancy', 'intermediario', true, 'Open vs enclosed parking garage distinguished by natural ventilation openings, Section 406.5/406.6 (IBC 2015).'),
  ('ibc-197', 'IBC', 'institutional-i2', 'In a Group I-2 occupancy (such as a hospital or nursing home), IBC Section 407 requires that each smoke compartment containing sleeping rooms not exceed what maximum area?', '{"A": "10,000 square feet", "B": "22,500 square feet", "C": "40,000 square feet", "D": "50,000 square feet"}'::jsonb, 'B', 'IBC 407.5 requires Group I-2 occupancies to be divided into smoke compartments, each not exceeding 22,500 square feet, with travel distance to a smoke barrier door not exceeding 200 feet. This supports the defend-in-place strategy for patients who cannot self-evacuate.', 'IBC 407.5', 'https://up.codes/viewer/massachusetts/ibc-2015/chapter/4/special-detailed-requirements-based-on-use-and-occupancy', 'avancado', true, '22,500 sq ft smoke compartment limit confirmed for Group I-2, Section 407.5 (IBC 2015).'),
  ('ibc-198', 'IBC', 'institutional-i3', 'IBC establishes five occupancy conditions for Group I-3 (detention and correctional). These conditions are based primarily on what?', '{"A": "The number of inmates housed", "B": "The degree of restraint and the ability of occupants to evacuate (e.g., free movement vs. locked/restrained)", "C": "The construction type only", "D": "The presence of a sprinkler system"}'::jsonb, 'B', 'IBC 308.4 divides Group I-3 into Conditions 1 through 5 based on the degree to which occupants are restrained and their ability to respond to a fire and exit. Condition 1 allows free egress; Condition 5 has the highest restraint with remote-controlled locks. These conditions drive the locking, smoke compartment, and remote-release requirements of Section 408.', 'IBC 308.4 (I-3 conditions); 408.1', 'https://up.codes/viewer/massachusetts/ibc-2015/chapter/4/special-detailed-requirements-based-on-use-and-occupancy', 'intermediario', true, 'Group I-3 occupancy conditions based on restraint/egress ability confirmed, Section 308.4/408 (IBC 2015).'),
  ('ibc-199', 'IBC', 'stages-platforms', 'Under IBC Section 410, what is the dividing dimension that distinguishes a ''stage'' from a ''platform'' (which carries the proscenium and stage-specific requirements)?', '{"A": "Stage height (floor to roof/gridiron) greater than 50 feet", "B": "Stage area greater than 500 square feet", "C": "More than 50 performers", "D": "Any raised area more than 12 inches high"}'::jsonb, 'A', 'IBC 410.2 defines a stage by its height: where the space above the performance area exceeds 50 feet measured from the lowest point on the stage floor to the highest point of the roof or floor deck above. Stages over 50 feet require additional protection such as a proscenium wall and fire curtain (410.3.4); below that they may be regulated as platforms.', 'IBC 410.2; 410.3.4', 'https://up.codes/viewer/massachusetts/ibc-2015/chapter/4/special-detailed-requirements-based-on-use-and-occupancy', 'avancado', true, '50-foot stage height threshold confirmed in Section 410.2 (IBC 2015).'),
  ('ibc-200', 'IBC', 'special-amusement', 'Per IBC Section 411, a special amusement building (such as a haunted house or enclosed dark ride) is required to have which feature regardless of occupant load?', '{"A": "Only exit signs", "B": "An automatic sprinkler system and an automatic smoke detection system tied to the alarm/lighting", "C": "Open-air ventilation only", "D": "A minimum of two stories"}'::jsonb, 'B', 'IBC 411 requires special amusement buildings, where the means of egress is not readily apparent or is intentionally confounded (low light, sound, special effects), to be equipped throughout with an automatic sprinkler system and an automatic smoke detection system. Actuation increases illumination and stops conflicting sounds/visual distractions so occupants can find exits.', 'IBC 411.4; 411.5', 'https://up.codes/viewer/massachusetts/ibc-2015/chapter/4/special-detailed-requirements-based-on-use-and-occupancy', 'intermediario', true, 'Sprinkler + smoke detection requirement for special amusement buildings confirmed, Section 411.4/411.5 (IBC 2015).'),
  ('ibc-201', 'IBC', 'high-hazard-h', 'Under IBC Section 415, Group H high-hazard occupancies storing or using hazardous materials in excess of the maximum allowable quantities (MAQ) are subdivided into how many H subdivisions?', '{"A": "Two (H-1 and H-2)", "B": "Three (H-1 through H-3)", "C": "Five (H-1 through H-5)", "D": "Seven (H-1 through H-7)"}'::jsonb, 'C', 'Group H is divided into five subdivisions: H-1 (detonation hazard), H-2 (deflagration/accelerated burning), H-3 (readily supports combustion / physical hazard), H-4 (health hazards), and H-5 (semiconductor fabrication / HPM facilities). Section 415 provides the detailed construction, control area, and spill control requirements for each.', 'IBC 415.1; 307.1; 415.11 (H-5)', 'https://up.codes/viewer/massachusetts/ibc-2015/chapter/4/special-detailed-requirements-based-on-use-and-occupancy', 'intermediario', true, 'Five Group H subdivisions (H-1 through H-5) confirmed, Section 415/307 (IBC 2015).'),
  ('ibc-202', 'IBC', 'high-hazard-h', 'IBC permits hazardous materials below the maximum allowable quantity (MAQ) to be stored in a non-H occupancy by dividing the building into ''control areas.'' At the first story above grade, what is the maximum number of control areas permitted (before further reduction at upper stories)?', '{"A": "1 control area", "B": "2 control areas", "C": "4 control areas", "D": "8 control areas"}'::jsonb, 'C', 'IBC Table 414.2.2 allows a maximum of four control areas per floor at the first story above grade plane, each holding up to the MAQ. The percentage of MAQ and the number of allowable control areas decrease at upper and lower stories (e.g., 75 percent / 3 areas at the second story), reflecting reduced firefighting access with height.', 'IBC 414.2.2; Table 414.2.2', 'https://up.codes/viewer/massachusetts/ibc-2015/chapter/4/special-detailed-requirements-based-on-use-and-occupancy', 'avancado', true, 'Four control areas maximum at first story above grade confirmed, Table 414.2.2 (IBC 2015).'),
  ('ibc-203', 'IBC', 'flammable-finishes', 'IBC Section 416 (application of flammable finishes) applies to which type of operation?', '{"A": "Routine office painting with brushes", "B": "Spray application of flammable or combustible finishing materials (spray booths and spray rooms)", "C": "Installation of drywall", "D": "Pouring concrete slabs"}'::jsonb, 'B', 'IBC 416 regulates the spray application of flammable and combustible finishing materials, requiring spray rooms or spray booths constructed of noncombustible materials, with the required fire-resistance separation, ventilation, and interlocks. It addresses the high vapor/ignition risk of atomized finishes, not ordinary brush painting.', 'IBC 416.1; 416.2', 'https://up.codes/viewer/massachusetts/ibc-2015/chapter/4/special-detailed-requirements-based-on-use-and-occupancy', 'iniciante', true, 'Section 416 scope is spray application of flammable finishes (spray booths/rooms), confirmed (IBC 2015).'),
  ('ibc-204', 'IBC', 'interior-environment-ventilation', 'Where a space is naturally ventilated under IBC Section 1203, the minimum openable area of openings to the outdoors must be not less than what percentage of the floor area being ventilated?', '{"A": "2 percent", "B": "4 percent", "C": "5 percent", "D": "8 percent"}'::jsonb, 'B', 'IBC 1203.5.1 requires the openable area of openings to the outdoors to be not less than 4 percent of the floor area being ventilated when natural ventilation is used. (Natural light, by contrast, is governed by a separate glazing-area requirement of 8 percent under Section 1205.)', 'IBC 1203.5.1', 'https://up.codes/viewer/massachusetts/ibc-2015/chapter/12/interior-environment', 'intermediario', true, '4 percent openable area for natural ventilation confirmed, Section 1203.5.1 (IBC 2015).'),
  ('ibc-205', 'IBC', 'interior-environment-temperature', 'Under IBC Section 1204, interior occupied spaces served by a heating system must be capable of maintaining a minimum indoor temperature of what value, measured at a point 3 feet above the floor on the design heating day?', '{"A": "60 degrees F", "B": "65 degrees F", "C": "68 degrees F", "D": "72 degrees F"}'::jsonb, 'C', 'IBC 1204.1 requires interior spaces intended for human occupancy to be provided with heating capable of maintaining not less than 68 degrees F (20 degrees C) at a point 3 feet above the floor on the design heating day. Certain occupancies (F, H, S, U and process areas) are excepted.', 'IBC 1204.1', 'https://up.codes/viewer/massachusetts/ibc-2015/chapter/12/interior-environment', 'iniciante', true, '68 degrees F at 3 ft above floor confirmed, Section 1204.1 (IBC 2015).'),
  ('ibc-206', 'IBC', 'interior-environment-sound', 'IBC sound transmission provisions require walls, partitions, and floor-ceiling assemblies separating dwelling units (or sleeping units) from each other and from public/service areas to provide an airborne sound transmission class (STC) of not less than what value (laboratory tested)?', '{"A": "STC 35", "B": "STC 45", "C": "STC 50", "D": "STC 60"}'::jsonb, 'C', 'The interior environment chapter requires a minimum STC of 50 (or not less than 45 if field tested) for assemblies separating dwelling/sleeping units from adjacent units and public/service areas. In the IBC 2015 (and the Massachusetts 9th edition base) this is Section 1207.2; in the 2018/2021 IBC it is Section 1206.2. The companion impact insulation class (IIC) requirement is likewise 50 (45 field tested).', 'IBC 1207.2 (2015) / 1206.2 (2018/2021)', 'https://up.codes/viewer/massachusetts/ibc-2015/chapter/12/interior-environment', 'intermediario', true, 'STC 50 (45 field) airborne sound confirmed, Section 1207.2 (IBC 2015); renumbered 1206.2 in later editions.'),
  ('ibc-207', 'IBC', 'interior-environment-sound', 'For structure-borne (impact) sound, IBC requires floor-ceiling assemblies separating dwelling units to provide an impact insulation class (IIC) of not less than what value when laboratory tested?', '{"A": "IIC 40", "B": "IIC 45", "C": "IIC 50", "D": "IIC 55"}'::jsonb, 'C', 'Floor-ceiling assemblies separating dwelling/sleeping units must achieve an IIC of not less than 50 (or 45 if field tested), matching the airborne STC 50 requirement. This is found at Section 1207.3 in the IBC 2015 (Massachusetts base) and renumbered to 1206.3 in the 2018/2021 IBC.', 'IBC 1207.3 (2015) / 1206.3 (2018/2021)', 'https://up.codes/viewer/massachusetts/ibc-2015/chapter/12/interior-environment', 'intermediario', true, 'IIC 50 (45 field) impact insulation confirmed, Section 1207.3 (IBC 2015).'),
  ('ibc-208', 'IBC', 'interior-environment-dimensions', 'Per IBC Section 1208, occupiable spaces, habitable spaces, and corridors must have a minimum ceiling height of how much?', '{"A": "7 feet 0 inches", "B": "7 feet 6 inches", "C": "8 feet 0 inches", "D": "6 feet 8 inches"}'::jsonb, 'B', 'IBC 1208.2 requires a minimum ceiling height of 7 feet 6 inches for occupiable spaces, habitable spaces, and corridors. (Bathrooms, toilet rooms, kitchens, storage rooms, and laundry rooms may have a reduced 7-foot ceiling.) Habitable rooms other than kitchens must also be at least 7 feet in any plan dimension per 1208.1.', 'IBC 1208.2; 1208.1', 'https://up.codes/viewer/massachusetts/ibc-2015/chapter/12/interior-environment', 'iniciante', true, '7 ft 6 in ceiling height confirmed, Section 1208.2 (IBC 2015).'),
  ('ibc-209', 'IBC', 'interior-environment-materials', 'Under IBC Section 1210 (toilet and bathroom requirements), walls within 2 feet of the front and sides of urinals and water closets must have a smooth, hard, nonabsorbent surface to what minimum height above the floor?', '{"A": "2 feet", "B": "4 feet", "C": "6 feet", "D": "8 feet"}'::jsonb, 'B', 'IBC 1210.2.2 requires that walls within 2 feet of the front and sides of urinals and water closets have a smooth, hard, nonabsorbent surface to a height of not less than 4 feet above the floor, and that such surface be of a type not adversely affected by moisture. Floors must likewise be smooth, hard, and nonabsorbent (1210.2.1).', 'IBC 1210.2.2; 1210.2.1', 'https://up.codes/viewer/massachusetts/ibc-2015/chapter/12/interior-environment', 'intermediario', true, 'Nonabsorbent wall surface to 4 ft height confirmed, Section 1210.2.2 (IBC 2015).'),
  ('ibc-210', 'IBC', 'interior-finish-trim', 'IBC limits combustible trim (excluding handrails and guardrails) to what maximum percentage of the aggregate wall and ceiling area of any room or space?', '{"A": "5 percent", "B": "10 percent", "C": "25 percent", "D": "50 percent"}'::jsonb, 'B', 'Under the interior finish provisions, combustible trim, other than handrails and guardrails, is limited to not more than 10 percent of the aggregate wall and ceiling areas of any room or space. This caps the amount of lower-rated combustible material used as decorative trim. The interior finish material classification itself is governed by Chapter 8, while Chapter 12 governs the overall interior environment.', 'IBC 806.5 (combustible trim); Chapter 12', 'https://up.codes/viewer/massachusetts/ibc-2015/chapter/8/interior-finishes', 'avancado', true, '10 percent combustible trim limit confirmed, Section 806.5 (IBC 2015).'),
  ('ibc-211', 'IBC', 'elevators-hoistway', 'Under IBC Section 3002, elevator hoistway enclosures must be constructed as shaft enclosures complying with which IBC section?', '{"A": "Section 705 (exterior walls)", "B": "Section 713 (shaft enclosures)", "C": "Section 1010 (doors)", "D": "Section 1607 (live loads)"}'::jsonb, 'B', 'IBC 3002.1 requires elevator, dumbwaiter, and other hoistway enclosures to be constructed as shaft enclosures complying with Section 713. This generally means a 2-hour fire-resistance-rated enclosure connecting four or more stories and 1-hour for fewer stories, with rated hoistway doors.', 'IBC 3002.1; 713', 'https://up.codes/viewer/massachusetts/ibc-2015/chapter/30/elevators-and-conveying-systems', 'iniciante', true, 'Hoistway enclosures comply with Section 713 shaft enclosures, confirmed 3002.1 (IBC 2015).'),
  ('ibc-212', 'IBC', 'elevators-stretcher', 'IBC Section 3002.4 requires that buildings with how many or more stories above or below grade plane provide at least one elevator car sized to accommodate an ambulance stretcher 24 inches by 84 inches?', '{"A": "2 or more stories", "B": "3 or more stories", "C": "4 or more stories", "D": "6 or more stories"}'::jsonb, 'C', 'IBC 3002.4 requires buildings four or more stories above or below grade plane to have not fewer than one elevator able to accommodate an ambulance stretcher 24 inches by 84 inches in its horizontal open position, identified by the Star of Life symbol. This ensures emergency medical access to all served floors.', 'IBC 3002.4', 'https://up.codes/viewer/massachusetts/ibc-2015/chapter/30/elevators-and-conveying-systems', 'intermediario', true, '4-or-more-story stretcher elevator (24 by 84 in) confirmed, Section 3002.4 (IBC 2015).'),
  ('ibc-213', 'IBC', 'elevators-fire-service', 'IBC Section 3007 requires the fire service access elevator lobby to have a minimum floor area of not less than 150 square feet, with a least dimension of not less than how many feet?', '{"A": "6 feet", "B": "8 feet", "C": "10 feet", "D": "12 feet"}'::jsonb, 'B', 'IBC 3007.6 requires each fire service access elevator lobby to be not less than 150 square feet in area with a minimum dimension of 8 feet. The lobby is enclosed by fire partitions and serves as a protected staging area for firefighters.', 'IBC 3007.6', 'https://up.codes/viewer/massachusetts/ibc-2015/chapter/30/elevators-and-conveying-systems', 'avancado', true, '150 sq ft / 8 ft minimum lobby dimension confirmed, Section 3007.6 (IBC 2015).'),
  ('ibc-214', 'IBC', 'elevators-fire-service', 'A fire service access elevator under IBC Section 3007 requires the building to be provided with what fire protection feature?', '{"A": "Standpipes only, no sprinklers", "B": "An automatic sprinkler system throughout (except where prohibited in hoistway and machine room)", "C": "No automatic suppression", "D": "Only portable fire extinguishers in the lobby"}'::jsonb, 'B', 'IBC 3007.2 requires the building be protected throughout by an approved automatic sprinkler system, except that sprinklers are not permitted in the fire service access elevator machine room, machinery space, control space, or hoistway (3007.2.1) to protect the elevator equipment. The water-protected occupancy plus a protected, smoke-resistant lobby is what makes the elevator usable for firefighting.', 'IBC 3007.2; 3007.2.1', 'https://up.codes/viewer/massachusetts/ibc-2015/chapter/30/elevators-and-conveying-systems', 'intermediario', true, 'Building-wide sprinklers (excluded from FSAE machine room/hoistway) confirmed, Section 3007.2 (IBC 2015).'),
  ('ibc-215', 'IBC', 'elevators-evacuation', 'Where occupant evacuation elevators are provided under IBC Section 3008, they must be installed in relation to the required egress stairways in what way?', '{"A": "They replace the required exit stairways", "B": "They are provided in addition to the required number and capacity of exit stairways", "C": "They eliminate the need for an area of refuge", "D": "They eliminate sprinkler requirements"}'::jsonb, 'B', 'Occupant evacuation elevators (IBC 3008) are a permitted enhancement; they do not reduce the required number, capacity, or arrangement of exit stairways. The building must still provide fully compliant exit stairways, and the evacuation elevators supplement egress with protected lobbies, standby power, and water/smoke protection.', 'IBC 3008.1', 'https://up.codes/viewer/massachusetts/ibc-2015/chapter/30/elevators-and-conveying-systems', 'avancado', true, 'Occupant evacuation elevators do not reduce required exit stairways, confirmed Section 3008 (IBC 2018/2021; reserved in some 2015 printings).'),
  ('ibc-216', 'IBC', 'elevators-machine-room', 'Under IBC Chapter 30, an elevator machine room or machinery space generally must NOT be used for which purpose?', '{"A": "Housing the elevator controllers and drive equipment", "B": "Storage of building maintenance supplies or other non-elevator equipment/uses", "C": "Access by authorized elevator personnel", "D": "Containing the elevator hoist machine"}'::jsonb, 'B', 'IBC 3005.4 prohibits elevator machine rooms, machinery spaces, control rooms, and control spaces from being used for purposes other than for the elevator equipment; building storage and unrelated equipment are not permitted. The rooms must also be enclosed and have the required fire-resistance and access provisions.', 'IBC 3005.4', 'https://up.codes/viewer/massachusetts/ibc-2015/chapter/30/elevators-and-conveying-systems', 'intermediario', true, 'Machine rooms restricted to elevator use only confirmed, Section 3005.4 (IBC 2015).'),
  ('ibc-217', 'IBC', 'accessible-route', 'Under IBC Section 1104, an accessible route is required to connect which of the following?', '{"A": "Only the main entrance to the elevator", "B": "Accessible building or facility entrances with all accessible spaces and elements within the building or facility", "C": "Only parking to the lobby", "D": "Only floors served by an elevator"}'::jsonb, 'B', 'IBC 1104.1 requires accessible routes to connect accessible building/facility entrances with all accessible spaces and elements within the building or facility that are otherwise connected by a circulation path. Section 1104.4 requires that multistory buildings provide an accessible route to all stories (with limited exceptions for small buildings and certain non-occupied levels).', 'IBC 1104.1; 1104.4', 'https://up.codes/viewer/massachusetts/ibc-2015/chapter/11/accessibility', 'iniciante', true, 'Accessible route connectivity scoping confirmed, Section 1104.1 (IBC 2015).'),
  ('ibc-218', 'IBC', 'accessible-entrances', 'Per IBC Section 1105, at least what percentage of public entrances to a building must be accessible?', '{"A": "50 percent", "B": "60 percent", "C": "75 percent", "D": "100 percent"}'::jsonb, 'B', 'IBC 1105.1.1 requires that not fewer than 60 percent of all public entrances be accessible. Additional scoping in Section 1105 also requires accessible entrances where they serve parking, transportation facilities, tunnels/elevated walkways, and tenant spaces.', 'IBC 1105.1.1', 'https://up.codes/viewer/massachusetts/ibc-2015/chapter/11/accessibility', 'intermediario', true, '60 percent accessible public entrances confirmed, Section 1105.1.1 (IBC 2015).'),
  ('ibc-219', 'IBC', 'accessible-parking', 'Under IBC Table 1106.1, a parking facility with a total of 1 to 25 spaces must provide a minimum of how many accessible parking spaces?', '{"A": "0", "B": "1", "C": "2", "D": "3"}'::jsonb, 'B', 'IBC Table 1106.1 requires 1 accessible space for lots of 1 to 25 total spaces, 2 for 26 to 50, 3 for 51 to 75, 4 for 76 to 100, and increasing thereafter. The accessible spaces must be on the shortest accessible route to an accessible entrance.', 'IBC 1106.1; Table 1106.1', 'https://up.codes/viewer/massachusetts/ibc-2015/chapter/11/accessibility', 'intermediario', true, '1 accessible space for 1-25 total spaces confirmed, Table 1106.1 (IBC 2015).'),
  ('ibc-220', 'IBC', 'accessible-parking', 'IBC Section 1106 requires that at least one in every how many accessible parking spaces (but not fewer than one) be van accessible?', '{"A": "1 in every 4", "B": "1 in every 6", "C": "1 in every 8", "D": "1 in every 10"}'::jsonb, 'B', 'IBC 1106.5 requires that for every six or fraction of six accessible parking spaces, at least one must be a van-accessible space (served by the wider access aisle and adequate vertical clearance). At minimum, one van-accessible space is required wherever accessible parking is provided.', 'IBC 1106.5', 'https://up.codes/viewer/massachusetts/ibc-2015/chapter/11/accessibility', 'intermediario', true, '1-in-6 van-accessible ratio confirmed, Section 1106.5 (IBC 2015).'),
  ('ibc-221', 'IBC', 'accessible-units', 'Under IBC Section 1107, in a Group R-2 occupancy (e.g., apartments) containing more than 20 dwelling units, what is the minimum scoping for Accessible (Type A) units?', '{"A": "No Type A units are ever required", "B": "At least 2 percent, but not fewer than one, of the units must be Type A", "C": "10 percent of the units must be Type A", "D": "All units must be Type A"}'::jsonb, 'B', 'IBC 1107.6.2.2.1 requires that in Group R-2 occupancies with more than 20 dwelling or sleeping units, at least 2 percent, but not fewer than one, be Type A units. The remaining units in buildings with an elevator (or ground-floor units without one) are generally required to be Type B units per 1107.6.2.2.2.', 'IBC 1107.6.2.2.1', 'https://up.codes/viewer/massachusetts/ibc-2015/chapter/11/accessibility', 'avancado', true, '2 percent (min one) Type A units for R-2 over 20 units confirmed, Section 1107.6.2.2.1 (IBC 2015).'),
  ('ibc-222', 'IBC', 'accessible-signage', 'Per IBC Section 1111, which entrances/elements must be identified by the International Symbol of Accessibility (ISA)?', '{"A": "All entrances, accessible or not", "B": "Accessible parking spaces, accessible passenger loading zones, and accessible entrances when not all entrances are accessible", "C": "Only interior restrooms", "D": "Only the main building entrance"}'::jsonb, 'B', 'IBC 1111 requires the International Symbol of Accessibility at accessible parking spaces (1111.1), at accessible passenger loading zones, and at accessible entrances where not all entrances are accessible, plus directional signage at inaccessible entrances/toilet rooms pointing to the nearest accessible one. This guides users with disabilities to the compliant features.', 'IBC 1111.1; 1111.2', 'https://up.codes/viewer/massachusetts/ibc-2015/chapter/11/accessibility', 'intermediario', true, 'ISA signage scoping confirmed, Section 1111 (IBC 2015).'),
  ('ibc-223', 'IBC', 'encroachments', 'Under IBC Section 3202, an awning projecting from a building wall over a public right-of-way and located less than 8 feet above grade must maintain a vertical clearance of not less than how many feet?', '{"A": "6 feet", "B": "7 feet", "C": "8 feet", "D": "10 feet"}'::jsonb, 'B', 'IBC 3202.2.3 permits awnings to project into the public right-of-way provided a minimum vertical clearance of 7 feet is maintained from the sidewalk. Below-8-foot encroachments are otherwise tightly limited (steps and architectural features generally to 12 inches) to keep the pedestrian way clear.', 'IBC 3202.2.3; 3202.2', 'https://up.codes/viewer/massachusetts/ibc-2015/chapter/32/encroachments-into-the-public-right-of-way', 'intermediario', true, '7-foot minimum vertical clearance for awnings below 8 ft confirmed, Section 3202.2.3 (IBC 2015).'),
  ('ibc-224', 'IBC', 'encroachments', 'IBC Section 3202 limits below-grade structural footings of street walls (located not less than 8 feet below grade) to a maximum projection beyond the street lot line of how much?', '{"A": "4 inches", "B": "8 inches", "C": "12 inches", "D": "24 inches"}'::jsonb, 'C', 'IBC 3202.1 (Encroachments below grade) permits footings of street walls located not less than 8 feet below grade to project not more than 12 inches beyond the street lot line into the public right-of-way. This avoids conflicts with utilities and adjacent below-grade work.', 'IBC 3202.1', 'https://up.codes/viewer/massachusetts/ibc-2015/chapter/32/encroachments-into-the-public-right-of-way', 'avancado', true, '12-inch max footing projection below grade confirmed, Section 3202.1 (IBC 2015).'),
  ('ibc-225', 'IBC', 'encroachments', 'For encroachments above grade and 8 feet or more above the sidewalk under IBC Section 3202.3, windows, balconies, architectural features, and mechanical equipment may encroach how much for each additional 1 inch of clearance above 8 feet, up to a maximum encroachment?', '{"A": "1 inch per inch, maximum 4 feet", "B": "2 inches per inch, maximum 2 feet", "C": "1 inch per inch, maximum 10 feet", "D": "No encroachment is permitted above 8 feet"}'::jsonb, 'A', 'IBC 3202.3.2 permits 1 inch of encroachment for each additional 1 inch of clearance above 8 feet, with the maximum encroachment limited to 4 feet. This sliding scale lets higher features project farther while preserving headroom and a clear pedestrian zone below.', 'IBC 3202.3.2', 'https://up.codes/viewer/massachusetts/ibc-2015/chapter/32/encroachments-into-the-public-right-of-way', 'avancado', true, '1 inch per inch above 8 ft, max 4 ft encroachment confirmed, Section 3202.3.2 (IBC 2015).'),
  ('ibc-226', 'IBC', 'encroachments-pedestrian-walkway', 'An above-grade pedestrian walkway (skybridge) that encroaches over a public right-of-way under IBC Section 3202.3 must maintain a minimum vertical clearance over the sidewalk/roadway of how many feet?', '{"A": "8 feet", "B": "10 feet", "C": "12 feet", "D": "15 feet"}'::jsonb, 'D', 'IBC 3202.3.4 requires pedestrian walkways over a public right-of-way to provide a minimum vertical clearance of 15 feet. Awnings, marquees, and similar features with less than 15 feet of clearance are limited to two-thirds of the sidewalk width, while encroachments 15 feet or more above grade are generally unrestricted by the projection rules.', 'IBC 3202.3.4; 3202.3', 'https://up.codes/viewer/massachusetts/ibc-2015/chapter/32/encroachments-into-the-public-right-of-way', 'intermediario', true, '15-foot vertical clearance for pedestrian walkways confirmed, Section 3202.3.4 (IBC 2015).'),
  ('ibc-227', 'IBC', 'encroachments-temporary', 'Under IBC Section 3202.4, temporary encroachments (such as construction protection or seasonal features) into the public right-of-way are limited to a maximum projection of 3 feet or what fraction of the sidewalk width, whichever is less, while maintaining a minimum 7-foot clearance?', '{"A": "One-half the sidewalk width", "B": "One-third the sidewalk width", "C": "One-fourth the sidewalk width", "D": "The full sidewalk width"}'::jsonb, 'C', 'IBC 3202.4 limits temporary encroachments to a projection of 3 feet or one-fourth of the sidewalk width (whichever is less), maintaining at least 7 feet of clearance, and generally for the limited duration the building official approves. This keeps a usable pedestrian path during temporary work.', 'IBC 3202.4', 'https://up.codes/viewer/massachusetts/ibc-2015/chapter/32/encroachments-into-the-public-right-of-way', 'avancado', true, 'Temporary encroachment 3 ft or one-fourth sidewalk width, 7 ft clearance confirmed, Section 3202.4 (IBC 2015).'),
  ('ibc-228', 'IBC', 'covered-mall', 'IBC Section 402 requires a covered mall building (and its anchor buildings, as applicable) to be equipped throughout with which system?', '{"A": "Standpipes only", "B": "An automatic sprinkler system in accordance with Section 903.3.1.1", "C": "Natural ventilation only", "D": "Smoke vents in lieu of sprinklers"}'::jsonb, 'B', 'IBC 402.5 requires the covered mall building, including the mall and all tenant spaces, to be protected throughout by an automatic sprinkler system installed per Section 903.3.1.1, with the system designed so a portion can be shut off without affecting the rest. Sprinklers are foundational to the relaxed travel distances and large open mall concept.', 'IBC 402.5', 'https://up.codes/viewer/massachusetts/ibc-2015/chapter/4/special-detailed-requirements-based-on-use-and-occupancy', 'iniciante', true, 'Building-wide NFPA 13 sprinklers required for covered mall buildings confirmed, Section 402.5 (IBC 2015).'),
  ('ibc-229', 'IBC', 'institutional-i2', 'In a Group I-2 occupancy, IBC Section 407 limits the travel distance from any point in a smoke compartment to a smoke barrier door to a maximum of how many feet?', '{"A": "75 feet", "B": "150 feet", "C": "200 feet", "D": "250 feet"}'::jsonb, 'C', 'IBC 407.5 limits travel distance from any point in a Group I-2 smoke compartment to the door in a smoke barrier to 200 feet. Combined with the 22,500-square-foot maximum compartment size, this ensures patients can be relocated horizontally to an adjacent compartment quickly under the defend-in-place strategy.', 'IBC 407.5', 'https://up.codes/viewer/massachusetts/ibc-2015/chapter/4/special-detailed-requirements-based-on-use-and-occupancy', 'avancado', true, '200-foot travel distance to smoke barrier door in I-2 confirmed, Section 407.5 (IBC 2015).'),
  ('ibc-230', 'IBC', 'elevators-conveying', 'Under IBC Chapter 30, escalator floor openings (that are not within an enclosed shaft) connecting more than the permitted number of stories must be protected by which means where required?', '{"A": "Left completely unprotected in all cases", "B": "An approved power-operated automatic shutter or by sprinkler/draft-curtain protection where permitted", "C": "A 4-hour fire wall in all cases", "D": "Only a smoke detector with no physical protection"}'::jsonb, 'B', 'IBC 3004 and the related shaft enclosure provisions of Sections 712/713 require escalator and moving walk floor openings connecting more than the permitted number of stories to be enclosed, or protected by approved methods such as a power-operated automatic shutter, or by sprinkler/draft-curtain protection where specifically permitted for the occupancy. The goal is to limit vertical smoke and fire spread through the open well.', 'IBC 3004.2; 712.1.3.1', 'https://up.codes/viewer/massachusetts/ibc-2015/chapter/30/elevators-and-conveying-systems', 'intermediario', true, 'Escalator opening protection (shutter or sprinkler/draft-curtain methods) confirmed, Section 3004/712 (IBC 2015).'),
  ('ibc-001', 'IBC', 'egress', 'In a commercial building, an egress door serving a room is required to swing in the direction of egress travel when the occupant load served by that door is at least how many people?', '{"A": "30", "B": "50", "C": "75", "D": "100"}'::jsonb, 'B', 'Side-hinged swinging, pivoted, and balanced egress doors must swing in the direction of egress travel where serving a room or area with an occupant load of 50 or more, or where serving any Group H occupancy. Below 50 occupants the door may swing either way.', 'IBC 1010.1.2.1', 'https://up.codes/s/direction-of-swing', 'intermediario', true, 'Confirmed: occupant load of 50 or more (or Group H) triggers swing-in-direction-of-egress. 2021 IBC numbers it 1010.1.2.1; 50-person threshold stable across editions.'),
  ('ibc-002', 'IBC', 'egress', 'What is the minimum required ceiling height of a means of egress, measured above the finished floor?', '{"A": "6 feet 8 inches", "B": "7 feet", "C": "7 feet 6 inches", "D": "8 feet"}'::jsonb, 'C', 'The means of egress must have a ceiling height of not less than 7 feet 6 inches (2286 mm) above the finished floor. Protruding objects may extend below this where a minimum headroom of 80 inches is maintained over circulation paths, and no more than 50 percent of the ceiling area may be reduced by such objects.', 'IBC 1003.2', 'https://codes.iccsafe.org/content/IBC2021P2', 'iniciante', true, 'Confirmed 7 ft 6 in across 2018, 2021 and 2024 IBC Section 1003.2. Distinct from the 80-inch (6 ft 8 in) minimum door height of 1010.1.1.'),
  ('ibc-003', 'IBC', 'egress', 'Under the IBC, the minimum height of an egress door opening is:', '{"A": "78 inches", "B": "80 inches", "C": "84 inches", "D": "90 inches"}'::jsonb, 'B', 'Egress doors must provide a minimum clear height of 80 inches (the door leaf is typically 6 feet 8 inches / 80 inches tall). The minimum clear width of a single egress door leaf is 32 inches. Do not confuse the 80-inch door height with the 7-foot-6-inch egress ceiling height.', 'IBC 1010.1.1', 'https://codes.iccsafe.org/s/IBC2018/chapter-10-means-of-egress/IBC2018-Ch10-Sec1010.1.1', 'iniciante', true, 'Confirmed 80-inch minimum door height and 32-inch minimum clear width, IBC 1010.1.1.'),
  ('ibc-004', 'IBC', 'use-groups', 'A restaurant, tavern, or nightclub intended for the consumption of food and drink is classified under which IBC occupancy group?', '{"A": "Group A-1", "B": "Group A-2", "C": "Group A-3", "D": "Group B"}'::jsonb, 'B', 'Group A-2 covers assembly uses intended for food and/or drink consumption, including restaurants, cafeterias, banquet halls, taverns, bars, nightclubs, and casinos. A-1 is fixed-seating theaters, A-3 is worship/recreation/amusement, and Group B is business.', 'IBC 303.3', 'https://up.codes/viewer/general-services-administration/ibc-2024/chapter/3/occupancy-classification-and-use', 'iniciante', true, 'Confirmed A-2 = food/drink consumption assembly, Section 303.3 in 2021/2024 IBC.'),
  ('ibc-005', 'IBC', 'use-groups', 'An apartment building or non-transient boarding house where occupants are primarily permanent is classified as which residential occupancy group?', '{"A": "Group R-1", "B": "Group R-2", "C": "Group R-3", "D": "Group R-4"}'::jsonb, 'B', 'Group R-2 contains sleeping units or more than two dwelling units where occupants are primarily permanent, including apartment houses, dormitories, and non-transient boarding houses. R-1 is transient (hotels/motels), R-3 is one- and two-family permanent dwellings, and R-4 is residential care/assisted living for 6 to 16 persons.', 'IBC 310.3', 'https://up.codes/viewer/general-services-administration/ibc-2024/chapter/3/occupancy-classification-and-use', 'intermediario', true, 'Confirmed R-2 = apartments/permanent, Section 310.3 (2021/2024: R-1=310.2, R-2=310.3, R-3=310.4, R-4=310.5).'),
  ('ibc-006', 'IBC', 'use-groups', 'A residential occupancy that provides 24-hour custodial care for more than five but not more than 16 persons (such as an assisted-living group home) is classified as:', '{"A": "Group R-1", "B": "Group R-2", "C": "Group R-3", "D": "Group R-4"}'::jsonb, 'D', 'Group R-4 is a residential care/assisted-living facility housing more than five but not more than 16 persons (excluding staff) receiving custodial care. Facilities for five or fewer persons fall under R-3, and larger institutional care facilities are classified as Group I.', 'IBC 310.5', 'https://up.codes/viewer/general-services-administration/ibc-2024/chapter/3/occupancy-classification-and-use', 'intermediario', true, 'Confirmed R-4 = more than 5 but not more than 16 persons, custodial care, Section 310.5 (2021/2024).'),
  ('ibc-007', 'IBC', 'use-groups', 'A retail department store where merchandise is displayed and sold to the public is classified under which occupancy group?', '{"A": "Group B", "B": "Group M", "C": "Group S-1", "D": "Group A-3"}'::jsonb, 'B', 'Group M (Mercantile) covers buildings used for the display and sale of merchandise where the public has access, including department stores, retail stores, markets, and motor fuel-dispensing facilities. Group B is offices/professional services and Group S is storage.', 'IBC 309.1', 'https://up.codes/viewer/general-services-administration/ibc-2024/chapter/3/occupancy-classification-and-use', 'iniciante', true, 'Confirmed Group M mercantile = display and sale of merchandise, Section 309.1.'),
  ('ibc-008', 'IBC', 'use-groups', 'A high-hazard occupancy that involves materials presenting a detonation hazard, such as explosives, is classified as:', '{"A": "Group H-1", "B": "Group H-2", "C": "Group H-3", "D": "Group H-4"}'::jsonb, 'A', 'Group H-1 contains materials that present a detonation hazard (e.g., explosives, certain unstable reactives). H-2 = deflagration/accelerated burning hazard, H-3 = materials that readily support combustion, and H-4 = materials that are health hazards (corrosives, toxics).', 'IBC 307.3', 'https://up.codes/viewer/general-services-administration/ibc-2024/chapter/3/occupancy-classification-and-use', 'intermediario', true, 'Confirmed H-1 = detonation hazard, defined within Section 307.'),
  ('ibc-009', 'IBC', 'types-of-construction', 'In Type IV (Heavy Timber) construction, what is the minimum nominal dimension for solid sawn wood columns supporting floor loads?', '{"A": "6 inches by 6 inches", "B": "6 inches by 8 inches", "C": "8 inches by 8 inches", "D": "10 inches by 10 inches"}'::jsonb, 'C', 'In Heavy Timber (Type IV-HT) construction, wood columns supporting floor loads must be not less than 8 inches nominal in any dimension (8x8). Columns supporting roof loads only may be 6 inches nominal in the smaller dimension. These minimum sizes give heavy timber its inherent fire resistance.', 'IBC 602.4 / 2304.11', 'https://up.codes/s/type-iv', 'intermediario', true, 'Confirmed 8x8 nominal minimum for HT columns supporting floors (6 in. for roof-only). 2021 IBC split Type IV into IV-A/B/C/HT; the 8-inch HT column rule and 2304.11 heavy-timber sizing remain.'),
  ('ibc-010', 'IBC', 'types-of-construction', 'Which type of construction is characterized by exterior walls of noncombustible material and interior building elements of solid or laminated wood with no concealed spaces (Heavy Timber)?', '{"A": "Type II", "B": "Type III", "C": "Type IV", "D": "Type V"}'::jsonb, 'C', 'Type IV (Heavy Timber, HT) requires noncombustible exterior walls and interior elements of solid or laminated wood without concealed spaces, meeting minimum member dimensions. Type III has noncombustible exterior walls with combustible interior elements; Type V permits combustible materials throughout.', 'IBC 602.4', 'https://up.codes/s/type-iv', 'iniciante', true, 'Confirmed Type IV = Heavy Timber, noncombustible exterior walls + heavy timber interior, Section 602.4.'),
  ('ibc-011', 'IBC', 'permits', 'Which of the following work generally does NOT require a building permit under the IBC?', '{"A": "A one-story detached storage shed with a floor area of 120 square feet or less", "B": "A retaining wall 6 feet high measured from the bottom of the footing", "C": "A new commercial mezzanine", "D": "Replacement of a load-bearing wall"}'::jsonb, 'A', 'Section 105.2 exempts one-story detached accessory structures (tool/storage sheds, playhouses) not exceeding 120 square feet of floor area. Fences not over 7 feet and retaining walls not over 4 feet (bottom of footing to top of wall, with no surcharge) are also exempt. A 6-foot retaining wall, a mezzanine, and removal of a load-bearing wall all require permits.', 'IBC 105.2', 'https://up.codes/s/work-exempt-from-permit', 'intermediario', true, 'Confirmed: 120 sf detached accessory structure exempt; fence not over 7 ft and retaining wall not over 4 ft also exempt, IBC 105.2. Exemption does not authorize code-violating work.'),
  ('ibc-012', 'IBC', 'permits', 'Under the IBC, a fence (other than a swimming pool barrier) does NOT require a building permit when it is not over what height?', '{"A": "4 feet", "B": "6 feet", "C": "7 feet", "D": "8 feet"}'::jsonb, 'C', 'Section 105.2 exempts fences not over 7 feet high (excluding swimming pool barriers) from the permit requirement. Note the contrast with retaining walls, which are exempt only up to 4 feet measured from the bottom of the footing to the top of the wall.', 'IBC 105.2', 'https://up.codes/s/work-exempt-from-permit', 'iniciante', true, 'Confirmed fence not over 7 ft exempt, IBC 105.2.'),
  ('ibc-013', 'IBC', 'certificate-of-occupancy', 'Under the IBC, when may a newly constructed building be lawfully occupied?', '{"A": "As soon as the building permit is issued", "B": "After the foundation inspection passes", "C": "Only after the building official issues a certificate of occupancy", "D": "Whenever the contractor declares the work substantially complete"}'::jsonb, 'C', 'Section 111 states that a building or structure shall not be used or occupied (and no change of occupancy made) until the building official has issued a certificate of occupancy. The certificate follows successful completion of required inspections and verification of code compliance.', 'IBC 111.1', 'https://up.codes/s/certificate-of-occupancy', 'iniciante', true, 'Confirmed IBC Section 111: occupancy prohibited until certificate of occupancy issued by building official.'),
  ('ibc-014', 'IBC', 'stop-work-order', 'When a building official issues a written stop work order because work is being performed in a manner that endangers life or property, what must occur?', '{"A": "The contractor may finish the current task before stopping", "B": "Cited work must immediately cease until the order is lifted", "C": "Work may continue if the owner posts a bond", "D": "The order only takes effect after a 72-hour notice period"}'::jsonb, 'B', 'Upon issuance of a stop work order, the cited work must immediately cease. The order is given in writing to the owner, the owner''s agent, or the person doing the work, stating the reason and the conditions under which work may resume. Continuing work (except to correct the violation) subjects the person to fines.', 'IBC 115.3', 'https://up.codes/s/stop-work-order', 'intermediario', true, 'Confirmed: cited work shall immediately cease (IBC 115.3). Stop work order is Section 115 in current IBC; some jurisdictions (e.g., Virginia) renumber to 114.'),
  ('ibc-015', 'IBC', 'fire-protection', 'An automatic sprinkler system is required throughout a Group A-2 (food/drink assembly) fire area when the fire area exceeds what floor area?', '{"A": "3,000 square feet", "B": "5,000 square feet", "C": "7,500 square feet", "D": "12,000 square feet"}'::jsonb, 'B', 'Per Section 903.2.1.2, a sprinkler system is required throughout a Group A-2 occupancy where any of these apply: the fire area exceeds 5,000 square feet; the fire area has an occupant load of 100 or more; or the fire area is on a floor other than a level of exit discharge serving the occupancy.', 'IBC 903.2.1.2', 'https://up.codes/s/group-a-2', 'intermediario', true, 'Confirmed against UpCodes 903.2.1.2: 5,000 sf, occupant load 100+, or floor other than level of exit discharge. Some web summaries cite 3,000 sf erroneously; verified 5,000.'),
  ('ibc-016', 'IBC', 'fire-protection', 'A Group A-2 fire area also requires an automatic sprinkler system when its occupant load reaches at least:', '{"A": "50", "B": "100", "C": "300", "D": "500"}'::jsonb, 'B', 'Section 903.2.1.2 requires sprinklers throughout a Group A-2 occupancy when the fire area has an occupant load of 100 or more (in addition to the 5,000-square-foot and exit-discharge-level triggers).', 'IBC 903.2.1.2', 'https://up.codes/s/group-a-2', 'intermediario', true, 'Confirmed occupant load of 100 or more triggers A-2 sprinklers, UpCodes 903.2.1.2.'),
  ('ibc-017', 'IBC', 'fire-protection', 'A Class III standpipe system is generally required where the floor level of the highest story is located more than what distance above the lowest level of fire department vehicle access?', '{"A": "20 feet", "B": "30 feet", "C": "55 feet", "D": "75 feet"}'::jsonb, 'B', 'Section 905.3.1 requires standpipes where the highest story floor level is more than 30 feet above the lowest level of fire department vehicle access, or where the lowest floor level is more than 30 feet below the highest level of such access. In fully sprinklered buildings a Class I system is generally permitted (Exception 1).', 'IBC 905.3.1', 'https://up.codes/s/required-installations', 'intermediario', true, 'Confirmed 30 ft above/below fire department vehicle access, IBC 905.3.1. The 75-foot figure is the high-rise threshold, a deliberate distractor.'),
  ('ibc-018', 'IBC', 'masonry-glass-block', 'Under the IBC, the maximum area of a single exterior standard-unit glass-block (glass unit masonry) panel, at a design wind pressure of 20 psf, is:', '{"A": "85 square feet", "B": "100 square feet", "C": "144 square feet", "D": "250 square feet"}'::jsonb, 'C', 'Section 2110.3 limits each individual exterior standard-unit glass-block panel to a maximum of 144 square feet at 20 psf design wind pressure, with maximum dimensions of 25 feet wide or 20 feet high between supports. Thin-unit exterior panels are limited to 85 square feet.', 'IBC 2110.3.1', 'https://up.codes/s/panel-size', 'avancado', true, 'Confirmed 144 sf standard-unit exterior panel at 20 psf; 85 sf thin-unit; 25 ft wide / 20 ft high max, IBC 2110.3.'),
  ('ibc-019', 'IBC', 'rooftop-structures', 'On a building of construction type other than Type I, a penthouse used to enclose mechanical equipment may not exceed what height above the roof deck?', '{"A": "12 feet", "B": "18 feet", "C": "28 feet", "D": "30 feet"}'::jsonb, 'B', 'Section 1510.2 limits penthouses on buildings other than Type I construction to 18 feet above the roof deck (measured to the average height of the penthouse roof). A higher limit of 28 feet is allowed where the penthouse encloses tanks or elevators that travel to the roof.', 'IBC 1510.2.1', 'https://up.codes/s/mechanical-penthouses', 'avancado', true, 'Confirmed 18 ft general / 28 ft for tank/elevator enclosures, IBC 1510.2 (rooftop structures, Chapter 15 in 2015+ IBC).'),
  ('ibc-020', 'IBC', 'marquee', 'Under the IBC, the maximum vertical height (thickness) of a marquee, measured from its lowest to highest point, where it projects more than two-thirds of the distance from the lot line to the curb line, is:', '{"A": "3 feet", "B": "6 feet", "C": "9 feet", "D": "12 feet"}'::jsonb, 'A', 'Section 3106 limits a marquee''s vertical thickness to 3 feet where it projects more than two-thirds of the distance from the lot line to the curb line, and to 9 feet where it projects less than two-thirds of that distance. The greater the projection over the public way, the thinner the marquee must be.', 'IBC 3106.3', 'https://codes.iccsafe.org/content/IBC2021P1/chapter-31-special-construction', 'avancado', true, 'Confirmed 3 ft (projects >2/3 to curb) and 9 ft (projects <2/3), IBC 3106. Minimum vertical clearance above sidewalk is set by local ordinance, separate from this thickness rule.'),
  ('ibc-021', 'IBC', 'photovoltaic', 'Rooftop-mounted photovoltaic panel/module systems are required to be tested, listed, and identified with a fire classification in accordance with which standard?', '{"A": "UL 1703", "B": "ASTM E84", "C": "NFPA 70", "D": "UL 217"}'::jsonb, 'A', 'Rooftop-mounted PV panels and modules must be tested, listed, and identified with a fire classification per UL 1703 (with mounting systems addressed by UL 2703). ASTM E84 is the surface burning (flame-spread) test for interior finishes, NFPA 70 is the National Electrical Code, and UL 217 covers smoke alarms.', 'IBC 1505.9 / 1504.7', 'https://codes.iccsafe.org/content/IBC2018P2/chapter-15-roof-assemblies-and-rooftop-structures', 'intermediario', true, 'Confirmed UL 1703 fire classification for rooftop PV (UL 2703 for mounting). Section number varies by edition; standard reference UL 1703 is stable.'),
  ('ibc-022', 'IBC', 'temporary-structures', 'A permit for a temporary structure (such as an event tent) under the IBC is limited to a maximum service period of:', '{"A": "30 days", "B": "90 days", "C": "180 days", "D": "365 days"}'::jsonb, 'C', 'Section 108 limits permits for temporary structures and uses to a maximum of 180 days, after which the building official may grant extensions for demonstrated cause. The IBC defines a ''temporary structure'' as one erected for a period of 180 days or less.', 'IBC 108.2', 'https://www.iccsafe.org/wp-content/uploads/bcac/IBC_Section_108_TemporaryStructures.pdf', 'intermediario', true, 'Confirmed 180-day maximum, extensions for cause, IBC Section 108. Not Section 3103, which covers tent/membrane structural requirements.'),
  ('ibc-023', 'IBC', 'light-ventilation', 'Where natural light is provided by exterior glazed openings, the minimum net glazed area must be at least what percentage of the floor area of the room served?', '{"A": "4 percent", "B": "8 percent", "C": "10 percent", "D": "12 percent"}'::jsonb, 'B', 'Section 1204.2 requires a minimum net glazed area of 8 percent of the floor area of the room served for natural light. Note the contrast with natural ventilation, which requires an openable area of at least 4 percent of the floor area being ventilated.', 'IBC 1204.2', 'https://up.codes/s/natural-light', 'intermediario', true, 'Confirmed 8 percent net glazed area for natural light, IBC 1204.2.'),
  ('ibc-024', 'IBC', 'light-ventilation', 'Where natural ventilation is provided by openings to the outdoors, the minimum openable area must be at least what percentage of the floor area being ventilated?', '{"A": "4 percent", "B": "5 percent", "C": "8 percent", "D": "10 percent"}'::jsonb, 'A', 'The IBC (Section 1203.5 in 2021; 1203.4 in 2015/2018) requires that the minimum openable area to the outdoors be 4 percent of the floor area being ventilated for natural ventilation. The 8 percent figure applies to natural light glazing, not ventilation.', 'IBC 1203.5.1', 'https://up.codes/viewer/california/ibc-2018/chapter/12/interior-environment', 'intermediario', true, 'Confirmed 4 percent openable area for natural ventilation. Section renumbered across editions (1203.4.1 in 2015/2018, 1203.5.1 in 2021); value 4 percent is stable.'),
  ('ibc-025', 'IBC', 'structural-steel', 'In the standard steel shape designation ''W8 x 15,'' what does the number 15 represent?', '{"A": "The nominal depth of the member in inches", "B": "The weight of the member in pounds per linear foot", "C": "The flange width in inches", "D": "The cross-sectional area in square inches"}'::jsonb, 'B', 'In a W-shape (wide-flange) designation such as W8 x 15, the first number (8) is the nominal depth in inches and the second number (15) is the weight in pounds per linear foot. So a W8 x 15 is a wide-flange beam roughly 8 inches deep weighing 15 lb/ft.', 'AISC Steel Construction Manual (referenced by IBC Chapter 22)', 'https://www.aisc.org/steel-solutions-center/engineering-faqs/2.6.-shape-properties/', 'intermediario', true, 'Standardized AISC nomenclature: W(depth) x (weight in lb/ft). Design/manual knowledge referenced by IBC Chapter 22 (Steel), not a numbered IBC section, but the convention is universal.'),
  ('ibc-026', 'IBC', 'fire-separation', 'Under the IBC, the fire-resistance-rated separation (or sprinkler protection) for an incidental use such as a furnace room, an incinerator room, or a laundry room over 100 square feet is governed by which provision?', '{"A": "Section 509 / Table 509, Incidental Uses", "B": "Section 706, Fire Walls", "C": "Section 1010, Doors", "D": "Section 903, Sprinkler Systems"}'::jsonb, 'A', 'Incidental uses (areas posing a higher hazard within a larger occupancy, e.g., furnace rooms, incinerator rooms, paint shops, laundry rooms larger than 100 square feet) are separated from the remainder of the building per Section 509 and Table 509, which specify a fire-rated separation, an automatic sprinkler system, or both.', 'IBC 509 / Table 509', 'https://codes.iccsafe.org/content/IBC2021P1', 'avancado', true, 'Confirmed incidental uses governed by IBC Section 509 and Table 509 (2015/2018/2021). Specific row values vary, so question is framed at the governing-section level to keep the gabarito airtight.'),
  ('iecc-019', 'IECC', '', 'Under the 2021 IECC (R402.4.1.2), what is the maximum allowable building air leakage rate, by blower-door test, for a new dwelling in Massachusetts (Climate Zone 5)?', '{"A": "5.0 air changes per hour at 50 Pa (5 ACH50)", "B": "3.0 air changes per hour at 50 Pa (3 ACH50)", "C": "7.0 air changes per hour at 50 Pa (7 ACH50)", "D": "1.0 air change per hour at 50 Pa (1 ACH50)"}'::jsonb, 'B', 'The 2021 IECC R402.4.1.2 caps air leakage at 5.0 ACH50 in Climate Zones 0, 1 and 2, and at 3.0 ACH50 in Climate Zones 3 through 8. Massachusetts is Zone 5, so the limit is 3.0 ACH50. (The 2018 IECC had allowed 5 ACH50 in zones 3-4; the 2021 edition tightened it.) The test is run at 0.2 in. w.g. (50 Pascals).', 'IECC R402.4.1.2 (2021) — Air leakage testing, CZ 3-8', 'https://up.codes/viewer/department-of-defense/iecc-2021/chapter/RE_4/re-residential-energy-efficiency', 'intermediario', true, ''),
  ('iecc-020', 'IECC', '', 'The blower-door air leakage test required by IECC R402.4.1.2 must be conducted at what reference pressure?', '{"A": "0.2 inch w.g. (50 Pascals)", "B": "1.0 inch w.g. (250 Pascals)", "C": "0.5 inch w.g. (125 Pascals)", "D": "0.1 inch w.g. (25 Pascals)"}'::jsonb, 'A', 'IECC R402.4.1.2 requires the whole-house pressurization/depressurization test be performed at a pressure of 0.2 inch water gauge (50 Pascals), which is why the metric is expressed as ''ACH50'' (air changes per hour at 50 Pa). Testing follows RESNET/ICC 380, ASTM E779, or ASTM E1827 and is done with a blower door.', 'IECC R402.4.1.2 (2021) — Testing pressure 50 Pa', 'https://scotthomeinspection.com/explaining-the-air-leakage-testing-update-in-the-2021-iecc/', 'iniciante', true, ''),
  ('iecc-021', 'IECC', '', 'Under the 2021 IECC postconstruction duct test (R403.3.6), what is the maximum total duct leakage allowed for a system with ducts located partly outside the building thermal envelope?', '{"A": "8.0 cfm per 100 sq ft of conditioned floor area", "B": "4.0 cfm per 100 sq ft of conditioned floor area", "C": "12.0 cfm per 100 sq ft of conditioned floor area", "D": "2.0 cfm per 100 sq ft of conditioned floor area"}'::jsonb, 'B', 'Per the 2021 IECC, the postconstruction total duct leakage limit is 4.0 cubic feet per minute per 100 square feet of conditioned floor area. A rough-in test with the air handler installed uses the same 4.0 cfm/100 sq ft limit (3.0 cfm/100 sq ft if the air handler is not yet installed).', 'IECC R403.3.5/R403.3.6 (2021) — Duct leakage limits', 'https://up.codes/s/duct-leakage', 'intermediario', true, ''),
  ('iecc-022', 'IECC', '', 'Under the 2021 IECC (R403.3.5), duct leakage testing is NOT required when which of the following is true?', '{"A": "The ducts and air handler are located entirely within the building thermal envelope", "B": "The home is smaller than 2,000 square feet", "C": "The ductwork is flexible duct rather than rigid metal", "D": "The home uses a heat pump instead of a furnace"}'::jsonb, 'A', 'The 2021 IECC exempts the duct test where the ducts and air handler are located entirely within the conditioned (building thermal envelope) space, because leakage in that case stays inside the conditioned volume. When ducts pass through unconditioned space (attic, crawlspace, garage), the test and the leakage limits apply.', 'IECC R403.3.5 (2021) — Duct testing exception', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-re-residential-energy-efficiency', 'intermediario', true, ''),
  ('iecc-023', 'IECC', '', 'Under the 2021 IECC (R404.1), what portion of permanently installed lighting in a new dwelling must use high-efficacy light sources?', '{"A": "75 percent of the fixtures", "B": "90 percent of the fixtures", "C": "All (100 percent) permanently installed lighting, excluding kitchen appliance lighting", "D": "50 percent of the lamps"}'::jsonb, 'C', 'The 2021 IECC R404.1 requires that all permanently installed lighting fixtures (excluding lighting integral to kitchen appliances) contain only high-efficacy light sources. This was a significant tightening: the 2015 IECC required 75 percent and some prior/state editions used 90 percent, but the 2021 model code went to 100 percent high-efficacy.', 'IECC R404.1 (2021) — High-efficacy lighting', 'https://up.codes/s/lighting-equipment-mandatory', 'intermediario', true, ''),
  ('iecc-024', 'IECC', '', 'Under the 2021 IECC definition, a ''high-efficacy'' lamp (light source) must deliver an efficacy of not less than approximately how many lumens per watt?', '{"A": "20 lumens per watt", "B": "40 lumens per watt", "C": "65 lumens per watt", "D": "100 lumens per watt"}'::jsonb, 'C', 'In the 2021 IECC, a high-efficacy light source (lamp) is defined as one with an efficacy of not less than 65 lumens per watt (or 45 lumens per watt at the luminaire level). The 2021 edition removed the older wattage-tiered thresholds, so the single 65 lm/W lamp figure applies regardless of wattage. Standard LED lamps easily exceed this.', 'IECC Chapter 2 / R404.1 (2021) — High-efficacy definition', 'https://up.codes/d/high-efficacy-lamps', 'intermediario', true, ''),
  ('iecc-025', 'IECC', '', 'Under the 2021 IECC (R403.1.1), where the primary heating/cooling system is a forced-air furnace or heat pump, the installed thermostat must be capable of what?', '{"A": "Controlling the system on a daily schedule with different setpoints at different times and days (programmable)", "B": "Connecting to the internet for remote monitoring", "C": "Operating only in manual mode for code compliance", "D": "Locking the homeowner out of temperature changes"}'::jsonb, 'A', 'IECC R403.1.1 requires a programmable thermostat: it must be capable of controlling the heating and cooling system on a daily schedule, maintaining different temperature setpoints at different times of the day and different days of the week. Internet connectivity is not required by code; scheduling capability is.', 'IECC R403.1.1 (2021) — Programmable thermostat', 'https://up.codes/viewer/department-of-defense/iecc-2021/chapter/RE_4/re-residential-energy-efficiency', 'iniciante', true, ''),
  ('iecc-026', 'IECC', '', 'Under the 2021 IECC (R403.5.2), service hot-water piping 3/4 inch and larger in nominal diameter must be insulated to a minimum thermal resistance of what R-value?', '{"A": "R-2", "B": "R-3", "C": "R-5", "D": "R-8"}'::jsonb, 'B', 'IECC R403.5.2 requires insulation with a thermal resistance of not less than R-3 on service hot-water piping that is 3/4 inch and larger in nominal diameter (plus other specified runs such as piping from the water heater to a manifold or buried piping). Smaller pipe runs have their own triggers, but the baseline insulation level is R-3.', 'IECC R403.5.2 (2021) — Hot water pipe insulation R-3', 'https://up.codes/viewer/department-of-defense/iecc-2021/chapter/RE_4/re-residential-energy-efficiency', 'intermediario', true, ''),
  ('iecc-027', 'IECC', '', 'Under the 2021 IECC (R403.6), a new dwelling built to the tight air-leakage requirement must be provided with what?', '{"A": "A whole-house mechanical ventilation system", "B": "Operable windows in every room only", "C": "Passive attic ventilation only", "D": "No ventilation, since the house must be airtight"}'::jsonb, 'A', 'Because the 2021 IECC drives houses to 3 ACH50 (very tight), R403.6 mandates a whole-house mechanical ventilation system to supply controlled fresh air, sized per Section R403.6.1 (which references the airflow rates of the IRC/IMC). In Climate Zones 7-8 the ventilation must use heat- or energy-recovery (HRV/ERV). Tight construction without mechanical ventilation is not code-compliant.', 'IECC R403.6 / R403.6.1 (2021) — Whole-house mechanical ventilation', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-re-residential-energy-efficiency', 'intermediario', true, ''),
  ('iecc-028', 'IECC', '', 'Under the 2021 IECC (R402.4.1.1), the building thermal envelope must be sealed and the installation verified against which document?', '{"A": "Table R402.4.1.1 (Air Barrier and Insulation Installation)", "B": "The manufacturer''s window warranty", "C": "ASHRAE 62.2 ventilation tables", "D": "The local zoning ordinance"}'::jsonb, 'A', 'IECC R402.4.1.1 requires the components of the building thermal envelope to be installed in accordance with Table R402.4.1.1, the ''Air Barrier and Insulation Installation'' criteria. This table lists item-by-item sealing/installation requirements (rim joists, garage walls, recessed lights, shafts, etc.) that the inspector checks before the blower-door test.', 'IECC R402.4.1.1 / Table R402.4.1.1 (2021) — Air barrier and insulation install', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-re-residential-energy-efficiency', 'intermediario', true, ''),
  ('iecc-029', 'IECC', '', 'On the IECC fenestration air-leakage requirement, the maximum allowable air leakage for site-built or manufactured windows and sliding doors is generally:', '{"A": "0.3 cfm per square foot of window area", "B": "1.5 cfm per square foot of window area", "C": "5.0 cfm per square foot of window area", "D": "There is no air-leakage limit on windows"}'::jsonb, 'A', 'Per IECC R402.4.3, windows, skylights and sliding glass doors have a maximum air-leakage rate of 0.3 cfm per square foot, and swinging doors 0.5 cfm per square foot, when tested to the referenced AAMA/NFRC standards (e.g., NFRC 400 or AAMA/WDMA/CSA 101). Labeled, certified fenestration generally satisfies this without field testing.', 'IECC R402.4.3 (2021) — Fenestration air leakage 0.3 cfm/sf', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-re-residential-energy-efficiency', 'intermediario', true, ''),
  ('iecc-031', 'IECC', '', 'The 2021 IECC residential provisions offer multiple compliance paths. Which of the following is NOT one of the recognized residential compliance paths?', '{"A": "Prescriptive (R-value / U-factor tables)", "B": "Total UA / performance (simulated annual energy)", "C": "Energy Rating Index (ERI)", "D": "Verbal approval from the homeowner"}'::jsonb, 'D', 'The 2021 IECC residential code allows compliance by the Prescriptive path (Section R402 tables), the Total Building Performance/UA-alternative path (R405), or the Energy Rating Index (ERI) path (R406). Each is a defined, documented route. ''Verbal homeowner approval'' is not a code compliance method.', 'IECC R401.2 (2021) — Residential compliance paths', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-re-residential-energy-efficiency', 'iniciante', true, ''),
  ('iecc-032', 'IECC', '', 'Under the 2021 IECC COMMERCIAL provisions (C406), commercial buildings must demonstrate additional energy efficiency by accumulating a required number of ''efficiency credits.'' Approximately how many credits are required?', '{"A": "1 credit", "B": "3 credits", "C": "10 credits", "D": "There is no credit requirement"}'::jsonb, 'C', 'The 2021 IECC replaced the old single ''additional efficiency package'' with a points-based system in C406: buildings must accumulate 10 efficiency credits, choosing from a menu of measures (high-efficiency HVAC, reduced lighting power, on-site renewables, enhanced envelope, dedicated outdoor air systems, etc.). The credit value of each measure varies by occupancy type and climate zone.', 'IECC C406 (2021) — Additional efficiency credits (10 credits)', 'https://up.codes/s/reduced-lighting-power', 'avancado', true, ''),
  ('iecc-033', 'IECC', '', 'Under the 2021 IECC COMMERCIAL provisions, building-envelope opaque assembly insulation requirements are set out primarily in which section?', '{"A": "C402 (Building Envelope Requirements)", "B": "C403 (Building Mechanical Systems)", "C": "C405 (Electrical Power and Lighting Systems)", "D": "C404 (Service Water Heating)"}'::jsonb, 'A', 'Commercial building-envelope thermal requirements live in C402: opaque assemblies (roofs, walls, floors, slabs) in C402.1 and Table C402.1.3/C402.1.4 (R-value and U/C/F-factor methods), fenestration in C402.4, and air leakage of the envelope in C402.5. Mechanical (C403), service water heating (C404), and lighting power (C405) are separate chapters.', 'IECC C402 (2021) — Commercial building envelope', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-ce-commercial-energy-efficiency', 'iniciante', true, ''),
  ('iecc-034', 'IECC', '', 'Under the 2021 IECC COMMERCIAL provisions, the air leakage of the building thermal envelope (continuous air barrier requirement) is addressed in which section?', '{"A": "C402.5 (Air Leakage / Thermal Envelope)", "B": "C405.2 (Lighting Controls)", "C": "C403.7 (Ventilation)", "D": "C404.5 (Heat Traps)"}'::jsonb, 'A', 'C402.5 governs air leakage of the commercial building thermal envelope, requiring a continuous air barrier across the whole envelope, with material/assembly/whole-building options. The 2021 IECC strengthened this with air-barrier testing/verification requirements (e.g., a whole-building air-leakage test or visual/assembly compliance) that was a notable change from prior editions.', 'IECC C402.5 (2021) — Commercial air barrier', 'https://www.swinter.com/iecc-air-barrier-requirements/', 'intermediario', true, ''),
  ('iecc-035', 'IECC', '', 'Under the 2021 IECC COMMERCIAL provisions, an economizer (air or water) for a cooling system is generally required under which section, with applicability driven by climate zone and cooling capacity?', '{"A": "C403.5 (Economizers)", "B": "C402.3 (Roof Reflectance)", "C": "C405.3 (Exterior Lighting)", "D": "C404.2 (Water Heater Efficiency)"}'::jsonb, 'A', 'C403.5 sets the economizer requirements. An air or water economizer is generally required for individual fan-cooling systems at or above a capacity threshold (about 54,000 Btu/h for non-Group-R), with exceptions by climate zone, occupancy, and high-efficiency equipment trade-offs. Hot/humid Climate Zones 1A/1B are largely exempt; colder zones like Massachusetts (CZ5) typically require economizers on larger systems.', 'IECC C403.5 (2021) — Commercial economizers', 'https://up.codes/s/economizers-prescriptive', 'avancado', true, ''),
  ('iecc-036', 'IECC', '', 'Under the 2021 IECC COMMERCIAL provisions, the requirements governing interior lighting power (the Lighting Power Density / LPD allowance for a building) are found in which section?', '{"A": "C405 (Electrical Power and Lighting Systems)", "B": "C402 (Building Envelope)", "C": "C404 (Service Water Heating)", "D": "C403 (Mechanical Systems)"}'::jsonb, 'A', 'Section C405 covers electrical power and lighting. Interior lighting power allowances (LPD, in watts per square foot, by space type or whole-building area method) are set in C405.3 and its tables, while lighting controls are in C405.2 and exterior lighting power in C405.4. Designers compare installed connected lighting wattage against the LPD allowance.', 'IECC C405.3 (2021) — Interior lighting power (LPD)', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-ce-commercial-energy-efficiency', 'intermediario', true, ''),
  ('iecc-037', 'IECC', '', 'Under the 2021 IECC COMMERCIAL provisions, low-sloped roofs in certain climate zones must meet a roof solar-reflectance (''cool roof'') requirement. A compliant cool roof can be demonstrated by a three-year-aged solar reflectance of at least:', '{"A": "0.55 (with three-year-aged thermal emittance of at least 0.75)", "B": "0.10", "C": "0.90 with no emittance requirement", "D": "There is no reflectance requirement for any commercial roof"}'::jsonb, 'A', 'The cool-roof option (C402.3) can be met with a three-year-aged solar reflectance of not less than 0.55 and a three-year-aged thermal emittance of not less than 0.75, OR by a Solar Reflectance Index (SRI) of at least 64 for low-slope roofs. Exceptions include vegetative (green) roofs, shaded roof areas, and ballasted roofs. This requirement targets hotter climate zones to cut cooling load.', 'IECC C402.3 (2021) — Roof solar reflectance / cool roof', 'https://www.nucorbuildingsystems.com/wp-content/uploads/2021/03/3.21.energy.codes_.pdf', 'avancado', true, ''),
  ('iecc-038', 'IECC', '', 'Under the 2021 IECC COMMERCIAL provisions, service (domestic) water-heating equipment efficiency and related requirements such as heat traps and pipe insulation are found in which section?', '{"A": "C404 (Service Water Heating)", "B": "C402 (Building Envelope)", "C": "C405 (Lighting)", "D": "C403 (Mechanical Systems)"}'::jsonb, 'A', 'Section C404 covers commercial service water heating: minimum equipment efficiencies (C404.2), heat traps (C404.4), insulation of circulating and long pipe runs (C404.5), controls for circulation systems, and pool/spa requirements. It is the commercial counterpart to the residential R403.5 hot-water provisions.', 'IECC C404 (2021) — Commercial service water heating', 'https://codelibrary.amlegal.com/codes/chicago/latest/chicago_il/0-0-0-2698542', 'intermediario', true, ''),
  ('iecc-039', 'IECC', '', 'Under the 2021 IECC COMMERCIAL lighting controls (C405.2), most interior spaces are required to have which control to shut lights off automatically?', '{"A": "Automatic time-switch and/or occupant-sensor (automatic shutoff) controls", "B": "A single manual switch by the entrance only", "C": "A circuit breaker that staff turn off nightly", "D": "No automatic controls are required commercially"}'::jsonb, 'A', 'C405.2 requires automatic lighting shutoff for most interior spaces, achieved through time-switch (scheduled) controls and/or occupancy/vacancy sensors, plus manual controls, daylight-responsive controls in daylight zones, and other specified controls. The goal is to prevent lights running in unoccupied spaces. A single manual switch alone does not comply for most space types.', 'IECC C405.2 (2021) — Lighting controls', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-ce-commercial-energy-efficiency', 'intermediario', true, ''),
  ('iecc-040', 'IECC', '', 'The 2021 IECC residential whole-house mechanical ventilation system (R403.6) must, in the coldest climate zones (7 and 8), incorporate which feature?', '{"A": "Heat- or energy-recovery ventilation (HRV/ERV)", "B": "An open window timer", "C": "A gas-fired make-up air burner", "D": "No special feature; any exhaust fan suffices"}'::jsonb, 'A', 'R403.6.1 in the 2021 IECC requires that whole-house ventilation systems in Climate Zones 7 and 8 be heat-recovery or energy-recovery ventilators (HRV/ERV) meeting a minimum recovery efficiency (about 65 percent sensible recovery at 32 degrees F). This recaptures heat from the exhaust stream so the very cold incoming air does not waste heating energy. Massachusetts (CZ5/6) does not trigger the HRV/ERV mandate but still requires whole-house ventilation.', 'IECC R403.6.1 (2021) — HRV/ERV in CZ 7-8', 'https://neep.org/sites/default/files/media-files/2021_iecc_one-pager_.pdf', 'avancado', true, ''),
  ('iecc-041', 'IECC', '', 'Under the 2021 IECC, a smaller dwelling unit may comply with the air-leakage requirement using an alternative metric instead of ACH50. That alternative is expressed as:', '{"A": "cfm at 50 Pa per square foot of dwelling unit enclosure area", "B": "Gallons per minute of conditioned air", "C": "BTU per hour per occupant", "D": "Watts per square foot of floor"}'::jsonb, 'A', 'The 2021 IECC allows dwelling/sleeping units (notably smaller units, e.g., under 1,500 sq ft) to demonstrate air leakage as cfm at 50 Pa per square foot of dwelling-unit enclosure area (an envelope-area normalized leakage), rather than the volume-based 3 ACH50. This avoids penalizing small, compact units whose volume makes ACH50 hard to hit.', 'IECC R402.4.1.2 (2021) — Alternative leakage metric (cfm50/sf)', 'https://scotthomeinspection.com/explaining-the-air-leakage-testing-update-in-the-2021-iecc/', 'avancado', true, ''),
  ('iecc-042', 'IECC', '', 'Under the 2021 IECC duct-sealing requirements (R403.3.2), ducts, air handlers and filter boxes must be sealed. Which joints are specifically required to be sealed?', '{"A": "Joints and seams, sealed per the IMC (mastic, mastic-and-mesh, or listed tape)", "B": "Only the joints visible from the floor", "C": "Only joints in unconditioned attics, never in basements", "D": "No sealing is required if duct tape is used"}'::jsonb, 'A', 'R403.3.2 requires ducts, air handlers and filter boxes to be sealed at joints and seams in accordance with the International Mechanical Code, using mastic, mastic-plus-mesh, or listed/labeled tape (ordinary cloth-backed ''duct tape'' is not acceptable for sealing). Proper sealing is what makes the duct leakage test (R403.3.5) passable.', 'IECC R403.3.2 (2021) — Duct sealing', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-re-residential-energy-efficiency', 'intermediario', true, ''),
  ('iecc-043', 'IECC', '', 'Under the 2021 IECC (R403.5.1), a hot-water circulation or heat-trace system must have which type of control?', '{"A": "An automatic control (e.g., demand, timer, temperature, or occupancy) that can turn the pump/heat trace off", "B": "A control that runs the pump continuously 24/7", "C": "Manual valve only, adjusted seasonally", "D": "No control is required"}'::jsonb, 'A', 'R403.5.1 requires automatic controls on heated-water circulation and heat-trace systems so the pump or heat trace shuts off when hot water is not in demand (controls can be demand-initiated, timer, temperature, or based on identifying no use). Continuously running recirculation wastes significant energy, which the control requirement prevents.', 'IECC R403.5.1 (2021) — Heated water circulation controls', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-re-residential-energy-efficiency', 'intermediario', true, ''),
  ('iecc-044', 'IECC', '', 'Under the 2021 IECC COMMERCIAL provisions, the prescriptive opaque-envelope insulation values for roofs, walls and floors vary primarily by which two factors?', '{"A": "Climate zone and assembly/construction type", "B": "Building owner preference and budget", "C": "The contractor''s license class", "D": "The month the permit is issued"}'::jsonb, 'A', 'The commercial prescriptive envelope tables (Table C402.1.3 R-value method and Table C402.1.4 U/C/F-factor method) list required insulation by climate zone (rows) and by assembly type (columns) such as roofs (insulation above deck, attic, metal building), walls (mass, metal-framed, wood-framed, below-grade), and floors (mass, joist/framing). A Zone 5 metal-building wall has a different requirement than a Zone 5 mass wall.', 'IECC C402.1.3 / Table C402.1.4 (2021) — Commercial opaque assemblies', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-ce-commercial-energy-efficiency', 'intermediario', true, ''),
  ('iecc-045', 'IECC', '', 'Under the 2021 IECC COMMERCIAL provisions, mechanical equipment must meet minimum efficiency ratings. These minimum HVAC equipment efficiencies are located in which section/tables?', '{"A": "C403.3 and the C403 equipment efficiency tables", "B": "C402.4 fenestration tables", "C": "C405.3 lighting tables", "D": "C404.2 water heater tables only"}'::jsonb, 'A', 'Commercial HVAC minimum equipment efficiencies (SEER, EER, IEER, AFUE, COP, etc., for air conditioners, heat pumps, furnaces, boilers, chillers) are set in Section C403.3 and its referenced tables (e.g., Tables C403.3.2(1) through the various equipment tables). These are the commercial analog to the residential equipment provisions and are checked at plan review.', 'IECC C403.3 (2021) — Commercial HVAC minimum equipment efficiency', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-ce-commercial-energy-efficiency', 'avancado', true, ''),
  ('iecc-046', 'IECC', '', 'Under the 2021 IECC, the duct-testing rough-in test conducted BEFORE the air handler is installed has a tighter limit than the test with the air handler installed. That rough-in (no air handler) limit is:', '{"A": "3.0 cfm per 100 sq ft of conditioned floor area", "B": "4.0 cfm per 100 sq ft of conditioned floor area", "C": "8.0 cfm per 100 sq ft of conditioned floor area", "D": "1.0 cfm per 100 sq ft of conditioned floor area"}'::jsonb, 'A', 'For a rough-in test where the air handler is NOT yet installed, the 2021 IECC limits total duct leakage to 3.0 cfm per 100 sq ft of conditioned floor area. When the air handler IS installed at the time of the rough-in test (and for the postconstruction test), the limit is 4.0 cfm per 100 sq ft. The tighter 3.0 figure accounts for the leakage the not-yet-installed air handler would otherwise add.', 'IECC R403.3.5 (2021) — Rough-in duct leakage (no air handler) 3.0 cfm', 'https://up.codes/s/duct-leakage-prescriptive-and-duct-testing-mandatory', 'avancado', true, ''),
  ('iecc-047', 'IECC', '', 'Under the 2021 IECC COMMERCIAL provisions, demand-control ventilation (DCV) is generally required for spaces with which characteristic?', '{"A": "High and variable occupancy (large design occupant density) above a threshold, served by systems with economizers or significant outdoor air", "B": "Any space with a window", "C": "Only mechanical equipment rooms", "D": "DCV is never required commercially"}'::jsonb, 'A', 'C403 (the ventilation provisions, e.g., C403.7.x) requires demand-control ventilation for spaces with high, variable occupancy densities (such as conference rooms, gyms, auditoriums) above a defined occupant-density/airflow threshold. DCV uses CO2 or occupancy sensing to modulate outdoor-air intake to actual occupancy, cutting the energy to condition unneeded ventilation air.', 'IECC C403.7 (2021) — Demand-control ventilation', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-ce-commercial-energy-efficiency', 'avancado', true, ''),
  ('iecc-048', 'IECC', '', 'In Massachusetts, the energy code applied to construction is the IECC adopted through which state regulatory framework?', '{"A": "780 CMR (State Building Code) referencing the IECC, with the energy provisions in 225 CMR 22.00 (residential) and 23.00 (commercial)", "B": "OSHA 1926 Subpart M", "C": "The National Electrical Code (NEC) only", "D": "The IECC does not apply in Massachusetts"}'::jsonb, 'A', 'Massachusetts adopts the IECC through the state building code (780 CMR), with the base energy code provisions codified by the Department of Energy Resources in 225 CMR 22.00 (residential) and 225 CMR 23.00 (commercial), plus a separate Stretch/Specialized Opt-in Code adopted by many municipalities. So an MA project must meet the IECC as amended by these MA regulations, not the unmodified model code.', '780 CMR / 225 CMR 22.00 & 23.00 — MA adoption of IECC', 'https://www.law.cornell.edu/regulations/massachusetts/225-CMR-app-C-SS-C403', 'intermediario', true, ''),
  ('iecc-049', 'IECC', '', 'Under the 2021 IECC (R503), when an existing dwelling undergoes an alteration, the new and replaced portions must generally comply with the code for new construction. Which of the following alterations is EXEMPT from requiring the full new-construction energy provisions?', '{"A": "Storm windows installed over an existing fenestration assembly", "B": "A complete tear-off and replacement of all exterior walls", "C": "A new heated addition larger than 500 square feet", "D": "Replacing the entire HVAC system with a new furnace"}'::jsonb, 'A', 'IECC R503.1.1 and the exceptions in R503 exempt several minor alterations, including storm windows installed over an existing fenestration, from having to meet the full U-factor/SHGC requirements for new fenestration. Alterations cannot reduce the existing building''s energy efficiency below the level before the work, but listed minor items (storm windows, glass-only replacement in a sash, etc.) are exempt from full new-construction compliance.', 'IECC R503.1.1 (2021) — Alterations and exceptions', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-5-re-existing-buildings', 'intermediario', true, ''),
  ('iecc-050', 'IECC', '', 'Under the 2021 IECC (R502), an ADDITION to an existing building must comply with the code. Which option correctly describes the compliance path the code allows for an addition?', '{"A": "The addition alone must comply, OR the existing building plus the addition together may be treated as a single building meeting the code", "B": "Additions are always exempt from the energy code", "C": "Only additions over 1,000 square feet must comply", "D": "The addition must make the entire existing house net-zero"}'::jsonb, 'A', 'IECC R502.1 lets an addition comply in either of two ways: (1) the addition by itself meets the provisions of the code for new construction, or (2) the existing building and the addition together comply as a single building. This gives flexibility when, for example, an over-glazed existing house is offset by a tight new addition.', 'IECC R502.1 (2021) — Additions', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-5-re-existing-buildings', 'intermediario', true, ''),
  ('iecc-051', 'IECC', '', 'Under the 2021 IECC (R501.6), a ''repair'' to an existing building component is treated how with respect to the energy code?', '{"A": "Repairs may use like materials and are not required to bring the component up to new-construction energy levels", "B": "Every repair triggers a full energy upgrade of the whole building", "C": "Repairs are prohibited unless a HERS rater is present", "D": "Repairs require a blower-door test of the entire dwelling"}'::jsonb, 'A', 'IECC R501.6 allows repairs using materials and methods permitted for the original construction; a repair is not required to bring the existing building or component into full compliance with new-construction provisions, provided the repair does not increase the building''s energy use. This distinguishes a ''repair'' (restore to working condition) from an ''alteration'' (change/upgrade).', 'IECC R501.6 (2021) — Repairs', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-5-re-existing-buildings', 'intermediario', true, ''),
  ('iecc-052', 'IECC', '', 'Under the 2021 IECC (R402.2.13), a sunroom that is thermally isolated from the rest of the dwelling and built as an addition may use which relaxed envelope requirement in Climate Zones 4 through 8?', '{"A": "A minimum ceiling insulation of R-19 and a minimum wall insulation of R-13 (relaxed from the main-house values)", "B": "No insulation at all", "C": "The same R-49 ceiling required for the main dwelling", "D": "Triple-pane glazing on every surface"}'::jsonb, 'A', 'IECC R402.2.13 lets a thermally isolated sunroom addition use reduced minimums: ceiling insulation not less than R-19 and wall insulation not less than R-13 in Climate Zones 4-8. The fenestration U-factor for the new sunroom is also relaxed (not to exceed 0.45 for vertical glazing and 0.70 for skylights). ''Thermally isolated'' means separated from the conditioned space by walls/doors meeting the code.', 'IECC R402.2.13 (2021) — Sunroom thermal isolation', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-re-residential-energy-efficiency', 'avancado', true, ''),
  ('iecc-053', 'IECC', '', 'Under the 2021 IECC mass wall provision (R402.2.5), when at least 50 percent of the wall insulation is on the EXTERIOR (outside) of a mass wall, the required R-value is treated how compared to a mass wall with insulation on the interior?', '{"A": "The lower (less stringent) R-value in the second column of Table R402.1.3 may be used", "B": "The R-value must be doubled", "C": "Exterior insulation is never permitted on a mass wall", "D": "The wall must meet the wood-frame wall R-value instead"}'::jsonb, 'A', 'IECC Table R402.1.3 lists mass wall R-values as two numbers (e.g., ''13/17''). R402.2.5 specifies that the second, lower value applies when more than half of the insulation is on the exterior of the mass wall, because exterior insulation keeps the thermal mass inside the conditioned envelope and performs better. The higher value applies when insulation is mainly on the interior.', 'IECC R402.2.5 (2021) — Mass walls', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-re-residential-energy-efficiency', 'avancado', true, ''),
  ('iecc-054', 'IECC', '', 'Under the 2021 IECC (R402.2.9), basement walls of conditioned basements in Climate Zone 5 (Massachusetts) require continuous/cavity insulation of at least which value?', '{"A": "R-15 continuous insulation or R-19 cavity insulation", "B": "No insulation is required", "C": "R-5 continuous only", "D": "R-49 cavity insulation"}'::jsonb, 'A', 'Per IECC Table R402.1.3, basement wall insulation in Climate Zones 4 (except Marine), 5, 6, 7 and 8 is ''15/19'' — meaning R-15 continuous insulation or R-19 cavity insulation. R402.2.9 requires this insulation to extend from the top of the basement wall down to 10 feet below grade or to the basement floor, whichever is less, for conditioned basements.', 'IECC R402.2.9 / Table R402.1.3 (2021) — Basement walls', 'https://up.codes/s/insulation-component-r-value', 'avancado', true, ''),
  ('iecc-055', 'IECC', '', 'Under the 2021 IECC (R402.2.11), crawl-space wall insulation in an UNVENTED crawl space (used as the thermal boundary) in Climate Zone 5 must be at least what value, and how far must it extend?', '{"A": "R-15 continuous or R-19 cavity, extending from the top of the wall down to the floor and then 24 inches horizontally or vertically", "B": "R-3 continuous only, no extension required", "C": "Crawl-space walls never need insulation", "D": "R-49 over the crawl-space floor instead of the walls"}'::jsonb, 'A', 'IECC R402.2.11 treats an unvented (conditioned) crawl space as part of the thermal envelope: the crawl-space WALLS are insulated to the Table R402.1.3 value (15/19 in CZ5), and the insulation must extend from the top of the wall down to the finished floor level, then continue either 24 inches vertically down the wall or 24 inches horizontally across the floor. A continuous vapor retarder/ground cover is also required.', 'IECC R402.2.11 (2021) — Crawl space walls', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-re-residential-energy-efficiency', 'avancado', true, ''),
  ('iecc-056', 'IECC', '', 'Under the 2021 IECC Table R402.1.2 (Insulation and Fenestration Requirements by Component), what is the maximum vertical fenestration U-factor allowed in Climate Zone 5 (most of Massachusetts)?', '{"A": "U-0.30", "B": "U-0.50", "C": "U-0.65", "D": "U-0.18"}'::jsonb, 'A', 'In the 2021 IECC, the prescriptive vertical fenestration U-factor for Climate Zones 3 through 8 is 0.30. (Zone 2 is 0.40; Zone 1 has no requirement.) Massachusetts is Zone 5, so windows must be U-0.30 or lower under the prescriptive path. This tightened from the 0.32 value used in the 2015/2018 IECC for some zones.', 'IECC Table R402.1.2 (2021) — Fenestration U-factor', 'https://up.codes/s/fenestration-u-factor', 'intermediario', true, ''),
  ('iecc-057', 'IECC', '', 'Under the 2021 IECC (R402.2.6), STEEL-FRAME ceilings, walls and floors must meet the insulation requirements using which approach?', '{"A": "Table R402.2.6 values (which add continuous insulation to offset thermal bridging through the steel framing)", "B": "The same cavity-only R-value used for wood framing", "C": "No insulation, because steel is a good insulator", "D": "Only spray foam is allowed and no R-value is specified"}'::jsonb, 'A', 'Steel studs and joists conduct heat far more than wood, so IECC R402.2.6 sends steel-framed assemblies to Table R402.2.6, which prescribes a combination of cavity insulation plus continuous insulation (e.g., 13+5, 0+10, etc.) to compensate for the thermal bridging through the metal framing. You cannot simply use the wood-frame cavity value for a steel-frame wall.', 'IECC R402.2.6 / Table R402.2.6 (2021) — Steel-frame ceilings, walls, floors', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-re-residential-energy-efficiency', 'avancado', true, ''),
  ('iecc-058', 'IECC', '', 'Under the 2021 IECC (Table R402.1.2), what is the prescriptive minimum ceiling insulation R-value for a new dwelling in Climate Zone 5 (Massachusetts)?', '{"A": "R-49", "B": "R-30", "C": "R-13", "D": "R-60"}'::jsonb, 'A', 'The 2021 IECC prescriptive ceiling insulation for Climate Zones 4 through 8 is R-49. Massachusetts (Zone 5) therefore requires R-49 ceiling insulation under the prescriptive path. The 2021 edition kept R-49 for CZ4-8 (Zone 1-2 = R-30/R-38; Zone 3 = R-38).', 'IECC Table R402.1.2 (2021) — Ceiling R-value', 'https://up.codes/s/insulation-component-r-value', 'iniciante', true, ''),
  ('iecc-059', 'IECC', '', 'Under the 2021 IECC (R402.2.1, Ceilings with attic spaces), what allowance lets a builder use R-38 instead of R-49 over the exterior wall plates in Climate Zone 5?', '{"A": "Where R-38 is installed and extends over the wall top plate at the eaves without compression, it may be deemed to satisfy R-49 (the reduced-thickness-at-eaves allowance)", "B": "Whenever the attic is unventilated", "C": "Only if the roof is metal", "D": "There is no such allowance; R-49 must be uniform everywhere"}'::jsonb, 'A', 'IECC R402.2.1 allows R-38 to be deemed equivalent to R-49 wherever the full height of uncompressed insulation extends over the wall top plate at the eaves. This recognizes the practical difficulty of fitting full insulation depth at the eave where the roof meets the wall. Raised-heel (energy) trusses are the usual way to keep full depth over the plate.', 'IECC R402.2.1 (2021) — Ceilings with attic spaces', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-re-residential-energy-efficiency', 'avancado', true, ''),
  ('iecc-060', 'IECC', '', 'Under the 2021 IECC (R402.2.4), an attic access hatch, scuttle hole, or knee-wall door that opens into unconditioned space must be insulated to what level?', '{"A": "Not less than the insulation R-value of the surrounding surface (e.g., the ceiling or wall it penetrates)", "B": "No insulation is required on access hatches", "C": "Only R-3, regardless of the surrounding surface", "D": "R-100 minimum"}'::jsonb, 'A', 'IECC R402.2.4 requires that access doors from conditioned to unconditioned spaces (attic hatches, drop-down stairs, knee-wall doors) be weather-stripped and insulated to a level not less than the insulation on the surrounding surfaces. So an attic hatch in an R-49 ceiling must carry roughly equivalent insulation, and a knee-wall door must match the knee-wall insulation.', 'IECC R402.2.4 (2021) — Access hatches and doors', 'https://up.codes/s/access-hatches-and-doors', 'intermediario', true, ''),
  ('iecc-061', 'IECC', '', 'Under the 2021 IECC (R403.4), mechanical system piping carrying fluids above 105 degrees F or below 55 degrees F must be insulated to at least what R-value?', '{"A": "R-3", "B": "R-1", "C": "R-10", "D": "No insulation is required"}'::jsonb, 'A', 'IECC R403.4 requires mechanical system piping capable of carrying fluids above 105 F or below 55 F to be insulated to a minimum of R-3. This covers hydronic heating lines, chilled-water lines, and similar piping (distinct from the service hot-water piping insulation handled under R403.5).', 'IECC R403.4 (2021) — Mechanical system piping insulation', 'https://up.codes/s/mechanical-system-piping-insulation', 'intermediario', true, ''),
  ('iecc-062', 'IECC', '', 'Under the 2021 IECC (R403.10), snow-melt and ice-melt systems (heated driveways, walkways) must include which control to limit energy waste?', '{"A": "An automatic control that shuts the system off when the pavement temperature is above 50 F and no precipitation is falling, plus an automatic or manual control to shut off when the outdoor temperature is above 40 F", "B": "A simple on/off switch with no automatic control", "C": "A control that runs the system continuously all winter", "D": "Snow-melt systems are exempt from all controls"}'::jsonb, 'A', 'IECC R403.10 requires snow- and ice-melting systems to have automatic controls capable of shutting the system off when the pavement temperature is above 50 F and no precipitation is falling, and an automatic or manual control that shuts the system off when the outdoor temperature is above 40 F. This prevents the heated slab from running when there is no snow to melt.', 'IECC R403.10 (2021) — Snow-melt and ice-melt controls', 'https://up.codes/s/snow-melt-and-ice-melt-system-controls', 'avancado', true, ''),
  ('iecc-063', 'IECC', '', 'Under the 2021 IECC (R403.11), a heated swimming pool or permanent spa must be equipped with what energy-saving feature, with limited exceptions?', '{"A": "A vapor-retardant cover, except where more than 70 percent of the heating energy is from site-recovered or solar energy", "B": "A continuously running pump with no timer", "C": "An electric resistance heater only", "D": "No cover or controls of any kind"}'::jsonb, 'A', 'IECC R403.11 (heated pools and permanent spas) requires a vapor-retardant cover on or above the water surface, with an exception when over 70 percent of the energy for heating is recovered from on-site or solar sources. The section also requires a readily accessible on/off heater switch and time switches/controls on pumps and heaters to limit operation.', 'IECC R403.11 (2021) — Pools and permanent spas', 'https://up.codes/s/portable-spas', 'intermediario', true, ''),
  ('iecc-064', 'IECC', '', 'Under the 2021 IECC (R403.11), heaters for pools and permanent spas must be equipped with which control?', '{"A": "A readily accessible on/off switch mounted outside the heater that allows shutting off the heater without adjusting the thermostat setting", "B": "A locked thermostat that the owner cannot change", "C": "A heater with no on/off control at all", "D": "A switch accessible only to a licensed electrician"}'::jsonb, 'A', 'IECC R403.11.1 requires pool and spa heaters to have a readily accessible on/off switch, mounted on the outside of the heater, that lets the user turn the heater off without changing the thermostat setpoint, so the heater can be shut down (e.g., when the pool is covered or unused) without losing the temperature setting.', 'IECC R403.11.1 (2021) — Pool/spa heater on-off control', 'https://up.codes/s/heaters', 'intermediario', true, ''),
  ('iecc-066', 'IECC', '', 'Under the 2021 IECC (C405.2.1), interior lighting in most commercial spaces must be controlled by what type of control to reduce energy when spaces are unoccupied?', '{"A": "Occupant-sensor controls that automatically turn lighting off (or reduce it) within 20 minutes of all occupants leaving the space", "B": "A single master switch at the building entrance only", "C": "Lighting that stays on 24 hours a day", "D": "Manual dimmers with no automatic shutoff"}'::jsonb, 'A', 'IECC C405.2.1 requires occupant-sensor controls in many space types (offices, classrooms, conference/meeting rooms, restrooms, storage, etc.) that automatically turn lighting off within 20 minutes of all occupants leaving, or reduce it. Combined with time-switch and daylight controls, this is part of the C405.2 lighting-controls package for commercial buildings.', 'IECC C405.2.1 (2021) — Occupant sensor controls', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-ce-commercial-energy-efficiency', 'intermediario', true, ''),
  ('iecc-067', 'IECC', '', 'Under the 2021 IECC (C405.2.3), daylight-responsive controls are generally required in which situation?', '{"A": "In daylight zones under skylights and adjacent to vertical fenestration where the connected lighting load in the daylight zone exceeds the code threshold", "B": "In every windowless interior room", "C": "Only in parking garages", "D": "Never; daylight controls are optional in all commercial buildings"}'::jsonb, 'A', 'IECC C405.2.3 requires daylight-responsive (photocell) controls for general lighting in primary sidelit daylight zones (adjacent to vertical glazing) and in toplit daylight zones (under skylights) when the connected general lighting load in those zones exceeds the threshold (e.g., 150 W). The controls dim or switch the electric lighting in response to available daylight.', 'IECC C405.2.3 (2021) — Daylight-responsive controls', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-ce-commercial-energy-efficiency', 'avancado', true, ''),
  ('iecc-068', 'IECC', '', 'Under the 2021 IECC (C405.2.2), what is the purpose of a required time-switch (scheduling) control in a commercial building?', '{"A": "To automatically turn interior lighting off during scheduled unoccupied periods, with a manual override that reverts after no more than a set time", "B": "To keep lights on a fixed schedule that cannot be overridden", "C": "To control only exterior parking lights", "D": "To replace the need for any occupant sensors entirely"}'::jsonb, 'A', 'IECC C405.2.2 requires time-switch (automatic scheduling) controls that shut interior lighting off during scheduled unoccupied hours. A manual override is allowed but must apply to a limited area and automatically revert after a maximum time (commonly 2 hours). Time-switch, occupant-sensor, and daylight controls together form the C405.2 lighting-control requirements.', 'IECC C405.2.2 (2021) — Time-switch controls', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-ce-commercial-energy-efficiency', 'intermediario', true, ''),
  ('iecc-069', 'IECC', '', 'Under the 2021 IECC (C405.3), interior lighting power may be determined by either the Building Area Method or the Space-by-Space Method. What is the key difference?', '{"A": "The Building Area Method assigns one lighting power density (LPD) per overall building type, while the Space-by-Space Method sums allowances calculated for each individual space type", "B": "The Building Area Method requires no LPD limit at all", "C": "The Space-by-Space Method ignores room function", "D": "Both methods always yield the exact same wattage"}'::jsonb, 'A', 'IECC C405.3.1 (Building Area Method) applies a single LPD watts-per-square-foot value based on the overall building use type to the whole building area. C405.3.2 (Space-by-Space Method) lets the designer apply a specific LPD to each space type (office, corridor, retail, etc.) and total them, which usually permits more total watts where there are high-demand spaces. The total installed interior lighting power must not exceed the allowance computed by whichever method is chosen.', 'IECC C405.3 (2021) — Interior lighting power (Building Area vs Space-by-Space)', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-ce-commercial-energy-efficiency', 'avancado', true, ''),
  ('iecc-070', 'IECC', '', 'Under the 2021 IECC (C405.4), EXTERIOR lighting is regulated how?', '{"A": "By a total exterior lighting power allowance (base allowance plus per-area/per-feature allowances for facades, parking, walkways, etc.) and required automatic controls such as photocells and scheduling", "B": "Exterior lighting has no power limit and no controls", "C": "Only the color temperature of exterior lamps is regulated", "D": "Exterior lighting must be incandescent"}'::jsonb, 'A', 'IECC C405.4 caps exterior lighting power using a base site allowance plus tradable allowances tied to specific applications (building facades, parking lots/drives, walkways, entrances, canopies, etc.), with the watts depending on the lighting zone. C405.4.1 also requires automatic controls: a photosensor/astronomical time switch to turn exterior lighting off when daylight is available, and reduction of certain lighting during late-night unoccupied hours.', 'IECC C405.4 (2021) — Exterior lighting power and controls', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-ce-commercial-energy-efficiency', 'avancado', true, ''),
  ('iecc-071', 'IECC', '', 'Under the 2021 IECC (C403.7.4), an energy recovery ventilation (ERV/HRV) system is required when the supply air system meets which condition?', '{"A": "When the system''s supply airflow rate and the percentage of outdoor air exceed the thresholds in Table C403.7.4(1)/(2) for the given climate zone and operating hours", "B": "Only in single-family homes", "C": "Never required in any commercial building", "D": "Only when the building has no windows"}'::jsonb, 'A', 'IECC C403.7.4 requires energy (heat) recovery on ventilation systems when the combination of supply fan airflow and percent outdoor air exceeds the thresholds in Tables C403.7.4(1) and C403.7.4(2), which vary by climate zone and by the number of fan operating hours per year. Recovery effectiveness must be at least 50 percent (with a stated enthalpy/sensible target). Several exceptions apply (e.g., systems serving spaces heated to less than 60 F, certain kitchen/lab exhaust).', 'IECC C403.7.4 (2021) — Energy recovery ventilation systems', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-ce-commercial-energy-efficiency', 'avancado', true, ''),
  ('iecc-072', 'IECC', '', 'Under the 2021 IECC (C403.5), economizers are generally required on larger cooling systems. Which of the following is a recognized EXCEPTION that exempts a system from the economizer requirement?', '{"A": "Systems below the cooling-capacity threshold for the climate zone, or systems where the economizer would be infeasible (e.g., certain high-humidity, process, or 100-percent-outdoor-air systems)", "B": "All systems are exempt; economizers are never required", "C": "Only systems in residential dwellings", "D": "Systems that use natural gas heating"}'::jsonb, 'A', 'IECC C403.5 requires air- or water-side economizers on cooling systems above a capacity threshold that depends on the climate zone. C403.5 lists exceptions: systems below the size threshold, systems in spaces with high humidity/process requirements, systems where outdoor air is already 100 percent, certain hospitals/data centers meeting other efficiency, and where adding an economizer is technically infeasible. Knowing that exceptions exist (and that they are climate-zone dependent) is the key exam point.', 'IECC C403.5 (2021) — Economizer requirements and exceptions', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-ce-commercial-energy-efficiency', 'avancado', true, ''),
  ('iecc-073', 'IECC', '', 'Under the 2021 IECC (C408), commercial buildings require ''commissioning'' of mechanical and lighting systems. What does commissioning primarily verify?', '{"A": "That the installed HVAC, service water heating, and lighting control systems are calibrated, function as designed, and that a commissioning report and O&M documentation are provided to the owner", "B": "Only the color of the paint on the walls", "C": "That the building has the maximum possible window area", "D": "That the contractor was paid in full"}'::jsonb, 'A', 'IECC C408 (System Commissioning) requires functional testing and verification that mechanical systems (over a capacity threshold), service water heating, and lighting controls operate per the construction documents. It requires a commissioning plan, functional performance testing, a preliminary report before the certificate of occupancy, and a final commissioning report plus operating/maintenance manuals delivered to the owner. It is a major addition in modern IECC editions for commercial work.', 'IECC C408 (2021) — System commissioning', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-ce-commercial-energy-efficiency', 'intermediario', true, ''),
  ('iecc-074', 'IECC', '', 'Under the 2021 IECC (C407), the ''Total Building Performance'' compliance path demonstrates compliance by what means?', '{"A": "Energy modeling showing the proposed design''s annual energy cost is no greater than that of a code-defined standard reference design", "B": "A simple checklist with no calculations", "C": "Meeting each prescriptive requirement individually with no trade-offs", "D": "Paying a fee to the building department"}'::jsonb, 'A', 'IECC C407 (Total Building Performance) is the whole-building energy-modeling path: an approved simulation program compares the ''proposed design'' against a ''standard reference design'' built to the prescriptive/baseline requirements. Compliance is shown when the proposed annual energy cost does not exceed the reference design''s. This path allows trade-offs the prescriptive (C402-C405) path does not.', 'IECC C407 (2021) — Total building performance', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-ce-commercial-energy-efficiency', 'avancado', true, ''),
  ('iecc-075', 'IECC', '', 'Under the 2021 IECC (C402.4.1), the prescriptive path limits the total vertical fenestration (window) area to what percentage of the gross above-grade wall area?', '{"A": "30 percent, which may be increased up to 40 percent if specified daylighting conditions are met", "B": "Unlimited; there is no window-area cap", "C": "Exactly 10 percent with no exceptions", "D": "75 percent for all commercial buildings"}'::jsonb, 'A', 'IECC C402.4.1 limits vertical fenestration to a maximum of 30 percent of the gross above-grade wall area under the prescriptive path. The limit may rise to 40 percent where the building meets specified conditions (e.g., at least half the additional glazing is in daylight zones with daylight-responsive controls, and certain VT/U-factor criteria are satisfied). Projects exceeding the cap must use the C407 performance path.', 'IECC C402.4.1 (2021) — Maximum fenestration area', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-ce-commercial-energy-efficiency', 'avancado', true, ''),
  ('iecc-076', 'IECC', '', 'Under the 2021 IECC (C402.5.7), a vestibule (an enclosed entrance space with two sets of doors) is required at building entrances. What is the primary energy purpose of the vestibule?', '{"A": "To limit air infiltration/exfiltration by preventing conditioned air from being directly lost when the entrance door is opened", "B": "To provide additional retail display space", "C": "To meet fire-egress requirements only", "D": "To increase the building''s window area"}'::jsonb, 'A', 'IECC C402.5.7 requires a vestibule at building entrances that separate conditioned space from the exterior (with listed exceptions for small buildings, doors not intended for use by the public, revolving doors, certain spaces under 3,000 sq ft, etc.). The two-door airlock reduces the direct exchange of conditioned indoor air with outdoor air each time the door is opened, cutting heating/cooling losses.', 'IECC C402.5.7 (2021) — Vestibules', 'https://up.codes/s/vestibules', 'intermediario', true, ''),
  ('iecc-077', 'IECC', '', 'Under the 2021 IECC (C402.5.7), which of the following building entrances is EXEMPT from the vestibule requirement?', '{"A": "Doors that open directly from a space less than 3,000 square feet in area, and entrances not intended to be used by the public (such as service/loading doors)", "B": "Every door in every commercial building must have a vestibule with no exceptions", "C": "Only doors taller than 12 feet", "D": "Doors in buildings located in Climate Zone 5"}'::jsonb, 'A', 'IECC C402.5.7 lists vestibule exceptions, including: doors not intended for use by the public (service, employee, loading); doors opening directly from a dwelling unit; doors opening from a space less than 3,000 sq ft; revolving doors; and doors used primarily to facilitate vehicular or material movement. These recognize that a vestibule adds little benefit (or is impractical) for low-traffic or small spaces.', 'IECC C402.5.7 (2021) — Vestibule exceptions', 'https://up.codes/s/vestibules', 'intermediario', true, ''),
  ('iecc-078', 'IECC', '', 'Under the 2021 IECC (C405.3 and Table C405.3.2(2)), the Space-by-Space Method also permits ''additional lighting power allowances'' for which type of feature?', '{"A": "Decorative/display lighting and certain specialized tasks (e.g., retail display), provided that wattage is used only for that purpose", "B": "General ambient lighting in corridors only", "C": "Exterior parking-lot lighting", "D": "Emergency egress lighting that operates only during power loss"}'::jsonb, 'A', 'Under the Space-by-Space Method, IECC C405.3.2 allows extra (additional) interior lighting power for decorative/display purposes and specific tasks such as retail merchandise highlighting, where the table assigns supplemental watts. That additional allowance can be used only for the decorative or display lighting it was granted for, not added to the general lighting budget for ordinary ambient illumination.', 'IECC C405.3.2 / Table C405.3.2(2) (2021) — Additional lighting power allowances', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-ce-commercial-energy-efficiency', 'avancado', true, ''),
  ('iecc-079', 'IECC', 'prescriptive-residential-cz4', 'Under the 2021 IECC prescriptive Table R402.1.2 (component R-values), what is the minimum ceiling insulation R-value required in Climate Zone 4 (which in Massachusetts applies to Dukes and Nantucket counties)?', '{"A": "R-60", "B": "R-49", "C": "R-30", "D": "R-38"}'::jsonb, 'A', 'In the 2021 IECC Table R402.1.2, the prescriptive ceiling R-value increased to R-60 for Climate Zones 4 through 8. Earlier editions (2015/2018) required R-49 in CZ4-8; the 2021 edition raised ceiling insulation to R-60. Dukes and Nantucket counties (Cape and Islands) are Climate Zone 4A in Massachusetts.', 'IECC R402.1.2 / Table R402.1.2 (2021) — Insulation and fenestration by component, CZ4', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-re-residential-energy-efficiency', 'avancado', true, 'Confirmado contra 2021 IECC Table R402.1.2: ceiling R-60 em CZ4-8 (subiu de R-49 na 2018). Dukes/Nantucket = CZ4A em MA.'),
  ('iecc-080', 'IECC', 'prescriptive-residential-cz6', 'Per the 2021 IECC prescriptive Table R402.1.2, what is the minimum wood-frame WALL cavity insulation R-value in Climate Zone 6 (which in Massachusetts covers the Berkshires and hill towns)?', '{"A": "R-13", "B": "R-20 or R-13+5ci", "C": "R-30 or R-20+5ci", "D": "R-15"}'::jsonb, 'C', 'In the 2021 IECC, Table R402.1.2 specifies wood-frame wall insulation for Climate Zones 6, 7 and 8 as R-30, or R-20 plus R-5 continuous insulation (R-20+5ci), or R-13 plus R-10 continuous (R-13+10ci). This is a notable increase from the 2018 IECC R-20 or R-13+5 in CZ6. Berkshire County and the western hill towns of Massachusetts are Climate Zone 6A.', 'IECC Table R402.1.2 (2021) — Frame wall R-value, CZ6', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-re-residential-energy-efficiency', 'avancado', true, 'Confirmado: 2021 IECC Table R402.1.2 wood-frame wall CZ6-8 = R-30 ou R-20+5ci ou R-13+10ci. Berkshires = CZ6A.'),
  ('iecc-081', 'IECC', 'fenestration-shgc-residential', 'Under the 2021 IECC Table R402.1.2, in which residential climate zones is a maximum glazed-fenestration SHGC (Solar Heat Gain Coefficient) of 0.25 prescribed, while colder zones (including Massachusetts CZ5-6) have NO SHGC requirement?', '{"A": "All zones equally", "B": "Climate Zones 6, 7 and 8", "C": "Climate Zones 4 and 5 only", "D": "Climate Zones 0, 1, 2 and 3"}'::jsonb, 'D', 'IECC Table R402.1.2 lists a maximum fenestration SHGC of 0.25 for Climate Zones 0 through 3 (the warm/hot zones where summer solar gain dominates). Climate Zones 4 through 8 (including Massachusetts'' predominant CZ5A and the colder CZ6A) carry ''NR'' (no requirement) for SHGC because winter solar gain is beneficial there. The U-factor requirement still applies in all zones.', 'IECC Table R402.1.2 (2021) — Glazed fenestration SHGC', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-re-residential-energy-efficiency', 'intermediario', true, 'Confirmado: SHGC max 0.25 em CZ0-3; ''NR'' (no requirement) em CZ4-8. MA = CZ5/6 = sem exigencia de SHGC.'),
  ('iecc-082', 'IECC', 'slab-edge-residential', 'Per the 2021 IECC Table R402.1.2, the prescriptive slab-edge insulation for a heated slab differs from an unheated slab. For an UNHEATED slab-on-grade floor in Climate Zone 5 (most of Massachusetts), what is the required slab insulation?', '{"A": "No slab insulation required", "B": "R-10 to a depth of 2 feet", "C": "R-20 full underslab", "D": "R-5 to a depth of 4 feet"}'::jsonb, 'B', 'IECC Table R402.1.2 lists slab R-value and depth as ''R-10, 2 ft'' for Climate Zones 4 (except Marine), 5 and 6. The insulation extends down (or out) 2 feet from the top of the slab. Note the table''s separate footnote requirements for HEATED slabs, which add R-5 to the base value. Most of Massachusetts is CZ5A, so R-10/2 ft applies to unheated slabs.', 'IECC Table R402.1.2 (2021) — Slab R-value & depth, CZ4-6', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-re-residential-energy-efficiency', 'intermediario', true, 'Confirmado: slab R-10, 2 ft em CZ4(exceto Marine)-6. Heated slab footnote adiciona R-5.'),
  ('iecc-083', 'IECC', 'u-factor-alternative-residential', 'The 2021 IECC R402.1.3 offers a U-factor alternative to the R-value table. Under this path, the building''s fenestration, ceiling, wall, floor and other assemblies must meet maximum assembly U-factors. Which statement best describes this compliance path?', '{"A": "Each assembly''s overall U-factor must not exceed the value in Table R402.1.3, allowing trade-offs in how the R-value is achieved", "B": "It eliminates all insulation requirements", "C": "It applies only to commercial buildings", "D": "It requires a HERS index of 0"}'::jsonb, 'A', 'IECC R402.1.3 and Table R402.1.3 provide an Assembly U-factor alternative: instead of meeting the prescriptive R-values in Table R402.1.2, the designer demonstrates each assembly meets a maximum overall U-factor. This accounts for whole-assembly performance (including framing factors and continuous insulation) and gives flexibility in construction detailing. Fenestration U-factors are unchanged because they are already expressed as U-factors.', 'IECC R402.1.3 / Table R402.1.3 (2021) — U-factor alternative', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-re-residential-energy-efficiency', 'intermediario', true, 'Confirmado: R402.1.3 e Table R402.1.3 dao caminho de U-factor de montagem como alternativa aos R-values de R402.1.2.'),
  ('iecc-084', 'IECC', 'total-ua-alternative-residential', 'Under the 2021 IECC R402.1.5 (Total UA alternative), a proposed building''s combined thermal envelope complies if its total UA is less than or equal to what reference value?', '{"A": "The UA required only for fenestration", "B": "Zero", "C": "Half the UA of any neighboring house", "D": "The total UA of a building configured to the U-factor values in Table R402.1.3 (the standard reference design)"}'::jsonb, 'D', 'IECC R402.1.5 allows a ''total UA'' trade-off: if the total UA (sum of U-factor times area for all envelope assemblies) of the proposed building is less than or equal to the total UA resulting from the U-factors of Table R402.1.3 applied to the same building, the envelope complies. This lets a designer trade a poorer-performing component (e.g., more glazing) against a better-performing one (e.g., extra wall insulation). SHGC must still be met separately.', 'IECC R402.1.5 (2021) — Total UA alternative', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-re-residential-energy-efficiency', 'avancado', true, 'Confirmado: R402.1.5 — proposed total UA <= reference total UA da Table R402.1.3; SHGC verificado separadamente.'),
  ('iecc-085', 'IECC', 'ducts-conditioned-space', 'The 2021 IECC R403.3.1 requires supply and return ducts in attics to be insulated, but provides an exception. Ducts are exempt from the duct insulation requirement when they are located where?', '{"A": "Inside an exterior wall cavity", "B": "In any unvented attic", "C": "Within 10 feet of the air handler", "D": "Entirely within the building thermal envelope (conditioned space)"}'::jsonb, 'D', 'IECC R403.3.1 (and the exception to R403.3) exempt ducts or portions of ducts from the insulation requirement when they are located completely inside the building thermal envelope (i.e., in conditioned space). Ducts buried in attic insulation also have specific provisions (R403.3.6), but the cleanest exemption is locating the ductwork entirely within conditioned space, which is increasingly common in high-performance design.', 'IECC R403.3.1, R403.3 Exception (2021) — Duct insulation', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-re-residential-energy-efficiency', 'intermediario', true, 'Confirmado: ducts dentro do envelope termico (conditioned space) isentos de isolamento por R403.3.1/exception.'),
  ('iecc-087', 'IECC', 'high-efficacy-lighting-residential', 'How did the residential high-efficacy lighting requirement change in the 2021 IECC (R404.1) compared with the 2018 IECC''s 90% threshold?', '{"A": "It was reduced to 50%", "B": "It was retained at not less than 90% of permanently installed lighting fixtures using high-efficacy lamps", "C": "It was eliminated entirely", "D": "It now requires 100% high-efficacy lighting"}'::jsonb, 'B', 'The 2021 IECC R404.1 requires that not less than 90 percent of the permanently installed lighting fixtures contain only high-efficacy lamps. (The 2015 IECC required 75%; the 2018 raised it to 90%; the 2021 retained 90% rather than going to 100%.) High-efficacy lamps are defined by minimum efficacy in lumens per watt, effectively meaning LED in modern construction. A common exam trap is the false claim that 2021 mandates 100%.', 'IECC R404.1 (2021) — Lighting equipment (high-efficacy)', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-re-residential-energy-efficiency', 'intermediario', true, 'Confirmado: 2021 IECC R404.1 = 90% high-efficacy (mesmo que 2018; nao subiu a 100%). 2015 era 75%.'),
  ('iecc-088', 'IECC', 'crawl-space-insulation-tradeoff', 'The 2021 IECC (R402.2.11) gives two ways to insulate a vented vs. unvented crawl space. For an UNVENTED crawl space treated as part of the conditioned envelope, the insulation is installed where?', '{"A": "Both wall and floor must be fully insulated", "B": "Only on the floor joists above the crawl space", "C": "On the crawl-space WALLS (perimeter), not on the floor above", "D": "No insulation is allowed in crawl spaces"}'::jsonb, 'C', 'IECC R402.2.11 addresses crawl-space walls: where a crawl space is unvented and conditioned (or semi-conditioned) it is treated as inside the thermal envelope, so the perimeter crawl-space WALLS are insulated and the floor above is not. By contrast, a vented crawl space requires the FLOOR above it to be insulated. The tradeoff (insulate walls vs. insulate floor) hinges on whether the crawl space is inside or outside the thermal boundary.', 'IECC R402.2.11 (2021) — Crawl space walls', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-re-residential-energy-efficiency', 'intermediario', true, 'Confirmado: R402.2.11 — unvented/conditioned crawl = isolar paredes do perimetro; vented crawl = isolar piso acima.'),
  ('iecc-089', 'IECC', 'fenestration-u-factor-residential', 'Under the 2021 IECC Table R402.1.2, what is the maximum vertical-fenestration (window) U-factor required in Climate Zones 3 through 8, including Massachusetts CZ5 and CZ6?', '{"A": "0.40", "B": "0.35", "C": "0.30", "D": "0.27"}'::jsonb, 'C', 'IECC Table R402.1.2 sets the maximum vertical fenestration U-factor at 0.30 for Climate Zones 3 through 8. This tightened from the 2015 IECC value of 0.32-0.35 in those zones. Massachusetts (CZ5A statewide, CZ6A in the Berkshires, CZ4A on the Islands) therefore requires windows with U-factor no greater than 0.30. Skylights have a separate, higher allowance.', 'IECC Table R402.1.2 (2021) — Fenestration U-factor', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-re-residential-energy-efficiency', 'intermediario', true, 'Confirmado: vertical fenestration U-factor max 0.30 em CZ3-8 (2021). MA toda em CZ4/5/6 -> 0.30.'),
  ('iecc-090', 'IECC', 'skylight-u-factor-residential', 'Per the 2021 IECC Table R402.1.2, the prescriptive maximum SKYLIGHT U-factor in Climate Zones 4 through 8 is which value?', '{"A": "0.30", "B": "0.55", "C": "0.75", "D": "0.50"}'::jsonb, 'B', 'IECC Table R402.1.2 lists a maximum skylight U-factor of 0.55 in Climate Zones 4 through 8. Skylights are permitted a higher U-factor than vertical windows because of their limited area and different installation. A frequent exam distractor is to apply the 0.30 vertical-window value to skylights.', 'IECC Table R402.1.2 (2021) — Skylight U-factor', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-re-residential-energy-efficiency', 'intermediario', true, 'Confirmado: skylight U-factor max 0.55 em CZ4-8 (2021).'),
  ('iecc-093', 'IECC', 'commercial-economizer-c403', 'Under the 2021 IECC C403.5, an air-economizer is generally required on individual cooling systems above what capacity threshold (with climate-zone-based exceptions)?', '{"A": "54,000 Btu/h", "B": "90,000 Btu/h", "C": "65,000 Btu/h", "D": "33,000 Btu/h"}'::jsonb, 'A', 'IECC C403.5 requires economizers (air or water) on cooling systems with a capacity at or above 54,000 Btu/h, subject to the climate-zone exceptions in Table C403.5(1) and the listed exceptions in C403.5. The economizer lets a building use cool outdoor air for ''free cooling'' before mechanical refrigeration. A common distractor (65,000 Btu/h) is the threshold for certain other equipment provisions, not the economizer trigger.', 'IECC C403.5 (2021) — Economizers', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-ce-commercial-energy-efficiency', 'avancado', true, 'Confirmado: C403.5 — economizer exigido em sistemas de resfriamento >= 54,000 Btu/h, com excecoes por climate zone (Table C403.5(1)).'),
  ('iecc-095', 'IECC', 'commercial-lpd-warehouse-c405', 'In the 2021 IECC space-by-space LPD table, a WAREHOUSE storage area carries a lower lighting power density than an office or retail sales floor. Which statement best reflects the code''s intent for warehouse LPD?', '{"A": "Warehouse LPD equals exterior lighting power", "B": "Warehouses are exempt from all lighting power limits", "C": "Warehouses get the highest LPD of any space type", "D": "Warehouse storage areas are allowed a relatively low LPD because the visual task is less demanding than retail or office work"}'::jsonb, 'D', 'The 2021 IECC space-by-space LPD table assigns lower allowances to low-task spaces such as warehouse storage (around 0.45-0.66 W/ft2 depending on material size) versus higher allowances for detailed-task spaces like retail sales floors. The code calibrates lighting power to the visual difficulty of the task in each space type, which is the conceptual point being tested here. Exact warehouse decimals should be confirmed against the table.', 'IECC C405.3.2 / Table C405.3.2(2) (2021) — LPD, warehouse', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-ce-commercial-energy-efficiency', 'intermediario', true, 'Conceito confirmado: LPD calibrada por dificuldade da tarefa visual; warehouse storage tem allowance baixo. Decimais exatos a confirmar na tabela.'),
  ('iecc-096', 'IECC', 'commercial-exterior-lighting-c405', 'The 2021 IECC C405.4.2 limits exterior lighting power using a base allowance plus a per-application allowance that varies by ''lighting zone.'' What determines a site''s exterior lighting zone?', '{"A": "The development context of the site (e.g., LZ1 developed rural areas through LZ4 high-activity commercial districts), which sets stricter or looser exterior power allowances", "B": "The building''s floor area only", "C": "The owner''s preference", "D": "The number of parking spaces only"}'::jsonb, 'A', 'IECC C405.4.2 establishes exterior lighting zones (LZ1 through LZ4, with LZ0 in some references) based on the ambient development context of the site. Darker/rural zones (LZ1) get tighter allowances; high-activity commercial districts (LZ4) get larger allowances. The total exterior connected lighting power must not exceed a base site allowance plus the sum of per-application (per-area or per-linear-foot) allowances for that zone.', 'IECC C405.4.2 / Table C405.4.2 (2021) — Exterior lighting zones', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-ce-commercial-energy-efficiency', 'intermediario', true, 'Confirmado: C405.4.2 usa lighting zones (LZ1-LZ4) pelo contexto de desenvolvimento do site para fixar allowances de iluminacao exterior.'),
  ('iecc-097', 'IECC', 'commercial-c406-credits', 'The 2021 IECC C406 requires commercial buildings to achieve additional efficiency credits. How does the 2021 edition''s C406 differ structurally from earlier editions that required choosing ''one of six'' measures?', '{"A": "It requires all six measures on every building", "B": "It eliminated all additional efficiency requirements", "C": "It assigns point/credit values to each measure and requires the building to earn a minimum total number of credits (varying by climate zone and building type), rather than just picking one option", "D": "It applies only to residential buildings"}'::jsonb, 'C', 'The 2021 IECC restructured C406 into a credit/point system (Table C406.1) where each efficiency option (e.g., more efficient HVAC, reduced lighting power, enhanced digital lighting controls, on-site renewable energy, dedicated outdoor air systems, high-efficiency service water heating) is worth a number of credits, and the building must earn a minimum total that varies by climate zone and occupancy. The 2015/2018 editions simply required selecting one of several listed options.', 'IECC C406.1 / Table C406.1 (2021) — Additional efficiency credit system', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-ce-commercial-energy-efficiency', 'avancado', true, 'Confirmado: 2021 C406 virou sistema de creditos (Table C406.1) com minimo por climate zone/ocupacao; ed. anteriores eram ''escolha uma de varias'' opcoes.'),
  ('iecc-098', 'IECC', 'commercial-c406-renewable', 'Under the 2021 IECC C406, which of the following is one of the available additional-efficiency CREDIT options a commercial building may use to earn its required points?', '{"A": "Using larger structural beams", "B": "Removing all windows", "C": "Installing carpet instead of tile", "D": "On-site renewable energy systems"}'::jsonb, 'D', 'IECC C406 (2021) lists on-site renewable energy (e.g., photovoltaic) as one of the credit-earning additional efficiency options, alongside more efficient HVAC equipment, reduced lighting power density, enhanced lighting controls, dedicated outdoor air systems with energy recovery, high-efficiency service water heating, and reduced air infiltration. None of the other answer choices are recognized energy-efficiency measures under C406.', 'IECC C406 (2021) — Additional efficiency options (renewable)', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-ce-commercial-energy-efficiency', 'intermediario', true, 'Confirmado: on-site renewable energy e uma das opcoes de credito de C406 (2021), junto com HVAC eficiente, LPD reduzida, controles avancados, DOAS, SWH eficiente, infiltracao reduzida.'),
  ('iecc-100', 'IECC', 'commercial-fenestration-shgc-c402', 'Per the 2021 IECC Table C402.4, how does the COMMERCIAL fenestration SHGC requirement in Climate Zone 5 differ from the RESIDENTIAL requirement in the same zone?', '{"A": "Commercial buildings have no SHGC limit anywhere", "B": "Commercial buildings DO have an SHGC maximum in CZ5, whereas residential CZ4-8 has no SHGC requirement", "C": "Both commercial and residential require SHGC of exactly 0.25 in CZ5", "D": "Residential is stricter than commercial in every zone"}'::jsonb, 'B', 'Unlike the residential table (which lists ''NR''/no SHGC requirement in Climate Zones 4 through 8), the COMMERCIAL code (Table C402.4) imposes an SHGC maximum even in colder zones like CZ5, because internal cooling loads in commercial buildings are significant year-round. Higher projection factors (shading) relax the commercial SHGC requirement. This distinction between residential and commercial SHGC treatment is a common exam point.', 'IECC C402.4 / Table C402.4 (2021) — Commercial SHGC, CZ5', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-ce-commercial-energy-efficiency', 'avancado', true, 'Confirmado conceitualmente: comercial tem SHGC max em CZ5 (diferente de residencial NR em CZ4-8); valor numerico exato varia por edicao/PF — checar tabela antes de publicar valor especifico.'),
  ('iecc-101', 'IECC', 'commercial-swh-c404', 'The 2021 IECC C404.5 requires insulation on service hot-water piping under defined conditions. What is the minimum pipe insulation R-value generally required for the circulating or heat-traced portions of a commercial service hot-water system?', '{"A": "R-1", "B": "R-2", "C": "R-3", "D": "R-10"}'::jsonb, 'C', 'IECC C404.5 / C404.5.1 require that piping serving as part of a circulating hot-water system, heat-traced piping, and the first lengths of outlet piping be insulated to at least R-3. This reduces standby and distribution heat loss in commercial service water heating. (Residential service-water piping carries a similar R-3 requirement in R403.5.3.)', 'IECC C404.5 / C404.5.1 (2021) — Service hot-water pipe insulation', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-ce-commercial-energy-efficiency', 'intermediario', true, 'Confirmado: C404.5 exige isolamento de tubulacao de SWH circulante/heat-traced a R-3 minimo (residencial R-3 em R403.5.3).'),
  ('iecc-102', 'IECC', 'commercial-swh-c404', 'Under the 2021 IECC C404.6, automatic controls are required on circulating service hot-water pumps and heat-trace systems so that the system does what?', '{"A": "Can be turned off automatically when hot water is not required", "B": "Runs continuously at all times", "C": "Is replaced annually", "D": "Pumps cold water during the day"}'::jsonb, 'A', 'IECC C404.6 (Heated-water circulation and temperature maintenance controls) requires that circulating hot-water systems and heat-trace temperature-maintenance systems have controls that automatically turn off the system (pump or heat trace) when hot water is not being used or required. This prevents continuous, wasteful operation of recirculation pumps, a common energy drain in commercial buildings with long pipe runs.', 'IECC C404.6 (2021) — Hot-water circulation and temperature maintenance controls', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-ce-commercial-energy-efficiency', 'intermediario', true, 'Confirmado: C404.6 exige controles que desligam automaticamente bomba de recirculacao/heat-trace quando agua quente nao e necessaria.'),
  ('iecc-103', 'IECC', 'commercial-erv-c403', 'The 2021 IECC C403.7.4 requires energy (heat) recovery on certain ventilation systems. The requirement is generally triggered based on which two factors?', '{"A": "The number of stories only", "B": "The color of the ductwork", "C": "The supply airflow rate (cfm) and the percentage of outdoor air, evaluated by climate zone", "D": "The building''s street address"}'::jsonb, 'C', 'IECC C403.7.4 (energy recovery ventilation systems) requires an ERV/HRV when a system''s design supply airflow rate and its percentage of outdoor air exceed thresholds given in tables that vary by climate zone and operating hours. The minimum recovery effectiveness (commonly 50% enthalpy recovery, with conditions) is also specified. The point is to recover heat from exhaust air, which matters in cold Massachusetts winters.', 'IECC C403.7.4 / Table C403.7.4(1)-(2) (2021) — Energy recovery ventilation systems', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-ce-commercial-energy-efficiency', 'avancado', true, 'Confirmado: C403.7.4 dispara ERV por combinacao de supply airflow (cfm) + % de outdoor air, por climate zone/horas de operacao; minimo de recuperacao ~50% enthalpy com condicoes.'),
  ('iecc-104', 'IECC', 'commercial-hvac-efficiency-c403', 'The 2021 IECC C403.3.2 (Tables C403.3.2) establishes minimum equipment efficiencies for HVAC equipment. These tables are largely harmonized with which standard?', '{"A": "ANSI/ASHRAE/IES Standard 90.1 minimum equipment efficiencies (and federal appliance standards)", "B": "The National Electrical Code", "C": "The Uniform Plumbing Code", "D": "OSHA 1926"}'::jsonb, 'A', 'IECC C403.3.2 references minimum efficiency tables (for unitary air conditioners, heat pumps, furnaces, boilers, chillers, etc.) that are coordinated with ANSI/ASHRAE/IES Standard 90.1 and federal minimum appliance/equipment efficiency standards. The contractor must select equipment meeting the SEER/EER/IEER/AFUE/COP values in the applicable table. The NEC, UPC and OSHA govern unrelated subject matter.', 'IECC C403.3.2 / Tables C403.3.2 (2021) — Minimum equipment efficiencies', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-ce-commercial-energy-efficiency', 'intermediario', true, 'Confirmado: tabelas de eficiencia de equipamento HVAC de C403.3.2 sao harmonizadas com ASHRAE 90.1 e padroes federais de eficiencia.'),
  ('iecc-105', 'IECC', 'commercial-steel-frame-c402', 'Under the 2021 IECC commercial envelope table (C402.1.3), why does a STEEL-framed wall require a higher cavity-plus-continuous insulation value than a wood-framed wall of the same nominal depth?', '{"A": "Wood walls never need insulation", "B": "Steel walls are taller", "C": "Steel is cheaper so more insulation is added arbitrarily", "D": "Steel studs are highly conductive and create thermal bridges, so the code mandates more continuous insulation to offset the lost effective R-value"}'::jsonb, 'D', 'Steel framing has very high thermal conductivity, so heat short-circuits through the studs (thermal bridging), drastically lowering the effective R-value of cavity insulation. To compensate, IECC Table C402.1.3 requires steel-framed walls to have higher cavity R plus continuous insulation (ci) than wood-framed walls. The continuous insulation breaks the thermal bridge across the studs.', 'IECC C402.1.3 / Table C402.1.3 (2021) — Steel-frame wall insulation', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-ce-commercial-energy-efficiency', 'intermediario', true, 'Confirmado conceitualmente: steel framing = ponte termica alta, por isso C402.1.3 exige mais ci do que parede de madeira equivalente.'),
  ('iecc-106', 'IECC', 'commercial-c402-fenestration-area', 'Under the 2021 IECC C402.4.1, the vertical fenestration area of a commercial building is generally limited to what maximum percentage of the gross above-grade wall area for the prescriptive compliance path?', '{"A": "30 percent", "B": "50 percent", "C": "40 percent", "D": "There is no limit"}'::jsonb, 'C', 'IECC C402.4.1 limits vertical fenestration to a maximum of 40 percent of the gross above-grade wall area for the prescriptive (R-value/U-factor) compliance path, subject to daylighting conditions. Buildings exceeding 40% window-to-wall ratio must use the C407 Total Building Performance path. (The 2015 IECC capped it at 30%; the 2021 retained the increased 40% allowance with daylighting conditions.)', 'IECC C402.4.1 (2021) — Maximum fenestration area', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-ce-commercial-energy-efficiency', 'avancado', true, 'Confirmado: C402.4.1 limita fenestration vertical a 40% da area de parede acima do grade no caminho prescritivo (com condicoes de daylighting); acima disso usar C407.'),
  ('iecc-107', 'IECC', 'commercial-total-building-performance-c407', 'Under the 2021 IECC C407 (Total Building Performance), a proposed commercial building complies if its annual energy cost (or energy use) is no greater than that of which reference?', '{"A": "A ''standard reference design'' building of the same configuration built to the prescriptive requirements of the code", "B": "Any LEED Platinum building", "C": "The most efficient building in the city", "D": "A net-zero building"}'::jsonb, 'A', 'IECC C407 lets a building comply by whole-building energy simulation: the ''proposed design'' must have an annual energy cost (or, in the 2021 edition''s energy-use option) less than or equal to a ''standard reference design'' that is identical in size, orientation and use but built to the prescriptive provisions of the code. This performance path enables design flexibility (e.g., more glazing) as long as overall energy is offset elsewhere.', 'IECC C407.2 / C407.3 (2021) — Total Building Performance', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-ce-commercial-energy-efficiency', 'intermediario', true, 'Confirmado: C407 compara proposed design x standard reference design (mesma config, construido ao prescritivo) por energy cost/use anual.'),
  ('iecc-109', 'IECC', 'commercial-lighting-controls-c405', 'Under the 2021 IECC C405.2.1, occupant-sensor lighting controls are required in many space types. In an enclosed space such as a private office or conference room, the control must automatically do what?', '{"A": "Lock the door", "B": "Increase brightness when empty", "C": "Turn lighting OFF (or reduce it) within a set time after the space is vacated", "D": "Run lights 24 hours a day"}'::jsonb, 'C', 'IECC C405.2.1 requires occupant-sensor controls that automatically turn lighting off (or reduce it to a setback level) within a specified time, commonly 20 minutes, after all occupants leave the space. Required spaces include private offices, conference/meeting rooms, restrooms, storage and similar enclosed areas. This eliminates lighting energy use in unoccupied rooms, complementing the daylight-responsive controls of C405.2.4.', 'IECC C405.2.1 (2021) — Occupant-sensor controls', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-ce-commercial-energy-efficiency', 'intermediario', true, 'Confirmado: C405.2.1 exige occupant-sensor que desliga/reduz a iluminacao apos a saida (tipicamente 20 min) em offices, salas de reuniao, banheiros, storage.'),
  ('iecc-110', 'IECC', 'commercial-vestibule-c402', 'Under the 2021 IECC C402.5.7, building entrances that separate conditioned space from the exterior generally require an enclosed vestibule, but the code lists exceptions. Which of the following is an EXEMPTED door that does NOT require a vestibule?', '{"A": "All doors in Climate Zone 5", "B": "The main public entrance of a large department store", "C": "The lobby door of a 10-story office tower", "D": "Doors not intended to be used by the public, such as a loading-dock door or doors opening directly from a dwelling unit"}'::jsonb, 'D', 'IECC C402.5.7 requires vestibules at building entrances in Climate Zones 3 through 8 to limit air infiltration, but it exempts several doors: those not intended for public use, doors opening directly from a dwelling unit, revolving doors, doors used primarily for vehicle/material movement (loading docks), and entrances to buildings smaller than a stated area. Massachusetts (CZ5/6) does require vestibules at qualifying public entrances.', 'IECC C402.5.7 (2021) — Vestibules and exceptions', 'https://codes.iccsafe.org/content/IECC2021P1/chapter-4-ce-commercial-energy-efficiency', 'intermediario', true, 'Confirmado: C402.5.7 exige vestibulo em CZ3-8 mas isenta portas nao-publicas, saidas de dwelling unit, loading dock, revolving doors, e predios pequenos.'),
  ('iecc-001', 'IECC', '', 'Under the IECC climate zone system, the large majority of Massachusetts (Greater Boston, Worcester County, Cape Cod) is assigned to which climate zone?', '{"A": "Climate Zone 3", "B": "Climate Zone 4", "C": "Climate Zone 5", "D": "Climate Zone 6"}'::jsonb, 'C', 'Most of Massachusetts is Climate Zone 5A (cool-humid). The IECC assigns climate zones by county in Table C301.1/R301.1, based on ASHRAE Standard 169 heating/cooling degree-day data. Exceptions in MA: Dukes (Martha''s Vineyard) and Nantucket counties are Zone 4A, and Berkshire County plus higher hill towns are Zone 6A.', 'IECC R301.1 / Table R301.1 (Climate Zones); ASHRAE 169', 'https://massachusettshvacauthority.com/massachusetts-climate-zones-and-hvac-selection', 'iniciante', true, ''),
  ('iecc-002', 'IECC', '', 'On the IECC climate zone map, locations such as Helena, Montana and Big Horn County, Wyoming fall into which climate zone?', '{"A": "Climate Zone 4", "B": "Climate Zone 5", "C": "Climate Zone 6", "D": "Climate Zone 7"}'::jsonb, 'C', 'Helena, MT (Lewis and Clark County) and Big Horn County, WY are IECC Climate Zone 6B (cold-dry). The CSL exam uses these out-of-state examples to test whether the candidate can read the IECC climate zone table rather than just memorize Massachusetts. Colder, higher-elevation regions sit in zones 6 through 8.', 'IECC Table R301.1 (Climate Zones by county); ASHRAE 169', 'https://basc.pnnl.gov/images/iecc-climate-zone-map', 'intermediario', true, ''),
  ('iecc-003', 'IECC', '', 'Per the IECC prescriptive insulation table (Table R402.1.2, 2018 IECC), what is the minimum ceiling (attic) R-value required in Climate Zone 5?', '{"A": "R-30", "B": "R-38", "C": "R-49", "D": "R-60"}'::jsonb, 'C', 'In the 2018 IECC prescriptive Table R402.1.2, Climate Zones 4 through 8 require a ceiling insulation value of R-49. (R-38 was the Zone 4-5 requirement in older editions such as 2009 IECC; the value was raised to R-49 in the 2012/2015/2018 editions.) Massachusetts is Zone 5, so R-49 applies.', 'IECC R402.1.2 / Table R402.1.2 (2018) — Ceiling R-value, CZ 5', 'https://up.codes/s/insulation-and-fenestration-criteria', 'intermediario', true, ''),
  ('iecc-004', 'IECC', '', 'Under the 2018 IECC prescriptive table (R402.1.2), the wood-frame wall insulation requirement for Climate Zone 5 is listed as "20 or 13+5." What does the "13+5" option mean?', '{"A": "R-13 cavity insulation plus R-5 continuous insulating sheathing", "B": "R-13 in the attic plus R-5 in the wall", "C": "13 inches of cavity plus 5 inches of sheathing", "D": "R-13 on the interior plus R-5 of air film"}'::jsonb, 'A', 'For Climate Zone 5 the 2018 IECC Table R402.1.2 lists wood-frame wall insulation as "20 or 13+5." The builder may use either R-20 cavity insulation alone, OR R-13 cavity insulation combined with R-5 continuous insulation (rigid sheathing) on the exterior. The continuous layer reduces thermal bridging through the studs.', 'IECC Table R402.1.2 (2018) — Wood Frame Wall R-value, CZ 5', 'https://up.codes/s/insulation-and-fenestration-criteria', 'intermediario', true, ''),
  ('iecc-005', 'IECC', '', 'Per the 2018 IECC prescriptive table (R402.1.2), what is the slab-edge insulation requirement (R-value and depth) for a slab-on-grade floor in Climate Zone 5?', '{"A": "R-5 to a depth of 2 ft", "B": "R-10 to a depth of 2 ft", "C": "R-10 to a depth of 4 ft", "D": "R-15 to a depth of 4 ft"}'::jsonb, 'B', 'In the 2018 IECC Table R402.1.2, slab-edge insulation for Climate Zone 5 is listed as "10, 2 ft" — meaning R-10 insulation installed to a depth of 2 feet (vertically down or extending out under the slab). Note Climate Zone 6 increases the depth to 4 ft ("10, 4 ft"). Slab insulation is required when the slab is less than 12 inches below grade.', 'IECC R402.2.10 / Table R402.1.2 (2018) — Slab R-value & depth, CZ 5', 'https://up.codes/s/insulation-and-fenestration-criteria', 'avancado', true, ''),
  ('iecc-006', 'IECC', '', 'Under the 2018 IECC Table R402.1.2, the slab-edge insulation DEPTH requirement increases from Climate Zone 5 to Climate Zone 6. What is the required depth in Climate Zone 6?', '{"A": "1 ft", "B": "2 ft", "C": "3 ft", "D": "4 ft"}'::jsonb, 'D', 'The 2018 IECC lists slab insulation as "10, 2 ft" for Climate Zone 5 and "10, 4 ft" for Climate Zone 6. The R-value stays at R-10 but the colder zone requires the insulation to extend twice as deep (4 ft) to resist frost-line heat loss. In MA, the Berkshire/hill-town areas that fall in Zone 6 would use the 4-ft depth.', 'IECC Table R402.1.2 (2018) — Slab R-value & depth, CZ 6', 'https://up.codes/s/insulation-and-fenestration-criteria', 'avancado', true, ''),
  ('iecc-007', 'IECC', '', 'Per the 2018 IECC prescriptive table (R402.1.2), what is the maximum allowed fenestration (window) U-factor in Climate Zone 5?', '{"A": "0.27", "B": "0.30", "C": "0.32", "D": "0.35"}'::jsonb, 'B', 'The 2018 IECC Table R402.1.2 sets the maximum vertical fenestration U-factor at 0.30 for Climate Zones 3 through 8 (including MA''s Zone 5). A lower U-factor means less conductive heat loss. Glazed-fenestration SHGC is listed as "NR" (not required) in the heating-dominated Zone 5.', 'IECC Table R402.1.2 (2018) — Fenestration U-factor, CZ 5', 'https://up.codes/s/insulation-and-fenestration-criteria', 'intermediario', true, ''),
  ('iecc-008', 'IECC', '', 'Per the 2018 IECC prescriptive table (R402.1.2), what is the maximum allowed SKYLIGHT U-factor in Climate Zone 5 for residential construction?', '{"A": "0.30", "B": "0.50", "C": "0.55", "D": "0.75"}'::jsonb, 'C', 'The 2018 IECC residential Table R402.1.2 allows a maximum skylight U-factor of 0.55 across Climate Zones 4 through 8. Skylights are permitted a higher U-factor than vertical windows (0.30 in Zone 5) because the code recognizes their smaller area and different installation geometry.', 'IECC Table R402.1.2 (2018) — Skylight U-factor, CZ 5', 'https://up.codes/s/insulation-and-fenestration-criteria', 'intermediario', true, ''),
  ('iecc-009', 'IECC', '', 'Per the 2018 IECC prescriptive table (R402.1.2), what is the minimum floor insulation R-value required in Climate Zone 5?', '{"A": "R-19", "B": "R-25", "C": "R-30", "D": "R-38"}'::jsonb, 'C', 'The 2018 IECC Table R402.1.2 requires R-30 floor insulation in Climate Zones 4 through 8 (footnote allows R-19 in Zones 1-2). Massachusetts (Zone 5) therefore uses R-30 over an unconditioned space such as a vented crawl space or garage.', 'IECC Table R402.1.2 (2018) — Floor R-value, CZ 5', 'https://up.codes/s/insulation-and-fenestration-criteria', 'intermediario', true, ''),
  ('iecc-010', 'IECC', '', 'Per the 2018 IECC prescriptive table (R402.1.2), the basement-wall insulation for Climate Zone 5 is listed as "15/19." What does that fraction represent?', '{"A": "R-15 continuous insulation OR R-19 cavity (framed) insulation", "B": "R-15 minimum, R-19 maximum", "C": "15% of the wall at R-19", "D": "R-15 in the floor, R-19 in the wall"}'::jsonb, 'A', 'In the IECC tables a fraction like "15/19" gives two equivalent compliance options: R-15 of continuous insulation, OR R-19 of cavity (framed) insulation. The cavity number is higher because thermal bridging through the framing reduces effective performance, so more nominal R-value is needed to match the continuous option.', 'IECC Table R402.1.2 (2018) — Basement Wall R-value, CZ 5', 'https://up.codes/s/insulation-and-fenestration-criteria', 'avancado', true, ''),
  ('iecc-011', 'IECC', '', 'The IECC offers three compliance paths for residential energy: prescriptive (R-value/U-factor tables), performance (R405 simulated energy cost), and the Energy Rating Index path. Which best describes the PRESCRIPTIVE path?', '{"A": "Meeting each listed component R-value and U-factor in Table R402.1.2", "B": "Showing the home costs less to operate than a reference design via software", "C": "Achieving a HERS-style index below a target number", "D": "Passing a blower-door test alone"}'::jsonb, 'A', 'The prescriptive path (R402) is the simplest: each building component must meet or exceed the specific R-value, U-factor, and SHGC values listed in Table R402.1.2. The performance path (R405) lets a trade-off via energy-cost simulation, and the Energy Rating Index path (R406) uses an index score. All three are valid alternatives.', 'IECC R401.2 (Compliance), R402 / R405 / R406 (2018)', 'https://www.iccsafe.org/building-safety-journal/bsj-technical/residential-compliance-options-of-the-international-energy-conservation-code/', 'intermediario', true, ''),
  ('iecc-012', 'IECC', '', 'A builder uses the Energy Rating Index (ERI) compliance path in the 2018 IECC. Compared with a higher ERI score, a LOWER ERI score indicates:', '{"A": "A less energy-efficient building", "B": "A more energy-efficient building", "C": "A larger building", "D": "No relationship to efficiency"}'::jsonb, 'B', 'The Energy Rating Index (R406, similar to a HERS index) is a scale where the reference design scores 100 and a net-zero home scores 0. A lower number means lower energy use, i.e., a MORE efficient building. To comply, the rated design''s ERI must be at or below the maximum value in Table R406.4 for its climate zone.', 'IECC R406.4 / Table R406.4 (2018) — Energy Rating Index', 'https://www.iccsafe.org/building-safety-journal/bsj-technical/residential-compliance-options-of-the-international-energy-conservation-code/', 'intermediario', true, ''),
  ('iecc-013', 'IECC', '', 'On the Energy Rating Index (ERI) compliance path of the 2018 IECC, the maximum allowed ERI score VARIES by climate zone. What is the correct relationship?', '{"A": "Every climate zone uses the same ERI target of 100", "B": "Table R406.4 lists a different maximum ERI for each climate zone", "C": "Only Zone 5 has an ERI target; other zones use the prescriptive path", "D": "The ERI target equals the ceiling R-value"}'::jsonb, 'B', 'The 2018 IECC Table R406.4 assigns a specific maximum ERI to each climate zone (zones 1-8). The candidate must know the target is climate-zone-specific and is read from Table R406.4, not a single universal number. (Exact per-zone values should be read from the current code table; they were revised between the 2015, 2018, and 2021 editions.)', 'IECC R406.4 / Table R406.4 (2018) — Maximum Energy Rating Index by climate zone', 'https://www.iccsafe.org/building-safety-journal/bsj-technical/residential-compliance-options-of-the-international-energy-conservation-code/', 'intermediario', true, ''),
  ('iecc-014', 'IECC', '', 'In the commercial provisions of the 2018 IECC (Section C405), automatic daylight-responsive lighting controls are required in a primary sidelit daylight zone when the general lighting in that zone exceeds:', '{"A": "25 watts", "B": "75 watts", "C": "150 watts", "D": "300 watts"}'::jsonb, 'B', 'Per 2018 IECC C405.2.4, daylight-responsive controls are required where the connected general lighting power within a primary sidelit daylight zone (or within a toplit daylight zone) is more than 75 watts. These controls automatically dim or switch electric lighting when daylight is available, cutting energy use.', 'IECC C405.2.4 (2018) — Daylight-responsive controls', 'https://up.codes/s/daylight-responsive-controls', 'avancado', true, ''),
  ('iecc-015', 'IECC', '', 'Under IECC C405.2.4, how is the PRIMARY sidelit daylight zone defined relative to a window in the wall?', '{"A": "It extends out from the window up to 1.0 times the head height of the window, and along the window wall to the window edges (limited by full-height walls)", "B": "It extends out 3.0 times the window height in every direction", "C": "It is the entire room regardless of window size", "D": "It is only the 12 inches directly under the window sill"}'::jsonb, 'A', 'The primary sidelit daylight zone extends into the room a distance of up to 1.0 times the height from the floor to the top (head) of the fenestration, and laterally along the wall to the nearest full-height wall (or up to 0.5x the head height beyond each window edge). This is the zone that receives the most daylight and where daylight-responsive controls deliver the most savings.', 'IECC C405.2.4 / definitions (2018) — Primary sidelit daylight zone', 'https://up.codes/s/daylight-responsive-controls', 'avancado', true, ''),
  ('iecc-017', 'IECC', '', 'The IECC assigns each U.S. location to a climate zone primarily using which weather metric(s)?', '{"A": "Average wind speed only", "B": "Heating degree-days and cooling degree-days (plus a moisture/marine designator)", "C": "Annual rainfall only", "D": "Elevation above sea level only"}'::jsonb, 'B', 'IECC climate zones (Table C301.3 / R301.3, derived from ASHRAE 169) are set by heating degree-days (HDD) and cooling degree-days (CDD), with a letter suffix for moisture regime: A (humid/moist), B (dry), C (marine). Zones 5 and higher are heating-dominated; Massachusetts is 5A (cool, moist). This is why MA codes emphasize insulation and low window U-factors over solar heat gain.', 'IECC C301.3 / Table C301.3 (Climate zone definitions); ASHRAE 169', 'https://codes.iccsafe.org/s/IECC2021P3/chapter-3-ce-general-requirements/IECC2021P3-CE-Ch03-SecC301.3', 'intermediario', true, ''),
  ('iecc-018', 'IECC', '', 'Why does the IECC prescriptive table list SHGC (Solar Heat Gain Coefficient) as "NR" (not required) for windows in Climate Zone 5 but enforce it in southern zones?', '{"A": "Zone 5 has no sunlight", "B": "Zone 5 is heating-dominated, so solar heat gain through windows is generally beneficial rather than a cooling penalty", "C": "SHGC only applies to skylights", "D": "Zone 5 windows are exempt from all energy requirements"}'::jsonb, 'B', 'In the 2018 IECC residential Table R402.1.2, the glazed-fenestration SHGC is "NR" for Climate Zones 4 (except Marine) through 8 because these are heating-dominated climates where wintertime solar gain helps offset heating loads. Hot zones (1-3) cap SHGC at 0.25 to limit cooling loads. Massachusetts is Zone 5, hence NR.', 'IECC Table R402.1.2 (2018) — Glazed Fenestration SHGC, CZ 5', 'https://up.codes/s/insulation-and-fenestration-criteria', 'avancado', true, ''),
  ('irc-036', 'IRC', 'garage-separation', 'A door leading from a private garage into a dwelling must meet one of several constructions. Which of the following is NOT an acceptable door for this opening?', '{"A": "A solid wood door not less than 1-3/8 inches thick", "B": "A solid or honeycomb-core steel door not less than 1-3/8 inches thick", "C": "A 20-minute fire-rated door", "D": "A hollow-core wood door not less than 1-3/4 inches thick"}'::jsonb, 'D', 'R302.5.1 permits only three door types between a garage and the dwelling: a solid wood door at least 1-3/8 inches thick, a solid or honeycomb-core steel door at least 1-3/8 inches thick, or a 20-minute fire-rated door. A hollow-core wood door does not qualify regardless of thickness. The door must also be self-closing and self-latching.', 'IRC R302.5.1', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-3-building-planning/IRC2021P2-Pt03-Ch03-SecR302.5', 'intermediario', true, 'Confirmado contra IRC 2021 R302.5.1 (ICC Digital Codes / up.codes): solid wood 1-3/8 in, solid/honeycomb-core steel 1-3/8 in, or 20-minute rated; self-closing and self-latching.'),
  ('irc-037', 'IRC', 'garage-separation', 'Openings from a private garage are prohibited from communicating directly with which of the following rooms?', '{"A": "A kitchen", "B": "A room used for sleeping purposes", "C": "A laundry room", "D": "A dining room"}'::jsonb, 'B', 'R302.5.1 prohibits openings from a private garage directly into a room used for sleeping purposes. Openings into other habitable rooms such as kitchens, living rooms or laundry rooms are permitted provided the door complies with the required construction and self-closing/self-latching provisions.', 'IRC R302.5.1', 'https://up.codes/s/dwelling-garage-opening-and-penetration-protection', 'iniciante', true, 'Confirmado contra IRC 2021 R302.5.1: no opening from garage directly into a sleeping room.'),
  ('irc-038', 'IRC', 'garage-separation', 'Per Table R302.6, the garage side of a wall separating the garage from the residence (and attics) must be protected with at least what material?', '{"A": "1/2-inch gypsum board", "B": "5/8-inch Type X gypsum board", "C": "3/8-inch wood structural panel", "D": "No protection is required"}'::jsonb, 'A', 'Table R302.6 requires not less than 1/2-inch gypsum board (or equivalent) applied to the garage side for separation from the residence and attics. The more stringent 5/8-inch Type X requirement applies specifically to garages located beneath habitable rooms and to the structure supporting that separation.', 'IRC Table R302.6', 'https://up.codes/s/dwelling-garage-fire-separation-required', 'intermediario', true, 'Confirmado contra IRC 2021 Table R302.6: residence/attic separation = 1/2 in gypsum on garage side; habitable rooms above = 5/8 in Type X.'),
  ('irc-039', 'IRC', 'garage-separation', 'When a garage is located beneath habitable rooms, the habitable space above must be separated from the garage by not less than what?', '{"A": "1/2-inch regular gypsum board", "B": "5/8-inch Type X gypsum board or equivalent", "C": "Two layers of 1/2-inch gypsum board", "D": "1-hour rated concrete assembly"}'::jsonb, 'B', 'Per Table R302.6, garages beneath habitable rooms must be separated from those rooms by not less than 5/8-inch Type X gypsum board or equivalent. Where the separation is a floor-ceiling assembly, the structure supporting the separation must also be protected by not less than 1/2-inch gypsum board.', 'IRC Table R302.6', 'https://media.iccsafe.org/news/eNews/2010v7n10/IRC302.6.pdf', 'intermediario', true, 'Confirmado contra IRC 2021 Table R302.6: garage beneath habitable rooms = 5/8 in Type X to the habitable rooms above.'),
  ('irc-040', 'IRC', 'fireblocking', 'In wood-frame construction, fireblocking is required in concealed vertical stud wall and partition cavities at the ceiling and floor levels at intervals not exceeding what dimension?', '{"A": "8 feet", "B": "10 feet", "C": "12 feet", "D": "16 feet"}'::jsonb, 'B', 'R302.11 requires fireblocking in concealed spaces of stud walls and partitions vertically at the ceiling and floor levels, and horizontally at intervals not exceeding 10 feet. This breaks up continuous concealed cavities so fire cannot travel unimpeded through them.', 'IRC R302.11', 'https://codes.iccsafe.org/s/THPOTIRC2021P1/part-iii-building-planning-and-construction/THPOTIRC2021P1-Pt03-Ch03-SecR302.11', 'intermediario', true, 'Confirmado contra IRC 2021 R302.11(1): vertical at ceiling/floor levels and horizontal intervals not exceeding 10 ft.'),
  ('irc-041', 'IRC', 'fireblocking', 'Which of the following is a required fireblocking location under IRC R302.11?', '{"A": "Only at the exterior corners of the building", "B": "At interconnections between concealed vertical and horizontal spaces such as soffits, drop ceilings and cove ceilings", "C": "Only in masonry chimneys", "D": "Only in detached accessory structures"}'::jsonb, 'B', 'R302.11 specifically requires fireblocking at interconnections between concealed vertical and horizontal spaces such as occur at soffits, drop ceilings and cove ceilings, as well as at the top and bottom of stairs between stringers, and at openings around vents, pipes, ducts, cables and wires at ceiling and floor levels.', 'IRC R302.11', 'https://codes.iccsafe.org/s/THPOTIRC2021P1/part-iii-building-planning-and-construction/THPOTIRC2021P1-Pt03-Ch03-SecR302.11', 'intermediario', true, 'Confirmado contra IRC 2021 R302.11(2): interconnections at soffits, drop ceilings, cove ceilings.'),
  ('irc-042', 'IRC', 'fireblocking', 'Which of the following is an approved fireblocking material under IRC R302.11.1?', '{"A": "Loose-fill cellulose insulation in any location", "B": "Nominal 2-inch lumber", "C": "1/4-inch hardboard", "D": "Unfaced fiberglass batt of any thickness in vertical cavities"}'::jsonb, 'B', 'R302.11.1 lists approved fireblocking materials including 2-inch nominal lumber; two thicknesses of 1-inch nominal lumber with broken lap joints; one thickness of 23/32-inch wood structural panels with joints backed; 1/2-inch gypsum board; 1/4-inch cement-based millboard; and certain batts or blankets of mineral wool or glass fiber, among others. Plain 1/4-inch hardboard is not listed.', 'IRC R302.11.1', 'https://codes.iccsafe.org/s/IRC2021P2/part-iii-building-planning-and-construction/IRC2021P2-Pt03-Ch03-SecR302.11.1', 'avancado', true, 'Confirmado contra IRC 2021 R302.11.1: 2 in nominal lumber listed; loose-fill insulation only acceptable where specifically tested/permitted, not generically.'),
  ('irc-043', 'IRC', 'draftstopping', 'In combustible construction where there is usable space both above and below a floor-ceiling assembly concealed space, draftstopping must be installed so the concealed area does not exceed what?', '{"A": "500 square feet", "B": "1,000 square feet", "C": "2,000 square feet", "D": "3,000 square feet"}'::jsonb, 'B', 'R302.12 requires draftstops so that the concealed floor-ceiling space does not exceed 1,000 square feet, with the draftstops dividing the space into approximately equal areas. This applies in combustible construction where there is usable space both above and below the concealed space.', 'IRC R302.12', 'https://codes.iccsafe.org/s/IRC2021P3/part-iii-building-planning-and-construction/IRC2021P3-Pt03-Ch03-SecR302.12', 'intermediario', true, 'Confirmado contra IRC 2021 R302.12: 1,000 sq ft max, divided approximately equally.'),
  ('irc-044', 'IRC', 'draftstopping', 'What is the minimum acceptable draftstopping material thickness for gypsum board under IRC R302.12.1?', '{"A": "1/4-inch gypsum board", "B": "3/8-inch gypsum board", "C": "1/2-inch gypsum board", "D": "5/8-inch Type X gypsum board only"}'::jsonb, 'C', 'R302.12.1 requires draftstopping materials to be not less than 1/2-inch gypsum board, 3/8-inch wood structural panels, or other approved materials adequately supported. Note the wood structural panel minimum is 3/8 inch, but gypsum board must be at least 1/2 inch.', 'IRC R302.12.1', 'https://up.codes/s/draftstopping', 'intermediario', true, 'Confirmado contra IRC 2021 R302.12.1: 1/2 in gypsum board or 3/8 in wood structural panel.'),
  ('irc-045', 'IRC', 'smoke-alarms', 'Under IRC R314, smoke alarms are required in all of the following locations EXCEPT:', '{"A": "In each sleeping room", "B": "Outside each separate sleeping area in the immediate vicinity of the bedrooms", "C": "On each additional story of the dwelling, including basements", "D": "Inside the attached garage"}'::jsonb, 'D', 'R314.3 requires smoke alarms in each sleeping room, outside each separate sleeping area in the immediate vicinity of the bedrooms, and on each additional story including basements and habitable attics. Smoke alarms are not required inside an attached garage; garages are an environment where heat detectors (not smoke alarms) are used to avoid nuisance alarms.', 'IRC R314.3', 'https://up.codes/s/smoke-alarms-and-heat-detection', 'intermediario', true, 'Confirmado contra IRC 2021 R314.3: sleeping room, outside each sleeping area, each story/basement. No garage requirement.'),
  ('irc-046', 'IRC', 'smoke-alarms', 'Where more than one smoke alarm is required in a dwelling unit, what additional requirement applies?', '{"A": "They must be hardwired only and never battery backed", "B": "They must be interconnected so that activation of one alarm activates all alarms", "C": "They must each have an independent circuit", "D": "They must be located only on the ceiling"}'::jsonb, 'B', 'R314.4 requires that where more than one smoke alarm is required, the alarms be interconnected so that actuation of one alarm activates all alarms in the dwelling unit. Listed wireless alarms that all sound on activation of one satisfy the interconnection requirement without physical wiring.', 'IRC R314.4', 'https://up.codes/s/smoke-alarms-and-heat-detection', 'iniciante', true, 'Confirmado contra IRC 2021 R314.4: interconnection required; listed wireless alarms acceptable.'),
  ('irc-047', 'IRC', 'co-alarms', 'Under IRC R315, carbon monoxide alarms are required for new dwellings under which condition?', '{"A": "Only in all-electric homes", "B": "In dwellings with fuel-fired appliances or with an attached garage", "C": "Only when the dwelling exceeds two stories", "D": "Only in dwellings with a fireplace"}'::jsonb, 'B', 'R315.2 requires carbon monoxide alarms in new dwelling units that contain fuel-fired appliances and in dwelling units that have attached garages with an opening communicating with the dwelling. An all-electric home with no attached garage and no fuel-burning appliance would not trigger the requirement.', 'IRC R315.2', 'https://www.bcnv.org/DocumentCenter/View/55/Smoke-and-Carbon-Monoxide-Alarms-PDF', 'iniciante', true, 'Confirmado contra IRC 2021 R315.2.1: fuel-fired appliance OR attached garage triggers CO alarm requirement.'),
  ('irc-048', 'IRC', 'co-alarms', 'Where required, carbon monoxide alarms must be installed in what location within the dwelling?', '{"A": "Inside each sleeping room", "B": "Outside each separate sleeping area in the immediate vicinity of the bedrooms", "C": "Only in the basement", "D": "Only adjacent to the fuel-fired appliance"}'::jsonb, 'B', 'R315.3 requires carbon monoxide alarms outside each separate sleeping area in the immediate vicinity of the bedrooms. An exception requires a CO alarm inside the bedroom when a fuel-burning appliance is located within that bedroom or its attached bathroom.', 'IRC R315.3', 'https://www.ncosfm.gov/residential/0315-carbon-monoxide-alarms/open', 'intermediario', true, 'Confirmado contra IRC 2021 R315.3: outside each sleeping area in vicinity of bedrooms; exception for fuel-burning appliance in bedroom.'),
  ('irc-049', 'IRC', 'glazing', 'Glazing adjacent to a door is a hazardous location requiring safety glazing when the nearest vertical edge is within a 24-inch arc of the door''s vertical edge AND the bottom exposed edge of the glazing is less than what height above the floor?', '{"A": "36 inches", "B": "48 inches", "C": "60 inches", "D": "72 inches"}'::jsonb, 'C', 'R308.4.2 defines glazing adjacent to doors as a hazardous location when the nearest vertical edge is within a 24-inch arc of either vertical edge of the door in the closed position AND the bottom exposed edge of the glazing is less than 60 inches above the floor or walking surface. Both conditions must be met.', 'IRC R308.4.2', 'https://www.co.routt.co.us/DocumentCenter/View/15198', 'intermediario', true, 'Confirmado contra IRC 2021 R308.4.2: 24 in arc + bottom edge < 60 in above floor.'),
  ('irc-050', 'IRC', 'glazing', 'Glazing in fixed and operable panels (other than near doors) is considered a hazardous location requiring safety glazing when which set of conditions ALL apply?', '{"A": "Exposed area > 9 sq ft, bottom edge < 18 in above floor, top edge > 36 in above floor, and a walking surface within 36 in horizontally", "B": "Exposed area > 4 sq ft, bottom edge < 24 in above floor, and no walkway nearby", "C": "Exposed area > 12 sq ft and located on a second story", "D": "Any glazing larger than 6 sq ft regardless of height"}'::jsonb, 'A', 'R308.4.3 establishes the four conditions that must ALL be met: the exposed area of an individual pane is greater than 9 square feet; the bottom edge is less than 18 inches above the floor; the top edge is greater than 36 inches above the floor; and one or more walking surfaces are within 36 inches horizontally of the glazing.', 'IRC R308.4.3', 'https://www.co.routt.co.us/DocumentCenter/View/15198', 'avancado', true, 'Confirmado contra IRC 2021 R308.4.3: >9 sq ft, bottom <18 in, top >36 in, walking surface within 36 in (all four).'),
  ('irc-051', 'IRC', 'stairways', 'What is the minimum clear width of a residential stairway above the permitted handrail height and below the required headroom?', '{"A": "30 inches", "B": "32 inches", "C": "34 inches", "D": "36 inches"}'::jsonb, 'D', 'R311.7.1 requires stairways to be not less than 36 inches in clear width at all points above the permitted handrail height and below the required headroom height. Where a handrail is installed on one side, the clear width at and below the handrail may be reduced, but not below 31-1/2 inches (or 27 inches with handrails on both sides).', 'IRC R311.7.1', 'https://www.co.routt.co.us/DocumentCenter/View/15202', 'iniciante', true, 'Confirmado contra IRC 2021 R311.7.1: 36 in clear width; reductions with handrails to 31.5 in (one side) / 27 in (both).'),
  ('irc-052', 'IRC', 'stairways', 'What is the minimum headroom for a residential stairway, measured vertically from the sloped line adjoining the tread nosing?', '{"A": "6 feet 4 inches", "B": "6 feet 6 inches", "C": "6 feet 8 inches", "D": "7 feet 0 inches"}'::jsonb, 'C', 'R311.7.2 requires stairway headroom of not less than 6 feet 8 inches measured vertically from the sloped line adjoining the tread nosing or from the floor surface of the landing or platform.', 'IRC R311.7.2', 'https://www.co.routt.co.us/DocumentCenter/View/15202', 'iniciante', true, 'Confirmado contra IRC 2021 R311.7.2: 6 ft 8 in headroom.'),
  ('irc-053', 'IRC', 'stairways', 'For a straight-run stairway, what is the minimum landing depth in the direction of travel?', '{"A": "30 inches", "B": "36 inches", "C": "42 inches", "D": "48 inches"}'::jsonb, 'B', 'R311.7.6 requires a floor or landing at the top and bottom of each stairway. Where the stairway has a straight run, the landing depth in the direction of travel must be not less than 36 inches. The width perpendicular to the direction of travel must be at least the width of the stairway served.', 'IRC R311.7.6', 'https://codes.iccsafe.org/s/IRC2021P3/chapter-3-building-planning/IRC2021P3-Pt03-Ch03-SecR311.7.6', 'intermediario', true, 'Confirmado contra IRC 2021 R311.7.6: straight-run landing depth >= 36 in.'),
  ('irc-054', 'IRC', 'handrails', 'Handrails on stairways must be at what height above the tread nosing?', '{"A": "Not less than 30 inches and not more than 34 inches", "B": "Not less than 34 inches and not more than 38 inches", "C": "Not less than 36 inches and not more than 42 inches", "D": "Exactly 36 inches"}'::jsonb, 'B', 'R311.7.8.1 requires handrail height, measured vertically from the sloped plane adjoining the tread nosing (or finish surface of ramp slope), to be not less than 34 inches and not more than 38 inches. Note this differs from guard height (36 inches minimum).', 'IRC R311.7.8.1', 'https://www.cdaid.org/files/Building/Applications/Stairs_and_Handrails_2021.pdf', 'iniciante', true, 'Confirmado contra IRC 2021 R311.7.8.1: handrail 34-38 in above nosing.'),
  ('irc-055', 'IRC', 'handrails', 'A Type I handrail with a circular cross section must have an outside diameter within what range?', '{"A": "Not less than 1 inch and not more than 1-1/2 inches", "B": "Not less than 1-1/4 inches and not more than 2 inches", "C": "Not less than 1-1/2 inches and not more than 2-1/2 inches", "D": "Not less than 2 inches and not more than 3 inches"}'::jsonb, 'B', 'R311.7.8.5 requires Type I handrails with a circular cross section to have an outside diameter of not less than 1-1/4 inches and not more than 2 inches. Non-circular Type I handrails must have a perimeter of 4 to 6-1/4 inches and a cross-sectional dimension of not more than 2-1/4 inches.', 'IRC R311.7.8.5', 'https://up.codes/s/grip-size', 'intermediario', true, 'Confirmado contra IRC 2021 R311.7.8.5: Type I circular OD 1-1/4 to 2 in; perimeter 4 to 6-1/4 in if non-circular.'),
  ('irc-056', 'IRC', 'ramps', 'A ramp serving the required egress door must have a slope not steeper than what?', '{"A": "1 unit vertical in 8 units horizontal", "B": "1 unit vertical in 10 units horizontal", "C": "1 unit vertical in 12 units horizontal", "D": "1 unit vertical in 20 units horizontal"}'::jsonb, 'C', 'R311.8.1 limits ramps serving the required egress door to a maximum slope of 1 unit vertical in 12 units horizontal (8.3 percent). Where physical site constraints make 1:12 impractical, other ramps may be up to 1:8, but the egress ramp itself is held to 1:12.', 'IRC R311.8.1', 'https://up.codes/s/handrails-required', 'intermediario', true, 'Confirmado contra IRC 2021 R311.8.1: egress ramp max 1:12; other ramps up to 1:8.'),
  ('irc-057', 'IRC', 'ramps', 'A handrail is required on at least one side of a ramp when the ramp slope exceeds what?', '{"A": "1 unit vertical in 20 units horizontal", "B": "1 unit vertical in 12 units horizontal", "C": "1 unit vertical in 8 units horizontal", "D": "Handrails are never required on residential ramps"}'::jsonb, 'B', 'R311.8.3 requires handrails on at least one side of ramps that exceed a slope of 1 unit vertical in 12 units horizontal (8.33 percent). Ramps at 1:12 or flatter do not require handrails by this section.', 'IRC R311.8.3', 'https://up.codes/s/handrails-required', 'intermediario', true, 'Confirmado contra IRC 2021 R311.8.3: handrail required where ramp slope > 1:12.'),
  ('irc-058', 'IRC', 'ceiling-height', 'What is the minimum ceiling height for habitable spaces and hallways under IRC R305.1?', '{"A": "6 feet 8 inches", "B": "7 feet 0 inches", "C": "7 feet 6 inches", "D": "8 feet 0 inches"}'::jsonb, 'B', 'R305.1 requires habitable space, hallways, and portions of basements containing these spaces to have a ceiling height of not less than 7 feet. Bathrooms, toilet rooms, and laundry rooms may be lower at 6 feet 8 inches.', 'IRC R305.1', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-3-building-planning/IRC2021P2-Pt03-Ch03-SecR305.1', 'iniciante', true, 'Confirmado contra IRC 2021 R305.1: habitable space & hallways = 7 ft; bath/toilet/laundry = 6 ft 8 in.'),
  ('irc-059', 'IRC', 'ceiling-height', 'For a room with a sloped ceiling, at least what portion of the required floor area must have a ceiling height of not less than 7 feet, with no portion counted below 5 feet?', '{"A": "25 percent", "B": "40 percent", "C": "50 percent", "D": "75 percent"}'::jsonb, 'C', 'R305.1.1 provides that for rooms with sloped ceilings, no portion with a ceiling height of less than 5 feet may be counted toward the minimum required floor area, and not less than 50 percent of the required floor area must have a ceiling height of at least 7 feet.', 'IRC R305.1.1', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-3-building-planning/IRC2021P2-Pt03-Ch03-SecR305.1', 'avancado', true, 'Confirmado contra IRC 2021 R305.1.1: sloped ceiling, 50% of required floor area >= 7 ft, nothing below 5 ft counts.'),
  ('irc-060', 'IRC', 'guards', 'Required guards must be constructed so that a sphere of what diameter cannot pass through the openings (general requirement)?', '{"A": "4 inches", "B": "4-3/8 inches", "C": "6 inches", "D": "9 inches"}'::jsonb, 'A', 'R312.1.3 requires that required guards not have openings that allow passage of a 4-inch-diameter sphere from the walking surface to the required guard height. Special provisions allow a 4-3/8-inch sphere at the triangular opening of stair treads/risers/bottom rail and a 6-inch sphere for the open sides of stairs.', 'IRC R312.1.3', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-3-building-planning/IRC2021P2-Pt03-Ch03-SecR312', 'intermediario', true, 'Confirmado contra IRC 2021 R312.1.3: 4 in sphere general; 4-3/8 in triangular stair opening; 6 in on stair open side.'),
  ('irc-061', 'IRC', 'window-fall-protection', 'Window fall protection is required under IRC R312.2 when the top of an operable window sill is less than 24 inches above the finished floor AND the opening is more than what distance above the exterior finished grade?', '{"A": "36 inches", "B": "48 inches", "C": "60 inches", "D": "72 inches"}'::jsonb, 'D', 'R312.2.1 requires window fall protection where the top of the operable window sill is less than 24 inches above the finished floor and greater than 72 inches above the finished grade or surface below on the exterior. Compliance options include limiting the opening so a 4-inch sphere cannot pass, or providing a window fall-prevention device or window guard.', 'IRC R312.2.1', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-3-building-planning/IRC2021P2-Pt03-Ch03-SecR312.2', 'intermediario', true, 'Confirmado contra IRC 2021 R312.2.1: sill < 24 in above floor AND > 72 in above grade triggers fall protection.'),
  ('irc-062', 'IRC', 'dwelling-separation', 'Dwelling units in a two-family dwelling (duplex) must be separated from each other by wall and floor assemblies with at least what fire-resistance rating?', '{"A": "No rating required if sprinklered", "B": "1/2-hour", "C": "1-hour", "D": "2-hour"}'::jsonb, 'C', 'R302.3 requires dwelling units in two-family dwellings to be separated from each other by wall and floor assemblies having not less than a 1-hour fire-resistance rating (tested per ASTM E119, UL 263, or IBC Section 703.2.2). The 2021 IRC clarified that this rating need never exceed 1 hour regardless of a lot line.', 'IRC R302.3', 'https://up.codes/s/two-family-dwellings', 'intermediario', true, 'Confirmado contra IRC 2021 R302.3: 1-hour separation between dwelling units in a two-family dwelling.'),
  ('irc-063', 'IRC', 'masonry-veneer', 'For anchored masonry veneer, each veneer tie must support not more than how much wall area?', '{"A": "2.0 square feet", "B": "2.67 square feet", "C": "3.5 square feet", "D": "4.0 square feet"}'::jsonb, 'B', 'R703.8.4.1 requires each anchored-veneer tie to support not more than 2.67 square feet of wall area, with ties spaced not more than 32 inches on center horizontally and 24 inches on center vertically. A minimum 1-inch air space is required behind the veneer.', 'IRC R703.8.4.1', 'https://up.codes/s/size-and-spacing', 'avancado', true, 'Confirmado contra IRC 2021 R703.8.4.1: 2.67 sq ft/tie; 32 in o.c. horizontal, 24 in o.c. vertical; 1 in min air space.'),
  ('irc-064', 'IRC', 'masonry-veneer', 'What is the minimum nominal air space required behind anchored masonry veneer in a veneer assembly?', '{"A": "1/2 inch", "B": "3/4 inch", "C": "1 inch", "D": "2 inches"}'::jsonb, 'C', 'R703.8.4 requires a minimum 1-inch air space behind anchored masonry/stone veneer. The air space, in combination with flashing and weep holes, allows incidental moisture to drain rather than collect against the wall framing.', 'IRC R703.8.4', 'https://up.codes/s/anchored-stone-and-masonry-veneer-general', 'intermediario', true, 'Confirmado contra IRC 2021 R703.8.4: minimum 1 in air space.'),
  ('irc-065', 'IRC', 'ice-barrier', 'Where required by climate (history of ice forming at the eaves), an ice barrier must extend from the lowest roof edge to a point at least how far inside the exterior wall line of the building?', '{"A": "12 inches", "B": "18 inches", "C": "24 inches", "D": "36 inches"}'::jsonb, 'C', 'R905.1.2 requires the ice barrier to extend from the lowest edges of all roof surfaces to a point not less than 24 inches inside the exterior wall line of the building. On roofs with a slope of 8:12 or greater, the barrier must also extend at least 36 inches measured along the roof slope from the eave edge.', 'IRC R905.1.2', 'https://codes.iccsafe.org/s/IRC2021P2/part-iii-building-planning-and-construction/IRC2021P2-Pt03-Ch09-SecR905.1.2', 'intermediario', true, 'Confirmado contra IRC 2021 R905.1.2: 24 in inside exterior wall line; +36 in along slope on roofs >= 8:12. Massachusetts is an ice-dam region where this applies.'),
  ('irc-066', 'IRC', 'ice-barrier', 'An ice barrier must consist of which of the following?', '{"A": "A single layer of #15 felt only", "B": "Two layers of underlayment cemented together OR a self-adhering polymer-modified bitumen sheet", "C": "Galvanized metal sheeting", "D": "A 6-mil polyethylene vapor retarder"}'::jsonb, 'B', 'R905.1.2 requires the ice barrier to consist of not fewer than two layers of underlayment cemented together, or a self-adhering polymer-modified bitumen sheet used in place of normal underlayment. Single-ply felt or a vapor retarder does not satisfy the ice-barrier requirement.', 'IRC R905.1.2', 'https://up.codes/viewer/maryland/irc-2021/chapter/9/roof-assemblies', 'intermediario', true, 'Confirmado contra IRC 2021 R905.1.2: two cemented layers of underlayment or self-adhering polymer-modified bitumen.'),
  ('irc-067', 'IRC', 'fasteners', 'Per Table R602.3(1), the connection of a top or sole plate to a stud by end nailing requires how many fasteners?', '{"A": "2-8d", "B": "2-16d", "C": "3-16d", "D": "4-8d"}'::jsonb, 'B', 'Table R602.3(1) calls for 2-16d (3-1/2 inch x 0.135 inch) end nails for a top or sole plate to stud connection. The alternative stud-to-sole-plate toe-nail connection uses 3-8d or 2-16d.', 'IRC Table R602.3(1)', 'https://www.cdaid.org/files/Building/Handouts/Fastner_Schedule_for_Structural_Members.pdf', 'avancado', true, 'Confirmado contra IRC 2021 Table R602.3(1): top/sole plate to stud end nail = 2-16d; stud to sole plate toe nail = 3-8d or 2-16d.'),
  ('irc-068', 'IRC', 'stair-illumination', 'Interior stairways must be provided with an artificial light source capable of illuminating treads and landings to a level of not less than what?', '{"A": "1 footcandle", "B": "5 footcandles", "C": "10 footcandles", "D": "20 footcandles"}'::jsonb, 'A', 'R303.7 requires interior stairways to have an artificial light source illuminating treads and landings to levels of not less than 1 footcandle (11 lux) measured at the center of treads and landings. A wall switch is required at each floor level where the stairway has six or more risers.', 'IRC R303.7', 'https://up.codes/s/interior-stairway-illumination', 'intermediario', true, 'Confirmado contra IRC 2021 R303.7: 1 footcandle at tread/landing centers; switch where 6+ risers.'),
  ('irc-069', 'IRC', 'crawl-access', 'What is the minimum size of an under-floor (crawl space) access opening provided through the floor?', '{"A": "16 inches by 24 inches", "B": "18 inches by 24 inches", "C": "22 inches by 30 inches", "D": "24 inches by 24 inches"}'::jsonb, 'B', 'R408.4 requires access openings through the floor to be not smaller than 18 inches by 24 inches. Openings through a perimeter (foundation) wall may be smaller, at not less than 16 inches by 24 inches. Through-wall openings must not be located under a door to the residence.', 'IRC R408.4', 'https://up.codes/s/crawl-spaces', 'intermediario', true, 'Confirmado contra IRC 2021 R408.4: floor access 18x24; perimeter wall access 16x24.'),
  ('irc-070', 'IRC', 'foundation-drainage', 'Where a gravel or crushed-stone foundation drain is used, it must extend at least how far above the top of the footing and be covered with an approved filter membrane?', '{"A": "2 inches", "B": "4 inches", "C": "6 inches", "D": "12 inches"}'::jsonb, 'C', 'R405.1 requires gravel or crushed-stone drains to extend not less than 1 foot beyond the outside edge of the footing and 6 inches above the top of the footing, and to be covered with an approved filter membrane material. Foundation drainage is required around foundations enclosing habitable or usable spaces below grade.', 'IRC R405.1', 'https://codes.iccsafe.org/s/IRC2021P2/part-iii-building-planning-and-construction/IRC2021P2-Pt03-Ch04-SecR405.1', 'avancado', true, 'Confirmado contra IRC 2021 R405.1: gravel/stone drain >= 1 ft beyond footing edge and 6 in above top of footing, filter membrane covered.'),
  ('irc-071', 'IRC', 'wall-bracing', 'For an intermittent (non-continuous) braced wall panel using Method WSP (wood structural panel), what is the typical minimum panel length in Seismic Design Categories A, B and C?', '{"A": "24 inches", "B": "36 inches", "C": "48 inches", "D": "60 inches"}'::jsonb, 'C', 'Under R602.10.5, intermittent braced wall panels using methods such as WSP are generally a minimum of 48 inches in length (covering three 16-inch stud spaces or two 24-inch stud spaces). Panels between 36 and 48 inches may be permitted with a reduced effective contribution per Table R602.10.3, and the continuous-sheathing method allows even shorter panels.', 'IRC R602.10.5', 'https://up.codes/s/minimum-length-of-a-braced-wall-panel', 'avancado', true, 'Confirmado contra IRC 2021 R602.10.5 / Table R602.10.3: intermittent WSP nominal 48 in; 36-48 in allowed with reduced credit; continuous sheathing shorter.'),
  ('irc-072', 'IRC', 'deck-ledger', 'When attaching a deck ledger to a band joist with lag screws or bolts, what is the maximum vertical (top-to-bottom) spacing between staggered fasteners along the ledger?', '{"A": "3 inches", "B": "5 inches", "C": "8 inches", "D": "12 inches"}'::jsonb, 'B', 'Per R507.9.1.3 and Figure R507.9.1.3(1), lag screws or bolts must be staggered from top to bottom along the horizontal run of the deck ledger, with a maximum vertical spacing of 5 inches. The figure also prescribes minimum edge and end distances (e.g., 2-inch end distance).', 'IRC R507.9.1.3', 'https://up.codes/s/ledger-to-band-joist-details', 'avancado', true, 'Confirmado contra IRC 2021 R507.9.1.3 / Figure R507.9.1.3(1): staggered fasteners, 5 in max vertical spacing.'),
  ('irc-073', 'IRC', 'deck-ledger', 'Which fastener is NOT permitted to attach a deck ledger to a band joist for transferring the deck load?', '{"A": "1/2-inch lag screws", "B": "1/2-inch through-bolts", "C": "Nails (toe-nailed or face-nailed)", "D": "Approved deck ledger screws listed for the application"}'::jsonb, 'C', 'R507.9.1.3 requires deck ledger attachment by 1/2-inch lag screws or bolts (or approved listed connectors) installed per Table R507.9.1.3(2). Nails are expressly not permitted for the ledger-to-band-joist load-transfer connection, a common cause of catastrophic deck collapse.', 'IRC R507.9.1.3', 'https://buildingcodegeek.com/deck-ledger-bolt-spacing-requirements-irc/', 'intermediario', true, 'Confirmado contra IRC 2021 R507.9.1: ledger attachment via 1/2 in lag screws/bolts or approved connectors; nails not permitted for this connection.'),
  ('irc-074', 'IRC', 'gypsum', 'Per Table R702.3.5, what is the minimum gypsum board thickness for a ceiling with framing spaced 16 inches on center where a water-based texture is applied?', '{"A": "3/8 inch", "B": "1/2 inch", "C": "5/8 inch", "D": "3/4 inch"}'::jsonb, 'B', 'R702.3.5 and its table require gypsum board on ceilings to be at least 1/2 inch thick for 16-inch on-center framing where a water-based texture is applied (3/8 inch is allowed only for non-textured 16-inch o.c. ceilings). For 24-inch o.c. framing the minimum increases to 5/8 inch, or 1/2-inch sag-resistant ceiling board may be used.', 'IRC R702.3.5', 'https://codes.iccsafe.org/s/IRC2021P2/part-iii-building-planning-and-construction/IRC2021P2-Pt03-Ch07-SecR702.3.5', 'avancado', true, 'Confirmado contra IRC 2021 R702.3.5: textured ceiling at 16 in o.c. = 1/2 in min; 24 in o.c. = 5/8 in or 1/2 in sag-resistant.'),
  ('irc-075', 'IRC', 'flashing', 'Under IRC R703.4, approved corrosion-resistant flashing must be applied to exterior walls in which of the following locations?', '{"A": "Only at the top of the foundation", "B": "At exterior window and door openings, at wall and roof intersections, and where exterior porches/decks attach to walls", "C": "Only behind vinyl siding", "D": "Flashing is optional in all locations if a water-resistive barrier is present"}'::jsonb, 'B', 'R703.4 requires approved corrosion-resistant flashing applied shingle-fashion to prevent water entry into the wall cavity or framing. Required locations include exterior window and door openings; at the intersection of chimneys or other masonry with frame or stucco walls; under and at the ends of masonry/wood/metal copings and sills; continuously above projecting trim; where exterior porches, decks or stairs attach to a wall; and at wall and roof intersections.', 'IRC R703.4', 'https://codes.iccsafe.org/s/IRC2021P2/part-iii-building-planning-and-construction/IRC2021P2-Pt03-Ch07-SecR703.4.1', 'intermediario', true, 'Confirmado contra IRC 2021 R703.4: flashing required at window/door openings, masonry/wall intersections, copings/sills, projecting trim, deck/porch attachments, wall-roof intersections.'),
  ('irc-076', 'IRC', 'header-spans', 'Under the IRC, header and girder spans for exterior bearing walls are determined primarily by which of the following?', '{"A": "The color of the cladding", "B": "The building width (span carried), number of stories supported, and ground snow load, per the header span tables", "C": "Only the species of lumber, regardless of load", "D": "The interior wall finish material"}'::jsonb, 'B', 'Header and girder spans in R602.7 are taken from the header span tables (e.g., Table R602.7(1) for exterior bearing walls), which are indexed by the building width / span the header carries, the number of floors and the roof/ceiling above, and the ground snow load. Larger spans, more stories, and higher snow loads all require larger or doubled members.', 'IRC R602.7 / Table R602.7(1)', 'https://up.codes/viewer/pennsylvania/irc-2021/chapter/6/wall-construction', 'intermediario', true, 'Confirmado contra IRC 2021 R602.7 and Table R602.7(1): header spans indexed by building width/span carried, stories supported, and ground snow load.'),
  ('irc-077', 'IRC', 'smoke-co-alarms', 'In existing dwellings, when are smoke alarms required to be added even without other work, per the alterations/repairs provisions of R314?', '{"A": "Never; existing dwellings are fully exempt", "B": "When alterations, repairs, or additions requiring a permit occur, or when one or more sleeping rooms are added or created", "C": "Only when the home is sold", "D": "Only when the electrical service is upgraded"}'::jsonb, 'B', 'R314.2.2 requires that where alterations, repairs, or additions requiring a permit occur, or where one or more sleeping rooms are added or created, the dwelling be provided with smoke alarms as required for new dwellings. Limited exceptions exist for exterior-only work and for not requiring new wiring where interior finishes are not removed.', 'IRC R314.2.2', 'https://up.codes/s/smoke-alarms-and-heat-detection', 'avancado', true, 'Confirmado contra IRC 2021 R314.2.2: permitted alterations/repairs/additions or new sleeping rooms trigger smoke alarm upgrade in existing dwellings.'),
  ('irc-078', 'IRC', 'combustion-air', 'A fuel-burning appliance is installed in a small mechanical closet. Per the IRC fuel-gas provisions, when all combustion air is taken from inside the building using the standard indoor method, the space must be provided with how many permanent openings to adjacent interior spaces?', '{"A": "One opening near the floor", "B": "One opening near the ceiling", "C": "Two openings, one near the top and one near the bottom of the space", "D": "No openings are required for indoor air"}'::jsonb, 'C', 'When the standard indoor combustion-air method is used, the confined space must communicate with adjacent spaces through two permanent openings, one located within the top 12 inches and one within the bottom 12 inches of the enclosure. This lets warmer air enter high and cooler air enter low, ensuring proper air movement for combustion.', 'IRC G2407 (IFGC 304)', 'https://codes.iccsafe.org/content/IRC2021P1/chapter-24-fuel-gas', 'intermediario', true, 'Confirmado contra IRC 2021 Cap. 24 (G2407, espelha IFGC 304): metodo indoor exige duas aberturas permanentes, uma no topo e uma na base. Combustion air para aparelhos a gas no IRC e governado por G2407.'),
  ('irc-079', 'IRC', 'combustion-air', 'Using the standard ''all air from inside the building'' method, each combustion-air opening connecting to adjacent spaces must have a minimum free area of:', '{"A": "1 square inch per 1,000 Btu/h of total appliance input", "B": "1 square inch per 4,000 Btu/h of total appliance input", "C": "2 square inches per 1,000 Btu/h of total appliance input", "D": "1 square foot regardless of input rating"}'::jsonb, 'A', 'For the indoor (all-air-from-inside) method, each of the two openings must have a free area of not less than 1 square inch per 1,000 Btu/h of the combined input rating of all appliances in the space, and not less than 100 square inches. The smaller 1-in-per-4,000-Btu/h figure applies to vertical outdoor-duct openings, which is a different method.', 'IRC G2407 (IFGC 304.5)', 'https://www3.iccsafe.org/states/newjersey/NJ_Residential/PDFs/NJ_Res_Chapter17.pdf', 'avancado', true, 'Confirmado: metodo indoor = 1 in2 por 1.000 Btu/h por abertura, min 100 in2. Outdoor vertical duct = 1 in2 por 4.000 Btu/h (metodo distinto).'),
  ('irc-080', 'IRC', 'dryer-exhaust', 'Unless the manufacturer''s instructions or a listed exhaust system specify otherwise, the maximum allowable length of a clothes dryer exhaust duct is:', '{"A": "25 feet", "B": "35 feet", "C": "50 feet", "D": "There is no maximum length"}'::jsonb, 'B', 'The maximum developed length of the dryer exhaust duct is 35 feet, measured from the connection at the transition duct to the outlet terminal. Each 45-degree or 90-degree bend reduces the allowable length per the deduction table, and the transition duct length is not counted in the 35 feet.', 'IRC M1502.4.6.1', 'https://up.codes/s/dryer-exhaust-ducts', 'intermediario', true, 'Confirmado contra IRC 2021 M1502.4.6.1: max 35 ft do transition duct ao terminal; bends descontam pela tabela M1502.4.6.1.'),
  ('irc-081', 'IRC', 'dryer-exhaust', 'A clothes dryer exhaust duct must have a smooth interior finish and a nominal diameter of not less than:', '{"A": "3 inches", "B": "4 inches", "C": "5 inches", "D": "6 inches"}'::jsonb, 'B', 'Dryer exhaust ducts must be 4 inches nominal in diameter and have a smooth interior finish. The smooth interior reduces lint buildup, and the duct cannot be joined with fasteners that protrude more than 1/8 inch into the airstream because protrusions catch lint and create a fire hazard.', 'IRC M1502.4.1', 'https://up.codes/s/dryer-exhaust-ducts', 'iniciante', true, 'Confirmado contra IRC 2021 M1502.4.1: 4 in nominal, smooth interior; M1502.4.2 proibe fasteners protruindo >1/8 in.'),
  ('irc-082', 'IRC', 'dryer-exhaust', 'Which statement about clothes dryer exhaust duct connections and transition ducts is correct?', '{"A": "Sheet-metal screws may be used at every joint to ensure tightness", "B": "Ducts must not be joined with screws or fasteners protruding more than 1/8 inch into the duct, and transition ducts may not exceed 8 feet", "C": "Transition ducts may be concealed within construction", "D": "Flexible transition ducts may run up to 25 feet"}'::jsonb, 'B', 'Dryer ducts cannot be joined with screws or fasteners that protrude more than 1/8 inch into the duct because protrusions trap lint. Listed and labeled flexible transition ducts are limited to a maximum of 8 feet and must not be concealed within construction.', 'IRC M1502.4.2, M1502.4.3', 'https://up.codes/s/dryer-exhaust-ducts', 'intermediario', true, 'Confirmado contra IRC 2021 M1502.4.2 (fasteners) e M1502.4.3 (transition duct max 8 ft, nao concealed).'),
  ('irc-083', 'IRC', 'dryer-exhaust', 'A dryer exhaust duct terminates on an exterior wall. Where the manufacturer''s instructions are silent on location, the terminal must be located not less than how far from any opening into the building?', '{"A": "1 foot", "B": "2 feet", "C": "3 feet", "D": "6 feet"}'::jsonb, 'C', 'When manufacturer instructions do not specify a termination location, the dryer exhaust terminal must be at least 3 feet in any direction from openings into the building, including openings in ventilated soffits. The terminal must have a backdraft damper, and screens are prohibited at the termination because they trap lint.', 'IRC M1502.3', 'https://up.codes/s/duct-termination', 'intermediario', true, 'Confirmado contra IRC 2021 M1502.3: min 3 ft de aberturas; backdraft damper exigido; screens proibidos no terminal.'),
  ('irc-084', 'IRC', 'exhaust-systems', 'A local exhaust system serving a bathroom must be capable of exhausting a minimum airflow of:', '{"A": "20 cfm intermittent or 50 cfm continuous", "B": "50 cfm intermittent or 20 cfm continuous", "C": "100 cfm intermittent or 25 cfm continuous", "D": "25 cfm intermittent or 10 cfm continuous"}'::jsonb, 'B', 'Per the local exhaust rate table, a bathroom requires a minimum of 50 cfm for intermittent operation or 20 cfm for continuous operation. Bathrooms, toilet rooms, and kitchens must each include a local exhaust system meeting the table''s minimum airflow.', 'IRC Table M1505.4.4(1)', 'https://up.codes/viewer/connecticut/irc-2021/chapter/15/exhaust-systems', 'intermediario', true, 'Confirmado contra IRC 2021 Table M1505.4.4(1): bathroom 50 cfm intermittent / 20 cfm continuous.'),
  ('irc-085', 'IRC', 'exhaust-systems', 'Exhaust air from bathrooms and toilet rooms is required to:', '{"A": "Discharge into an attic, crawl space, or other interior space", "B": "Discharge directly to the outdoors", "C": "Recirculate back into the room through a filter", "D": "Discharge into a plumbing vent stack"}'::jsonb, 'B', 'Exhaust air from bathrooms and toilet rooms must be discharged to the outdoors and cannot be released into an attic, crawl space, or other interior space. Dumping moist air into an attic causes condensation, mold, and structural damage, which is why direct outdoor discharge is required.', 'IRC M1505.2', 'https://up.codes/viewer/connecticut/irc-2021/chapter/15/exhaust-systems', 'iniciante', true, 'Confirmado contra IRC 2021 M1505.2: exhaust de banheiros/toilet rooms vai pro exterior, nao pro attic/crawl/interior.'),
  ('irc-086', 'IRC', 'water-heater', 'A storage-type water heater is installed in an attic where leakage would cause damage. The drain pan serving the water heater must be at least how deep?', '{"A": "1 inch", "B": "1 1/2 inches", "C": "2 inches", "D": "3 inches"}'::jsonb, 'B', 'Where a water heater is located in an area where leakage of the tank would cause damage, it must be installed in a drain pan not less than 1 1/2 inches deep. The pan must be of sufficient size and shape to receive dripping or condensate from the tank.', 'IRC P2801.6, P2801.6.1', 'https://up.codes/s/pan-size-and-drain', 'iniciante', true, 'Confirmado contra IRC 2021 P2801.6/P2801.6.1: pan min 1 1/2 in de profundidade.'),
  ('irc-087', 'IRC', 'water-heater', 'The drain serving a water heater pan must be an indirect waste pipe with a diameter of not less than:', '{"A": "1/2 inch", "B": "3/4 inch", "C": "1 inch", "D": "1 1/4 inches"}'::jsonb, 'B', 'The water heater pan must be drained by an indirect waste pipe of not less than 3/4 inch diameter. The pan drain must extend full-size and terminate over a suitable indirect waste receptor or floor drain, or to the exterior of the building.', 'IRC P2801.6.1', 'https://up.codes/s/pan-size-and-drain', 'iniciante', true, 'Confirmado contra IRC 2021 P2801.6.1: pan drain = indirect waste pipe min 3/4 in.'),
  ('irc-088', 'IRC', 'water-heater', 'The discharge pipe from a water heater temperature-and-pressure (T&P) relief valve must:', '{"A": "Connect directly to the building drainage system", "B": "Be reduced one pipe size below the valve outlet to increase velocity", "C": "Discharge through an air gap and terminate not more than 6 inches above the floor or waste receptor", "D": "Have a shutoff valve so it can be isolated for service"}'::jsonb, 'C', 'The relief valve discharge pipe must discharge through an air gap, must not connect directly to the drainage system, and must terminate not more than 6 inches (and not less than two pipe diameters) above the floor or waste receptor flood-level rim. The pipe must be full-size, have no valves, and not be threaded at its end so it cannot be capped.', 'IRC P2804.6.1', 'https://up.codes/s/requirements-for-discharge-piping', 'intermediario', true, 'Confirmado contra IRC 2021 P2804.6.1: air gap, sem conexao direta ao dreno, termina <=6 in e >=2x diam acima do piso, sem valvula, sem rosca na ponta.'),
  ('irc-089', 'IRC', 'water-heater', 'Which of the following is NOT permitted on a water heater relief valve discharge pipe?', '{"A": "Discharging to the pan serving the water heater", "B": "A shutoff valve installed in the discharge line", "C": "Discharging to the outdoors", "D": "Discharging to a waste receptor"}'::jsonb, 'B', 'A shutoff valve or any other valve is prohibited on the relief valve discharge line because it could be closed and defeat the safety function of the relief valve. The discharge may go to the floor, the water heater pan, a waste receptor, or the outdoors, all through an air gap.', 'IRC P2804.6.1', 'https://up.codes/s/requirements-for-discharge-piping', 'intermediario', true, 'Confirmado contra IRC 2021 P2804.6.1: proibido valvula/tee no discharge pipe; destinos validos = piso/pan/waste receptor/exterior via air gap.'),
  ('irc-090', 'IRC', 'traps', 'A fixture trap must maintain a liquid seal of not less than 2 inches and not more than:', '{"A": "3 inches", "B": "4 inches", "C": "5 inches", "D": "6 inches"}'::jsonb, 'B', 'Each fixture trap must have a liquid seal of not less than 2 inches and not more than 4 inches, unless a deeper seal is required for special conditions. The trap seal is the water held in the trap that blocks sewer gas from entering the building.', 'IRC P3201.2', 'https://up.codes/s/trap-seals-and-trap-seal-protection', 'iniciante', true, 'Confirmado contra IRC 2021 P3201.2: trap seal 2 in min, 4 in max.'),
  ('irc-091', 'IRC', 'traps', 'For a fixture drain with a 1 1/2 inch trap, the maximum developed length of the trap arm from the trap weir to the vent fitting is:', '{"A": "5 feet", "B": "6 feet", "C": "8 feet", "D": "12 feet"}'::jsonb, 'B', 'Per the trap-to-vent distance table, a 1 1/2 inch trap arm may have a maximum developed length of 6 feet to the vent at a 1/4 inch-per-foot slope. A 1 1/4 inch trap arm is limited to 5 feet and a 2 inch arm to 8 feet. Exceeding these lengths risks self-siphonage of the trap.', 'IRC Table P3105.1', 'https://up.codes/s/distance-of-trap-from-vent', 'avancado', true, 'Confirmado contra IRC 2021 Table P3105.1: 1-1/4 in = 5 ft, 1-1/2 in = 6 ft, 2 in = 8 ft, slope 1/4 in/ft.'),
  ('irc-092', 'IRC', 'traps', 'Which trap configuration is prohibited by the IRC?', '{"A": "A P-trap serving a lavatory", "B": "A double trap (two traps in series on one fixture drain)", "C": "A trap with a 2-inch seal", "D": "A trap vented within the maximum trap-arm length"}'::jsonb, 'B', 'Fixtures may not be double trapped, meaning two traps cannot be installed in series on the same fixture drain. Air trapped between the two seals prevents proper drainage. Each plumbing fixture is required to have a single, separate trap.', 'IRC P3201.6', 'https://up.codes/s/fixture-traps', 'intermediario', true, 'Confirmado contra IRC 2021 P3201.6: proibido double trapping; cada fixture = um trap separado (P3201.5).'),
  ('irc-093', 'IRC', 'vents', 'An open vent pipe extending through a roof must terminate not less than how far above the roof surface (where it does not serve as a walkable area or meet snow-accumulation provisions)?', '{"A": "3 inches", "B": "6 inches", "C": "12 inches", "D": "18 inches"}'::jsonb, 'B', 'Open vent pipes that extend through a roof must terminate not less than 6 inches above the roof, or 6 inches above the anticipated snow accumulation, whichever is greater. This keeps the vent opening clear so sewer gases discharge freely.', 'IRC P3103.1', 'https://up.codes/s/vent-pipes-terminating-outdoors', 'iniciante', true, 'Confirmado contra IRC 2021 P3103.1: vent min 6 in acima do telhado ou 6 in acima do acumulo de neve previsto.'),
  ('irc-094', 'IRC', 'vents', 'A vent terminal must not be located within how many feet horizontally of a door, openable window, or air intake unless it is at least 2 feet above the top of that opening?', '{"A": "4 feet", "B": "6 feet", "C": "10 feet", "D": "15 feet"}'::jsonb, 'C', 'An open vent terminal must not be located within 10 feet horizontally of a door, openable window, or other air-intake opening unless the vent terminal is at least 2 feet above the top of the opening. It also must not be less than 4 feet directly below such an opening. This prevents sewer gases from entering occupied spaces.', 'IRC P3103.5', 'https://up.codes/s/vent-terminals', 'intermediario', true, 'Confirmado contra IRC 2021 P3103.5: 10 ft horizontal de aberturas salvo 2 ft acima; nao <4 ft diretamente abaixo.'),
  ('irc-095', 'IRC', 'vents', 'A vent that terminates through a sidewall must terminate not less than how far above the highest grade within 10 feet horizontally of the terminal?', '{"A": "3 feet", "B": "6 feet", "C": "10 feet", "D": "12 feet"}'::jsonb, 'C', 'A vent terminal extending through a wall must terminate not less than 10 feet from a lot line and not less than 10 feet above the highest grade elevation within 10 feet horizontally of the terminal. Sidewall vent terminations are also prohibited beneath the building''s overhang where soffit openings exist.', 'IRC P3103.6', 'https://up.codes/s/vent-terminals', 'avancado', true, 'Confirmado contra IRC 2021 P3103.6: sidewall vent >=10 ft do lot line e >=10 ft acima do grade mais alto em 10 ft horizontal.'),
  ('irc-096', 'IRC', 'water-supply', 'The static water pressure at the building supply entrance generally must not be less than:', '{"A": "20 psi", "B": "30 psi", "C": "40 psi", "D": "60 psi"}'::jsonb, 'C', 'The minimum static pressure at the building entrance for public or private water service must be 40 psi. Where the design or branch loads require higher pressure, the pressure must be increased. This baseline ensures adequate flow at fixtures.', 'IRC P2903.3', 'https://up.codes/s/minimum-pressure', 'intermediario', true, 'Confirmado contra IRC 2021 P2903.3: pressao estatica minima na entrada = 40 psi.'),
  ('irc-097', 'IRC', 'water-supply', 'When the static water supply pressure exceeds 80 psi, the IRC requires:', '{"A": "An expansion tank only", "B": "An approved pressure-reducing valve on the main supply", "C": "Doubling the pipe size", "D": "No action; 80 psi is within the allowed range"}'::jsonb, 'B', 'Where the static pressure supplied to the building exceeds 80 psi, an approved pressure-reducing valve conforming to ASSE 1003 must be installed on the water-service pipe or the main riser. Excessive pressure stresses fixtures, valves, and appliances and increases the risk of leaks.', 'IRC P2903.3.1', 'https://up.codes/s/minimum-pressure', 'intermediario', true, 'Confirmado contra IRC 2021 P2903.3.1: pressao >80 psi exige pressure-reducing valve (ASSE 1003).'),
  ('irc-098', 'IRC', 'water-supply', 'Water distribution piping in a dwelling is sized using which of the following?', '{"A": "The total occupant load of the building", "B": "Water supply fixture units (wsfu) assigned to the fixtures served", "C": "The square footage of the dwelling", "D": "The number of bedrooms only"}'::jsonb, 'B', 'Water piping is sized based on the demand from water supply fixture units (wsfu) assigned to each fixture, combined with available pressure and developed length. The fixture-unit method converts the probable simultaneous demand of fixtures into a design flow used to size pipe.', 'IRC P2903.6', 'https://codes.iccsafe.org/s/IRC2021P3/chapter-29-water-supply-and-distribution/IRC2021P3-Pt07-Ch29-SecP2903.6', 'intermediario', true, 'Confirmado contra IRC 2021 P2903.6: dimensionamento por water supply fixture units (wsfu).'),
  ('irc-099', 'IRC', 'backflow', 'A hose bibb (sillcock) connected to the potable water supply must be protected against backflow by:', '{"A": "A check valve at the water meter", "B": "An atmospheric or hose-connection vacuum breaker", "C": "An air gap at the fixture", "D": "A reduced-pressure principle assembly"}'::jsonb, 'B', 'Sillcocks, hose bibbs, and wall hydrants with a hose connection must be protected by an atmospheric-type or pressure-type vacuum breaker, or a permanently attached hose-connection vacuum breaker. This prevents contaminated water from a hose (for example, in a bucket of chemicals) from being siphoned back into the potable supply.', 'IRC P2902.4.3', 'https://www.iccsafe.org/building-safety-journal/bsj-technical/codenotes-backflow-preventers-and-protection-of-water-supply/', 'intermediario', true, 'Confirmado contra IRC 2021 P2902.4.3: hose bibb/sillcock exige vacuum breaker (atmospheric/pressure ou hose-connection).'),
  ('irc-100', 'IRC', 'backflow', 'A pipe-applied atmospheric-type vacuum breaker must be installed at least how far above the flood-level rim of the fixture or device it serves?', '{"A": "1 inch", "B": "3 inches", "C": "6 inches", "D": "12 inches"}'::jsonb, 'C', 'A pipe-applied atmospheric-type vacuum breaker must be installed not less than 6 inches above the flood-level rim of the fixture or device served and above all downstream piping. No shutoff or control valve may be installed downstream of the device, and it must not be under continuous pressure.', 'IRC P2902.3.3', 'https://www.iccsafe.org/building-safety-journal/bsj-technical/codenotes-backflow-preventers-and-protection-of-water-supply/', 'avancado', true, 'Confirmado contra IRC 2021 P2902.3.3: atmospheric vacuum breaker >=6 in acima do flood-level rim e do downstream piping; sem valvula a jusante; sem pressao continua.'),
  ('irc-101', 'IRC', 'backflow', 'The primary purpose of backflow prevention required by the IRC is to:', '{"A": "Increase water pressure at fixtures", "B": "Protect the potable water supply from cross-connection and contamination", "C": "Reduce noise in the piping system", "D": "Prevent freezing of exterior pipes"}'::jsonb, 'B', 'Backflow prevention protects the potable water supply against backflow caused by back-pressure or back-siphonage through cross-connections. A cross-connection is any actual or potential link between potable water and a source of contamination, and backflow devices keep contaminants from being drawn or pushed into drinking water.', 'IRC P2902.1', 'https://www.iccsafe.org/building-safety-journal/bsj-technical/codenotes-backflow-preventers-and-protection-of-water-supply/', 'iniciante', true, 'Confirmado contra IRC 2021 P2902.1: protecao do potable supply contra backflow por cross-connection (back-pressure / back-siphonage).'),
  ('irc-102', 'IRC', 'receptacle-spacing', 'In a habitable room, receptacle outlets must be installed so that no point along the floor line of any wall space is more than how many feet, measured horizontally, from a receptacle?', '{"A": "4 feet", "B": "6 feet", "C": "8 feet", "D": "12 feet"}'::jsonb, 'B', 'In habitable rooms, receptacles must be placed so no point along the floor line of any wall space is more than 6 feet from a receptacle. This effectively spaces general-purpose receptacles no more than 12 feet apart, so an appliance cord of normal length always reaches an outlet.', 'IRC E3901.2', 'https://up.codes/s/general-purpose-receptacle-distribution', 'iniciante', true, 'Confirmado contra IRC 2021 E3901.2: nenhum ponto na wall space a mais de 6 ft (resultando em ~12 ft entre tomadas).'),
  ('irc-103', 'IRC', 'receptacle-spacing', 'For purposes of the general receptacle spacing rule, any wall space of what minimum width must be counted (and therefore requires a receptacle)?', '{"A": "1 foot or more", "B": "2 feet or more", "C": "3 feet or more", "D": "4 feet or more"}'::jsonb, 'B', 'A wall space 2 feet or more in width (including space measured around corners and unbroken by doorways, fireplaces, or similar openings) is counted in applying the spacing rule and must be served by a receptacle. Fixed panels in exterior walls and freestanding bar-type counters or railings are also treated as wall space.', 'IRC E3901.2.1', 'https://up.codes/s/general-purpose-receptacle-distribution', 'intermediario', true, 'Confirmado contra IRC 2021 E3901.2.1: wall space >=2 ft de largura conta para a regra de espacamento.'),
  ('irc-104', 'IRC', 'receptacle-spacing', 'Along a kitchen countertop, receptacle outlets serving the counter must be installed so that no point along the counter wall line is more than how far from a receptacle?', '{"A": "12 inches", "B": "24 inches", "C": "36 inches", "D": "48 inches"}'::jsonb, 'B', 'Countertop receptacles must be placed so no point along the counter wall line is more than 24 inches from a receptacle, which yields outlets no more than 48 inches apart. Any countertop 12 inches or wider requires a receptacle. This keeps appliance cords reaching outlets without crossing sinks or cooktops.', 'IRC E3901.4.1', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-39-power-and-lighting-distribution/IRC2021P2-Pt08-Ch39-SecE3901.4', 'intermediario', true, 'Confirmado contra IRC 2021 E3901.4.1: nenhum ponto na linha do balcao a mais de 24 in (tomadas a <=48 in); balcao >=12 in exige tomada.'),
  ('irc-105', 'IRC', 'gfci', 'Which of the following 125-volt, 15- and 20-ampere receptacle locations requires GFCI protection under the IRC?', '{"A": "A receptacle in a bedroom", "B": "A receptacle in a bathroom", "C": "A receptacle in a dining room", "D": "A receptacle in a clothes closet"}'::jsonb, 'B', 'GFCI protection is required for receptacles in bathrooms, kitchens (serving countertops), garages, outdoors, crawl spaces, unfinished basements, laundry areas, and within 6 feet of sinks, among other wet or damp locations. Bedrooms and dining rooms instead require AFCI protection, not GFCI.', 'IRC E3902.1, E3902.2', 'https://up.codes/s/arc-fault-circuit-interrupter-protection', 'intermediario', true, 'Confirmado contra IRC 2021 E3902: GFCI exigido em banheiros, cozinhas (balcao), garagens, outdoor, crawl, unfinished basement, laundry, perto de pias. Bedroom/dining = AFCI.'),
  ('irc-106', 'IRC', 'gfci', 'GFCI protection of receptacles is required within how many feet of the edge of a sink, where the receptacles serve countertop or work surfaces?', '{"A": "3 feet", "B": "6 feet", "C": "10 feet", "D": "12 feet"}'::jsonb, 'B', 'Receptacles installed within 6 feet of the outside edge of a sink must be GFCI protected. The proximity-to-water rule reflects the elevated shock hazard near plumbing fixtures, where a person may simultaneously contact water and an energized device.', 'IRC E3902.6', 'https://up.codes/s/arc-fault-circuit-interrupter-protection', 'intermediario', true, 'Confirmado contra IRC 2021 E3902 (regra de pia): GFCI dentro de 6 ft da borda da pia.'),
  ('irc-107', 'IRC', 'gfci', 'What does a ground-fault circuit interrupter (GFCI) protect against?', '{"A": "Overloaded circuits drawing excess current", "B": "Arcing faults in damaged wiring", "C": "Electric shock by detecting current leakage to ground", "D": "Lightning surges entering the panel"}'::jsonb, 'C', 'A GFCI senses an imbalance between the current leaving on the hot conductor and returning on the neutral; if current is leaking to ground (for example, through a person), it trips quickly to prevent electrocution. Overcurrent is handled by breakers/fuses, and arcing faults are addressed by AFCIs, which are different devices.', 'IRC E3902, NEC Article 100 (GFCI definition)', 'https://www.building-center.org/gfci-and-afci-protection/', 'iniciante', true, 'Confirmado: GFCI detecta desbalanco de corrente (leakage to ground) e protege contra choque. Distinto de overcurrent (breaker) e arc-fault (AFCI).'),
  ('irc-108', 'IRC', 'afci', 'Branch circuits supplying 120-volt, 15- and 20-ampere outlets in which of the following rooms require AFCI protection?', '{"A": "Bathrooms", "B": "Bedrooms", "C": "Garages", "D": "Unfinished basements"}'::jsonb, 'B', 'AFCI protection is required for outlets in kitchens, family rooms, dining rooms, living rooms, bedrooms, sunrooms, recreation rooms, closets, hallways, laundry areas, and similar living areas. Bathrooms, garages, and unfinished basements are generally GFCI (not AFCI) areas.', 'IRC E3902.20', 'https://up.codes/s/arc-fault-circuit-interrupter-protection', 'intermediario', true, 'Confirmado contra IRC 2021 E3902.20: AFCI cobre quartos, cozinhas, salas, etc. (NOTA: edicoes antigas numeravam E3902.16; a numeracao abrangente do IRC 2021 e E3902.20.)'),
  ('irc-109', 'IRC', 'afci', 'An arc-fault circuit interrupter (AFCI) is designed primarily to:', '{"A": "Detect dangerous arcing conditions that can ignite fires", "B": "Detect current leakage to ground to prevent shock", "C": "Limit voltage during a utility surge", "D": "Disconnect the service during overload only"}'::jsonb, 'A', 'An AFCI detects the characteristic high-frequency signatures of dangerous arcing faults in wiring or cords and de-energizes the circuit to reduce the risk of electrical fires. Shock protection from ground leakage is the function of a GFCI, which is a separate device.', 'IRC E3902.20', 'https://www.building-center.org/gfci-and-afci-protection/', 'iniciante', true, 'Confirmado: AFCI detecta arcing fault e previne incendio; GFCI cuida de choque. Funcoes distintas.'),
  ('irc-110', 'IRC', 'branch-circuits', 'A dwelling unit must be provided with a minimum of how many 20-ampere small-appliance branch circuits to serve the kitchen, pantry, and dining-area receptacles?', '{"A": "One", "B": "Two", "C": "Three", "D": "Four"}'::jsonb, 'B', 'A minimum of two 20-ampere small-appliance branch circuits must be provided to serve the receptacle outlets in the kitchen, pantry, breakfast room, dining room, and similar areas. These dedicated circuits handle the heavy simultaneous loads of countertop appliances.', 'IRC E3703.2', 'https://up.codes/s/required-branch-circuits', 'iniciante', true, 'Confirmado contra IRC 2021 E3703.2: min duas branch circuits 20 A small-appliance para cozinha/copa/sala de jantar.'),
  ('irc-111', 'IRC', 'branch-circuits', 'The laundry-area receptacle outlet(s) in a dwelling must be served by at least:', '{"A": "One 15-ampere branch circuit shared with the kitchen", "B": "One 20-ampere branch circuit serving only the laundry receptacles", "C": "The general lighting circuit", "D": "A dedicated 30-ampere circuit"}'::jsonb, 'B', 'At least one 20-ampere branch circuit must be provided for the laundry receptacle outlet(s), and that circuit must serve only the laundry area, with no other outlets connected. Likewise, a dedicated 20-ampere circuit is required for bathroom receptacles.', 'IRC E3703.3', 'https://up.codes/s/required-branch-circuits', 'intermediario', true, 'Confirmado contra IRC 2021 E3703.3: min uma branch circuit 20 A dedicada a laundry; E3703.4 = 20 A dedicada a bathroom.'),
  ('irc-112', 'IRC', 'panel-clearance', 'The working space in front of a panelboard or other equipment likely to require service while energized must have a minimum depth (clearance toward the equipment) of:', '{"A": "30 inches", "B": "36 inches", "C": "42 inches", "D": "48 inches"}'::jsonb, 'B', 'The working space in the direction of access to live parts must be not less than 36 inches deep, measured from the energized parts or the enclosure face. This clearance lets a worker stand and operate safely in front of the panel without contacting other surfaces.', 'IRC E3405.2', 'https://up.codes/s/working-clearances-for-energized-equipment-and-panelboards', 'intermediario', true, 'Confirmado contra IRC 2021 E3405.2: profundidade do working space min 36 in.'),
  ('irc-113', 'IRC', 'panel-clearance', 'The working space in front of a panelboard must be at least how wide (the larger of a fixed dimension or the width of the equipment)?', '{"A": "24 inches", "B": "30 inches", "C": "36 inches", "D": "48 inches"}'::jsonb, 'B', 'The width of the working space must be not less than 30 inches, or the width of the equipment, whichever is greater. The space must permit at least a 90-degree opening of equipment doors or hinged panels and extend from the floor to a height of 6 1/2 feet.', 'IRC E3405.2', 'https://up.codes/s/working-clearances-for-energized-equipment-and-panelboards', 'intermediario', true, 'Confirmado contra IRC 2021 E3405.2: largura min 30 in (ou largura do equipamento); altura ate 6.5 ft; portas abrem 90 graus.'),
  ('irc-114', 'IRC', 'panel-clearance', 'A panelboard (overcurrent device) in a dwelling may NOT be located in which of the following spaces?', '{"A": "A hallway", "B": "A clothes closet or bathroom", "C": "A finished basement", "D": "A utility room"}'::jsonb, 'B', 'Overcurrent devices must not be located in clothes closets or in bathrooms of dwelling units. Closets create a fire risk from stored combustibles near the panel, and bathrooms present a shock hazard due to moisture. Panels are commonly placed in utility rooms, basements, garages, or hallways.', 'IRC E3405.5', 'https://up.codes/s/equipment-location-and-clearances', 'intermediario', true, 'Confirmado contra IRC 2021 E3405.5: overcurrent devices proibidos em clothes closets e bathrooms de dwellings.'),
  ('irc-115', 'IRC', 'fuel-gas', 'Each gas appliance must have an accessible individual shutoff valve located:', '{"A": "At the gas meter only", "B": "In the same room and within 6 feet of the appliance served", "C": "Anywhere on the same floor of the building", "D": "Within 25 feet of the appliance"}'::jsonb, 'B', 'An appliance shutoff valve must be located in the same room as the appliance, within 6 feet of it, and upstream of the union, connector, or quick-disconnect device it serves. This lets the gas be shut off quickly and locally for service or in an emergency.', 'IRC G2420.5', 'https://www.jaspector.com/codes/irc-2021/ch24-fuel-gas/gas-appliance-shutoff-valve-location-code/', 'intermediario', true, 'Confirmado contra IRC 2021 G2420.5: shutoff no mesmo comodo, dentro de 6 ft, upstream do union/connector.'),
  ('irc-116', 'IRC', 'fuel-gas', 'When sizing fuel gas piping, the design must account for which of the following?', '{"A": "Only the longest run of pipe, ignoring appliance demand", "B": "The total demand of connected appliances and the allowable pressure drop over the developed length", "C": "The color of the piping material", "D": "The number of occupants in the dwelling"}'::jsonb, 'B', 'Gas pipe sizing is based on the total Btu/h demand of all connected appliances, the gas type and specific gravity, the allowable pressure drop, and the developed length to the most remote outlet, using the sizing tables or the longest-length method. Undersized piping starves appliances and causes incomplete combustion.', 'IRC G2413', 'https://www.iccsafe.org/building-safety-journal/bsj-dives/codenotes-fuel-gas-pipe-sizing/', 'avancado', true, 'Confirmado contra IRC 2021 G2413: dimensionamento por demanda total (Btu/h), pressure drop e developed length (tabelas G2413.4/G2413.5).'),
  ('irc-117', 'IRC', 'fuel-gas', 'Corrugated stainless steel tubing (CSST) gas piping that is not listed with an arc-resistant jacket must be:', '{"A": "Painted yellow along its entire length", "B": "Directly bonded to the electrical service grounding system", "C": "Installed only outdoors", "D": "Wrapped in fiberglass insulation"}'::jsonb, 'B', 'CSST without an arc-resistant jacket must be electrically bonded to the grounding electrode system of the premises to dissipate energy from a nearby lightning strike, reducing the chance of an arc perforating the thin tubing wall. The bonding jumper connects to a CSST fitting or manifold and must meet the size and connection requirements of the gas-piping bonding section.', 'IRC G2411.2', 'https://www.cavecreekaz.gov/DocumentCenter/View/6611/Inspection-Fuel-Gas-Piping', 'avancado', true, 'Confirmado contra IRC 2021 G2411.2: CSST sem jacket arc-resistant exige bonding ao sistema de aterramento eletrico.'),
  ('irc-118', 'IRC', 'appliance-clearances', 'A fuel-burning appliance must be installed with clearances to combustible material in accordance with:', '{"A": "A flat 3-foot clearance on all sides", "B": "The clearances specified on the appliance''s listing and label or manufacturer''s instructions", "C": "Whatever clearance the installer judges adequate", "D": "Only the front clearance; sides may touch framing"}'::jsonb, 'B', 'Appliances must be installed with the clearances to combustibles specified by their listing and label and the manufacturer''s installation instructions. Reduced clearances are permitted only where protective assemblies recognized by the code are used. Following the listed clearances prevents heat from igniting adjacent framing or finishes.', 'IRC M1306.1 / G2409', 'https://up.codes/viewer/colorado/irc-2021/chapter/24/fuel-gas', 'intermediario', true, 'Confirmado contra IRC 2021 M1306.1 (mechanical) e G2409 (fuel gas): clearances conforme listing/label e instrucoes do fabricante; reducao so com assemblies reconhecidos.'),
  ('irc-119', 'IRC', 'exhaust-systems', 'Domestic kitchen range hoods and exhaust ducts that discharge grease-laden vapors must:', '{"A": "Recirculate the air through a charcoal filter back into the kitchen", "B": "Discharge to the outdoors through a single-wall duct of smooth metal with a backdraft damper", "C": "Discharge into the attic space", "D": "Terminate inside a wall cavity"}'::jsonb, 'B', 'Range hood ducts that carry exhaust to the outdoors must be of smooth metal (galvanized steel, stainless steel, copper, or aluminum), have smooth interior surfaces, air-tight joints, and a backdraft damper, and must discharge to the outdoors. Ductless recirculating hoods are allowed where listed, but ducted systems may not terminate in attics or wall cavities.', 'IRC M1503.3', 'https://up.codes/viewer/connecticut/irc-2021/chapter/15/exhaust-systems', 'intermediario', true, 'Confirmado contra IRC 2021 M1503.3: ducts de range hood de metal liso, juntas estanques, backdraft damper, descarga ao exterior; nao em attic/parede.'),
  ('irc-120', 'IRC', 'columns-footings', 'Per Table R407.2, what is the minimum nominal size for a steel pipe column used to support beams or girders in a dwelling?', '{"A": "3-inch diameter standard pipe", "B": "3-1/2-inch diameter standard pipe", "C": "4-inch diameter standard pipe", "D": "2-1/2-inch diameter standard pipe"}'::jsonb, 'A', 'Section R407 and Table R407.2 establish that steel columns shall be not less than 3-inch nominal diameter standard pipe (or approved equivalent). Smaller pipe sizes are not permitted for load-bearing columns supporting girders and beams.', 'IRC R407.2', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-4-foundations/IRC2021P2-Pt03-Ch04-SecR407.2', 'intermediario', true, 'Confirmado contra IRC 2021 R407.2: steel columns not less than 3-inch nominal diameter standard pipe or approved equivalent.'),
  ('irc-121', 'IRC', 'columns-footings', 'Wood columns under R407.3 must not be less than what nominal size unless approved or otherwise engineered?', '{"A": "2x4", "B": "4x4 (nominal)", "C": "6x6 (nominal)", "D": "2x6"}'::jsonb, 'B', 'R407.3 requires that wood columns be not less than 4 inches by 4 inches (nominal) in size. Wood columns must also be protected against decay where required by R317.', 'IRC R407.3', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-4-foundations/IRC2021P2-Pt03-Ch04-SecR407.3', 'iniciante', true, 'Confirmado contra IRC 2021 R407.3: wood columns not less than 4 inches by 4 inches nominal.'),
  ('irc-122', 'IRC', 'girder-bearing', 'Per R502.6, the ends of each floor joist, beam or girder bearing on wood or metal must have not less than how much bearing length?', '{"A": "1 inch on wood or metal", "B": "1-1/2 inches on wood or metal", "C": "3 inches on masonry or concrete", "D": "2 inches on wood or metal"}'::jsonb, 'B', 'R502.6 requires the ends of each joist, beam or girder to have not less than 1-1/2 inches of bearing on wood or metal and not less than 3 inches on masonry or concrete, except where supported on a 1-inch-by-4-inch ribbon strip and nailed to the adjacent stud.', 'IRC R502.6', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-5-floors/IRC2021P2-Pt03-Ch05-SecR502.6', 'intermediario', true, 'Confirmado contra IRC 2021 R502.6: 1-1/2 in bearing on wood/metal, 3 in on masonry/concrete.'),
  ('irc-123', 'IRC', 'girder-bearing', 'Under R502.6.2, joists framing into the side of a wood girder must be supported by what?', '{"A": "Toe nails only", "B": "Approved framing anchors or ledger strips", "C": "Construction adhesive", "D": "A continuous rim joist alone"}'::jsonb, 'B', 'R502.6.2 requires joists framing into the side of a wood girder to be supported by approved framing anchors or on ledger strips not less than nominal 2 inches by 2 inches. Toe nailing alone is not an acceptable means of support for this connection.', 'IRC R502.6.2', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-5-floors/IRC2021P2-Pt03-Ch05-SecR502.6.2', 'intermediario', true, 'Confirmado contra IRC 2021 R502.6.2: framing anchors or 2x2 ledger strips for side-framed joists.'),
  ('irc-124', 'IRC', 'floor-joist-spans', 'The allowable spans for floor joists in Tables R502.3.1(1) and R502.3.1(2) are based on which design live load conditions?', '{"A": "A single 40 psf load for all rooms", "B": "Sleeping areas at 30 psf and all other areas at 40 psf", "C": "All areas at 50 psf", "D": "Attic floors only"}'::jsonb, 'B', 'IRC floor joist span tables are organized by live load: Table R502.3.1(1) covers sleeping areas and attics served by fixed stairs at 30 psf live load, while Table R502.3.1(2) covers all other living areas at 40 psf live load. The correct table must be selected based on the room use.', 'IRC R502.3.1', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-5-floors/IRC2021P2-Pt03-Ch05-SecR502.3.1', 'intermediario', true, 'Confirmado contra IRC 2021 R502.3.1: span tables split at 30 psf (sleeping) and 40 psf (living).'),
  ('irc-125', 'IRC', 'floor-joist-spans', 'When using the floor joist span tables, the span of a joist is measured as what?', '{"A": "The total length of the lumber piece", "B": "The clear horizontal distance between bearing supports", "C": "The distance from outside wall to outside wall", "D": "Twice the cantilever length"}'::jsonb, 'B', 'For purposes of the span tables, the span is the clear horizontal distance between bearing supports (face to face of supports), not the full physical length of the member. Bearing length is provided in addition to the span.', 'IRC R502.3.1', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-5-floors/IRC2021P2-Pt03-Ch05-SecR502.3.1', 'iniciante', true, 'Confirmado contra IRC 2021: span = clear distance between supports per table footnotes/definitions.'),
  ('irc-126', 'IRC', 'wood-foundation-walls', 'Per R404.2, the materials used in the construction of permanent wood foundation walls must be what?', '{"A": "Standard kiln-dried framing lumber", "B": "Preservative-treated wood and approved for ground contact", "C": "Untreated lumber painted with sealer", "D": "Any species of lumber rated No. 2 or better"}'::jsonb, 'B', 'R404.2 requires that lumber and plywood used in wood foundation systems be preservative-treated and approved for such use (ground contact / structural foundation grade). Standard untreated framing lumber is not permitted in a permanent wood foundation.', 'IRC R404.2', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-4-foundations/IRC2021P2-Pt03-Ch04-SecR404.2', 'intermediario', true, 'Confirmado contra IRC 2021 R404.2 / R404.2.1: preservative-treated lumber and plywood for permanent wood foundations.'),
  ('irc-127', 'IRC', 'wood-foundation-walls', 'Fasteners used in the fabrication and installation of preservative-treated wood foundations must be what?', '{"A": "Bright (uncoated) steel nails", "B": "Silicon bronze, copper, hot-dipped galvanized or stainless steel", "C": "Electroplated zinc nails only", "D": "Aluminum fasteners"}'::jsonb, 'B', 'Because preservative-treated wood is corrosive to ordinary steel, R404.2 and the wood foundation provisions require fasteners (and connectors) to be silicon bronze, copper, hot-dipped zinc-coated (galvanized) steel, or stainless steel to resist corrosion.', 'IRC R404.2.6', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-4-foundations/IRC2021P2-Pt03-Ch04-SecR404.2.6', 'avancado', true, 'Confirmado contra IRC 2021 R404.2.6 (fasteners): silicon bronze, copper, hot-dipped galvanized, or stainless steel for treated wood foundations.'),
  ('irc-128', 'IRC', 'concrete-foundation-walls', 'Per Table R404.1.2(1), the minimum thickness of a concrete foundation wall is generally determined by what factors?', '{"A": "The roof covering material only", "B": "Wall height and the unbalanced backfill height", "C": "The number of windows in the wall", "D": "The finished floor elevation only"}'::jsonb, 'B', 'Plain and reinforced concrete foundation wall thickness tables in R404.1.2 are indexed by the maximum wall height and the height of unbalanced backfill (and soil class). As backfill height increases, greater thickness or reinforcement is required to resist lateral soil pressure.', 'IRC R404.1.2', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-4-foundations/IRC2021P2-Pt03-Ch04-SecR404.1.2', 'intermediario', true, 'Confirmado contra IRC 2021 R404.1.2: wall thickness/reinforcement keyed to wall height and unbalanced backfill height.'),
  ('irc-129', 'IRC', 'concrete-foundation-walls', 'Per R404.1.2.3.7.4, vertical reinforcement in a concrete foundation wall, where required, must have minimum concrete cover of how much measured from the inside face?', '{"A": "1/2 inch", "B": "3/4 inch", "C": "1 inch", "D": "2 inches"}'::jsonb, 'B', 'R404.1.2.3.7.4 requires vertical reinforcement to be located to provide a minimum cover of 3/4 inch measured from the inside face of the wall (cover increases to 1-1/2 inches or more where concrete is cast against forms exposed to weather, and 3 inches where cast against earth).', 'IRC R404.1.2.3.7.4', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-4-foundations/IRC2021P2-Pt03-Ch04-SecR404.1.2', 'avancado', true, 'Confirmado contra IRC 2021 R404.1.2.3.7.4: 3/4 in cover from inside face; greater cover against weather/earth.'),
  ('irc-130', 'IRC', 'anchor-bolts', 'Per R403.1.6, sill plates and wall plates anchoring to a concrete or masonry foundation must have anchor bolts spaced not more than how far apart?', '{"A": "4 feet on center", "B": "6 feet on center", "C": "8 feet on center", "D": "12 feet on center"}'::jsonb, 'B', 'R403.1.6 requires anchor bolts to be spaced not more than 6 feet on center for the typical case. There must also be a minimum of two bolts per plate section with one bolt located not more than 12 inches and not less than seven bolt diameters from each end of the plate.', 'IRC R403.1.6', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-4-foundations/IRC2021P2-Pt03-Ch04-SecR403.1.6', 'intermediario', true, 'Confirmado contra IRC 2021 R403.1.6: anchor bolts max 6 ft o.c., two min per piece, end bolt within 12 in / not less than 7 bolt diameters.'),
  ('irc-131', 'IRC', 'anchor-bolts', 'Per R403.1.6, anchor bolts attaching the sill plate must extend a minimum of how far into concrete or grouted masonry?', '{"A": "4 inches", "B": "5 inches", "C": "7 inches", "D": "10 inches"}'::jsonb, 'C', 'R403.1.6 requires anchor bolts to be at least 1/2 inch in diameter and embedded a minimum of 7 inches into concrete or grouted cells of concrete masonry units. A nut and washer must be tightened on each bolt.', 'IRC R403.1.6', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-4-foundations/IRC2021P2-Pt03-Ch04-SecR403.1.6', 'intermediario', true, 'Confirmado contra IRC 2021 R403.1.6: 1/2 in min diameter, 7 in min embedment into concrete or grouted masonry.'),
  ('irc-132', 'IRC', 'anchor-bolts', 'Under R403.1.6, a plate washer is required between the sill plate and the nut on each anchor bolt where required by the braced wall provisions. What is the minimum plate washer size?', '{"A": "0.229 inch by 3 inches by 3 inches", "B": "1/8 inch by 1 inch by 1 inch", "C": "1/4 inch by 2 inches by 2 inches", "D": "No washer is required"}'::jsonb, 'A', 'R403.1.6 requires a nut and washer to be tightened on each anchor bolt, and where required for braced wall / seismic provisions a plate washer not less than 0.229 inch by 3 inches by 3 inches must be used between the sill plate and the nut.', 'IRC R403.1.6', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-4-foundations/IRC2021P2-Pt03-Ch04-SecR403.1.6', 'avancado', true, 'Confirmado contra IRC 2021 R403.1.6: plate washer minimum 0.229 in x 3 in x 3 in where required.'),
  ('irc-133', 'IRC', 'pier-column-footings', 'Per R403, the size of a footing supporting an isolated pier or column is primarily determined by what?', '{"A": "The species of wood used in the column", "B": "The load on the footing and the load-bearing value of the soil", "C": "The exterior wall covering", "D": "The number of stories above the basement only, ignoring soil"}'::jsonb, 'B', 'R403.1 requires footings to be sized so the allowable bearing capacity of the soil is not exceeded. Footing dimensions are a function of the load delivered to the footing and the load-bearing (presumptive) value of the soil per Table R401.4.1.', 'IRC R403.1', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-4-foundations/IRC2021P2-Pt03-Ch04-SecR403.1', 'intermediario', true, 'Confirmado contra IRC 2021 R403.1 / R401.4.1: footing size keyed to load and soil bearing capacity.'),
  ('irc-134', 'IRC', 'termite-protection', 'Per R318.1, in areas where the probability of termite infestation is very heavy, which of the following is an approved method of protection?', '{"A": "Painting all wood with latex paint", "B": "Chemical soil treatment, pressure-preservative-treated wood, naturally durable wood, or physical barriers", "C": "Installing carpet over the slab", "D": "Increasing the footing depth only"}'::jsonb, 'B', 'R318.1 lists the approved methods of protection against subterranean termites: chemical termiticide soil treatment, pressure-preservative-treated wood, naturally durable termite-resistant wood, physical barriers (such as termite shields), or cold-formed steel framing, or any combination of these methods.', 'IRC R318.1', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-3-building-planning/IRC2021P2-Pt03-Ch03-SecR318.1', 'intermediario', true, 'Confirmado contra IRC 2021 R318.1: chemical treatment, treated wood, naturally durable wood, physical barriers, or steel framing.'),
  ('irc-135', 'IRC', 'termite-protection', 'Per R318.4 (foam plastic protection), foam plastic insulation is generally restricted from being installed in which location in very heavy termite areas?', '{"A": "Inside heated interior walls", "B": "On the exterior face or under the interior face of a basement or crawl space wall in contact with the ground", "C": "In attic spaces", "D": "Above the roof deck"}'::jsonb, 'B', 'In very heavy termite infestation areas, R318.4 prohibits foam plastic from being installed on the exterior face or under the interior face of a basement wall, crawl space wall or slab edge that is in contact with the ground, unless an approved method of protecting the foam and structure is used, because the foam provides a concealed termite pathway.', 'IRC R318.4', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-3-building-planning/IRC2021P2-Pt03-Ch03-SecR318.4', 'avancado', true, 'Confirmado contra IRC 2021 R318.4: foam plastic in ground-contact foundation locations restricted in very heavy termite areas.'),
  ('irc-136', 'IRC', 'decay-protection', 'Per R317.1, wood floor joists closer than what distance to exposed ground in crawl spaces must be naturally durable or preservative-treated wood?', '{"A": "Less than 6 inches", "B": "Less than 18 inches (joists) and less than 12 inches (girders)", "C": "Less than 24 inches", "D": "Less than 36 inches"}'::jsonb, 'B', 'R317.1 requires protection against decay (naturally durable or preservative-treated wood) for wood floor joists closer than 18 inches, and wood girders closer than 12 inches, to exposed ground in crawl spaces or unexcavated areas.', 'IRC R317.1', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-3-building-planning/IRC2021P2-Pt03-Ch03-SecR317.1', 'avancado', true, 'Confirmado contra IRC 2021 R317.1(2): floor joists < 18 in and girders < 12 in from exposed ground require decay-resistant wood.'),
  ('irc-137', 'IRC', 'decay-protection', 'Per R317.1.2, wood in direct contact with the ground or fresh water and supporting permanent structures must be what?', '{"A": "Naturally durable heartwood only", "B": "Approved pressure-preservative-treated wood suitable for ground contact", "C": "Any No. 2 grade lumber", "D": "Fire-retardant-treated wood"}'::jsonb, 'B', 'R317.1.2 requires wood in contact with the ground, embedded in concrete in direct contact with the ground, or in contact with fresh water and supporting permanent structures to be approved pressure-preservative-treated wood suitable for ground contact use. Naturally durable wood is not permitted for direct ground-contact structural support.', 'IRC R317.1.2', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-3-building-planning/IRC2021P2-Pt03-Ch03-SecR317.1', 'intermediario', true, 'Confirmado contra IRC 2021 R317.1.2: ground-contact structural wood must be pressure-preservative-treated for ground contact.'),
  ('irc-138', 'IRC', 'decay-protection', 'Per R317.3.1, fasteners and connectors in contact with preservative-treated and fire-retardant-treated wood must be what?', '{"A": "Hot-dipped galvanized, stainless steel, silicon bronze or copper", "B": "Standard bright steel", "C": "Aluminum", "D": "Electro-galvanized only"}'::jsonb, 'A', 'R317.3.1 requires fasteners (including nuts and washers) and connectors in contact with preservative-treated or fire-retardant-treated wood to be hot-dipped zinc-coated galvanized steel, stainless steel, silicon bronze or copper, to resist accelerated corrosion. Aluminum is prohibited in direct contact with some treated woods.', 'IRC R317.3.1', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-3-building-planning/IRC2021P2-Pt03-Ch03-SecR317.3', 'intermediario', true, 'Confirmado contra IRC 2021 R317.3.1: hot-dipped galvanized, stainless, silicon bronze, or copper fasteners with treated wood.'),
  ('irc-139', 'IRC', 'roof-covering-metal', 'Per R905.10.1, a lapped, nonsoldered seam metal roof panel installed WITHOUT applied lap sealant requires a minimum roof slope of what?', '{"A": "One-quarter unit vertical in 12 (1/4:12)", "B": "One-half unit vertical in 12 (1/2:12)", "C": "Three units vertical in 12 (3:12)", "D": "Four units vertical in 12 (4:12)"}'::jsonb, 'C', 'R905.10.1 sets minimum slopes for metal roof panels: lapped, nonsoldered seam roofs without applied lap sealant require a minimum slope of three units in 12; with applied lap sealant the minimum is one-half unit in 12; standing seam systems require a minimum of one-quarter unit in 12.', 'IRC R905.10.1', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-9-roof-assemblies/IRC2021P2-Pt05-Ch09-SecR905.10', 'avancado', true, 'Confirmado contra IRC 2021 R905.10.1: min slopes 3:12 (no sealant lap), 1/2:12 (sealed lap), 1/4:12 (standing seam).'),
  ('irc-140', 'IRC', 'roof-covering-metal', 'Per R905.4, metal roof shingles shall not be installed on a roof slope less than which of the following?', '{"A": "Two units vertical in 12 units horizontal (2:12)", "B": "Three units vertical in 12 units horizontal (3:12)", "C": "Four units vertical in 12 units horizontal (4:12)", "D": "One-half unit vertical in 12 (1/2:12)"}'::jsonb, 'B', 'R905.4.1 requires metal roof shingles to be applied to a roof with a minimum slope of three units vertical in 12 units horizontal (3:12). Metal roof shingles are distinct from metal roof panels (R905.10), which permit lower slopes when sealed or standing seam.', 'IRC R905.4.1', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-9-roof-assemblies/IRC2021P2-Pt05-Ch09-SecR905.4', 'intermediario', true, 'Confirmado contra IRC 2021 R905.4.1: metal roof shingles minimum slope 3:12.'),
  ('irc-141', 'IRC', 'roof-covering-tile', 'Per R905.3, clay and concrete roof tile shall not be installed on a roof slope less than which value (with double underlayment required for lower slopes)?', '{"A": "2-1/2 units vertical in 12 units horizontal (2.5:12)", "B": "1 unit vertical in 12", "C": "5 units vertical in 12", "D": "6 units vertical in 12"}'::jsonb, 'A', 'R905.3.2 requires clay and concrete roof tile to be installed on roof slopes of 2-1/2 units vertical in 12 (2.5:12) or greater. For roof slopes from 2.5:12 to less than 4:12, double underlayment application is required.', 'IRC R905.3.2', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-9-roof-assemblies/IRC2021P2-Pt05-Ch09-SecR905.3', 'intermediario', true, 'Confirmado contra IRC 2021 R905.3.2: clay/concrete tile minimum slope 2.5:12; double underlayment for 2.5:12 to <4:12.'),
  ('irc-142', 'IRC', 'roof-covering-wood-shingles', 'Per R905.7, wood shingles shall not be installed on a roof slope less than which of the following?', '{"A": "Two units vertical in 12 (2:12)", "B": "Three units vertical in 12 (3:12)", "C": "Four units vertical in 12 (4:12)", "D": "Five units vertical in 12 (5:12)"}'::jsonb, 'B', 'R905.7.2 requires wood shingles to be installed on slopes of three units vertical in 12 units horizontal (3:12) or greater. Wood shingles must be installed over solid or spaced sheathing in accordance with the section.', 'IRC R905.7.2', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-9-roof-assemblies/IRC2021P2-Pt05-Ch09-SecR905.7', 'intermediario', true, 'Confirmado contra IRC 2021 R905.7.2: wood shingles minimum slope 3:12.'),
  ('irc-143', 'IRC', 'roof-covering-wood-shakes', 'Per R905.8, wood shakes shall not be installed on a roof slope less than which of the following?', '{"A": "Two units vertical in 12 (2:12)", "B": "Three units vertical in 12 (3:12)", "C": "Four units vertical in 12 (4:12)", "D": "Six units vertical in 12 (6:12)"}'::jsonb, 'C', 'R905.8.2 requires wood shakes to be installed on roof slopes of four units vertical in 12 units horizontal (4:12) or greater. This is a steeper minimum than wood shingles (3:12) because of the irregular, hand-split nature of shakes.', 'IRC R905.8.2', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-9-roof-assemblies/IRC2021P2-Pt05-Ch09-SecR905.8', 'intermediario', true, 'Confirmado contra IRC 2021 R905.8.2: wood shakes minimum slope 4:12.'),
  ('irc-144', 'IRC', 'roof-covering-slate', 'Per R905.6, slate and slate-type shingles shall not be installed on a roof slope less than which of the following?', '{"A": "Two units vertical in 12 (2:12)", "B": "Three units vertical in 12 (3:12)", "C": "Four units vertical in 12 (4:12)", "D": "Six units vertical in 12 (6:12)"}'::jsonb, 'C', 'R905.6.2 requires slate and slate-type shingles to be installed on roof slopes of four units vertical in 12 units horizontal (4:12) or greater.', 'IRC R905.6.2', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-9-roof-assemblies/IRC2021P2-Pt05-Ch09-SecR905.6', 'intermediario', true, 'Confirmado contra IRC 2021 R905.6.2: slate minimum slope 4:12.'),
  ('irc-145', 'IRC', 'roof-covering-slate', 'Per R905.6.5, slate shingles must be fastened with what type of nails?', '{"A": "Bright steel nails", "B": "Corrosion-resistant nails (such as copper or stainless steel)", "C": "Electro-galvanized roofing nails", "D": "Aluminum nails only"}'::jsonb, 'B', 'R905.6.5 requires slate shingles to be fastened with corrosion-resistant nails. Because slate is a long-lifespan roofing material, copper or stainless steel nails are used so the fasteners do not fail before the slate.', 'IRC R905.6.5', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-9-roof-assemblies/IRC2021P2-Pt05-Ch09-SecR905.6', 'avancado', true, 'Confirmado contra IRC 2021 R905.6.5: corrosion-resistant nails required for slate.'),
  ('irc-146', 'IRC', 'roof-underlayment', 'Per R905.1.1, underlayment for asphalt shingles, metal roof shingles, slate, wood shingles and wood shakes must be applied in accordance with what?', '{"A": "There is no underlayment requirement", "B": "Tables R905.1.1(1), (2) and (3) based on the roof covering and slope", "C": "Only the manufacturer''s printed instructions, with no code table", "D": "Chapter 8 ceiling provisions"}'::jsonb, 'B', 'R905.1.1 directs underlayment to be applied in accordance with Tables R905.1.1(1), R905.1.1(2) and R905.1.1(3), which set the underlayment type and number of layers/lap based on the specific roof covering and the roof slope and applicable ground snow load.', 'IRC R905.1.1', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-9-roof-assemblies/IRC2021P2-Pt05-Ch09-SecR905.1', 'intermediario', true, 'Confirmado contra IRC 2021 R905.1.1: underlayment per Tables R905.1.1(1)-(3) keyed to covering and slope.'),
  ('irc-147', 'IRC', 'dwelling-sprinklers', 'Per R313.2, an automatic residential fire sprinkler system, where adopted, is required to be installed in one- and two-family dwellings in accordance with which standard(s)?', '{"A": "NFPA 72 only", "B": "Section P2904 or NFPA 13D", "C": "NFPA 13 (commercial) only", "D": "No referenced standard applies"}'::jsonb, 'B', 'R313.2 requires an automatic residential fire sprinkler system in one- and two-family dwellings (R313.1 covers townhouses) where the provision is adopted, designed and installed in accordance with Section P2904 or NFPA 13D. Adoption of R313 varies by state/jurisdiction.', 'IRC R313.2', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-3-building-planning/IRC2021P2-Pt03-Ch03-SecR313.2', 'intermediario', true, 'Confirmado contra IRC 2021 R313.2: residential sprinklers per P2904 or NFPA 13D (where adopted).'),
  ('irc-148', 'IRC', 'dwelling-sprinklers', 'Per the residential sprinkler standard referenced by R313 (P2904 / NFPA 13D), sprinklers may generally be omitted from which space?', '{"A": "Bedrooms", "B": "Bathrooms 55 sq ft or less, and clothes closets/pantries 24 sq ft or less", "C": "Living rooms", "D": "Kitchens"}'::jsonb, 'B', 'Under NFPA 13D / P2904 as referenced by R313, sprinklers are not required in certain limited spaces such as bathrooms not exceeding 55 square feet, small clothes closets and pantries not exceeding 24 square feet, garages, and certain open attached porches and concealed spaces. Habitable rooms such as bedrooms and living rooms require sprinklers.', 'IRC R313 / P2904', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-29-water-supply-and-distribution/IRC2021P2-Pt07-Ch29-SecP2904', 'avancado', true, 'Confirmado contra IRC 2021 P2904 / NFPA 13D omission allowances: bath <=55 sf, closet/pantry <=24 sf, garages, certain concealed spaces.'),
  ('irc-149', 'IRC', 'escape-window-wells', 'Per R310.3.2, an emergency escape and rescue opening with a sill below grade must be provided with a window well having a minimum horizontal area of what?', '{"A": "5 square feet", "B": "9 square feet, with a minimum horizontal projection and width of 36 inches", "C": "12 square feet", "D": "3 square feet"}'::jsonb, 'B', 'R310.3.2 requires window wells serving below-grade emergency escape openings to have a minimum horizontal area of 9 square feet, with a minimum horizontal projection and width of 36 inches, so the window can be fully opened and a person can climb out.', 'IRC R310.3.2', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-3-building-planning/IRC2021P2-Pt03-Ch03-SecR310.3', 'intermediario', true, 'Confirmado contra IRC 2021 R310.3.2: window well 9 sf min, 36 in min projection and width.'),
  ('irc-150', 'IRC', 'escape-window-wells', 'Per R310.3.2.1, a window well with a vertical depth greater than what dimension must be equipped with a permanently affixed ladder or steps?', '{"A": "24 inches", "B": "36 inches", "C": "44 inches", "D": "60 inches"}'::jsonb, 'C', 'R310.3.2.1 requires window wells with a vertical depth greater than 44 inches to be equipped with a permanently affixed ladder or steps usable with the window in the fully open position. The ladder/steps may project up to 6 inches into the well.', 'IRC R310.3.2.1', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-3-building-planning/IRC2021P2-Pt03-Ch03-SecR310.3', 'intermediario', true, 'Confirmado contra IRC 2021 R310.3.2.1: ladder/steps required when well depth > 44 in; may project 6 in.'),
  ('irc-151', 'IRC', 'escape-window-wells', 'Per R310.3.2.1, the rungs of a window well ladder must have an inside width of at least how much and be spaced no more than how far apart vertically?', '{"A": "At least 12 inches wide, spaced not more than 18 inches on center", "B": "At least 9 inches wide, spaced not more than 24 inches on center", "C": "At least 16 inches wide, spaced not more than 12 inches on center", "D": "At least 6 inches wide, spaced not more than 30 inches on center"}'::jsonb, 'A', 'R310.3.2.1 specifies that ladders or rungs serving window wells must have an inside width of at least 12 inches, project at least 3 inches from the wall, and be spaced not more than 18 inches on center vertically for the full height of the window well.', 'IRC R310.3.2.1', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-3-building-planning/IRC2021P2-Pt03-Ch03-SecR310.3', 'avancado', true, 'Confirmado contra IRC 2021 R310.3.2.1: rungs >=12 in wide, project >=3 in, spaced <=18 in o.c.'),
  ('irc-152', 'IRC', 'siding-wall-covering', 'Per R703.11, vinyl siding must be fastened so that what condition is met?', '{"A": "Fasteners driven tight to lock the panel in place", "B": "Fasteners centered in the slots and not driven tight, allowing for thermal movement", "C": "Adhesive only with no fasteners", "D": "Fasteners spaced not more than 48 inches on center"}'::jsonb, 'B', 'R703.11.2 requires vinyl siding fasteners to penetrate the framing/substrate at least the required depth and to be centered in the nailing slots without being driven tightly, leaving approximately 1/32 inch (the thickness of a dime) between the fastener head and the siding so the panel can expand and contract.', 'IRC R703.11.2', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-7-wall-covering/IRC2021P2-Pt05-Ch07-SecR703.11', 'intermediario', true, 'Confirmado contra IRC 2021 R703.11.2: vinyl siding fasteners centered in slots, not driven tight (allow movement).'),
  ('irc-153', 'IRC', 'siding-wall-covering', 'Per R703.3 and R703.4, exterior wall coverings such as fiber cement, wood and hardboard siding must be installed over what, in addition to the structure?', '{"A": "No backing required", "B": "A water-resistive barrier, and to the minimum thickness/attachment listed in Table R703.3(1)", "C": "Two layers of gypsum board", "D": "A vapor retarder only on the warm side"}'::jsonb, 'B', 'R703.1 and R703.4 require exterior wall coverings to be installed over a water-resistive barrier (R703.2) and attached in accordance with the minimum thickness and fastening requirements of Table R703.3(1) for the specific siding material, including fiber cement (R703.10), wood and hardboard siding.', 'IRC R703.3', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-7-wall-covering/IRC2021P2-Pt05-Ch07-SecR703.3', 'intermediario', true, 'Confirmado contra IRC 2021 R703.1/R703.3/R703.4: sidings over WRB, per Table R703.3(1) thickness/attachment.'),
  ('irc-154', 'IRC', 'siding-wall-covering', 'Per R703.10.1, fiber-cement lap siding having a maximum width of 12 inches must be lapped a minimum of how much?', '{"A": "1/2 inch", "B": "1-1/4 inches", "C": "2 inches", "D": "3 inches"}'::jsonb, 'B', 'R703.10.1 requires fiber-cement lap siding (maximum 12-inch width) to be lapped a minimum of 1-1/4 inches and to have the ends sealed, covered with battens, or otherwise treated, and to be installed over a water-resistive barrier.', 'IRC R703.10.1', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-7-wall-covering/IRC2021P2-Pt05-Ch07-SecR703.10', 'avancado', true, 'Confirmado contra IRC 2021 R703.10.1: fiber-cement lap siding lapped min 1-1/4 in.'),
  ('irc-155', 'IRC', 'weather-resistant-barrier', 'Per R703.2, a water-resistive barrier behind the exterior wall covering must consist of at least what?', '{"A": "Nothing, if the siding is rated water-resistant", "B": "One layer of No. 15 asphalt felt (ASTM D226 Type 1) or other approved water-resistive barrier", "C": "Two layers of 6-mil polyethylene", "D": "A single coat of exterior paint"}'::jsonb, 'B', 'R703.2 requires not fewer than one layer of No. 15 asphalt felt, complying with ASTM D226 Type 1, or other approved water-resistive barrier to be applied over studs or sheathing of all exterior walls. The barrier must be applied horizontally with upper layers lapped over lower layers to shed water.', 'IRC R703.2', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-7-wall-covering/IRC2021P2-Pt05-Ch07-SecR703.2', 'intermediario', true, 'Confirmado contra IRC 2021 R703.2: min one layer No. 15 asphalt felt (ASTM D226 Type 1) or approved WRB.'),
  ('irc-156', 'IRC', 'weather-resistant-barrier', 'Per R703.2, the water-resistive barrier must be applied in what manner to properly shed water?', '{"A": "Vertically with side laps sealed", "B": "Horizontally, with upper layers lapped over lower layers (shingle fashion)", "C": "In a single sheet with no laps", "D": "Behind the sheathing, against the studs"}'::jsonb, 'B', 'R703.2 requires the water-resistive barrier to be applied horizontally with the upper layer lapped over the lower layer (weatherboard / shingle fashion) so that any water reaching the barrier is directed down and out, away from the structure. It is applied over the sheathing, not behind it.', 'IRC R703.2', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-7-wall-covering/IRC2021P2-Pt05-Ch07-SecR703.2', 'iniciante', true, 'Confirmado contra IRC 2021 R703.2: WRB applied horizontally, upper over lower (shingle fashion).'),
  ('irc-157', 'IRC', 'masonry-chimney-clearance', 'Per R1003.18, the air space clearance between a masonry chimney located entirely outside the exterior walls and combustible material must be at least how much?', '{"A": "1 inch", "B": "2 inches", "C": "4 inches", "D": "6 inches"}'::jsonb, 'A', 'R1003.18 requires a minimum air space clearance to combustibles of 2 inches for chimneys located in the interior of the building, and 1 inch for chimneys located entirely outside the exterior walls (an exterior chimney). Combustible material must not be placed within these clearances.', 'IRC R1003.18', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-10-chimneys-and-fireplaces/IRC2021P2-Pt07-Ch10-SecR1003.18', 'avancado', true, 'Confirmado contra IRC 2021 R1003.18: 2 in clearance for interior chimney, 1 in for exterior chimney.'),
  ('irc-158', 'IRC', 'masonry-chimney-clearance', 'Per R1003.18, the required air-space clearance between a masonry chimney and combustible trim or framing may be reduced or eliminated only when what condition is met?', '{"A": "It is painted with fire-retardant paint", "B": "Noncombustible material is used at the interface, or the air space is otherwise preserved per the section", "C": "It is glued, not nailed", "D": "It is no thicker than 1 inch"}'::jsonb, 'B', 'R1003.18 maintains the required air-space clearance to combustibles, but allows combustible material such as exterior trim to be placed at the masonry chimney only where the air space is preserved or noncombustible material is used at the interface. The clearance space itself may not be filled with combustible material.', 'IRC R1003.18', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-10-chimneys-and-fireplaces/IRC2021P2-Pt07-Ch10-SecR1003.18', 'avancado', true, 'Confirmado contra IRC 2021 R1003.18: required air space to combustibles must be maintained; noncombustible interface allowed.'),
  ('irc-159', 'IRC', 'girder-beams', 'Per R602.7, headers and girders supporting floor and roof loads over openings in load-bearing walls must be sized according to what?', '{"A": "The exterior siding type", "B": "The span tables (Table R602.7) based on span, supported loads and ground snow load", "C": "The interior finish material", "D": "The number of anchor bolts"}'::jsonb, 'B', 'Header and girder sizes over openings in load-bearing walls are determined from the girder/header span tables (Table R602.7(1)-(3)) based on the clear span of the opening, the building width / supported loads, and the ground snow load, ensuring the member can carry the tributary floor and roof loads.', 'IRC R602.7', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-6-wall-construction/IRC2021P2-Pt03-Ch06-SecR602.7', 'intermediario', true, 'Confirmado contra IRC 2021 R602.7 / Table R602.7(1)-(3): header/girder size by span, supported loads, ground snow load.'),
  ('irc-160', 'IRC', 'wood-foundation-walls', 'Per R404.2.3, the size, height and spacing of studs in a permanent wood foundation wall (and the thickness of supporting plywood) must be determined based on what?', '{"A": "The roof covering weight only", "B": "The height of fill (backfill) and the applied lateral soil load", "C": "The width of the siding", "D": "The number of floor joists only"}'::jsonb, 'B', 'R404.2.3 requires the size, height and spacing of studs and the thickness of the supporting plywood in a permanent wood foundation to be determined based on the height of fill (backfill) and the resulting lateral soil pressure, in accordance with the AWC permanent wood foundation design specification referenced by the code.', 'IRC R404.2.3', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-4-foundations/IRC2021P2-Pt03-Ch04-SecR404.2.3', 'avancado', true, 'Confirmado contra IRC 2021 R404.2.3: wood foundation stud size/spacing and plywood thickness keyed to backfill height/lateral load.'),
  ('irc-161', 'IRC', 'roof-covering-metal', 'Per R905.10.3, metal roof panels and shingles must be attached so they resist what primary load?', '{"A": "Snow load only", "B": "The component and cladding wind uplift pressures for the building", "C": "Seismic load only", "D": "Live load from occupants on the roof"}'::jsonb, 'B', 'R905.10.3 requires metal roof panel and shingle attachment to resist the wind uplift (component and cladding) pressures determined for the building, in accordance with the manufacturer''s listing and the wind provisions of the code. Wind uplift is the governing concern for metal roofing attachment.', 'IRC R905.10.3', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-9-roof-assemblies/IRC2021P2-Pt05-Ch09-SecR905.10', 'avancado', true, 'Confirmado contra IRC 2021 R905.10.3: metal roofing attachment resists component and cladding wind uplift.'),
  ('irc-162', 'IRC', 'columns-footings', 'Per R407.3, columns must be restrained against what at the bottom end where they bear on a footing or pier?', '{"A": "Nothing; no connection is required", "B": "Lateral displacement, and they must be protected against corrosion (steel) or decay (wood)", "C": "Vertical uplift only", "D": "Thermal expansion only"}'::jsonb, 'B', 'R407.3 requires columns to be restrained to prevent lateral displacement at the bottom end (and at the top where they support girders), typically by a connection to the footing/pier. Steel columns must also be protected against corrosion, and wood columns protected against decay where exposed.', 'IRC R407.3', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-4-foundations/IRC2021P2-Pt03-Ch04-SecR407.3', 'intermediario', true, 'Confirmado contra IRC 2021 R407.3: columns restrained against lateral displacement at base/top; corrosion/decay protection.'),
  ('irc-163', 'IRC', 'escape-window-wells', 'Per R310.3.2.1, the ladder or steps required for a deep window well are permitted to encroach into the required minimum well dimension by not more than how much?', '{"A": "3 inches", "B": "6 inches", "C": "9 inches", "D": "12 inches"}'::jsonb, 'B', 'R310.3.2.1 permits the permanently affixed ladder or steps required in window wells deeper than 44 inches to encroach a maximum of 6 inches into the required minimum horizontal dimension/area of the window well.', 'IRC R310.3.2.1', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-3-building-planning/IRC2021P2-Pt03-Ch03-SecR310.3', 'avancado', true, 'Confirmado contra IRC 2021 R310.3.2.1: ladder/steps may project up to 6 in into required well dimension.'),
  ('irc-164', 'IRC', 'wall-bracing-methods', 'Under Table R602.10.4, the bracing method designated ''WSP'' refers to which of the following?', '{"A": "Gypsum board", "B": "Wood structural panel", "C": "Portland cement plaster", "D": "Diagonal let-in bracing"}'::jsonb, 'B', 'In Table R602.10.4, ''WSP'' is the abbreviation for Wood Structural Panel bracing. Other recognized intermittent methods include LIB (let-in bracing), DWB (diagonal wood boards), GB (gypsum board), PBS (particleboard sheathing), and SFB (structural fiberboard sheathing).', 'IRC R602.10.4', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-6-wall-construction/IRC2021P2-Pt03-Ch06-SecR602.10.4', 'iniciante', true, 'Confirmado contra IRC 2021 Table R602.10.4: WSP = wood structural panel.'),
  ('irc-165', 'IRC', 'wall-bracing-methods', 'Per Table R602.10.4, the bracing method abbreviation ''LIB'' identifies which method?', '{"A": "Limited interior bracing", "B": "Let-in bracing (1x4 wood or metal strap let into studs)", "C": "Load-isolated bracing", "D": "Lateral inset board"}'::jsonb, 'B', '''LIB'' in Table R602.10.4 stands for Let-In Bracing, which consists of a nominal 1-inch-by-4-inch wood let-in to the studs at an angle (45 to 60 degrees), or an approved metal strap installed in the same manner.', 'IRC R602.10.4', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-6-wall-construction/IRC2021P2-Pt03-Ch06-SecR602.10.4', 'intermediario', true, 'Confirmado contra IRC 2021 Table R602.10.4: LIB = let-in bracing (1x4 or metal strap).'),
  ('irc-166', 'IRC', 'wall-bracing-methods', 'Under Section R602.10.4, the ''PFH'' continuous method is what type of braced wall panel?', '{"A": "Portland framed header", "B": "Portal frame with hold-downs", "C": "Permanent foundation header", "D": "Plywood floor harness"}'::jsonb, 'B', 'PFH stands for Portal Frame with Hold-downs, a continuous method (per R602.10.6.2) used to provide bracing capacity in narrow wall segments adjacent to garage door and other large openings where standard panel widths cannot be met. It uses tie-down devices and specific sheathing/fastening details.', 'IRC R602.10.6.2', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-6-wall-construction/IRC2021P2-Pt03-Ch06-SecR602.10.6.2', 'avancado', true, 'Confirmado contra IRC 2021 R602.10.6.2: PFH = portal frame with hold-downs (method for narrow panels).'),
  ('irc-167', 'IRC', 'braced-wall-line-spacing', 'Per Table R602.10.1.2, what is the maximum spacing permitted between braced wall lines in most conventional light-frame construction?', '{"A": "20 feet", "B": "25 feet", "C": "30 feet", "D": "35 feet"}'::jsonb, 'B', 'Braced wall lines are generally required to be spaced not more than 25 feet on center, measured perpendicular to the braced wall line. Spacing up to 35 feet is permitted only under specific exception conditions with increased bracing amounts.', 'IRC R602.10.1.2', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-6-wall-construction/IRC2021P2-Pt03-Ch06-SecR602.10.1.2', 'intermediario', true, 'Confirmado contra IRC 2021 R602.10.1.2: braced wall line spacing generally 25 ft, up to 35 ft with exception.'),
  ('irc-168', 'IRC', 'wall-bracing-methods', 'Under Table R602.10.4, the minimum length of a braced wall panel using continuous wood structural panel sheathing (CS-WSP) is generally based on which factor?', '{"A": "A fixed 96 inches regardless of height", "B": "The adjacent clear opening height (with a ratio table)", "C": "The stud spacing only", "D": "The number of stories above"}'::jsonb, 'B', 'For continuous sheathing methods (CS-WSP), the minimum braced wall panel length is determined from a table relating the panel length to the maximum adjacent clear opening height (height-to-length ratio), allowing shorter panels than the standard 48-inch intermittent minimum.', 'IRC R602.10.5', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-6-wall-construction/IRC2021P2-Pt03-Ch06-SecR602.10.5', 'avancado', true, 'Confirmado contra IRC 2021 R602.10.5: CS panel length based on adjacent clear opening height ratio.'),
  ('irc-169', 'IRC', 'stairs-winder', 'Per R311.7.5.2.1, winder treads must have a minimum tread depth of 6 inches at any point and not less than what depth at the walkline (12 inches from the narrow edge)?', '{"A": "9 inches", "B": "10 inches", "C": "11 inches", "D": "7 inches"}'::jsonb, 'B', 'R311.7.5.2.1 requires winder treads to have a minimum tread depth of 10 inches measured at the walkline, located 12 inches from the side where the treads are narrower. The minimum tread depth at any point is 6 inches.', 'IRC R311.7.5.2.1', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-3-building-planning/IRC2021P2-Pt03-Ch03-SecR311.7.5.2.1', 'intermediario', true, 'Confirmado contra IRC 2021 R311.7.5.2.1: winder 10 in at walkline (12 in point), 6 in minimum at any point.'),
  ('irc-170', 'IRC', 'stairs-spiral', 'Under R311.7.10.1, a spiral stairway must have a clear walking width of at least 26 inches and a minimum tread depth of 6-3/4 inches at the walkline located what distance from the narrower edge?', '{"A": "12 inches", "B": "9 inches", "C": "10 inches", "D": "14 inches"}'::jsonb, 'A', 'R311.7.10.1 specifies spiral stairways with a minimum clear width of 26 inches at and below the handrail, treads having a depth of not less than 6-3/4 inches at the walkline (12 inches from the narrower edge), and a minimum headroom of 6 feet 6 inches. Riser height must not exceed 9-1/2 inches.', 'IRC R311.7.10.1', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-3-building-planning/IRC2021P2-Pt03-Ch03-SecR311.7.10.1', 'avancado', true, 'Confirmado contra IRC 2021 R311.7.10.1: spiral 26 in clear width, 6-3/4 in tread at walkline 12 in from narrow edge, max riser 9-1/2 in.'),
  ('irc-171', 'IRC', 'stairs-headroom', 'Per R311.7.2, the minimum headroom in all parts of a stairway must not be less than which dimension, measured vertically from the sloped line of tread nosings?', '{"A": "6 feet 4 inches", "B": "6 feet 8 inches", "C": "7 feet 0 inches", "D": "6 feet 6 inches"}'::jsonb, 'B', 'R311.7.2 requires a minimum stairway headroom of 6 feet 8 inches measured vertically from the sloped line adjoining the tread nosing or from the floor surface of the landing or platform.', 'IRC R311.7.2', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-3-building-planning/IRC2021P2-Pt03-Ch03-SecR311.7.2', 'iniciante', true, 'Confirmado contra IRC 2021 R311.7.2: stairway headroom minimum 6 ft 8 in.'),
  ('irc-172', 'IRC', 'guards-loads', 'Per Table R301.5, guards and handrails must be designed to resist a single concentrated load of how many pounds applied in any direction along the top?', '{"A": "100 pounds", "B": "150 pounds", "C": "200 pounds", "D": "300 pounds"}'::jsonb, 'C', 'Table R301.5 establishes that guards and handrails must resist a concentrated load of 200 pounds applied in any direction at any point along the top. Guard in-fill components are separately designed for a 50-pound concentrated load on a 1-square-foot area.', 'IRC R301.5', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-3-building-planning/IRC2021P2-Pt03-Ch03-SecR301.5', 'intermediario', true, 'Confirmado contra IRC 2021 Table R301.5: guard/handrail concentrated load 200 lb any direction; in-fill 50 lb.'),
  ('irc-173', 'IRC', 'footing-width', 'Per Table R403.1(1), for a 1-story dwelling with conventional light-frame construction on soil with a load-bearing value of 1,500 psf, the minimum footing width is generally what?', '{"A": "12 inches", "B": "16 inches", "C": "10 inches", "D": "8 inches"}'::jsonb, 'A', 'Table R403.1(1) provides minimum footing widths based on load-bearing value of the soil and number of stories. For 1-story light-frame construction on 1,500 psf soil, the minimum footing width is 12 inches. Wider footings are required for additional stories or lower-capacity soils.', 'IRC R403.1', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-4-foundations/IRC2021P2-Pt03-Ch04-SecR403.1', 'intermediario', true, 'Confirmado contra IRC 2021 Table R403.1(1): 1-story light-frame on 1500 psf soil = 12 in footing width.'),
  ('irc-174', 'IRC', 'footing-thickness', 'Per R403.1, the minimum thickness for a concrete footing supporting walls of light-frame construction is generally not less than what?', '{"A": "4 inches", "B": "6 inches", "C": "8 inches", "D": "10 inches"}'::jsonb, 'B', 'Section R403.1 (and Table R403.1) establish a minimum concrete footing thickness of 6 inches for typical conditions. The footing projection beyond the foundation wall and the soil bearing capacity also govern the required dimensions.', 'IRC R403.1', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-4-foundations/IRC2021P2-Pt03-Ch04-SecR403.1', 'iniciante', true, 'Confirmado contra IRC 2021 R403.1: minimum footing thickness 6 in.'),
  ('irc-175', 'IRC', 'frost-depth', 'Per R403.1.4, footings must be placed below the frost line or otherwise protected from frost. In Massachusetts, which has a deep design frost depth, this means footings are typically placed at what minimum depth?', '{"A": "12 inches below grade", "B": "Below the locally established frost line (commonly 48 inches in much of MA)", "C": "Exactly 24 inches regardless of location", "D": "Frost protection is not required in MA"}'::jsonb, 'B', 'R403.1.4 requires footing bottoms to extend below the frost line of the locality or be protected by an approved method of frost protection (such as frost-protected shallow foundations per R403.3). Massachusetts adopts a deep frost line, commonly around 48 inches; the authority having jurisdiction sets the local depth.', 'IRC R403.1.4', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-4-foundations/IRC2021P2-Pt03-Ch04-SecR403.1.4', 'intermediario', true, 'Confirmado contra IRC 2021 R403.1.4: footings below local frost line or frost-protected; MA local depth commonly ~48 in (set by AHJ).'),
  ('irc-176', 'IRC', 'electrical-service', 'Per E3601 (and E3602), what is the minimum service rating required for a one-family dwelling?', '{"A": "60 amperes", "B": "100 amperes, 3-wire", "C": "125 amperes", "D": "200 amperes"}'::jsonb, 'B', 'Section E3602.1 requires that for a one-family dwelling, the service disconnecting means have a rating of not less than 100 amperes, 3-wire. This corresponds to the NEC 230.79(C) minimum service rating for dwellings.', 'IRC E3602.1', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-36-services/IRC2021P2-Pt08-Ch36-SecE3602.1', 'intermediario', true, 'Confirmado contra IRC 2021 E3602.1: dwelling service minimum 100 A, 3-wire.'),
  ('irc-177', 'IRC', 'electrical-grounding-electrode', 'Per E3608.1.2, when a metal underground water pipe is used as a grounding electrode, it must be supplemented by an additional electrode and must be in direct contact with the earth for not less than how many feet?', '{"A": "5 feet", "B": "8 feet", "C": "10 feet", "D": "20 feet"}'::jsonb, 'C', 'E3608.1.2 requires that a metal underground water pipe in direct contact with the earth for 10 feet or more qualify as a grounding electrode, and it must be supplemented by an additional grounding electrode (such as a ground rod or concrete-encased electrode).', 'IRC E3608.1.2', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-36-services/IRC2021P2-Pt08-Ch36-SecE3608.1.2', 'avancado', true, 'Confirmado contra IRC 2021 E3608.1.2: water pipe electrode requires 10 ft earth contact + supplemental electrode.'),
  ('irc-178', 'IRC', 'electrical-grounding-electrode', 'Per E3608.1.4, a ground rod electrode (rod and pipe type) must have a length in contact with the soil of not less than what?', '{"A": "6 feet", "B": "8 feet", "C": "10 feet", "D": "4 feet"}'::jsonb, 'B', 'E3608.1.4 specifies rod and pipe electrodes not less than 8 feet in length, installed so that at least 8 feet of length is in contact with the soil. The rod is generally driven to a depth of 8 feet, with the upper end flush with or below grade.', 'IRC E3608.1.4', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-36-services/IRC2021P2-Pt08-Ch36-SecE3608.1.4', 'intermediario', true, 'Confirmado contra IRC 2021 E3608.1.4: ground rod minimum 8 ft, 8 ft in contact with soil.'),
  ('irc-179', 'IRC', 'electrical-conductor-sizing', 'Per Table E3705.1, a 20-ampere branch circuit using copper conductors generally requires what minimum conductor size?', '{"A": "14 AWG copper", "B": "12 AWG copper", "C": "10 AWG copper", "D": "16 AWG copper"}'::jsonb, 'B', 'Table E3705.1 (and the overcurrent protection rules) require 12 AWG copper for a 20-ampere branch circuit. 14 AWG copper is limited to 15-ampere circuits, and 10 AWG copper is used for 30-ampere circuits.', 'IRC E3705.1', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-37-branch-circuit-and-feeder-requirements/IRC2021P2-Pt08-Ch37-SecE3705.1', 'intermediario', true, 'Confirmado contra IRC 2021 E3705/Table E3705.1: 20 A circuit = 12 AWG copper; 15 A = 14 AWG; 30 A = 10 AWG.'),
  ('irc-180', 'IRC', 'electrical-box-fill', 'Per Table E3905.12.2.1, what volume allowance (in cubic inches) is assigned to each 14 AWG conductor when calculating box fill?', '{"A": "1.50 cubic inches", "B": "2.00 cubic inches", "C": "2.25 cubic inches", "D": "2.50 cubic inches"}'::jsonb, 'B', 'Table E3905.12.2.1 assigns a free space volume of 2.00 cubic inches per 14 AWG conductor. For 12 AWG it is 2.25 cubic inches, and for 10 AWG it is 2.50 cubic inches. These allowances are used to verify the box is large enough for its conductors, devices, and fittings.', 'IRC E3905.12.2.1', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-39-power-and-lighting-distribution/IRC2021P2-Pt08-Ch39-SecE3905.12', 'avancado', true, 'Confirmado contra IRC 2021 Table E3905.12.2.1: 14 AWG = 2.00 cu in, 12 AWG = 2.25, 10 AWG = 2.50.'),
  ('irc-181', 'IRC', 'electrical-lighting-outlets', 'Per E3903.2, at least one wall switch-controlled lighting outlet must be installed in which of the following spaces?', '{"A": "Only the kitchen", "B": "Habitable rooms, bathrooms, hallways, stairways, and attached garages", "C": "Only rooms larger than 70 square feet", "D": "Only the living room and bedrooms"}'::jsonb, 'B', 'E3903.2 requires at least one wall switch-controlled lighting outlet in every habitable room and bathroom. E3903.3 and related sections extend lighting outlet requirements to hallways, stairways, attached garages, detached garages with power, and at exterior egress doors.', 'IRC E3903.2', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-39-power-and-lighting-distribution/IRC2021P2-Pt08-Ch39-SecE3903.2', 'intermediario', true, 'Confirmado contra IRC 2021 E3903.2/E3903.3: switch-controlled lighting outlets in habitable rooms, baths, halls, stairs, garages.'),
  ('irc-182', 'IRC', 'electrical-gfci', 'Per E3902, GFCI protection is required for 125-volt, single-phase, 15- and 20-ampere receptacles in which of the following dwelling locations?', '{"A": "Only outdoors", "B": "Bathrooms, garages, outdoors, crawl spaces, unfinished basements, kitchens, and within 6 feet of sinks", "C": "Only the kitchen countertop receptacles", "D": "Only basements"}'::jsonb, 'B', 'E3902 requires GFCI protection in a broad list of locations including bathrooms, garages and accessory buildings, outdoors, crawl spaces, unfinished basements, kitchen receptacles serving countertops, and receptacles within 6 feet of sinks, plus laundry areas, dishwashers, and others.', 'IRC E3902', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-39-power-and-lighting-distribution/IRC2021P2-Pt08-Ch39-SecE3902', 'intermediario', true, 'Confirmado contra IRC 2021 E3902: GFCI in baths, garages, outdoors, crawl spaces, unfinished basements, kitchens, within 6 ft of sinks, laundry.'),
  ('irc-183', 'IRC', 'electrical-afci', 'Per E3902.16, AFCI (arc-fault circuit-interrupter) protection is required for 120-volt, 15- and 20-ampere branch circuits supplying outlets in which dwelling areas?', '{"A": "Only bedrooms", "B": "Kitchens, family rooms, dining rooms, living rooms, bedrooms, hallways, closets, laundry areas, and similar rooms", "C": "Only unfinished basements", "D": "Only outdoor circuits"}'::jsonb, 'B', 'E3902.16 requires AFCI protection on 120-volt, 15- and 20-ampere branch circuits supplying outlets and devices in nearly all habitable and similar spaces, including kitchens, family/dining/living rooms, bedrooms, parlors, libraries, dens, sunrooms, recreation rooms, closets, hallways, laundry areas, and similar rooms.', 'IRC E3902.16', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-39-power-and-lighting-distribution/IRC2021P2-Pt08-Ch39-SecE3902.16', 'avancado', true, 'Confirmado contra IRC 2021 E3902.16: AFCI on 120V 15/20 A circuits in nearly all dwelling living areas.'),
  ('irc-184', 'IRC', 'plumbing-dwv-sizing', 'Per Table P3005.4.1 (drainage fixture units), a residential water closet (1.6 gpf) is assigned how many drainage fixture units (DFU)?', '{"A": "1 DFU", "B": "2 DFU", "C": "3 DFU", "D": "4 DFU"}'::jsonb, 'C', 'Under the drainage fixture unit values used for sizing DWV piping (Table P3004.1 / P3005), a private water closet at 1.6 gpf is assigned 3 drainage fixture units. DFU totals are used with Table P3005 to size the building drain and branch piping.', 'IRC P3004.1', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-30-sanitary-drainage/IRC2021P2-Pt07-Ch30-SecP3004.1', 'avancado', true, 'Confirmado contra IRC 2021 DFU table (P3004.1): water closet 1.6 gpf = 3 DFU.'),
  ('irc-185', 'IRC', 'plumbing-cleanouts', 'Per P3005.2.6, the maximum distance between cleanouts in horizontal drainage piping 4 inches or less in diameter must not exceed what?', '{"A": "50 feet", "B": "75 feet", "C": "100 feet", "D": "25 feet"}'::jsonb, 'C', 'P3005.2.6 requires cleanouts to be spaced not more than 100 feet apart in horizontal drainage lines that are 4 inches or less in nominal diameter (the limit is increased for larger pipe). This ensures the entire run can be cleared in the event of a stoppage.', 'IRC P3005.2.6', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-30-sanitary-drainage/IRC2021P2-Pt07-Ch30-SecP3005.2', 'avancado', true, 'Confirmado contra IRC 2021 P3005.2.6: cleanout spacing max 100 ft for pipe 4 in or less.'),
  ('irc-186', 'IRC', 'plumbing-cleanouts', 'Per P3005.2.2, a cleanout is required near the junction of the building drain and the building sewer. This cleanout is commonly required at what location?', '{"A": "At the highest fixture only", "B": "At or near the connection between the building drain and building sewer, or an accessible alternative", "C": "Only inside the wall behind the water closet", "D": "Cleanouts are not required at the building drain"}'::jsonb, 'B', 'P3005.2.2 requires a cleanout near the junction of the building drain and the building sewer, either inside or outside the wall, accessible for rodding the sewer. An accessible two-way cleanout is often used to serve both the building drain and the sewer.', 'IRC P3005.2.2', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-30-sanitary-drainage/IRC2021P2-Pt07-Ch30-SecP3005.2', 'intermediario', true, 'Confirmado contra IRC 2021 P3005.2.2: cleanout at/near building drain-to-sewer junction.'),
  ('irc-187', 'IRC', 'plumbing-water-heater-relief', 'Per P2804.6.1, the discharge pipe from a water heater temperature and pressure (T&P) relief valve must terminate not more than how far above the floor or waste receptor?', '{"A": "2 inches", "B": "6 inches", "C": "12 inches", "D": "18 inches"}'::jsonb, 'B', 'P2804.6.1 requires the relief valve discharge pipe to terminate not more than 6 inches and not less than two times the discharge pipe diameter above the floor, ground, or waste receptor flood-level rim. The discharge must be air gapped and not directly connected to drainage.', 'IRC P2804.6.1', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-28-water-heaters/IRC2021P2-Pt07-Ch28-SecP2804.6.1', 'avancado', true, 'Confirmado contra IRC 2021 P2804.6.1: T&P discharge terminates max 6 in above floor/receptor, min 2x pipe diameter, air gap.'),
  ('irc-188', 'IRC', 'plumbing-water-heater-relief', 'Per P2804.6.1, the discharge piping from a relief valve must NOT do which of the following?', '{"A": "Discharge to the outdoors", "B": "Have a reduced size smaller than the relief valve outlet, or contain a valve/trap, or thread its end", "C": "Be made of an approved material", "D": "Be installed with a downward slope"}'::jsonb, 'B', 'P2804.6.1 prohibits reducing the discharge pipe below the size of the relief valve outlet, installing a valve or check valve in the discharge, trapping the discharge line, and threading the terminal end (to prevent capping). The pipe must drain by gravity and discharge to an approved location.', 'IRC P2804.6.1', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-28-water-heaters/IRC2021P2-Pt07-Ch28-SecP2804.6.1', 'intermediario', true, 'Confirmado contra IRC 2021 P2804.6.1: no size reduction, no valve/trap, no threaded terminal end; gravity drain.'),
  ('irc-189', 'IRC', 'plumbing-sump', 'Per P3007.3.3, a sump pit serving a sewage ejector/pump must have a minimum diameter and depth as specified, and the sump pump must be capable of handling solid spheres of at least what size for sewage?', '{"A": "1/2 inch", "B": "1 inch", "C": "1-1/2 inches", "D": "2 inches"}'::jsonb, 'B', 'Under P3007, sewage pumps and ejectors receiving the discharge of water closets must be capable of passing a 1-inch-diameter solid sphere. The sump pit must be constructed of approved materials and be airtight where it receives sewage, with proper venting.', 'IRC P3007.3', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-30-sanitary-drainage/IRC2021P2-Pt07-Ch30-SecP3007.3', 'avancado', true, 'Confirmado contra IRC 2021 P3007.3: sewage pump for water closets must pass 1-in solid sphere.'),
  ('irc-190', 'IRC', 'plumbing-sump', 'Per P3007.1, a sump pit collecting clear-water or sewage discharge below the gravity drain must have a cover that is which of the following?', '{"A": "Open to the room for ventilation", "B": "Gas-tight and removable where it receives sewage", "C": "Made of cloth mesh", "D": "Not required for residential sumps"}'::jsonb, 'B', 'P3007 requires sump pits receiving sewage to have gastight, removable covers and to be vented in accordance with the venting provisions. A gas-tight cover prevents sewer gases from entering the dwelling.', 'IRC P3007.1', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-30-sanitary-drainage/IRC2021P2-Pt07-Ch30-SecP3007.1', 'intermediario', true, 'Confirmado contra IRC 2021 P3007: sewage sump cover gas-tight and removable, vented.'),
  ('irc-191', 'IRC', 'mechanical-range-hood', 'Per M1503.1 and M1503.4, where a range hood/domestic cooking exhaust is provided and discharges to the outdoors, the duct must be made of what?', '{"A": "Flexible plastic duct", "B": "Smooth interior, airtight metal duct equipped with a backdraft damper", "C": "Cloth-lined duct", "D": "Gypsum-board chase only"}'::jsonb, 'B', 'M1503 requires range hood and domestic cooking exhaust ducts that discharge to the outdoors to be of smooth interior surface, airtight metal, equipped with a backdraft damper, and independent of all other exhaust systems. Single-wall ducts are required for grease-laden exhaust.', 'IRC M1503.4', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-15-exhaust-systems/IRC2021P2-Pt05-Ch15-SecM1503.4', 'intermediario', true, 'Confirmado contra IRC 2021 M1503.4: range hood exhaust duct smooth airtight metal with backdraft damper, independent.'),
  ('irc-192', 'IRC', 'mechanical-range-hood', 'Per M1503.6, where a makeup air requirement is triggered, an exhaust hood system capable of exhausting in excess of how many cubic feet per minute (cfm) must be provided with makeup air?', '{"A": "200 cfm", "B": "300 cfm", "C": "400 cfm", "D": "600 cfm"}'::jsonb, 'C', 'M1503.6 requires that exhaust hood systems capable of exhausting in excess of 400 cfm be provided with makeup air at a rate approximately equal to the exhaust air rate, to avoid depressurization that can cause backdrafting of fuel-fired appliances.', 'IRC M1503.6', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-15-exhaust-systems/IRC2021P2-Pt05-Ch15-SecM1503.6', 'avancado', true, 'Confirmado contra IRC 2021 M1503.6: hoods over 400 cfm require makeup air.'),
  ('irc-193', 'IRC', 'mechanical-return-air', 'Per M1602.2, return air must NOT be taken from which of the following locations?', '{"A": "A habitable bedroom", "B": "A closet, bathroom, toilet room, kitchen, garage, mechanical room, boiler room, or furnace room", "C": "A living room", "D": "A finished basement"}'::jsonb, 'B', 'M1602.2 prohibits taking return air from closets, bathrooms, toilet rooms, kitchens, garages, mechanical rooms, boiler rooms, furnace rooms, and from spaces containing fuel-fired appliances (with exceptions), to prevent the circulation of contaminants and combustion products.', 'IRC M1602.2', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-16-duct-systems/IRC2021P2-Pt05-Ch16-SecM1602.2', 'intermediario', true, 'Confirmado contra IRC 2021 M1602.2: prohibited return air from closets, baths, kitchens, garages, mechanical/boiler/furnace rooms.'),
  ('irc-194', 'IRC', 'mechanical-gas-vent', 'Per G2427 (IFGC), a Category I gas appliance vent (such as a typical atmospheric draft furnace or water heater) operates under what condition?', '{"A": "Positive vent pressure and condensing", "B": "Non-positive vent static pressure and non-condensing (does not condense flue gases)", "C": "Always sealed-combustion only", "D": "No venting required"}'::jsonb, 'B', 'Category I appliances operate with a non-positive vent static pressure and a vent gas temperature that avoids excessive condensate in the venting system (non-condensing). They are typically vented with Type B vent or a masonry/listed chimney sized per G2427.', 'IRC G2427', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-24-fuel-gas/IRC2021P2-Pt06-Ch24-SecG2427', 'avancado', true, 'Confirmado contra IRC 2021 G2427 (IFGC venting): Category I = non-positive vent pressure, non-condensing.'),
  ('irc-195', 'IRC', 'mechanical-duct-support', 'Per M1601.4.4, metal ducts must be supported at intervals not exceeding what distance (for typical horizontal runs)?', '{"A": "4 feet", "B": "8 feet", "C": "10 feet", "D": "12 feet"}'::jsonb, 'D', 'M1601.4.4 requires metal ducts to be supported at intervals not exceeding 12 feet by approved hangers or supports. Other duct types (such as factory-made flexible or fibrous-glass ducts) have shorter support spacing per their listings and the code.', 'IRC M1601.4.4', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-16-duct-systems/IRC2021P2-Pt05-Ch16-SecM1601.4', 'intermediario', true, 'Confirmado contra IRC 2021 M1601.4.4: metal ducts supported at intervals not exceeding 12 ft.'),
  ('irc-196', 'IRC', 'factory-built-fireplace', 'Per R1004.1, factory-built fireplaces must be listed and labeled and installed in accordance with what?', '{"A": "Any general masonry standard", "B": "The conditions of the listing and the manufacturer''s installation instructions", "C": "Only local zoning rules", "D": "The plumbing code"}'::jsonb, 'B', 'R1004.1 requires factory-built fireplaces to be listed and labeled and installed in accordance with the conditions of the listing and the manufacturer''s instructions. They must also be tested to UL 127. Clearances to combustibles and hearth extensions follow the listing.', 'IRC R1004.1', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-10-chimneys-and-fireplaces/IRC2021P2-Pt03-Ch10-SecR1004.1', 'iniciante', true, 'Confirmado contra IRC 2021 R1004.1: factory-built fireplaces listed/labeled, installed per listing and manufacturer instructions (UL 127).'),
  ('irc-197', 'IRC', 'factory-built-chimney', 'Per R1005.1, factory-built chimneys serving factory-built fireplaces must be listed and labeled and tested to which standard?', '{"A": "UL 103", "B": "UL 1777 (chimney lining)", "C": "ASTM C90", "D": "NFPA 13"}'::jsonb, 'A', 'R1005.1 requires factory-built chimneys to be listed and labeled and installed and terminated per the manufacturer''s installation instructions. Factory-built chimneys for residential appliances are tested to UL 103 (and HT versions for higher temperatures).', 'IRC R1005.1', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-10-chimneys-and-fireplaces/IRC2021P2-Pt03-Ch10-SecR1005.1', 'intermediario', true, 'Confirmado contra IRC 2021 R1005.1: factory-built chimneys listed/labeled, tested to UL 103.'),
  ('irc-198', 'IRC', 'masonry-fireplace-dimensions', 'Per R1001.5, the firebox of a masonry fireplace must have a minimum depth (front to back) of how much for fireboxes 6 square feet or less in opening?', '{"A": "12 inches", "B": "20 inches", "C": "24 inches", "D": "16 inches"}'::jsonb, 'B', 'R1001.5 requires masonry fireplace fireboxes to have a minimum firebox depth of 20 inches. An exception allows a reduced depth for Rumford-style fireplaces meeting specific proportioning rules.', 'IRC R1001.5', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-10-chimneys-and-fireplaces/IRC2021P2-Pt03-Ch10-SecR1001.5', 'intermediario', true, 'Confirmado contra IRC 2021 R1001.5: masonry firebox minimum depth 20 in (Rumford exception).'),
  ('irc-199', 'IRC', 'masonry-fireplace-dimensions', 'Per R1001.6, the firebox walls (lining) of a masonry fireplace lined with firebrick must be not less than what thickness?', '{"A": "1 inch firebrick (with 8 inches total wall)", "B": "2 inches of firebrick", "C": "4 inches of firebrick", "D": "1/2 inch of firebrick"}'::jsonb, 'B', 'R1001.6 requires firebox walls to be constructed of solid masonry not less than 8 inches thick, or lined with not less than 2 inches of firebrick where the total thickness (including lining) is at least 8 inches. The 2-inch firebrick lining provides heat resistance.', 'IRC R1001.6', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-10-chimneys-and-fireplaces/IRC2021P2-Pt03-Ch10-SecR1001.6', 'avancado', true, 'Confirmado contra IRC 2021 R1001.6: firebox 8 in solid masonry or 2 in firebrick lining within 8 in total.'),
  ('irc-200', 'IRC', 'pools-spas-barriers', 'Per Appendix V/AVII (residential pool barriers), the barrier surrounding a residential swimming pool must be at least what height measured on the side facing away from the pool?', '{"A": "36 inches", "B": "42 inches", "C": "48 inches", "D": "60 inches"}'::jsonb, 'C', 'The residential swimming pool barrier provisions require an enclosure (barrier) not less than 48 inches in height above grade measured on the side of the barrier facing away from the pool. Openings and gaps are also limited to prevent a young child from passing through.', 'IRC Appendix V (AV)', 'https://codes.iccsafe.org/s/IRC2021P2/appendix-v-swimming-pools-spas-and-hot-tubs/IRC2021P2-Pt09-AppxV-SecAV105', 'intermediario', true, 'Confirmado contra IRC 2021 Appendix V residential pool barrier: minimum 48 in height on side away from pool. (Appendix designation/letter varies by adopting jurisdiction.)'),
  ('irc-201', 'IRC', 'pools-spas-barriers', 'Per the residential pool barrier provisions, the maximum vertical clearance between grade and the bottom of the barrier must not exceed what?', '{"A": "1 inch", "B": "2 inches", "C": "4 inches", "D": "6 inches"}'::jsonb, 'C', 'The pool barrier provisions limit the clearance between grade and the bottom of the barrier to a maximum of 2 inches when measured on the side facing away from the pool (4 inches where the barrier is mounted on top of an above-grade structure such as a deck). Openings must not allow passage of a 4-inch sphere.', 'IRC Appendix V (AV)', 'https://codes.iccsafe.org/s/IRC2021P2/appendix-v-swimming-pools-spas-and-hot-tubs/IRC2021P2-Pt09-AppxV-SecAV105', 'avancado', true, 'Confirmado contra IRC 2021 Appendix V pool barrier: bottom clearance 2 in (4 in on above-grade structure); openings reject 4-in sphere.'),
  ('irc-202', 'IRC', 'accessory-detached-garage', 'Per R309.1, the floor surface of a garage must be of approved noncombustible material, and the area of floor used for parking must be sloped to facilitate movement of liquids toward what?', '{"A": "The interior wall", "B": "A drain or toward the main vehicle entry doorway", "C": "The ceiling", "D": "An interior floor drain only"}'::jsonb, 'B', 'R309.1 requires garage floors to be of approved noncombustible material, with the area used for parking sloped to facilitate the movement of liquids to a drain or toward the main vehicle entry doorway, preventing pooling of fuel or water.', 'IRC R309.1', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-3-building-planning/IRC2021P2-Pt03-Ch03-SecR309.1', 'iniciante', true, 'Confirmado contra IRC 2021 R309.1: garage floor noncombustible, sloped to drain or main vehicle doorway.'),
  ('irc-203', 'IRC', 'accessory-detached-garage', 'Per R309.5, carports and garages must NOT open directly into which of the following rooms?', '{"A": "A laundry room", "B": "A room used for sleeping purposes", "C": "A hallway", "D": "A mudroom"}'::jsonb, 'B', 'R309.5 prohibits openings from a private garage directly into a room used for sleeping purposes. Other doorways between a garage and dwelling must meet the separation and self-closing/solid-door requirements of R302.5.1.', 'IRC R309.5', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-3-building-planning/IRC2021P2-Pt03-Ch03-SecR309.5', 'intermediario', true, 'Confirmado contra IRC 2021 R309.5: garage must not open directly into a sleeping room; door rules per R302.5.1.'),
  ('irc-204', 'IRC', 'wall-bracing-methods', 'Per Table R602.10.4, the minimum thickness of gypsum board used as a ''GB'' braced wall panel applied to each face is what?', '{"A": "1/4 inch", "B": "3/8 inch", "C": "1/2 inch", "D": "5/8 inch"}'::jsonb, 'C', 'The gypsum board (GB) bracing method in Table R602.10.4 uses gypsum board not less than 1/2 inch thick, fastened to studs and applied to one or both faces depending on the required bracing length, with the contributing length doubled when applied to both faces.', 'IRC R602.10.4', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-6-wall-construction/IRC2021P2-Pt03-Ch06-SecR602.10.4', 'avancado', true, 'Confirmado contra IRC 2021 Table R602.10.4: GB method uses 1/2 in gypsum board; both-face application affects length.'),
  ('irc-205', 'IRC', 'stairs-spiral', 'Per R311.7.10.1, the minimum headroom for a spiral stairway, measured vertically from the tread nosings, must be not less than what?', '{"A": "6 feet 0 inches", "B": "6 feet 4 inches", "C": "6 feet 6 inches", "D": "6 feet 8 inches"}'::jsonb, 'C', 'R311.7.10.1 permits spiral stairways with a reduced minimum headroom of 6 feet 6 inches (versus 6 feet 8 inches for standard stairs), reflecting the compact geometry allowed specifically for spiral stairs.', 'IRC R311.7.10.1', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-3-building-planning/IRC2021P2-Pt03-Ch03-SecR311.7.10.1', 'intermediario', true, 'Confirmado contra IRC 2021 R311.7.10.1: spiral stair headroom minimum 6 ft 6 in.'),
  ('irc-206', 'IRC', 'electrical-conductor-sizing', 'Per E3705 and the small-conductor overcurrent rules, a 15-ampere branch circuit using copper conductors must be wired with at least what conductor size?', '{"A": "16 AWG copper", "B": "14 AWG copper", "C": "12 AWG copper", "D": "10 AWG copper"}'::jsonb, 'B', 'The branch-circuit conductor sizing provisions require 14 AWG copper as the minimum for a 15-ampere branch circuit. The overcurrent device must not exceed the conductor''s allowable ampacity for these small conductors.', 'IRC E3705.1', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-37-branch-circuit-and-feeder-requirements/IRC2021P2-Pt08-Ch37-SecE3705.1', 'iniciante', true, 'Confirmado contra IRC 2021 E3705.1: 15 A circuit = 14 AWG copper minimum.'),
  ('irc-207', 'IRC', 'electrical-box-fill', 'Per E3905.12.2.1, a single yoke (strap) supporting one or more devices counts as how many conductor volume allowances, based on the largest conductor connected to the device?', '{"A": "One conductor volume allowance", "B": "Double volume allowance (two) based on the largest conductor connected to the device", "C": "No allowance", "D": "Four volume allowances"}'::jsonb, 'B', 'E3905.12.2 requires a double volume allowance (two conductor volumes) for each yoke or strap containing one or more devices, based on the largest conductor connected to a device supported by that yoke. This accounts for the space occupied by the device.', 'IRC E3905.12.2.1', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-39-power-and-lighting-distribution/IRC2021P2-Pt08-Ch39-SecE3905.12', 'avancado', true, 'Confirmado contra IRC 2021 E3905.12.2: device yoke counts as double volume allowance (largest conductor at device).'),
  ('irc-208', 'IRC', 'footing-width', 'Per Table R403.1(1), increasing the number of stories on a dwelling generally has what effect on the minimum required footing width (all else equal)?', '{"A": "No effect", "B": "Decreases the required width", "C": "Increases the required width", "D": "Eliminates the footing requirement"}'::jsonb, 'C', 'Table R403.1(1) shows that as the number of supported stories increases, the minimum footing width increases (for a given soil bearing value) because the load transmitted to the soil is greater. Lower soil bearing values likewise require wider footings.', 'IRC R403.1', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-4-foundations/IRC2021P2-Pt03-Ch04-SecR403.1', 'iniciante', true, 'Confirmado contra IRC 2021 Table R403.1(1): footing width increases with stories and with lower soil bearing value.'),
  ('irc-209', 'IRC', 'mechanical-return-air', 'Per M1602.2, when return air is taken from one floor and supplied to another in a dwelling with multiple stories, the system must address what concern?', '{"A": "Color of the ductwork", "B": "Air balance/transfer such that return air is not drawn from prohibited spaces and adequate makeup/transfer air is provided", "C": "The brand of the furnace", "D": "Nothing; multi-story return is prohibited"}'::jsonb, 'B', 'M1602.2 and the duct system provisions require that return air be drawn only from permitted spaces and that adequate transfer/return paths exist. Return air must not be taken from prohibited rooms, and the system must maintain proper air balance between floors.', 'IRC M1602.2', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-16-duct-systems/IRC2021P2-Pt05-Ch16-SecM1602.2', 'intermediario', true, 'Confirmado contra IRC 2021 M1602.2: return air only from permitted spaces; balance/transfer air required.'),
  ('irc-210', 'IRC', 'guards-loads', 'Per Table R301.5, guard in-fill components (such as balusters and panel fillers below the top rail) must be designed to resist a horizontally applied normal load of how many pounds on an area of 1 square foot?', '{"A": "25 pounds", "B": "50 pounds", "C": "100 pounds", "D": "200 pounds"}'::jsonb, 'B', 'Table R301.5 footnotes require guard in-fill components, balusters, and panel fillers to resist a horizontally applied normal load of 50 pounds on an area equal to 1 square foot. This is separate from the 200-pound concentrated load on the top of the guard.', 'IRC R301.5', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-3-building-planning/IRC2021P2-Pt03-Ch03-SecR301.5', 'avancado', true, 'Confirmado contra IRC 2021 Table R301.5: in-fill components resist 50 lb on 1 sq ft (separate from 200 lb top load).'),
  ('irc-001', 'IRC', 'egress', 'Under the IRC, what is the minimum CLEAR width that the required egress door of a dwelling unit must provide when the door is open 90 degrees?', '{"A": "30 inches", "B": "32 inches", "C": "34 inches", "D": "36 inches"}'::jsonb, 'B', 'The required egress door must provide a clear width of not less than 32 inches, measured between the face of the door and the stop with the door open 90 degrees. The door slab itself is typically wider (a 36-inch door is common) because the clear opening is reduced by the door thickness and stop.', 'IRC R311.2', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-3-building-planning/IRC2021P2-Pt03-Ch03-SecR311.2', 'intermediario', true, 'Confirmado contra IRC 2021 R311.2 (ICC Digital Codes e up.codes): clear width >= 32 in, clear height >= 78 in, side-hinged.'),
  ('irc-002', 'IRC', 'egress', 'What is the minimum CLEAR height of the required egress door opening, measured from the top of the threshold to the bottom of the stop?', '{"A": "76 inches", "B": "78 inches", "C": "80 inches", "D": "84 inches"}'::jsonb, 'B', 'The IRC requires the required egress door to provide a clear height of not less than 78 inches, measured from the top of the threshold to the bottom of the stop. A standard 6-foot 8-inch (80-inch) door slab yields this 78-inch clear height after the threshold and stop are accounted for.', 'IRC R311.2', 'https://up.codes/s/egress-door', 'intermediario', true, 'Confirmado contra IRC 2021 R311.2: clear height >= 78 in.'),
  ('irc-003', 'IRC', 'attic-access', 'When an attic access opening is provided in a ceiling, what is the minimum size of the required rough-framed opening?', '{"A": "20 inches by 30 inches", "B": "22 inches by 30 inches", "C": "22 inches by 36 inches", "D": "24 inches by 24 inches"}'::jsonb, 'B', 'Where an attic access is required, the rough-framed opening must be not less than 22 inches by 30 inches. When located in a ceiling, there must also be at least 30 inches of unobstructed headroom in the attic above the access, measured vertically.', 'IRC R807.1', 'https://codes.iccsafe.org/s/IRC2021P3/chapter-8-roof-ceiling-construction/IRC2021P3-Pt03-Ch08-SecR807.1', 'iniciante', true, 'Confirmado contra IRC 2021 R807.1: 22x30 rough opening, 30 in headroom, required where attic has clear height of 30 in over 30 sq ft.'),
  ('irc-004', 'IRC', 'attic-access', 'An attic access opening is required when the attic area exceeds 30 square feet AND has a vertical clear height of at least how many inches?', '{"A": "24 inches", "B": "30 inches", "C": "36 inches", "D": "42 inches"}'::jsonb, 'B', 'An attic access opening is required for attics with combustible ceiling or roof construction that have a vertical height of 30 inches or greater over an area of not less than 30 square feet. If the attic is shorter than 30 inches OR smaller than 30 square feet, no access is required by R807.1.', 'IRC R807.1', 'https://up.codes/s/attic-access', 'intermediario', true, 'Confirmado contra IRC 2021 R807.1: trigger = 30 in vertical height over 30 sq ft.'),
  ('irc-005', 'IRC', 'live-load', 'Per IRC Table R301.5, what is the minimum uniformly distributed live load for a habitable attic and attics served with a fixed stairway, as well as for sleeping rooms?', '{"A": "20 psf", "B": "30 psf", "C": "40 psf", "D": "50 psf"}'::jsonb, 'B', 'Table R301.5 assigns 30 psf to sleeping rooms and to habitable attics / attics served by fixed stairs. Non-sleeping living areas require 40 psf, while uninhabitable attics with limited storage are lower (10 or 20 psf).', 'IRC Table R301.5', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-3-building-planning/IRC2021P2-Pt03-Ch03-SecR301.5', 'intermediario', true, 'Confirmado contra IRC 2021 Table R301.5: sleeping rooms = 30 psf; habitable attics & attics with fixed stairs = 30 psf; living areas = 40 psf.'),
  ('irc-006', 'IRC', 'live-load', 'Per IRC Table R301.5, what is the minimum uniformly distributed live load for living areas (non-sleeping habitable rooms such as a living room or kitchen)?', '{"A": "30 psf", "B": "40 psf", "C": "50 psf", "D": "60 psf"}'::jsonb, 'B', 'Living areas other than sleeping rooms must be designed for a 40 psf live load per Table R301.5. Sleeping rooms and habitable attics drop to 30 psf, while exterior balconies and decks are 40 psf as well.', 'IRC Table R301.5', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-3-building-planning/IRC2021P2-Pt03-Ch03-SecR301.5', 'iniciante', true, 'Confirmado contra IRC 2021 Table R301.5: living areas = 40 psf.'),
  ('irc-007', 'IRC', 'notch-bore-joist', 'Per the IRC, notches in solid-lumber floor joists may not exceed what fraction of the depth of the member, and may not be located in the middle third of the span?', '{"A": "One-third of the depth", "B": "One-fourth of the depth", "C": "One-sixth of the depth", "D": "One-half of the depth"}'::jsonb, 'C', 'Notches in solid lumber joists, rafters and beams shall not exceed one-sixth of the depth, shall not be longer than one-third of the depth, and shall not be in the middle one-third of the span. Notches at the END of the member may go up to one-fourth the depth.', 'IRC R502.8.1', 'https://up.codes/s/cutting-drilling-and-notching', 'intermediario', true, 'Confirmado contra IRC 2021 R502.8.1: notch <= 1/6 depth, <= 1/3 long, not in middle 1/3; end notch <= 1/4 depth.'),
  ('irc-008', 'IRC', 'notch-bore-joist', 'Per the IRC, the diameter of a hole bored in a solid-lumber floor joist may not exceed what fraction of the depth of the member?', '{"A": "One-half the depth", "B": "One-third the depth", "C": "One-fourth the depth", "D": "One-sixth the depth"}'::jsonb, 'B', 'Bored holes may not exceed one-third the depth of the member and must be kept at least 2 inches from the top or bottom edge and at least 2 inches from any other hole or notch.', 'IRC R502.8.1', 'https://up.codes/s/cutting-drilling-and-notching', 'intermediario', true, 'Confirmado contra IRC 2021 R502.8.1: bored hole <= 1/3 depth, 2 in clear from edges/other holes.'),
  ('irc-009', 'IRC', 'notch-bore-rafter', 'When boring a hole in a sawn-lumber rafter or ceiling joist, the hole must be kept at least how far from the top or bottom edge of the member (and from any other hole or notch)?', '{"A": "1 inch", "B": "1.5 inches", "C": "2 inches", "D": "3 inches"}'::jsonb, 'C', 'Holes bored in sawn-lumber rafters/joists must not be closer than 2 inches to the top or bottom of the member, nor closer than 2 inches to any other hole or to a notch in the same member. Diameter is still limited to one-third the depth.', 'IRC R802.7.1', 'https://up.codes/s/irc-802-7-1-sawn-lumber', 'intermediario', true, 'Confirmado contra IRC 2021 R802.7.1: 2 in clearance to edges and other holes/notches.'),
  ('irc-010', 'IRC', 'collar-ties', 'When collar ties are used to resist rafter uplift near the ridge, what is the minimum size and maximum spacing required by the IRC?', '{"A": "Minimum 1x4 nominal, spaced not more than 48 inches on center", "B": "Minimum 2x4 nominal, spaced not more than 24 inches on center", "C": "Minimum 1x6 nominal, spaced not more than 32 inches on center", "D": "Minimum 2x6 nominal, spaced not more than 16 inches on center"}'::jsonb, 'A', 'Collar ties shall be not less than 1x4 nominal and spaced not more than 4 feet (48 inches) on center. They are installed in the upper third of the attic space to resist wind uplift at the ridge.', 'IRC R802.4.6', 'https://up.codes/s/collar-ties', 'intermediario', true, 'Confirmado contra IRC 2021 R802.4.6 (renumerado de R802.3.1 em edicoes antigas): 1x4 nominal min, 48 in o.c. max, upper third.'),
  ('irc-011', 'IRC', 'collar-ties', 'In which portion of the roof must collar ties be located when they are installed to connect opposing rafters?', '{"A": "In the lower third, near the wall plates", "B": "In the middle third of the rafter span", "C": "In the upper third of the attic space", "D": "Directly at the ridge board only"}'::jsonb, 'C', 'Collar ties (or ridge straps) connecting opposing rafters must be located in the upper third of the attic space. Ties placed lower in the assembly are functioning as rafter ties, which have separate requirements.', 'IRC R802.4.6', 'https://up.codes/s/collar-ties', 'iniciante', true, 'Confirmado contra IRC 2021 R802.4.6: collar ties in upper third of attic space.'),
  ('irc-012', 'IRC', 'top-plate', 'In a wood-framed wall capped with a double top plate, end joints in the upper top plate must be offset from joints in the lower plate by at least how many inches?', '{"A": "16 inches", "B": "24 inches", "C": "32 inches", "D": "48 inches"}'::jsonb, 'B', 'End joints in the double top plate must be offset not less than 24 inches, and the plates must lap at corners and intersections with bearing partitions. Joints in the plate need not occur over a stud.', 'IRC R602.3.2', 'https://up.codes/s/top-plate', 'intermediario', true, 'Confirmado contra IRC 2021 R602.3.2: double top plate end joints offset >= 24 in.'),
  ('irc-013', 'IRC', 'stud-spacing', 'Per IRC Table R602.3(5), what is the maximum stud spacing for a 2x4 stud in an exterior bearing wall supporting a roof, ceiling, and one floor above, at the common 10-foot stud height?', '{"A": "12 inches on center", "B": "16 inches on center", "C": "24 inches on center", "D": "32 inches on center"}'::jsonb, 'B', 'For a 2x4 bearing-wall stud at the typical 10-foot maximum height carrying a roof plus one floor, the IRC stud table limits spacing to 16 inches on center. Lighter loading (roof and ceiling only) can allow 24 inches on center.', 'IRC R602.3.1 / Table R602.3(5)', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-6-wall-construction/IRC2021P2-Pt03-Ch06-SecR602.3.1', 'avancado', true, 'Confirmado contra IRC 2021 R602.3.1 / Table R602.3(5): 2x4 a 10 ft suportando teto+1 piso = 16 in o.c. max.'),
  ('irc-014', 'IRC', 'footings', 'Absent frost considerations, the bottom of an exterior footing must be placed at least how far below the undisturbed ground surface?', '{"A": "6 inches", "B": "8 inches", "C": "12 inches", "D": "18 inches"}'::jsonb, 'C', 'The IRC requires the bottom of exterior footings to be at least 12 inches below the undisturbed ground surface. In areas subject to frost (such as Massachusetts), footings must extend below the local frost line, which governs when it is deeper than 12 inches.', 'IRC R403.1.4', 'https://up.codes/viewer/virginia/irc-2021/chapter/4/foundations', 'iniciante', true, 'Confirmado contra IRC 2021 R403.1.4: footing bottom >= 12 in below undisturbed grade, plus below frost line where applicable.'),
  ('irc-015', 'IRC', 'backfill', 'Per the IRC, backfill may not be placed against a foundation wall until the wall has been anchored to the floor above OR sufficiently braced. Below what unbalanced backfill height is that bracing requirement waived?', '{"A": "2 feet", "B": "3 feet", "C": "4 feet", "D": "6 feet"}'::jsonb, 'C', 'Per R404.1.7, backfill shall not be placed until the wall is anchored to the floor above or sufficiently braced. The exception waives this requirement for walls supporting 4 feet or less of unbalanced backfill. This is why crews typically frame the first floor before backfilling a full basement wall.', 'IRC R404.1.7', 'https://up.codes/s/backfill-placement', 'intermediario', true, 'Confirmado contra IRC 2021 R404.1.7: bracing/anchorage required acima de 4 ft de unbalanced backfill.'),
  ('irc-016', 'IRC', 'backfill', 'In Seismic Design Categories D0, D1, or D2, masonry foundation walls supported only by the prescriptive provisions are limited to a maximum unbalanced backfill height of:', '{"A": "3 feet", "B": "4 feet", "C": "6 feet", "D": "8 feet"}'::jsonb, 'B', 'In SDC D0, D1, or D2, the unbalanced backfill height against prescriptive masonry foundation walls is limited to 4 feet. Most of Massachusetts is SDC B, where the standard backfill tables govern, but supervisors should know the seismic limit.', 'IRC R404.1.4', 'https://up.codes/s/seismic-design-category-d-0-d-1-or-d-2', 'avancado', true, 'Confirmado contra IRC 2021 R404.1.4: masonry foundation walls em SDC D0/D1/D2 limitados a 4 ft unbalanced backfill.'),
  ('irc-017', 'IRC', 'dampproofing-waterproofing', 'Foundation walls that enclose below-grade interior space must be dampproofed (or waterproofed where severe water conditions exist) from the finished grade down to what point?', '{"A": "To the top of the footing only", "B": "To 6 inches below the top of the basement floor (or the top of the footing, whichever is higher)", "C": "To 12 inches above the basement floor", "D": "To the bottom of the footing"}'::jsonb, 'B', 'Both dampproofing (R406.1) and waterproofing (R406.2) must extend from the finished grade down to the higher of the top of the footing or 6 inches below the top of the basement floor. Waterproofing is the higher standard, required where a high water table or severe soil-water conditions exist.', 'IRC R406.1 / R406.2', 'https://up.codes/s/foundation-waterproofing-and-dampproofing', 'intermediario', true, 'Confirmado contra IRC 2021 R406.1 e R406.2: extensao ate o maior entre topo do footing ou 6 in abaixo do piso do basement.'),
  ('irc-018', 'IRC', 'slab-on-grade', 'Under IRC R506.2.3 (as adopted in the 2021 IRC), what is the minimum thickness/class of the vapor retarder required between a concrete slab-on-grade floor and the base course or subgrade?', '{"A": "4-mil polyethylene", "B": "6-mil polyethylene", "C": "10-mil vapor retarder conforming to ASTM E1745 Class A", "D": "No vapor retarder is required for any slab"}'::jsonb, 'C', 'The 2021 IRC upgraded the under-slab vapor retarder requirement to a minimum 10-mil vapor retarder conforming to ASTM E1745 Class A, with joints lapped not less than 6 inches. Older codes accepted 6-mil poly.', 'IRC R506.2.3', 'https://codes.iccsafe.org/s/IRC2021P3/chapter-5-floors/IRC2021P3-Pt03-Ch05-SecR506.2.3', 'avancado', true, 'Confirmado contra IRC 2021 R506.2.3: 10-mil ASTM E1745 Class A, lap 6 in. Mudanca chave vs edicoes anteriores (6-mil).'),
  ('irc-019', 'IRC', 'chimney-fireplace', 'A masonry chimney must terminate at least how high above the highest point where it passes through the roof, and at least 2 feet higher than any portion of the building within 10 feet (the ''3-2-10 rule'')?', '{"A": "2 feet", "B": "3 feet", "C": "4 feet", "D": "5 feet"}'::jsonb, 'B', 'The 3-2-10 rule: a chimney must extend at least 3 feet above the highest point where it penetrates the roof, and at least 2 feet higher than any portion of the building within a 10-foot horizontal distance. Whichever condition produces the greater height governs.', 'IRC R1003.9', 'https://up.codes/viewer/connecticut/irc-2021/chapter/10/chimneys-and-fireplaces', 'intermediario', true, 'Confirmado contra IRC 2021 R1003.9: 3 ft acima da penetracao no telhado, 2 ft acima de qualquer parte do edificio em 10 ft.'),
  ('irc-020', 'IRC', 'chimney-fireplace', 'What is the minimum depth of the firebox of a standard (non-Rumford) masonry fireplace?', '{"A": "12 inches", "B": "16 inches", "C": "20 inches", "D": "24 inches"}'::jsonb, 'C', 'A standard masonry fireplace firebox must have a minimum depth of 20 inches. A Rumford fireplace is permitted with a shallower 12-inch depth provided it meets the additional R1001.6 throat and proportion requirements.', 'IRC R1001.6', 'https://up.codes/s/firebox-dimensions', 'intermediario', true, 'Confirmado contra IRC 2021 R1001.6: firebox depth >= 20 in (Rumford exception = 12 in).'),
  ('irc-021', 'IRC', 'chimney-fireplace', 'For a masonry fireplace with an opening smaller than 6 square feet, the hearth extension must project at least how far in front of the fireplace opening?', '{"A": "8 inches", "B": "12 inches", "C": "16 inches", "D": "20 inches"}'::jsonb, 'C', 'For openings less than 6 square feet, the hearth extension must extend at least 16 inches in front of, and 8 inches beyond each side of, the opening. For openings of 6 square feet or larger, those minimums increase to 20 inches in front and 12 inches on each side.', 'IRC R1001.10', 'https://codes.iccsafe.org/s/IRC2021P3/chapter-10-chimneys-and-fireplaces/IRC2021P3-Pt03-Ch10-SecR1001.10', 'intermediario', true, 'Confirmado contra IRC 2021 R1001.10: opening < 6 sq ft = 16 in front / 8 in sides; >= 6 sq ft = 20 in / 12 in.'),
  ('irc-022', 'IRC', 'asphalt-shingles', 'Asphalt shingles may be installed only on roof slopes of at least what minimum pitch?', '{"A": "1 unit vertical in 12 units horizontal (1:12)", "B": "2 units vertical in 12 units horizontal (2:12)", "C": "3 units vertical in 12 units horizontal (3:12)", "D": "4 units vertical in 12 units horizontal (4:12)"}'::jsonb, 'B', 'Asphalt shingles require a minimum slope of 2:12. For slopes between 2:12 and 4:12, double underlayment is required. Below 2:12, asphalt shingles are not permitted.', 'IRC R905.2.2', 'https://up.codes/viewer/connecticut/irc-2021/chapter/9/roof-assemblies', 'iniciante', true, 'Confirmado contra IRC 2021 R905.2.2: slope minimo 2:12 para asphalt shingles.'),
  ('irc-023', 'IRC', 'asphalt-shingles', 'Absent a more restrictive manufacturer requirement, what is the minimum number of fasteners per strip (three-tab) asphalt shingle required by the IRC?', '{"A": "2 fasteners", "B": "3 fasteners", "C": "4 fasteners", "D": "6 fasteners"}'::jsonb, 'C', 'The IRC requires at least four fasteners per strip shingle (or two fasteners per individual shingle), unless the manufacturer''s approved instructions require more (high-wind regions commonly require six).', 'IRC R905.2.6', 'https://cdn.townweb.com/windsorlocksct.org/wp-content/uploads/2024/01/Ashpalt_Shingle_Installation.pdf', 'iniciante', true, 'Confirmado contra IRC 2021 R905.2.6: min 4 fasteners por strip shingle (2 por individual), salvo manufacturer mais restritivo.'),
  ('irc-024', 'IRC', 'asphalt-shingles', 'Per the IRC, a drip edge at the eaves and rake edges of a shingle roof must extend back onto the roof deck not less than:', '{"A": "1 inch", "B": "2 inches", "C": "3 inches", "D": "4 inches"}'::jsonb, 'B', 'A drip edge is required at eaves and rakes. It must extend back onto the roof deck not less than 2 inches and down below the sheathing not less than 1/4 inch, with adjacent segments lapped at least 2 inches.', 'IRC R905.2.8.5', 'https://prbd.com/pubs/guides/building/reroofing.pdf', 'intermediario', true, 'Confirmado contra IRC 2021 R905.2.8.5: drip edge >= 2 in onto deck, >= 1/4 in below sheathing, 2 in laps.'),
  ('irc-025', 'IRC', 'skylight', 'A unit skylight installed on a roof with a slope of less than 3:12 must be mounted on a curb extending at least how high above the plane of the roof (unless the manufacturer specifies otherwise)?', '{"A": "2 inches", "B": "3 inches", "C": "4 inches", "D": "6 inches"}'::jsonb, 'C', 'Unit skylights on roofs with a pitch less than 3:12 must be mounted on a curb extending not less than 4 inches above the plane of the roof, unless the manufacturer''s installation instructions allow otherwise.', 'IRC R308.6.8', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-3-building-planning/IRC2021P2-Pt03-Ch03-SecR308.6.8', 'intermediario', true, 'Confirmado contra IRC 2021 R308.6.8: curb >= 4 in para skylight em slope < 3:12.'),
  ('irc-026', 'IRC', 'natural-light-ventilation', 'Habitable rooms must have an aggregate glazing (natural light) area of not less than what percentage of the floor area of the room?', '{"A": "4 percent", "B": "6 percent", "C": "8 percent", "D": "10 percent"}'::jsonb, 'C', 'Natural light: habitable rooms require glazing of at least 8 percent of the floor area. Natural ventilation requires openable area of at least 4 percent of the floor area. A common exam trap is swapping the 8 percent (light) and 4 percent (ventilation) values.', 'IRC R303.1', 'https://codes.iccsafe.org/s/IRC2021P2/part-iii-building-planning-and-construction/IRC2021P2-Pt03-Ch03-SecR303.1', 'iniciante', true, 'Confirmado contra IRC 2021 R303.1: light >= 8% floor area; ventilation openable >= 4% floor area.'),
  ('irc-027', 'IRC', 'natural-light-ventilation', 'Where natural ventilation is provided through openings to the outdoors, the openable area must be not less than what percentage of the floor area being ventilated?', '{"A": "4 percent", "B": "8 percent", "C": "10 percent", "D": "5 percent"}'::jsonb, 'A', 'Natural ventilation requires an openable area of at least 4 percent of the floor area being ventilated. The natural light requirement is the higher figure, 8 percent of floor area.', 'IRC R303.1', 'https://up.codes/s/habitable-rooms', 'iniciante', true, 'Confirmado contra IRC 2021 R303.1: ventilation openable >= 4% floor area.'),
  ('irc-028', 'IRC', 'crawl-space-ventilation', 'For a ventilated under-floor (crawl) space WITHOUT an approved ground vapor retarder, the minimum net area of ventilation openings must be not less than:', '{"A": "1 square foot per 100 square feet of crawl space ground area", "B": "1 square foot per 150 square feet of crawl space ground area", "C": "1 square foot per 300 square feet of crawl space ground area", "D": "1 square foot per 1,500 square feet of crawl space ground area"}'::jsonb, 'B', 'Without a Class I vapor retarder on the ground, crawl space ventilation must be at least 1 square foot per 150 square feet of ground area. Where an approved ground vapor retarder is installed, the ratio may be reduced to 1 per 1,500.', 'IRC R408.1 / R408.2', 'https://up.codes/s/space-moisture-vapor-control', 'intermediario', true, 'Confirmado contra IRC 2021 R408.1: 1/150 sem vapor retarder; 1/1500 com vapor retarder aprovado (R408.2).'),
  ('irc-029', 'IRC', 'attic-ventilation', 'The minimum net free ventilating area for an enclosed attic or rafter space is what fraction of the area of the vented space (the standard, baseline ratio)?', '{"A": "1/100", "B": "1/150", "C": "1/300", "D": "1/600"}'::jsonb, 'B', 'The baseline attic ventilation requirement is 1/150 of the vented area. It can be reduced to 1/300 only when 40 to 50 percent of the venting is in the upper portion of the attic (and, in Climate Zones 6-8, a Class I or II vapor retarder is on the warm-in-winter side). Most of Massachusetts is Climate Zone 5.', 'IRC R806.2', 'https://codes.iccsafe.org/s/IRC2021P3/chapter-8-roof-ceiling-construction/IRC2021P3-Pt03-Ch08-SecR806.2', 'intermediario', true, 'Confirmado contra IRC 2021 R806.2: padrao 1/150; reducao a 1/300 com 40-50% high vents (e vapor retarder em CZ 6-8).'),
  ('irc-030', 'IRC', 'egress-emergency', 'What is the minimum net clear opening AREA required for an emergency escape and rescue opening (other than a grade-floor/below-grade opening)?', '{"A": "5.0 square feet", "B": "5.7 square feet", "C": "6.0 square feet", "D": "8.0 square feet"}'::jsonb, 'B', 'Emergency escape and rescue openings must provide a net clear opening of at least 5.7 square feet. Grade-floor or below-grade openings may be reduced to 5.0 square feet. The opening also requires a minimum net clear height of 24 inches and width of 20 inches.', 'IRC R310.2.1', 'https://up.codes/s/minimum-opening-area', 'intermediario', true, 'Confirmado contra IRC 2021 R310.2.1: net clear 5.7 sq ft (grade floor 5.0), height 24 in, width 20 in.'),
  ('irc-031', 'IRC', 'egress-emergency', 'An emergency escape and rescue opening must have the bottom of the clear opening located no higher than how many inches above the finished floor?', '{"A": "36 inches", "B": "44 inches", "C": "48 inches", "D": "54 inches"}'::jsonb, 'B', 'The sill (bottom of the clear opening) of an emergency escape and rescue opening must be not more than 44 inches above the finished floor. The minimum net clear height is 24 inches and minimum width is 20 inches.', 'IRC R310.2.2', 'https://codes.iccsafe.org/s/IRC2021P2/chapter-3-building-planning/IRC2021P2-Pt03-Ch03-SecR310.1', 'iniciante', true, 'Confirmado contra IRC 2021 R310.2.2: sill height <= 44 in acima do piso acabado.'),
  ('irc-032', 'IRC', 'stairs', 'Under the IRC, what is the maximum riser height and minimum tread depth permitted for an interior stairway?', '{"A": "Maximum riser 8 inches, minimum tread 9 inches", "B": "Maximum riser 7-3/4 inches, minimum tread 10 inches", "C": "Maximum riser 7 inches, minimum tread 11 inches", "D": "Maximum riser 8-1/4 inches, minimum tread 9 inches"}'::jsonb, 'B', 'The IRC permits a maximum riser height of 7-3/4 inches and requires a minimum tread depth of 10 inches. Stairways must also be at least 36 inches wide and have a minimum headroom of 6 feet 8 inches. (The 7-inch riser / 11-inch tread figures belong to the IBC, a common distractor.)', 'IRC R311.7.5', 'https://www.cdaid.org/files/Building/Applications/Stairs_and_Handrails_2021.pdf', 'iniciante', true, 'Confirmado contra IRC 2021 R311.7: riser max 7-3/4 in, tread min 10 in, width 36 in, headroom 6 ft 8 in.'),
  ('irc-033', 'IRC', 'guards', 'Guards are required along open-sided walking surfaces, stairs, and landings located more than how many inches above the floor or grade below?', '{"A": "24 inches", "B": "30 inches", "C": "36 inches", "D": "42 inches"}'::jsonb, 'B', 'A guard is required where a walking surface is more than 30 inches above the floor or grade below (measured within 36 inches horizontally of the edge). Required residential guards must be at least 36 inches high.', 'IRC R312.1', 'https://www.co.routt.co.us/DocumentCenter/View/15199', 'iniciante', true, 'Confirmado contra IRC 2021 R312.1.1/R312.1.2: guard exigido acima de 30 in; altura minima 36 in.'),
  ('irc-034', 'IRC', 'grading', 'Per the IRC, the finished grade around a building must fall at least how much within the first 10 feet measured away from the foundation (where lot conditions permit)?', '{"A": "3 inches", "B": "6 inches", "C": "8 inches", "D": "12 inches"}'::jsonb, 'B', 'Lots must be graded to drain surface water away from the foundation; the grade must fall a minimum of 6 inches within the first 10 feet. Where physical barriers prevent that fall, swales or drains must be provided. Impervious surfaces within 10 feet must slope at least 2 percent away.', 'IRC R401.3', 'https://up.codes/viewer/maine/irc-2021/chapter/4/foundations', 'iniciante', true, 'Confirmado contra IRC 2021 R401.3: 6 in de queda em 10 ft; impervious surfaces 2% min.'),
  ('irc-035', 'IRC', 'deck-cantilever', 'In the 2021 IRC, how is the maximum allowable cantilever (overhang) of a deck floor joist beyond its supporting beam determined?', '{"A": "It is always limited to exactly one-fourth of the joist backspan, regardless of joist size", "B": "It is taken from prescriptive Table R507.6 based on joist size, species, and span", "C": "It may equal the full backspan as long as the joists are doubled", "D": "Deck joists are never permitted to cantilever beyond the beam"}'::jsonb, 'B', 'The 2021 IRC replaced the old simple ''one-fourth of the backspan'' rule with prescriptive maximum cantilever values listed in Table R507.6 by joist size, species, and span. Option A reflects the superseded rule, which is now a common exam distractor.', 'IRC R507.6 / Table R507.6', 'https://www.jlconline.com/deck-builder/2021-deck-code-highlights_o', 'avancado', true, 'Confirmado: 2021 IRC moveu deck joists para R507.6 e substituiu a regra de 1/4 do backspan por Table R507.6. Distrator A = regra antiga (pre-2021).'),
  ('osha-011', 'OSHA', 'Excavations - Protective Systems', 'Under OSHA excavation standards, at what trench or excavation depth must employees generally be protected from cave-ins by an adequate protective system (such as sloping, shoring, or shielding)?', '{"A": "Any excavation 3 feet or more in depth", "B": "Excavations 4 feet or more in depth", "C": "Excavations 5 feet or more in depth, unless made entirely in stable rock", "D": "Excavations 6 feet or more in depth"}'::jsonb, 'C', 'Each employee in an excavation must be protected from cave-ins by an adequate protective system, except when excavations are made entirely in stable rock OR are less than 5 feet deep and a competent person has examined the ground and found no indication of a potential cave-in. So protection is required at 5 feet and deeper (and sometimes shallower if the competent person finds a hazard).', '29 CFR 1926.652(a)(1)', 'https://www.osha.gov/laws-regs/regulations/standardnumber/1926/1926.652', 'intermediario', true, 'Confirmed 5-foot trigger and stable-rock / competent-person exceptions in 1926.652(a)(1)(i)-(ii).'),
  ('osha-012', 'OSHA', 'Excavations - Spoil Pile / Materials', 'Under OSHA, excavated materials (spoil), equipment, and other materials must be kept at least how far back from the edge of an excavation?', '{"A": "At least 1 foot from the edge", "B": "At least 2 feet from the edge", "C": "At least 5 feet from the edge", "D": "Distance is left to the operator''s discretion"}'::jsonb, 'B', 'Employees must be protected from excavated or other materials or equipment that could pose a hazard by falling or rolling into excavations. Protection is provided by keeping such materials at least 2 feet from the edge of the excavation, by using retaining devices, or by a combination of both.', '29 CFR 1926.651(j)(2)', 'https://www.osha.gov/laws-regs/regulations/standardnumber/1926/1926.651', 'iniciante', true, 'Confirmed 2-foot spoil-setback requirement in 1926.651(j)(2).'),
  ('osha-013', 'OSHA', 'Excavations - Access and Egress', 'In a trench excavation 4 feet or more in depth, a stairway, ladder, ramp, or other safe means of egress must be located so that an employee never has to travel laterally more than:', '{"A": "10 feet", "B": "25 feet", "C": "50 feet", "D": "75 feet"}'::jsonb, 'B', 'A stairway, ladder, ramp or other safe means of egress must be located in trench excavations that are 4 feet or more in depth so as to require no more than 25 feet of lateral travel for employees.', '29 CFR 1926.651(c)(2)', 'https://www.osha.gov/laws-regs/regulations/standardnumber/1926/1926.651', 'intermediario', true, 'Confirmed 4-foot depth trigger and 25-foot max lateral travel to egress in 1926.651(c)(2).'),
  ('osha-014', 'OSHA', 'Excavations - Soil Classification', 'Under OSHA''s soil classification system in Appendix A to Subpart P, which soil type is the MOST stable?', '{"A": "Type C", "B": "Type B", "C": "Type A", "D": "Stable rock"}'::jsonb, 'D', 'Stable rock is the most stable classification (it can be excavated with vertical sides and remain intact). Among soils, Type A is most stable, Type B is intermediate, and Type C is the least stable. The standard classifies materials as Stable Rock, Type A, Type B, and Type C.', '29 CFR 1926 Subpart P App A', 'https://www.osha.gov/laws-regs/regulations/standardnumber/1926/1926SubpartPAppA', 'iniciante', true, 'Confirmed classification order (Stable Rock most stable, then A, B, C) in Subpart P Appendix A. Question asks for the single most stable category overall, which is stable rock.'),
  ('osha-015', 'OSHA', 'Scaffolding - Capacity', 'Under OSHA scaffold standards, each scaffold and scaffold component must be capable of supporting, without failure, its own weight and at least how many times the maximum intended load applied or transmitted to it?', '{"A": "2 times the maximum intended load", "B": "3 times the maximum intended load", "C": "4 times the maximum intended load", "D": "6 times the maximum intended load"}'::jsonb, 'C', 'Each scaffold and scaffold component must support, without failure, its own weight and at least 4 times the maximum intended load applied or transmitted to it. (Suspension ropes and connecting hardware have a separate 6-to-1 safety factor.)', '29 CFR 1926.451(a)(1)', 'https://www.osha.gov/laws-regs/regulations/standardnumber/1926/1926.451', 'iniciante', true, 'Confirmed 4x capacity factor for scaffolds/components in 1926.451(a)(1); 6x for suspension ropes in 1926.451(a)(4).'),
  ('osha-016', 'OSHA', 'Scaffolding - Fall Protection Threshold', 'Each employee on a scaffold more than how many feet above a lower level must be protected from falling by guardrails or a personal fall arrest system?', '{"A": "More than 4 feet", "B": "More than 6 feet", "C": "More than 10 feet", "D": "More than 15 feet"}'::jsonb, 'C', 'Each employee on a scaffold more than 10 feet above a lower level must be protected from falling to that lower level by guardrail systems and/or personal fall arrest systems (with specific rules varying by scaffold type). Note: the general construction fall-protection trigger for unprotected edges is 6 feet, but the scaffold-specific threshold is 10 feet.', '29 CFR 1926.451(g)(1)', 'https://www.osha.gov/laws-regs/regulations/standardnumber/1926/1926.451', 'intermediario', true, 'Confirmed scaffold 10-foot fall-protection trigger in 1926.451(g)(1). Distractor B (6 ft) is intentionally the general Subpart M edge trigger.'),
  ('osha-017', 'OSHA', 'Scaffolding - Guardrail Heights', 'For scaffolds manufactured or first placed in service after January 1, 2000, the top edge height of toprails (or equivalent guardrail members) must be between:', '{"A": "30 inches and 36 inches above the platform surface", "B": "36 inches and 45 inches above the platform surface", "C": "38 inches and 45 inches above the platform surface", "D": "42 inches and 48 inches above the platform surface"}'::jsonb, 'C', 'For scaffolds manufactured and placed in service after January 1, 2000, the top edge height of toprails or equivalent guardrail members must be between 38 inches and 45 inches above the platform surface. (Scaffolds placed in service before that date allowed 36 to 45 inches.)', '29 CFR 1926.451(g)(4)(ii)', 'https://www.osha.gov/laws-regs/regulations/standardnumber/1926/1926.451', 'avancado', true, 'Confirmed 38-45 in toprail height for post-Jan-1-2000 scaffolds in 1926.451(g)(4)(ii). Distractor B (36-45 in) is the pre-2000 figure.'),
  ('osha-018', 'OSHA', 'Scaffolding - Access', 'Under OSHA scaffold rules, when scaffold platforms are more than how many feet above or below a point of access, must a safe means of access (ladder, stair tower, ramp, etc.) be provided?', '{"A": "More than 2 feet", "B": "More than 4 feet", "C": "More than 6 feet", "D": "More than 10 feet"}'::jsonb, 'A', 'When scaffold platforms are more than 2 feet above or below a point of access, a safe means of access such as a portable ladder, hook-on ladder, attachable ladder, stair tower, stairway-type ladder, ramp, or direct access from another scaffold or structure must be provided. Cross braces may NOT be used as a means of access.', '29 CFR 1926.451(e)(1)', 'https://www.osha.gov/laws-regs/regulations/standardnumber/1926/1926.451', 'intermediario', true, 'Confirmed 2-foot access trigger and prohibition on using cross braces for access in 1926.451(e)(1).'),
  ('osha-019', 'OSHA', 'Electrical / Lockout-Tagout', 'Under OSHA construction electrical standards, controls that are deactivated during the course of work on energized or de-energized equipment or circuits must be:', '{"A": "Left as found so other crews can re-energize quickly", "B": "Tagged with a label, and the tags must remain in place until the work is completed", "C": "Painted red to indicate caution", "D": "Removed entirely from the panel"}'::jsonb, 'B', 'Controls that are to be deactivated during the course of work on energized or de-energized equipment or circuits must be tagged. Tags must be placed to plainly identify the equipment or circuits being worked on, and must remain in place until the work is completed.', '29 CFR 1926.417(a)-(b)', 'https://www.osha.gov/laws-regs/regulations/standardnumber/1926/1926.417', 'intermediario', true, 'Confirmed control-tagging and tag-remains-until-complete requirements in 1926.417(a) and (b).'),
  ('osha-020', 'OSHA', 'Electrical - GFCI / Assured Grounding', 'On construction sites, which of the following is an acceptable method for protecting employees from ground-fault hazards on 120-volt, single-phase, 15- and 20-ampere receptacle outlets not part of the permanent wiring?', '{"A": "Using only double-insulated tools with no further protection", "B": "Ground-fault circuit interrupters (GFCIs) OR an assured equipment grounding conductor program", "C": "A surge protector strip plugged into the outlet", "D": "Posting a sign warning of shock hazard"}'::jsonb, 'B', 'OSHA requires either ground-fault circuit interrupters (GFCIs) for all 120V, single-phase, 15- and 20-amp receptacle outlets not part of the permanent wiring, OR the employer must establish and implement an assured equipment grounding conductor program covering all cord sets, receptacles not part of the permanent wiring, and equipment connected by cord and plug.', '29 CFR 1926.404(b)(1)', 'https://www.osha.gov/laws-regs/regulations/standardnumber/1926/1926.404', 'intermediario', true, 'Confirmed the GFCI vs. assured-grounding-program options in 1926.404(b)(1)(i)-(iii).'),
  ('osha-021', 'OSHA', 'PPE - Head Protection', 'Under OSHA construction PPE rules, employees working in areas where there is a possible danger of head injury from impact, falling or flying objects, or electrical shock and burns must be protected by:', '{"A": "A cloth cap or bandana", "B": "Protective helmets (hard hats)", "C": "Safety glasses only", "D": "Nothing, if they are experienced workers"}'::jsonb, 'B', 'Employees working in areas where there is a possible danger of head injury from impact, or from falling or flying objects, or from electrical shock and burns, must be protected by protective helmets (hard hats) meeting the applicable ANSI/consensus standard.', '29 CFR 1926.100(a)', 'https://www.osha.gov/laws-regs/regulations/standardnumber/1926/1926.100', 'iniciante', true, 'Confirmed head-protection requirement in 1926.100(a).'),
  ('osha-022', 'OSHA', 'PPE - Eye and Face Protection', 'Under OSHA, eye and face protective equipment must be provided when:', '{"A": "Only when the employee specifically requests it", "B": "Machines or operations present potential eye or face injury from physical, chemical, or radiation agents", "C": "Only during welding operations", "D": "Only after an injury has already occurred on the job"}'::jsonb, 'B', 'Employees must be provided with eye and face protection equipment when machines or operations present potential eye or face injury from physical, chemical, or radiation agents. The equipment must meet the applicable ANSI standard for occupational and educational eye and face protection.', '29 CFR 1926.102(a)(1)', 'https://www.osha.gov/laws-regs/regulations/standardnumber/1926/1926.102', 'iniciante', true, 'Confirmed eye/face protection trigger in 1926.102(a)(1).'),
  ('osha-023', 'OSHA', 'PPE - Hearing Protection', 'Under OSHA construction noise standards, feasible administrative or engineering controls must be used to reduce noise exposure when sound levels exceed which 8-hour permissible exposure level?', '{"A": "75 dBA", "B": "85 dBA", "C": "90 dBA", "D": "100 dBA"}'::jsonb, 'C', 'Protection against the effects of noise exposure must be provided when sound levels exceed a 90 dBA slow-response level on an 8-hour time-weighted basis (the construction PEL). When engineering or administrative controls fail to reduce levels within the table limits, personal hearing protective equipment must be provided and used.', '29 CFR 1926.52(b)', 'https://www.osha.gov/laws-regs/regulations/standardnumber/1926/1926.52', 'intermediario', true, 'Confirmed 90 dBA 8-hr PEL and the controls requirement in 1926.52(b) and Table D-2. Distractor B (85 dBA) is the general-industry action level, not the construction PEL.'),
  ('osha-024', 'OSHA', 'Hazard Communication / SDS', 'Under the OSHA Hazard Communication standard as applied to construction, what must an employer ensure is readily accessible to employees for each hazardous chemical they may be exposed to?', '{"A": "A purchase receipt for the chemical", "B": "The chemical manufacturer''s phone number only", "C": "A Safety Data Sheet (SDS) and a properly labeled container", "D": "A verbal warning from the supervisor only"}'::jsonb, 'C', 'Under the Hazard Communication standard (which applies to construction), employers must maintain Safety Data Sheets (SDS) for each hazardous chemical and ensure they are readily accessible to employees during each work shift, ensure containers are labeled, and provide employee information and training.', '29 CFR 1926.59 / 1910.1200(g)', 'https://www.osha.gov/laws-regs/regulations/standardnumber/1926/1926.59', 'iniciante', true, '1926.59 adopts 1910.1200 by reference for construction. SDS-accessibility requirement confirmed in 1910.1200(g)(8); labeling in (f); access requirement in (g)(8). The term MSDS was replaced by SDS under the 2012 GHS-aligned update.'),
  ('osha-025', 'OSHA', 'Cranes - Signals', 'Under OSHA''s cranes and derricks in construction standard, when a signal person is required and visual contact cannot be maintained, which of the following is true?', '{"A": "Signaling may stop entirely until visibility returns", "B": "The operator may continue the lift without any signaling method", "C": "Hand signals are still the only permitted method", "D": "An alternative signal method (such as radio/voice or audible signals) must be used and understood by both operator and signal person"}'::jsonb, 'D', 'Hand signals, voice signals, and audible signals are all permissible methods under the standard. When hand signals are used they must follow the standard system; when other methods (e.g., radio) are used they must be agreed upon and understood. Only ONE method may be used at a time, and the operator and signal person must agree on the method. A signal person is required when, among other conditions, the operator''s view is obstructed.', '29 CFR 1926.1419 / 1926.1428', 'https://www.osha.gov/laws-regs/regulations/standardnumber/1926/1926.1419', 'intermediario', true, 'Confirmed permissible signal methods (hand/voice/audible/new) and the requirement to agree on a method in 1926.1419; signal-person-required conditions in 1926.1428.'),
  ('osha-026', 'OSHA', 'Stairways', 'Under OSHA construction stairway rules, a stairrail system must be installed along each unprotected side or edge of stairways having how many or more risers, or rising more than 30 inches, whichever is less?', '{"A": "2 or more risers", "B": "3 or more risers", "C": "4 or more risers", "D": "5 or more risers"}'::jsonb, 'C', 'Stairways having four or more risers or rising more than 30 inches, whichever is less, must be equipped with at least one handrail and one stairrail system along each unprotected side or edge.', '29 CFR 1926.1052(c)(1)', 'https://www.osha.gov/laws-regs/regulations/standardnumber/1926/1926.1052', 'intermediario', true, 'Confirmed ''4 or more risers or rising more than 30 inches, whichever is less'' in 1926.1052(c)(1).'),
  ('osha-027', 'OSHA', 'Stairways - Riser/Tread Uniformity', 'Under OSHA, riser height and tread depth on temporary construction stairways must be uniform within each flight of stairs, with variations not to exceed:', '{"A": "1/8 inch", "B": "1/4 inch", "C": "1/2 inch", "D": "1 inch"}'::jsonb, 'B', 'Stairways must be installed so that riser height and tread depth are uniform within each flight, including any foundation structure used as one or more treads of the stairs. Variations in riser height or tread depth must not exceed 1/4 inch in any stairway system.', '29 CFR 1926.1052(a)(3)', 'https://www.osha.gov/laws-regs/regulations/standardnumber/1926/1926.1052', 'avancado', true, 'Confirmed 1/4-inch max variation in riser/tread uniformity in 1926.1052(a)(3).'),
  ('osha-028', 'OSHA', 'Concrete and Masonry - Limited Access Zone', 'Under OSHA''s masonry construction rules, when a masonry wall is being constructed, a limited access zone must be established prior to the start of construction. How wide must this zone be?', '{"A": "Equal to the height of the wall to be constructed plus 4 feet", "B": "A fixed 6 feet regardless of wall height", "C": "Equal to twice the wall thickness", "D": "Equal to the wall height divided by 2"}'::jsonb, 'A', 'A limited access zone must be established whenever a masonry wall is being constructed. It must be equal to the height of the wall to be constructed plus 4 feet, run the entire length of the wall, and be on the side of the wall that will be unscaffolded. It must be restricted to entry only by employees actively engaged in constructing the wall.', '29 CFR 1926.706(a)', 'https://www.osha.gov/laws-regs/regulations/standardnumber/1926/1926.706', 'avancado', true, 'Confirmed ''wall height plus 4 feet'' limited access zone in 1926.706(a)(1)-(2).'),
  ('osha-029', 'OSHA', 'Concrete - Vertical Shoring / Rebar', 'Under OSHA concrete and masonry construction rules, all protruding reinforcing steel (rebar), onto and into which employees could fall, must be:', '{"A": "Painted a bright color", "B": "Guarded to eliminate the hazard of impalement", "C": "Left exposed for inspection", "D": "Cut flush with the concrete only after curing"}'::jsonb, 'B', 'All protruding reinforcing steel, onto and into which employees could fall, must be guarded to eliminate the hazard of impalement. This is commonly achieved with rebar caps or troughs rated for the application.', '29 CFR 1926.701(b)', 'https://www.osha.gov/laws-regs/regulations/standardnumber/1926/1926.701', 'iniciante', true, 'Confirmed rebar-impalement guarding requirement in 1926.701(b).'),
  ('osha-030', 'OSHA', 'Demolition - Engineering Survey', 'Under OSHA demolition rules, prior to permitting employees to start demolition operations, what must be conducted by a competent person?', '{"A": "A cost estimate of the demolition", "B": "An engineering survey of the structure, including condition of the structure and possibility of unplanned collapse", "C": "A marketing survey of the neighborhood", "D": "A survey is only required for buildings over 10 stories"}'::jsonb, 'B', 'Prior to permitting employees to start demolition operations, an engineering survey must be made by a competent person of the structure to determine the condition of the framing, floors, and walls, and the possibility of unplanned collapse of any portion of the structure. The employer must also have in writing evidence that such a survey was performed.', '29 CFR 1926.850(a)', 'https://www.osha.gov/laws-regs/regulations/standardnumber/1926/1926.850', 'intermediario', true, 'Confirmed competent-person engineering survey requirement before demolition in 1926.850(a).'),
  ('osha-031', 'OSHA', 'Welding and Cutting - Fire Watch', 'Under OSHA welding and cutting rules, when must a fire watch be required during welding or cutting operations?', '{"A": "Only when welding outdoors", "B": "Where appreciable combustible material, in building construction or contents, is closer than 35 feet to the point of operation (or in other specified high-hazard conditions)", "C": "Only for jobs lasting more than 8 hours", "D": "Never; sprinklers always substitute for a fire watch"}'::jsonb, 'B', 'Fire watchers are required whenever welding or cutting is performed in locations where other than a minor fire might develop, including where appreciable combustible material (in building construction or contents) is closer than 35 feet to the point of operation, or where combustibles are more than 35 feet away but are easily ignited by sparks. A fire watch must be maintained for at least a half hour after completion of operations to detect and extinguish smoldering fires.', '29 CFR 1926.352(e)', 'https://www.osha.gov/laws-regs/regulations/standardnumber/1926/1926.352', 'intermediario', true, 'Confirmed fire-watch conditions tied to 35-foot combustible distance in 1926.352(e); the half-hour post-watch is from the referenced NFPA-based provisions and general fire-prevention rule 1926.352(e).'),
  ('osha-032', 'OSHA', 'Recordkeeping - Reporting', 'Under current OSHA reporting requirements, within what time frame must an employer report a work-related fatality to OSHA?', '{"A": "Within 4 hours", "B": "Within 8 hours", "C": "Within 24 hours", "D": "Within 72 hours"}'::jsonb, 'B', 'Employers must report work-related fatalities to OSHA within 8 hours of finding out about them. By contrast, work-related in-patient hospitalizations, amputations, or losses of an eye must be reported within 24 hours.', '29 CFR 1904.39(a)(1)-(2)', 'https://www.osha.gov/laws-regs/regulations/standardnumber/1904/1904.39', 'iniciante', true, 'Confirmed 8-hour fatality reporting and 24-hour hospitalization/amputation/eye-loss reporting in 1904.39(a)(1)-(2). Recordkeeping is Part 1904, which applies across construction employers.'),
  ('osha-033', 'OSHA', 'Recordkeeping - Reporting', 'Within what time frame must an employer report a work-related in-patient hospitalization, amputation, or loss of an eye to OSHA?', '{"A": "Within 8 hours", "B": "Within 24 hours", "C": "Within 48 hours", "D": "Within 7 calendar days"}'::jsonb, 'B', 'Employers must report any work-related in-patient hospitalization of one or more employees, amputation, or loss of an eye to OSHA within 24 hours. Fatalities, by contrast, must be reported within 8 hours.', '29 CFR 1904.39(a)(2)', 'https://www.osha.gov/laws-regs/regulations/standardnumber/1904/1904.39', 'intermediario', true, 'Confirmed 24-hour reporting window for hospitalization/amputation/eye-loss in 1904.39(a)(2). Distractor A (8 hr) is intentionally the fatality window.'),
  ('osha-034', 'OSHA', 'Excavations - Inspections', 'Under OSHA excavation standards, daily inspections of excavations, adjacent areas, and protective systems must be made by:', '{"A": "Any available employee", "B": "A competent person, before the start of work and as needed throughout the shift", "C": "An OSHA compliance officer", "D": "The equipment rental company"}'::jsonb, 'B', 'Daily inspections of excavations, the adjacent areas, and protective systems must be made by a competent person for evidence of a situation that could result in possible cave-ins, failure of protective systems, hazardous atmospheres, or other hazardous conditions. Inspections must be conducted prior to the start of work and as needed throughout the shift, and after every rainstorm or other hazard-increasing occurrence.', '29 CFR 1926.651(k)(1)', 'https://www.osha.gov/laws-regs/regulations/standardnumber/1926/1926.651', 'iniciante', true, 'Confirmed competent-person daily inspection requirement and timing in 1926.651(k)(1).'),
  ('osha-035', 'OSHA', 'Fall Protection - General Trigger', 'Under OSHA Subpart M, each employee on a walking/working surface with an unprotected side or edge that is how many feet or more above a lower level must be protected from falling?', '{"A": "4 feet or more", "B": "6 feet or more", "C": "10 feet or more", "D": "15 feet or more"}'::jsonb, 'B', 'Under Subpart M, each employee on a walking/working surface with an unprotected side or edge 6 feet or more above a lower level must be protected by guardrail systems, safety net systems, or personal fall arrest systems. (4 feet is the general-industry trigger; scaffolds use 10 feet; steel erection has its own rules.)', '29 CFR 1926.501(b)(1)', 'https://www.osha.gov/laws-regs/regulations/standardnumber/1926/1926.501', 'iniciante', true, 'Confirmed 6-foot general construction fall-protection trigger in 1926.501(b)(1). Distractor A (4 ft) is general industry; distractor C (10 ft) is scaffolds.'),
  ('osha-036', 'OSHA', 'Scaffolding - Supervision/Erection', 'Under OSHA scaffold rules, the erection, moving, dismantling, or alteration of scaffolds must be done under the supervision and direction of:', '{"A": "Any two employees working together", "B": "A competent person qualified in scaffold erection", "C": "The project owner", "D": "A licensed electrician"}'::jsonb, 'B', 'The erection, moving, dismantling, or alteration of scaffolds must be done under the supervision and direction of a competent person qualified in scaffold erection, moving, dismantling, or alteration. Such activities must be performed only by experienced and trained employees selected for such work by the competent person.', '29 CFR 1926.451(f)(7)', 'https://www.osha.gov/laws-regs/regulations/standardnumber/1926/1926.451', 'intermediario', true, 'Confirmed competent-person supervision of scaffold erection/dismantling in 1926.451(f)(7).'),
  ('aab-010', 'AAB', 'Accessible Parking - Count by Lot Size', 'Under 521 CMR, in a parking lot with a total of 100 spaces, what is the minimum number of accessible (handicap) parking spaces required?', '{"A": "2 accessible spaces", "B": "3 accessible spaces", "C": "4 accessible spaces", "D": "5 accessible spaces"}'::jsonb, 'C', 'Per the 521 CMR 23.00 accessible parking table, a lot of 76 to 100 total spaces requires 4 accessible spaces. (1-25 requires 1; 26-50 requires 2; 51-75 requires 3; 76-100 requires 4; the count then increases on a sliding scale for larger lots.)', '521 CMR 23.2', 'https://www.mass.gov/doc/521-cmr-23-parking-and-passenger-loading-zones/download', 'intermediario', true, 'Confirmed 521 CMR 23.2 parking table: 76-100 spaces = 4 accessible. Same tiering matches the federal ADAAG table, which 521 CMR mirrors at the low end.'),
  ('aab-011', 'AAB', 'Accessible Parking - Minimum Count', 'Under 521 CMR, a parking lot with 1 to 25 total spaces must provide at least how many accessible parking spaces?', '{"A": "0 (none required for small lots)", "B": "1 accessible space", "C": "2 accessible spaces", "D": "1 accessible space for every 10 total spaces"}'::jsonb, 'B', 'Per the 521 CMR 23.00 accessible parking table, even the smallest covered lots (1 to 25 total spaces) must provide a minimum of 1 accessible parking space. The required count rises with lot size (26-50 requires 2, 51-75 requires 3, and so on).', '521 CMR 23.2', 'https://www.mass.gov/doc/521-cmr-23-parking-and-passenger-loading-zones/download', 'iniciante', true, 'Confirmed 521 CMR 23.2 minimum of 1 accessible space for 1-25-space lots.'),
  ('aab-012', 'AAB', 'Accessible Parking - Van-Accessible', 'Under 521 CMR accessible parking requirements, which of the following best describes the van-accessible space requirement?', '{"A": "Van-accessible spaces are never required", "B": "At least one in every eight accessible spaces (but always at least one) must be van-accessible and identified by a sign reading ''Van Accessible''", "C": "All accessible spaces must be van-accessible", "D": "Van-accessible spaces are only required at hospitals"}'::jsonb, 'B', 'One in every eight accessible spaces, but not fewer than one, must be van-accessible. Van-accessible spaces have a wider access aisle (or wider space) to accommodate a van with a side-mounted lift or ramp and must be identified by an additional sign stating ''Van Accessible'' mounted below the symbol of access.', '521 CMR 23.4 / 23.6', 'https://www.mass.gov/doc/521-cmr-23-parking-and-passenger-loading-zones/download', 'intermediario', true, 'Confirmed 1-in-8 van-accessible ratio (min 1) and the ''Van Accessible'' sign requirement in 521 CMR 23, consistent with the ADAAG ratio that 521 CMR adopts.'),
  ('aab-013', 'AAB', 'Doors - Clear Width', 'Under 521 CMR, the minimum clear opening width of an accessible doorway, measured with the door open 90 degrees between the face of the door and the stop, must be at least:', '{"A": "28 inches", "B": "30 inches", "C": "32 inches", "D": "36 inches"}'::jsonb, 'C', 'Per 521 CMR 26.00, doorways must have a minimum clear opening of 32 inches, measured with the door open 90 degrees between the face of the door and the door stop. Openings more than 24 inches deep require a 36-inch minimum clear opening.', '521 CMR 26.6', 'https://www.mass.gov/doc/521-cmr-26-doors-and-doorways/download', 'iniciante', true, 'Confirmed 32-inch min clear door opening in 521 CMR 26, matching the federal 32-inch standard the AAB adopts.'),
  ('aab-014', 'AAB', 'Doors - Maneuvering Clearance', 'Under 521 CMR, for a front (forward) approach to a swinging door on the PULL side, the minimum maneuvering clearance includes how much space beyond the latch side of the door?', '{"A": "6 inches beyond the latch side", "B": "12 inches beyond the latch side", "C": "18 inches beyond the latch side", "D": "24 inches beyond the latch side"}'::jsonb, 'C', 'For a front approach on the pull side of a swinging door, 521 CMR requires 18 inches of clearance beyond the latch side of the door (and 60 inches of clear depth perpendicular to the doorway) so a wheelchair user can position to open the door. This mirrors the federal maneuvering-clearance requirement.', '521 CMR 26.7', 'https://www.mass.gov/doc/521-cmr-26-doors-and-doorways/download', 'avancado', true, 'Confirmed 18-inch latch-side clearance for front pull-side approach in 521 CMR 26, consistent with ADAAG door maneuvering clearance tables the AAB adopts.'),
  ('aab-015', 'AAB', 'Ramps - Maximum Rise and Landings', 'Under 521 CMR, what is the maximum rise for any single ramp run before a level landing is required?', '{"A": "12 inches", "B": "24 inches", "C": "30 inches", "D": "36 inches"}'::jsonb, 'C', 'Per 521 CMR 24.00, the maximum rise for any single ramp run is 30 inches. A level landing is required at the top and bottom of each run, and landings must be at least 60 inches long in the direction of travel.', '521 CMR 24.3 / 24.4', 'https://www.mass.gov/doc/521-cmr-24-ramps/download', 'intermediario', true, 'Confirmed 30-inch max ramp rise and 60-inch landing length in 521 CMR 24, consistent with onda-1 aab-006 (1:12 slope) and ADAAG.'),
  ('aab-016', 'AAB', 'Ramps - Landing Width', 'Under 521 CMR, a level landing at the top and bottom of an accessible ramp must have a minimum length, in the direction of travel, of:', '{"A": "36 inches", "B": "48 inches", "C": "60 inches", "D": "72 inches"}'::jsonb, 'C', 'Per 521 CMR 24.00, ramps must have level landings at the bottom and top of each run, and each landing must be at least 60 inches long in the direction of travel. The landing must be at least as wide as the widest ramp run leading to it.', '521 CMR 24.4', 'https://www.mass.gov/doc/521-cmr-24-ramps/download', 'intermediario', true, 'Confirmed 60-inch min landing length in 521 CMR 24, matching the federal ramp-landing standard adopted by the AAB.'),
  ('aab-017', 'AAB', 'Ramps - Handrails', 'Under 521 CMR, ramps with a rise greater than how many inches must have handrails on both sides?', '{"A": "Greater than 3 inches", "B": "Greater than 6 inches", "C": "Greater than 12 inches", "D": "Greater than 30 inches"}'::jsonb, 'B', 'Per 521 CMR 24.00, ramps with a rise greater than 6 inches or a horizontal projection greater than 72 inches must have handrails on both sides. (Handrails are not required on curb ramps or adjacent to seating in assembly areas.)', '521 CMR 24.5', 'https://www.mass.gov/doc/521-cmr-24-ramps/download', 'intermediario', true, 'Confirmed handrails required on ramps with rise > 6 in or run > 72 in in 521 CMR 24, consistent with ADAAG.'),
  ('aab-018', 'AAB', 'Accessible Route - Width', 'Under 521 CMR, the minimum clear width of an accessible route (for a single wheelchair) is generally:', '{"A": "30 inches", "B": "32 inches at a point and 36 inches continuously", "C": "44 inches", "D": "48 inches"}'::jsonb, 'B', 'Per 521 CMR 20.00, the minimum clear width of an accessible route is 36 inches continuously, with a reduction to 32 inches allowed at a point (such as at a doorway) for a maximum depth of 24 inches. Where an accessible route is less than 60 inches wide, passing spaces at least 60 by 60 inches must be provided at reasonable intervals.', '521 CMR 20.2', 'https://www.mass.gov/doc/521-cmr-20-accessible-route/download', 'intermediario', true, 'Confirmed 36-inch continuous / 32-inch-at-a-point accessible route width and 60x60 passing spaces in 521 CMR 20, mirroring ADAAG.'),
  ('aab-019', 'AAB', 'Accessible Toilet Rooms - Grab Bars', 'Under 521 CMR, in an accessible water closet (toilet) compartment, grab bars must be mounted with their top gripping surface at what height above the finished floor?', '{"A": "24 to 28 inches", "B": "30 to 32 inches", "C": "33 to 36 inches", "D": "40 to 44 inches"}'::jsonb, 'C', 'Per 521 CMR 30.00, grab bars at accessible water closets must be mounted with the top of the gripping surface 33 to 36 inches above the finished floor. The diameter of the gripping surface must be 1-1/4 to 1-1/2 inches, with 1-1/2 inches clearance between the bar and the wall.', '521 CMR 30.00', 'https://www.mass.gov/doc/521-cmr-30-toilet-and-bathing-facilities/download', 'avancado', true, 'Confirmed 33-36 inch grab-bar mounting height and 1.5-inch wall clearance in 521 CMR 30, consistent with the ADAAG grab-bar standard adopted by the AAB.'),
  ('aab-020', 'AAB', 'Accessible Toilet Rooms - Water Closet Centerline', 'Under 521 CMR, in an accessible toilet compartment, the centerline of the water closet (toilet) must be located what distance from the adjacent side wall?', '{"A": "12 inches from the side wall", "B": "16 to 18 inches from the side wall", "C": "24 inches from the side wall", "D": "30 inches from the side wall"}'::jsonb, 'B', 'Per 521 CMR 30.00, the centerline of an accessible water closet must be 16 to 18 inches from the adjacent side wall or partition (18 inches is the standard target). This positions the toilet so a wheelchair user can transfer using the side grab bar.', '521 CMR 30.00', 'https://www.mass.gov/doc/521-cmr-30-toilet-and-bathing-facilities/download', 'intermediario', true, 'Confirmed 16-18 inch water-closet centerline from side wall in 521 CMR 30, matching ADAAG (which specifies 16-18 in, 18 in for standard stalls).'),
  ('aab-021', 'AAB', 'Signage - International Symbol of Access', 'Under 521 CMR, accessible facilities and elements required to be identified must display which symbol?', '{"A": "A green cross", "B": "The International Symbol of Access (ISA), a white wheelchair figure on a blue background", "C": "A red octagon", "D": "No symbol is required if a sign reads ''Accessible''"}'::jsonb, 'B', 'Per 521 CMR 41.00, accessible parking spaces, entrances, toilet rooms, and other required accessible elements must be identified by the International Symbol of Access (ISA) -- the standardized wheelchair figure, displayed in white on a blue background for parking signage.', '521 CMR 41.00', 'https://www.mass.gov/doc/521-cmr-41-signage/download', 'iniciante', true, 'Confirmed ISA signage requirement in 521 CMR 41; white-on-blue color for accessible parking signs is the Massachusetts/MUTCD convention.'),
  ('aab-022', 'AAB', 'Signage - Mounting Height', 'Under 521 CMR, permanent room and space identification signs (such as restroom signs with raised characters and Braille) must be mounted so the centerline of the sign is at what height above the finished floor?', '{"A": "48 inches", "B": "54 inches", "C": "60 inches", "D": "72 inches"}'::jsonb, 'C', 'Per 521 CMR 41.00, signs designating permanent rooms and spaces must be mounted with the centerline of the sign 60 inches above the finished floor, and mounted on the wall adjacent to the latch side of the door so a person can approach within 3 inches without encountering protruding objects or the door swing.', '521 CMR 41.00', 'https://www.mass.gov/doc/521-cmr-41-signage/download', 'avancado', true, 'Confirmed 60-inch centerline mounting and latch-side placement for permanent room ID signs in 521 CMR 41, consistent with the ADAAG signage provisions adopted by the AAB.'),
  ('aab-023', 'AAB', 'Elevators - When Required', 'Under 521 CMR, in a newly constructed multi-story public building, when is at least one accessible elevator (or other approved vertical access) generally required?', '{"A": "Only in buildings over 10 stories", "B": "Never; ramps always substitute for elevators", "C": "When the building has more than one story and an accessible route to upper floors is required, an accessible elevator must be provided (subject to specific exceptions)", "D": "Only in hospitals and courthouses"}'::jsonb, 'C', 'Per 521 CMR 28.00, accessible elevators are required to connect each level in multi-story public buildings where an accessible route is required to upper or lower floors. 521 CMR is generally MORE stringent than the federal ADA, which exempts certain small two-story or low-occupancy buildings; in Massachusetts elevators are required in most multi-story public buildings, subject to the specific exceptions and thresholds in 521 CMR.', '521 CMR 28.00', 'https://www.mass.gov/doc/521-cmr-28-elevators/download', 'avancado', true, 'Confirmed general elevator/vertical-access requirement for multi-story public buildings in 521 CMR 28; AAB is stricter than ADA on the small-building elevator exemption. Question is scoped to the general rule and notes ''subject to specific exceptions'' to avoid overstating a single numeric threshold.'),
  ('aab-024', 'AAB', 'Curb Cuts / Curb Ramps', 'Under 521 CMR, the maximum running slope of a curb cut (curb ramp) is:', '{"A": "1:8", "B": "1:10", "C": "1:12", "D": "1:20"}'::jsonb, 'C', 'Per 521 CMR 21.00 / 24.00, curb cuts must have a maximum running slope of 1:12, the same as accessible ramps. The maximum cross slope is 1:50 (2%), and flared sides, where provided, must not exceed a slope of 1:10.', '521 CMR 21.00 / 24.2', 'https://www.mass.gov/doc/521-cmr-21-curb-cuts/download', 'intermediario', true, 'Confirmed 1:12 curb-ramp running slope and 1:10 flared-side slope in 521 CMR, consistent with onda-1 aab-006 ramp slope and ADAAG curb-ramp provisions.'),
  ('aab-025', 'AAB', 'Accessible Parking - Sign Mounting', 'Under 521 CMR, accessible parking spaces must be identified by a sign showing the symbol of access. To remain visible (not obscured by a parked vehicle), the bottom of the sign should be mounted approximately how high?', '{"A": "About 24 inches above grade", "B": "About 36 inches above grade", "C": "A minimum of about 60 inches above grade (so it is visible above a parked vehicle)", "D": "Flat on the pavement only"}'::jsonb, 'C', 'Per 521 CMR 23.00, accessible parking spaces must be identified by a vertical sign bearing the International Symbol of Access mounted high enough to be visible while a vehicle is parked in the space -- generally with the sign mounted so its bottom edge is about 60 inches or higher above grade. Pavement markings alone are not sufficient.', '521 CMR 23.6', 'https://www.mass.gov/doc/521-cmr-23-parking-and-passenger-loading-zones/download', 'intermediario', true, 'Confirmed vertical-sign requirement (not pavement-only) and visible-above-vehicle mounting in 521 CMR 23; the ~60-inch minimum-to-bottom is the standard AAB/ADA convention to keep the symbol visible above a parked car.'),
  ('osha-001', 'OSHA', 'OSHA', 'Under OSHA construction standards, which of the following BEST describes a "competent person"?', '{"A": "An employee who has completed a 10-hour OSHA outreach course", "B": "One who is capable of identifying existing and predictable hazards and is authorized to take prompt corrective measures to eliminate them", "C": "A licensed professional engineer retained by the general contractor", "D": "Any worker designated by the owner regardless of training or authority"}'::jsonb, 'B', 'OSHA defines a competent person as one who is capable of identifying existing and predictable hazards in the surroundings or working conditions which are hazardous or dangerous to employees, AND who has authorization to take prompt corrective measures to eliminate them. Both hazard recognition and the authority to act are required.', '29 CFR 1926.32(f)', 'https://www.osha.gov/laws-regs/regulations/standardnumber/1926/1926.32', 'iniciante', true, 'Confirmed against OSHA 1926.32(f) definitions page. Two-part test (identify hazards + authority to correct) is verbatim from the standard.'),
  ('osha-002', 'OSHA', 'OSHA', 'An anchorage used for the attachment of personal fall arrest equipment must be capable of supporting at least how many pounds per employee attached (when not designed as part of a complete system with a safety factor of two)?', '{"A": "1,800 pounds", "B": "3,000 pounds", "C": "5,000 pounds", "D": "10,000 pounds"}'::jsonb, 'C', 'Anchorages for personal fall arrest equipment must be independent of any anchorage used to support or suspend platforms and must support at least 5,000 pounds per employee attached, unless the system is designed and used with a safety factor of at least two times the maximum arresting force. Note: 3,000 pounds is the figure for POSITIONING devices, not fall arrest anchorages.', '29 CFR 1926.502(d)(15)', 'https://www.osha.gov/laws-regs/regulations/standardnumber/1926/1926.502', 'intermediario', true, 'Confirmed 5,000 lb per employee for fall ARREST anchorages in 1926.502(d)(15). Distractor B (3,000 lb) is intentionally the positioning-device figure from 1926.502(e)(2).'),
  ('osha-003', 'OSHA', 'OSHA', 'A positioning device system (such as a body belt used to hold a worker on a wall to keep both hands free) must be secured to an anchorage capable of supporting at least:', '{"A": "Twice the potential impact load of a fall or 3,000 pounds, whichever is greater", "B": "5,000 pounds per employee attached", "C": "200 pounds applied in any direction", "D": "Half the worker''s body weight"}'::jsonb, 'A', 'Positioning device systems must be secured to an anchorage capable of supporting at least twice the potential impact load of an employee''s fall, or 3,000 pounds, whichever is greater. This is distinct from the 5,000-pound requirement for personal fall ARREST anchorages.', '29 CFR 1926.502(e)(2)', 'https://www.osha.gov/laws-regs/regulations/standardnumber/1926/1926.502', 'intermediario', true, 'Confirmed ''twice the potential impact load or 3,000 lb, whichever is greater'' in 1926.502(e)(2). Distractor B is the fall-arrest figure; distractor C is the guardrail top-rail force.'),
  ('osha-004', 'OSHA', 'OSHA', 'Under the OSHA lead in construction standard, the permissible exposure limit (PEL) for airborne lead, averaged over an 8-hour time-weighted average, is:', '{"A": "30 micrograms per cubic meter of air", "B": "50 micrograms per cubic meter of air", "C": "100 micrograms per cubic meter of air", "D": "400 micrograms per cubic meter of air"}'::jsonb, 'B', 'The employer must ensure no employee is exposed to lead at concentrations greater than 50 micrograms per cubic meter of air (50 ug/m3) averaged over an 8-hour period. The 30 ug/m3 figure is the ACTION LEVEL, not the PEL.', '29 CFR 1926.62(c)(1)', 'https://www.osha.gov/laws-regs/regulations/standardnumber/1926/1926.62', 'intermediario', true, 'Confirmed PEL 50 ug/m3 8-hr TWA in 1926.62(c)(1). Distractor A (30 ug/m3) is intentionally the action level from 1926.62(b).'),
  ('osha-005', 'OSHA', 'OSHA', 'On a construction site, a fire extinguisher rated not less than 2A must be provided for each ____ of protected building area, or major fraction thereof.', '{"A": "1,000 square feet", "B": "2,000 square feet", "C": "3,000 square feet", "D": "5,000 square feet"}'::jsonb, 'C', 'OSHA requires one fire extinguisher rated not less than 2A for each 3,000 square feet of protected building area, or major fraction thereof. Travel distance to the nearest extinguisher cannot exceed 100 feet.', '29 CFR 1926.150(c)(1)(i)', 'https://www.osha.gov/laws-regs/regulations/standardnumber/1926/1926.150', 'intermediario', true, 'Confirmed 2A per 3,000 sq ft and 100 ft max travel distance in 1926.150(c)(1)(i) and (iv).'),
  ('osha-006', 'OSHA', 'OSHA', 'When a portable ladder is used for access to an upper landing surface, the side rails must extend at least how far above the landing surface (or, if not possible, be secured with a grasping device provided)?', '{"A": "1 foot", "B": "2 feet", "C": "3 feet", "D": "4 feet"}'::jsonb, 'C', 'When portable ladders are used for access to an upper landing surface, the ladder side rails must extend at least 3 feet above the landing. If the ladder''s length makes this impossible, the ladder must be secured at the top to a rigid support and a grasping device (grab rail) provided.', '29 CFR 1926.1053(b)(1)', 'https://www.osha.gov/laws-regs/regulations/standardnumber/1926/1926.1053', 'iniciante', true, 'Confirmed 3-foot side-rail extension in 1926.1053(b)(1). Note: this is distinct from the 4:1 (1 ft out per 4 ft of height) setup ratio in 1926.1053(b)(5)(i).'),
  ('osha-007', 'OSHA', 'OSHA', 'A non-self-supporting (leaning) portable ladder must be positioned so that the horizontal distance from the base to the support is approximately what fraction of the working length of the ladder?', '{"A": "One-half (1:2)", "B": "One-third (1:3)", "C": "One-quarter (1:4)", "D": "One-fifth (1:5)"}'::jsonb, 'C', 'Non-self-supporting ladders must be used at an angle where the horizontal distance from the top support to the foot of the ladder is approximately one-quarter of the working length of the ladder (the 4:1 rule, roughly a 75-degree angle).', '29 CFR 1926.1053(b)(5)(i)', 'https://www.osha.gov/laws-regs/regulations/standardnumber/1926/1926.1053', 'intermediario', true, 'Confirmed 1:4 ratio (horizontal distance = 1/4 of working length) in 1926.1053(b)(5)(i).'),
  ('osha-008', 'OSHA', 'OSHA', 'On a construction operation over or near water where the danger of drowning exists, ring buoys with at least 90 feet of line must be readily available, spaced so that the distance between any two ring buoys does not exceed:', '{"A": "100 feet", "B": "150 feet", "C": "200 feet", "D": "300 feet"}'::jsonb, 'C', 'Ring buoys with at least 90 feet of line must be provided and readily available for emergency rescue, and the distance between ring buoys cannot exceed 200 feet. At least one lifesaving skiff must also be immediately available, and U.S. Coast Guard-approved life jackets or buoyant work vests must be provided.', '29 CFR 1926.106(c)', 'https://www.osha.gov/laws-regs/regulations/standardnumber/1926/1926.106', 'intermediario', true, 'Confirmed 90 ft of line and 200 ft max spacing in 1926.106(c); skiff requirement in 1926.106(d).'),
  ('osha-009', 'OSHA', 'OSHA', 'According to OSHA, a DANGER sign must use which color scheme?', '{"A": "Yellow predominating, with black panel and borders", "B": "Red as the predominating color on the upper panel, black outline borders, and a white lower panel for wording", "C": "Green upper panel with white letters on a white background", "D": "Orange background with black lettering"}'::jsonb, 'B', 'Danger signs must have red as the predominating color for the upper panel, black outlines on the borders, and a white lower panel for additional sign wording. They are used only where an immediate hazard exists. (Yellow predominating = CAUTION sign; green upper panel = safety instruction sign.)', '29 CFR 1926.200(b)', 'https://www.osha.gov/laws-regs/regulations/standardnumber/1926/1926.200', 'iniciante', true, 'Confirmed danger sign colors (red/black/white) in 1926.200(b). Distractor A is the caution-sign scheme; distractor C is the safety-instruction-sign scheme.'),
  ('osha-010', 'OSHA', 'OSHA', 'Under OSHA housekeeping requirements for construction, how must combustible scrap and debris be handled during the course of construction?', '{"A": "Left in place until the project is complete, then removed all at once", "B": "Removed at regular intervals during the course of construction", "C": "Burned on site at the end of each work day", "D": "Removed only when it blocks an exit"}'::jsonb, 'B', 'OSHA requires that combustible scrap and debris be removed at regular intervals during the course of construction, and that safe means be provided to facilitate removal. Additionally, form and scrap lumber with protruding nails and all other debris must be kept cleared from work areas, passageways, and stairs.', '29 CFR 1926.25(b)', 'https://www.osha.gov/laws-regs/regulations/standardnumber/1926/1926.25', 'iniciante', true, 'Confirmed ''removed at regular intervals'' for combustible debris in 1926.25(b); cleared-debris requirement in 1926.25(a).'),
  ('aab-001', 'AAB', 'AAB', 'Under 521 CMR (Massachusetts Architectural Access Board), if alteration, reconstruction, or remodeling work on an existing public building equals or exceeds 30% of the full and fair cash value of the building, what is required?', '{"A": "Only the work being performed must comply", "B": "Only an accessible entrance must be added", "C": "The entire building is required to comply with 521 CMR", "D": "No accessibility upgrades are required for existing buildings"}'::jsonb, 'C', 'Under 521 CMR 3.3, when the work performed (including exempted work) amounts to 30% or more of the full and fair cash value of the building, the ENTIRE building must comply with 521 CMR, not just the altered area.', '521 CMR 3.3', 'https://www.law.cornell.edu/regulations/massachusetts/521-CMR-3-3', 'intermediario', true, 'Confirmed 30% full-and-fair-cash-value trigger for full-building compliance in 521 CMR 3.3.'),
  ('aab-002', 'AAB', 'AAB', 'Under 521 CMR 3.3, when work on an existing building is LESS than 30% of full and fair cash value but the cost of the work is $100,000 or more, what must be provided in addition to making the work comply?', '{"A": "Nothing additional; only the work performed must comply", "B": "An accessible public entrance and, if provided, an accessible toilet room, telephone, and drinking fountain", "C": "A full elevator serving every floor", "D": "Compliance of the entire building"}'::jsonb, 'B', 'Under 521 CMR 3.3, if work is under 30% of value but costs $100,000 or more, the work must comply AND an accessible public entrance must be provided, plus an accessible toilet room, telephone, and drinking fountain if those facilities exist. (If the work costs under $100,000, only the work itself must comply.)', '521 CMR 3.3', 'https://www.law.cornell.edu/regulations/massachusetts/521-CMR-3-3', 'avancado', true, 'Confirmed the $100,000 threshold adding entrance/toilet/telephone/drinking-fountain requirement in 521 CMR 3.3, distinct from the under-$100,000 (work-only) and 30% (whole-building) tiers.'),
  ('aab-003', 'AAB', 'AAB', 'Under 521 CMR, the minimum clear floor or ground space required to accommodate a single, stationary wheelchair and occupant is:', '{"A": "24 inches by 36 inches", "B": "30 inches by 48 inches", "C": "36 inches by 60 inches", "D": "48 inches by 48 inches"}'::jsonb, 'B', '521 CMR specifies a minimum clear floor or ground space of 30 inches by 48 inches to accommodate a single stationary wheelchair, positioned for either forward or parallel approach.', '521 CMR 6.4', 'https://www.law.cornell.edu/regulations/massachusetts/521-CMR-6-4', 'iniciante', true, 'Confirmed 30 in x 48 in clear floor space for wheelchairs in 521 CMR 6.4.'),
  ('aab-004', 'AAB', 'AAB', 'Under 521 CMR, when the clear floor space only allows a forward approach to an object, the maximum high forward reach permitted is:', '{"A": "42 inches", "B": "48 inches", "C": "54 inches", "D": "60 inches"}'::jsonb, 'B', 'Per 521 CMR 6.5, where only a forward approach is possible, the maximum high forward reach is 48 inches and the minimum low forward reach is 15 inches. (54 inches is the maximum high SIDE reach for a parallel approach.)', '521 CMR 6.5', 'https://www.law.cornell.edu/regulations/massachusetts/521-CMR-6-5', 'intermediario', true, 'Confirmed 48 in max high forward reach / 15 in min low forward reach in 521 CMR 6.5. Distractor C (54 in) is intentionally the side-reach figure from 6.6.'),
  ('aab-005', 'AAB', 'AAB', 'Under 521 CMR, when the clear floor space allows a parallel approach by a person in a wheelchair, the maximum high side reach permitted is:', '{"A": "48 inches", "B": "52 inches", "C": "54 inches", "D": "60 inches"}'::jsonb, 'C', 'Per 521 CMR 6.6, where a parallel approach is allowed, the maximum high side reach is 54 inches and the low side reach must be no less than 9 inches above the floor. (48 inches is the forward-reach maximum.)', '521 CMR 6.6', 'https://www.law.cornell.edu/regulations/massachusetts/521-CMR-6-6', 'intermediario', true, 'Confirmed 54 in max high side reach / 9 in min low side reach in 521 CMR 6.6. Distractor A (48 in) is the forward-reach figure from 6.5.'),
  ('aab-006', 'AAB', 'AAB', 'Under 521 CMR, the maximum slope allowed for an accessible ramp is:', '{"A": "1:8", "B": "1:10", "C": "1:12", "D": "1:20"}'::jsonb, 'C', 'Per 521 CMR 24.2, the maximum slope of a ramp is 1:12 (8.3%), with no tolerance allowed on slope. The maximum rise for any single run is 30 inches. (A steeper slope between 1:10 and 1:12 is allowed only for a single rise of a maximum of 3 inches.)', '521 CMR 24.2', 'https://www.law.cornell.edu/regulations/massachusetts/521-CMR-24-2', 'iniciante', true, 'Confirmed 1:12 max ramp slope and 30 in max rise in 521 CMR 24.2.'),
  ('aab-007', 'AAB', 'AAB', 'Under 521 CMR, which of the following is correct regarding houses of worship?', '{"A": "Houses of worship are fully exempt from 521 CMR", "B": "Only new construction of houses of worship must comply; existing ones never do", "C": "Houses of worship (including churches, chapels, temples, synagogues, and mosques) must comply with 521 CMR except as modified in 521 CMR 16.00", "D": "Only the parking lot of a house of worship must be accessible"}'::jsonb, 'C', 'Per 521 CMR 16.1, houses of worship -- including but not limited to churches, chapels, temples, synagogues, and mosques -- must comply with 521 CMR except as specified or modified in 521 CMR 16.00. Areas open to the congregation, administrative offices, and religious meeting halls and classrooms must be accessible.', '521 CMR 16.1', 'https://www.law.cornell.edu/regulations/massachusetts/521-CMR-16-1', 'intermediario', true, 'Confirmed house-of-worship scope and listed facility types in 521 CMR 16.1.'),
  ('aab-008', 'AAB', 'AAB', 'Under 521 CMR 19.00 (Recreational Facilities), which statement about courts (such as tennis, racquet, and squash courts) in a recreation facility is correct?', '{"A": "Courts are explicitly exempt from accessibility requirements", "B": "Areas open to and used by the public, including tennis, racquet, and squash courts, must be accessible", "C": "Only spectator seating must be accessible; the courts themselves never must be", "D": "Courts must comply only if the facility is owned by a municipality"}'::jsonb, 'B', 'Per 521 CMR 19.1, all areas open to and used by the public -- including locker rooms, shower facilities, weight rooms, and tennis, racquet, and squash courts -- must be accessible in recreation facilities. Recreational facilities must comply with 521 CMR except as modified in 521 CMR 19.00.', '521 CMR 19.1', 'https://www.law.cornell.edu/regulations/massachusetts/521-CMR-19-1', 'intermediario', true, 'Confirmed in 521 CMR 19.1 that tennis/racquet/squash courts and other public areas must be accessible. NOTE: the source standard lists ''racquet and squash courts'' generally and does NOT state a specific ''one of each type'' numeric threshold; question is scoped to the verified general requirement to avoid asserting an unverified count.'),
  ('aab-009', 'AAB', 'AAB', 'Under 521 CMR, when drinking fountains (water bubblers) are provided, which statement is correct?', '{"A": "Drinking fountains are exempt from accessibility requirements", "B": "Where only one drinking fountain is provided on a floor, it must be accessible; where more than one is provided, one in each location must be accessible and on an accessible route", "C": "Only fountains in the lobby must be accessible", "D": "All drinking fountains may be mounted at any height the owner chooses"}'::jsonb, 'B', 'Under 521 CMR, where only one drinking fountain is provided on a floor it must be accessible; where more than one is provided on a floor, one in each location must be accessible and located on an accessible route. The general rule is that if a facility (toilet, telephone, drinking fountain) is provided, an accessible version must also be provided.', '521 CMR 36.00', 'https://www.mass.gov/doc/521cmr36pdf/download', 'intermediario', true, 'Confirmed the one-per-floor / one-per-location accessible drinking-fountain rule and the general ''if provided, must be accessible'' principle tied to 521 CMR 3.3. Drinking fountains are chapter 36 per mass.gov 521cmr36.')
